      setResolutionScale, togglePerformanceMode,
      togglePlayModePhysics, setSpringStiffness, setSpringDamping
  } = useStore();

  const fileInputRef = useRef<HTMLInputElement>(null);

  if (!isSettingsOpen) return null;

  const handleReset = (e: React.MouseEvent) => {
      e.preventDefault();
      e.stopPropagation();
      if (window.confirm('WARNING: This will completely erase your current project.\n\nAre you sure you want to start over?')) {
          resetProject();
      }
  };

  const handleExport = () => {
      const data = JSON.stringify(project, null, 2);
      const blob = new Blob([data], { type: 'application/json' });
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = `${project.name.replace(/\s+/g, '_').toLowerCase()}_v${project.version}.json`;
      a.click();
      URL.revokeObjectURL(url);
  };

  const handleImport = (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (file) {
          const reader = new FileReader();
          reader.onload = (event) => {
              try {
                  const json = JSON.parse(event.target?.result as string);
                  loadProject(json);
              } catch (err) {
                  alert("Invalid project file.");
              }
          };
          reader.readAsText(file);
      }
  };

