};

// components/Canvas.tsx
import React, { useRef, useLayoutEffect, useEffect, useState } from 'react';
import { useStore } from '../store/useStore';
import { interpolateStrokePoints, snapPointToGrid, isPointInStroke, calculateInterpolationWeights, distance, getBoundingBox, rotatePoint, lerp } from '../utils/math';
import { Point } from '../types';
import { APP_COLORS } from '../constants';

type InteractionMode = 'none' | 'drawing' | 'polyline' | 'dragging' | 'resizing' | 'rotating';
type ResizeHandle = 'tl' | 'tr' | 'bl' | 'br';

export const Canvas: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  const { 
      ui, project, updateAxisValue, updateMultipleAxisValues, 
      addStrokeToCurrentKeyframe, updateStrokeInCurrentKeyframe, selectStroke,
      undo, redo, deleteStroke 
  } = useStore();

  // -- Stable Refs for Animation Loop --
  const projectRef = useRef(project);
  const uiRef = useRef(ui);

  useEffect(() => { projectRef.current = project; }, [project]);
  useEffect(() => { uiRef.current = ui; }, [ui]);

  // -- Physics State (Refs to avoid re-renders) --
  const targetAxesRef = useRef<Record<string, number>>({ 'axis-x': 0.5, 'axis-y': 0.5 });
  const velocityRef = useRef<{ x: number, y: number }>({ x: 0, y: 0 });
  const lastFrameTimeRef = useRef<number>(0);

  // -- Interaction State (Refs needed for Loop access without stale closure) --
  const currentPointsRef = useRef<Point[]>([]); 
  const interactionModeRef = useRef<InteractionMode>('none');

  const [polylinePoints, setPolylinePoints] = useState<Point[]>([]);
  const [mousePos, setMousePos] = useState<Point | null>(null);
  const [activeHandle, setActiveHandle] = useState<ResizeHandle | null>(null);

  // Helpers to sync Ref and State
  const setInteractionMode = (mode: InteractionMode) => {
      interactionModeRef.current = mode;
      // We also trigger a re-render for UI (cursor changes etc) but the loop uses the Ref
      setInteractionModeState(mode);
  };
  const [interactionModeState, setInteractionModeState] = useState<InteractionMode>('none');

  // Transform Data
  const [transformStart, setTransformStart] = useState<{
      mouse: Point;
      center: Point;
      angle: number;
      width: number;
      height: number;
      points: Point[]; // Original points snapshot
  } | null>(null);

  // Live Bounding Box
  const [selectionBounds, setSelectionBounds] = useState<{
      cx: number; cy: number; width: number; height: number; rotation: number;
  } | null>(null);

  // Layout
  const [scale, setScale] = useState(1);
  const CANVAS_WIDTH = project.canvasSize.width;
  const CANVAS_HEIGHT = project.canvasSize.height;

  // -- Helpers --

  // Auto-Scale Canvas
  useEffect(() => {
    const handleResize = () => {
      if (!containerRef.current) return;
      const { width: contW, height: contH } = containerRef.current.getBoundingClientRect();
      const margin = 80;
      const newScale = Math.min((contW - margin) / CANVAS_WIDTH, (contH - margin) / CANVAS_HEIGHT, 1);
      setScale(Math.max(0.1, newScale));
    };
    window.addEventListener('resize', handleResize);
    handleResize();
    return () => window.removeEventListener('resize', handleResize);
  }, [CANVAS_WIDTH, CANVAS_HEIGHT]);

  const getCanvasPoint = (e: React.PointerEvent): Point => {
    if (!canvasRef.current) return { x: 0, y: 0 };
    const rect = canvasRef.current.getBoundingClientRect();
    const x = (e.clientX - rect.left) * (CANVAS_WIDTH / rect.width);
    const y = (e.clientY - rect.top) * (CANVAS_HEIGHT / rect.height);
    return { x, y, pressure: e.pressure || 0.5 };
  };

  const getSnappedPoint = (p: Point): Point => {
      if (ui.snapToGrid) return snapPointToGrid(p, ui.gridSize);
      return p;
  };

  // -- GLOBAL PLAY MODE TRACKING --
  useEffect(() => {
    if (ui.mode !== 'play') return;

    const handleWindowPointerMove = (e: PointerEvent) => {
        if (!canvasRef.current) return;
        const rect = canvasRef.current.getBoundingClientRect();

        let normX = (e.clientX - rect.left) / rect.width;
        let normY = (e.clientY - rect.top) / rect.height;

        // Clamp strictly to 0-1 for axis value logic
        normX = Math.max(0, Math.min(1, normX));
        normY = Math.max(0, Math.min(1, normY));

        if (ui.snapPlayMode) {
            normX = Math.round(normX * 10) / 10;
            normY = Math.round(normY * 10) / 10;
        }

        targetAxesRef.current = { 'axis-x': normX, 'axis-y': normY };
    };

    window.addEventListener('pointermove', handleWindowPointerMove);
    return () => {
        window.removeEventListener('pointermove', handleWindowPointerMove);
    };
  }, [ui.mode, ui.snapPlayMode]);

  const handleDoubleClick = () => {
      if (ui.selectedTool === 'polyline') {
          if (polylinePoints.length > 1) addStrokeToCurrentKeyframe(polylinePoints, false, true);
          setPolylinePoints([]);
      }
  };

  // -- KEYBOARD SHORTCUTS MANAGER --
  useEffect(() => {
      const handleKeyDown = (e: KeyboardEvent) => {
          // Ignore if user is typing in an input
          if ((e.target as HTMLElement).tagName === 'INPUT') return;

          // 1. Tool Shortcuts
          if (e.key === 'Enter') { 
              if (ui.selectedTool === 'polyline') handleDoubleClick(); 
          }
          if (e.key === 'Escape') { 
              setPolylinePoints([]); 
              setInteractionMode('none'); 
              selectStroke(null);
          }

          // 2. Undo / Redo
          if ((e.metaKey || e.ctrlKey) && e.key === 'z') {
              e.preventDefault();
              if (e.shiftKey) redo();
              else undo();
          }
          if ((e.metaKey || e.ctrlKey) && e.key === 'y') {
              e.preventDefault();
              redo();
          }

          // 3. Deletion
          if (e.key === 'Backspace' || e.key === 'Delete') {
              if (ui.selectedStrokeId) {
                  deleteStroke(ui.selectedStrokeId);
              }
          }

          // 4. Nudge (Arrow Keys)
          if (ui.selectedStrokeId && ui.selectedKeyframeId && ui.selectedLayerId && (e.key.startsWith('Arrow'))) {
              e.preventDefault();
              const kf = project.keyframes.find(k => k.id === ui.selectedKeyframeId);
              const ls = kf?.layerStates.find(s => s.layerId === ui.selectedLayerId);
              const stroke = ls?.strokes.find(s => s.id === ui.selectedStrokeId);

              if (stroke) {
                  const step = e.shiftKey ? ui.gridSize : 1;
                  let dx = 0;
                  let dy = 0;
                  if (e.key === 'ArrowUp') dy = -step;
                  if (e.key === 'ArrowDown') dy = step;
                  if (e.key === 'ArrowLeft') dx = -step;
                  if (e.key === 'ArrowRight') dx = step;

                  const newPoints = stroke.points.map(p => ({ ...p, x: p.x + dx, y: p.y + dy }));
                  updateStrokeInCurrentKeyframe(stroke.id, newPoints);
              }
          }
      };

      window.addEventListener('keydown', handleKeyDown);
      return () => window.removeEventListener('keydown', handleKeyDown);
  }, [ui.selectedTool, ui.selectedStrokeId, ui.selectedKeyframeId, ui.selectedLayerId, polylinePoints, project.keyframes]);

  // -- Selection Logic --
  useEffect(() => {
    if (ui.selectedTool !== 'select' || !ui.selectedStrokeId || !ui.selectedKeyframeId) {
        setSelectionBounds(null);
        return;
    }
    const kf = project.keyframes.find(k => k.id === ui.selectedKeyframeId);
    if (!kf) return;
    const layerState = kf.layerStates.find(ls => ls.layerId === ui.selectedLayerId);
    if (!layerState) return;
    const stroke = layerState.strokes.find(s => s.id === ui.selectedStrokeId);
    if (!stroke) return;
    const bbox = getBoundingBox(stroke.points);
    setSelectionBounds({
        cx: bbox.centerX, cy: bbox.centerY, width: bbox.width, height: bbox.height, rotation: 0
    });
  }, [ui.selectedStrokeId, ui.selectedKeyframeId, ui.selectedLayerId, ui.selectedTool, project.keyframes]);

  // -- Gizmo Hit Testing --
  const getGizmoHit = (p: Point, bounds: { cx: number, cy: number, width: number, height: number, rotation: number } | null) => {
      if (!bounds) return null;
      const { cx, cy, width, height, rotation } = bounds;
      const hw = width / 2; const hh = height / 2;
      const localP = rotatePoint(p, {x: cx, y: cy}, -rotation);
      const HANDLE_SIZE = 10 / scale;
      if (distance(localP, {x: cx, y: cy - hh - 25}) < HANDLE_SIZE) return 'rotator';
      if (distance(localP, {x: cx - hw, y: cy - hh}) < HANDLE_SIZE) return 'tl';
      if (distance(localP, {x: cx + hw, y: cy - hh}) < HANDLE_SIZE) return 'tr';
      if (distance(localP, {x: cx - hw, y: cy + hh}) < HANDLE_SIZE) return 'bl';
      if (distance(localP, {x: cx + hw, y: cy + hh}) < HANDLE_SIZE) return 'br';
      if (localP.x >= cx - hw && localP.x <= cx + hw && localP.y >= cy - hh && localP.y <= cy + hh) return 'body';
      return null;
  };

  const findHitStroke = (p: Point): string | null => {
     const kf = project.keyframes.find(k => k.id === ui.selectedKeyframeId);
     if (!kf) return null;
     const layerState = kf.layerStates.find(ls => ls.layerId === ui.selectedLayerId);
     if (!layerState) return null;
     for (let i = layerState.strokes.length - 1; i >= 0; i--) {
        const s = layerState.strokes[i];
        if (isPointInStroke(p, s.points)) return s.id;
     }
     return null;
  };

  // -- Event Handlers --

  const handlePointerDown = (e: React.PointerEvent) => {
    const p = getCanvasPoint(e);

    // In Play Mode, we don't capture pointer on canvas anymore, 
    // because we use the global window listener for movement.
    if (ui.mode === 'play') {
       return;
    }

    if (ui.selectedTool === 'select') {
        const hitGizmo = getGizmoHit(p, selectionBounds);
        if (hitGizmo && selectionBounds && ui.selectedStrokeId) {
            const kf = project.keyframes.find(k => k.id === ui.selectedKeyframeId);
            const ls = kf?.layerStates.find(s => s.layerId === ui.selectedLayerId);
            const stroke = ls?.strokes.find(s => s.id === ui.selectedStrokeId);
            if (stroke) {
                setTransformStart({
                    mouse: p, center: { x: selectionBounds.cx, y: selectionBounds.cy },
                    angle: selectionBounds.rotation, width: selectionBounds.width, height: selectionBounds.height, points: stroke.points
                });
                if (hitGizmo === 'body') setInteractionMode('dragging');
                else if (hitGizmo === 'rotator') setInteractionMode('rotating');
                else { setInteractionMode('resizing'); setActiveHandle(hitGizmo as ResizeHandle); }
                (e.target as Element).setPointerCapture(e.pointerId);
            }
            return;
        }
        const hitId = findHitStroke(p);
        if (hitId) selectStroke(hitId); else selectStroke(null);
        return;
    }

    if (ui.selectedTool === 'polyline') {
       const snappedP = getSnappedPoint(p);
       if (polylinePoints.length > 2 && distance(snappedP, polylinePoints[0]) < 15) {
           addStrokeToCurrentKeyframe(polylinePoints, true, true);
           setPolylinePoints([]);
           return;
       }
       if (polylinePoints.length > 0) {
           const lastPoint = polylinePoints[polylinePoints.length - 1];
           if (distance(snappedP, lastPoint) < 15) {
               addStrokeToCurrentKeyframe(polylinePoints, false, true);
               setPolylinePoints([]);
               return;
           }
       }
       setPolylinePoints(prev => [...prev, snappedP]);
       return;
    }

    if (ui.selectedTool === 'pen') {
      setInteractionMode('drawing'); // Updates Ref immediately
      currentPointsRef.current = [getSnappedPoint(p)];
      (e.target as Element).setPointerCapture(e.pointerId);
    } 
  };

  const handlePointerMove = (e: React.PointerEvent) => {
    const p = getCanvasPoint(e);
    setMousePos(getSnappedPoint(p));

    // PLAY MODE: Handled by global window listener now.
    if (ui.mode === 'play') return;

    if (interactionModeRef.current !== 'none' && transformStart && selectionBounds) {
        if (interactionModeRef.current === 'dragging') {
            let dx = p.x - transformStart.mouse.x; let dy = p.y - transformStart.mouse.y;
            if (ui.snapToGrid) {
                const targetX = transformStart.center.x + dx; const targetY = transformStart.center.y + dy;
                const snappedX = Math.round(targetX / ui.gridSize) * ui.gridSize; const snappedY = Math.round(targetY / ui.gridSize) * ui.gridSize;
                dx = snappedX - transformStart.center.x; dy = snappedY - transformStart.center.y;
            }
            setSelectionBounds({ ...selectionBounds, cx: transformStart.center.x + dx, cy: transformStart.center.y + dy });
        } else if (interactionModeRef.current === 'rotating') {
            const currentAngle = Math.atan2(p.y - selectionBounds.cy, p.x - selectionBounds.cx);
            const startAngle = Math.atan2(transformStart.mouse.y - selectionBounds.cy, transformStart.mouse.x - selectionBounds.cx);
            let dAngle = currentAngle - startAngle; let newRotation = transformStart.angle + dAngle;
            if (e.shiftKey) { const step = Math.PI / 12; newRotation = Math.round(newRotation / step) * step; }
            setSelectionBounds({ ...selectionBounds, rotation: newRotation });
        } else if (interactionModeRef.current === 'resizing' && activeHandle) {
            const unrotatedMouse = rotatePoint(p, transformStart.center, -transformStart.angle);
            const unrotatedStart = rotatePoint(transformStart.mouse, transformStart.center, -transformStart.angle);
            let dx = unrotatedMouse.x - unrotatedStart.x; let dy = unrotatedMouse.y - unrotatedStart.y;
            if (e.shiftKey) { const aspect = transformStart.width / transformStart.height; dy = (activeHandle === 'br' || activeHandle === 'tl') ? dx / aspect : -dx / aspect; }
            if (ui.snapToGrid && !e.shiftKey) { dx = Math.round(dx / ui.gridSize) * ui.gridSize; dy = Math.round(dy / ui.gridSize) * ui.gridSize; }
            let newW = transformStart.width; let newH = transformStart.height;
            if (activeHandle === 'br') { newW += dx * 2; newH += dy * 2; }
            if (activeHandle === 'tl') { newW -= dx * 2; newH -= dy * 2; }
            if (activeHandle === 'tr') { newW += dx * 2; newH -= dy * 2; }
            if (activeHandle === 'bl') { newW -= dx * 2; newH += dy * 2; }
            newW = Math.max(1, newW); newH = Math.max(1, newH);
            setSelectionBounds({ ...selectionBounds, width: newW, height: newH });
        }
        return;
    }

    if (interactionModeRef.current === 'drawing') {
        currentPointsRef.current.push(getSnappedPoint(p));
    }
  };

  const handlePointerUp = (e: React.PointerEvent) => {
    if (ui.mode !== 'play') {
       (e.target as Element).releasePointerCapture(e.pointerId);
    }

    if (interactionModeRef.current !== 'none' && transformStart && selectionBounds && ui.selectedStrokeId) {
        const scaleX = selectionBounds.width / transformStart.width;
        const scaleY = selectionBounds.height / transformStart.height;
        const dRot = selectionBounds.rotation - transformStart.angle;
        const dX = selectionBounds.cx - transformStart.center.x;
        const dY = selectionBounds.cy - transformStart.center.y;
        const newPoints = transformStart.points.map(pt => {
            let x = pt.x - transformStart.center.x; let y = pt.y - transformStart.center.y;
            x *= scaleX; y *= scaleY;
            const cos = Math.cos(dRot); const sin = Math.sin(dRot);
            const rx = x * cos - y * sin; const ry = x * sin + y * cos;
            return { x: rx + transformStart.center.x + dX, y: ry + transformStart.center.y + dY, pressure: pt.pressure };
        });
        updateStrokeInCurrentKeyframe(ui.selectedStrokeId, newPoints);
    }

    // DRAWING END
    if (interactionModeRef.current === 'drawing' && currentPointsRef.current.length > 1) {
        const points = [...currentPointsRef.current];
        const start = points[0];
        const end = points[points.length - 1];

        // AUTO-CLOSE LOGIC: 
        // Close only if loop detected AND user has active Fill Color.
        // If Fill Color is 'none', keep it open even if it overlaps.
        const isLoop = distance(start, end) < 20; // 20px threshold
        const shouldClose = isLoop && (ui.fillColor !== 'none');

        addStrokeToCurrentKeyframe(points, shouldClose);
    }
    setInteractionMode('none'); setActiveHandle(null); setTransformStart(null); currentPointsRef.current = [];
  };

  // -- THE RENDER LOOP --
  // This loop depends mainly on canvas size to restart, but reads data from Refs to stay fresh.
  useLayoutEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    let animationFrameId: number;

    const render = (time: number) => {
      // 1. Calculate Delta Time for Physics
      if (!lastFrameTimeRef.current) lastFrameTimeRef.current = time;
      const dt = Math.min((time - lastFrameTimeRef.current) / 1000, 0.1); // Cap dt to avoid explosion on lag
      lastFrameTimeRef.current = time;

      // 2. Read Fresh State from Refs
      const currentProject = projectRef.current;
      const currentUI = uiRef.current;

      const dpr = currentUI.resolutionScale || window.devicePixelRatio || 1;
      const interpolationTargetCount = currentUI.performanceMode ? 80 : 200;

      // Ensure Canvas Size is correct (this might be redundant if deps are correct, but safe)
      if (canvas.width !== CANVAS_WIDTH * dpr || canvas.height !== CANVAS_HEIGHT * dpr) {
          canvas.width = CANVAS_WIDTH * dpr;
          canvas.height = CANVAS_HEIGHT * dpr;
          ctx.scale(dpr, dpr);
      }

      // 3. PLAY MODE PHYSICS (Spring System)
      if (currentUI.mode === 'play') {
          const axisX = currentProject.axes.find(a => a.id === 'axis-x');
          const axisY = currentProject.axes.find(a => a.id === 'axis-y');

          if (axisX && axisY) {
              const targetX = targetAxesRef.current['axis-x'];
              const targetY = targetAxesRef.current['axis-y'];

              let nextX = axisX.currentValue;
              let nextY = axisY.currentValue;

              if (currentUI.playModePhysics) {
                  // Second Order Dynamics (Spring-Damper)
                  const stiffness = currentUI.springStiffness || 120;
                  const damping = currentUI.springDamping || 20;

                  // F = -kx - cv
                  const forceX = (targetX - nextX) * stiffness - velocityRef.current.x * damping;
                  const forceY = (targetY - nextY) * stiffness - velocityRef.current.y * damping;

                  velocityRef.current.x += forceX * dt;
                  velocityRef.current.y += forceY * dt;

                  nextX += velocityRef.current.x * dt;
                  nextY += velocityRef.current.y * dt;
              } else {
                  nextX = targetX;
                  nextY = targetY;
                  velocityRef.current = { x: 0, y: 0 };
              }

              // Update Store if significant change
              if (Math.abs(nextX - axisX.currentValue) > 0.0001 || Math.abs(nextY - axisY.currentValue) > 0.0001) {
                  // Clamp value strictly for the store (Puppet Model Requirement)
                  const clampedX = Math.max(0, Math.min(1, nextX));
                  const clampedY = Math.max(0, Math.min(1, nextY));

                  // This triggers React Render -> Updates Project Prop -> Updates ProjectRef
                  updateMultipleAxisValues({ 'axis-x': clampedX, 'axis-y': clampedY });
              }
          }
      } else {
           // In Edit mode, sync target ref with actual values so we don't jump when switching to play
           const curX = currentProject.axes.find(a => a.id === 'axis-x')?.currentValue || 0.5;
           const curY = currentProject.axes.find(a => a.id === 'axis-y')?.currentValue || 0.5;
           targetAxesRef.current = { 'axis-x': curX, 'axis-y': curY };
           velocityRef.current = { x: 0, y: 0 };
      }

      // 4. CLEAR & DRAW
      ctx.clearRect(0, 0, CANVAS_WIDTH, CANVAS_HEIGHT);
      ctx.fillStyle = '#FFFFFF';
      ctx.fillRect(0, 0, CANVAS_WIDTH, CANVAS_HEIGHT);

      // GRID
      if (currentUI.showGrid && currentUI.mode === 'edit') {
        ctx.fillStyle = '#D1D5DB';
        const gridSize = currentUI.gridSize;
        const centerX = CANVAS_WIDTH / 2;
        const centerY = CANVAS_HEIGHT / 2;
        const startX = (centerX % gridSize);
        const startY = (centerY % gridSize);
        for (let x = startX; x <= CANVAS_WIDTH; x += gridSize) {
           for (let y = startY; y <= CANVAS_HEIGHT; y += gridSize) {
              ctx.beginPath();
              ctx.arc(x, y, 1.5, 0, Math.PI * 2);
              ctx.fill();
           }
        }
      }

      // ONION SKIN
      if (currentUI.onionSkinEnabled && currentUI.mode === 'edit') {
         currentProject.keyframes.forEach(kf => {
           if (kf.id === currentUI.selectedKeyframeId) return; 
           ctx.globalAlpha = currentUI.onionSkinOpacity;
           kf.layerStates.forEach(ls => {
              if (ls.layerId !== currentUI.selectedLayerId) return;
              const stroke = ls.strokes[0];
              if (stroke && stroke.points.length > 1) {
                ctx.beginPath();
                ctx.moveTo(stroke.points[0].x, stroke.points[0].y);
                for (let i = 1; i < stroke.points.length; i++) ctx.lineTo(stroke.points[i].x, stroke.points[i].y);
                if (stroke.closed) ctx.closePath();
                ctx.strokeStyle = '#3B82F6'; 
                ctx.lineWidth = 1; 
                ctx.stroke();
              }
           });
           ctx.globalAlpha = 1.0;
         });
      }

      // INTERPOLATION RENDERING
      const currentAxesDict: Record<string, number> = {};
      currentProject.axes.forEach(a => currentAxesDict[a.id] = a.currentValue);

      currentProject.layers.forEach(layer => {
        if (!layer.visible) return;

        const layerRelevantKeyframes = currentProject.keyframes.filter(kf => {
            const ls = kf.layerStates.find(s => s.layerId === layer.id);
            return ls && ls.strokes.length > 0;
        });

        if (layerRelevantKeyframes.length === 0) return;

        const weights = calculateInterpolationWeights(currentAxesDict, layerRelevantKeyframes, currentUI.interpolationExponent, currentUI.interpolationStrategy);

        const activeKeyframes = layerRelevantKeyframes
             .map(k => ({ ...k, weight: weights[k.id] || 0 }))
             .filter(k => k.weight > 0.0001);

        const strokeId = `stroke-${layer.id}-unique`;
        const isLayerActive = layer.id === currentUI.selectedLayerId;
        const isCreatingNewState = currentUI.selectedKeyframeId === null;

        let layerGlobalAlpha = layer.opacity;
        if (!isLayerActive && currentUI.mode !== 'play') layerGlobalAlpha *= currentUI.inactiveLayerOpacity;
        if (isCreatingNewState && currentUI.mode === 'edit') layerGlobalAlpha *= currentUI.ghostStrokeOpacity;

        const strokeData = activeKeyframes.map(kf => {
            const state = kf.layerStates.find(ls => ls.layerId === layer.id);
            const s = state?.strokes[0]; 
            return { weight: kf.weight, points: s?.points, style: s, color: s?.color || 'none', fillColor: s?.fillColor, width: s?.width || 1 };
        });

        const sortedByWeight = [...strokeData].sort((a,b) => b.weight - a.weight);
        const primaryStroke = sortedByWeight.find(sd => sd.style)?.style;
        if (!primaryStroke) return;

        const { points: interpolatedPoints, color: interpolatedColor, fillColor: interpolatedFill, width: interpolatedWidth } = interpolateStrokePoints(
            strokeId, 
            primaryStroke.points, 
            strokeData, 
            layer.interpolationMode,
            interpolationTargetCount 
        );

        if (interpolatedPoints.length > 0) {
            ctx.beginPath();
            ctx.moveTo(interpolatedPoints[0].x, interpolatedPoints[0].y);
            for (let i = 1; i < interpolatedPoints.length; i++) ctx.lineTo(interpolatedPoints[i].x, interpolatedPoints[i].y);
            if (primaryStroke.closed) ctx.closePath();

            ctx.globalAlpha = layerGlobalAlpha;
            switch(layer.blendMode) {
                case 'multiply': ctx.globalCompositeOperation = 'multiply'; break;
                case 'screen': ctx.globalCompositeOperation = 'screen'; break;
                case 'overlay': ctx.globalCompositeOperation = 'overlay'; break;
                case 'difference': ctx.globalCompositeOperation = 'difference'; break;
                case 'exclusion': ctx.globalCompositeOperation = 'exclusion'; break;
                default: ctx.globalCompositeOperation = 'source-over';
            }

            if (interpolatedFill && interpolatedFill !== 'none') {
                ctx.fillStyle = interpolatedFill;
                ctx.fill();
            }
            if (interpolatedColor && interpolatedColor !== 'none') {
                ctx.lineCap = 'round';
                ctx.lineJoin = 'round';
                ctx.strokeStyle = interpolatedColor;
                ctx.lineWidth = interpolatedWidth;
                ctx.stroke();
            }

            ctx.globalAlpha = 1.0;
            ctx.globalCompositeOperation = 'source-over';
        }
      });

      // ACTIVE DRAWING (Using Refs to bypass stale closure issues)
      if (interactionModeRef.current === 'drawing' && currentPointsRef.current.length > 0) {
        const isGhostState = currentUI.selectedKeyframeId === null;
        ctx.globalAlpha = isGhostState ? currentUI.ghostStrokeOpacity : 1.0;

        ctx.beginPath();
        const pts = currentPointsRef.current;
        ctx.moveTo(pts[0].x, pts[0].y);
        for (let i = 1; i < pts.length; i++) ctx.lineTo(pts[i].x, pts[i].y);
        ctx.strokeStyle = currentUI.brushColor !== 'none' ? currentUI.brushColor : 'rgba(0,0,0,0.2)'; 
        ctx.lineWidth = currentUI.brushSize;
        ctx.lineCap = 'round';
        ctx.lineJoin = 'round';
        ctx.stroke();
        ctx.globalAlpha = 1.0; 
      }

      // ACTIVE POLYLINE
      if (polylinePoints.length > 0) {
         const isGhostState = currentUI.selectedKeyframeId === null;
         ctx.globalAlpha = isGhostState ? currentUI.ghostStrokeOpacity : 1.0;

         ctx.beginPath();
         ctx.moveTo(polylinePoints[0].x, polylinePoints[0].y);
         for (let i = 1; i < polylinePoints.length; i++) ctx.lineTo(polylinePoints[i].x, polylinePoints[i].y);

         if (mousePos) ctx.lineTo(mousePos.x, mousePos.y); 

         if (currentUI.fillColor !== 'none') {
             ctx.fillStyle = currentUI.fillColor;
             ctx.globalAlpha = isGhostState ? currentUI.ghostStrokeOpacity * 0.5 : 0.5;
             ctx.fill();
             ctx.globalAlpha = isGhostState ? currentUI.ghostStrokeOpacity : 1.0;
         }

         ctx.strokeStyle = currentUI.brushColor !== 'none' ? currentUI.brushColor : 'rgba(0,0,0,0.5)';
         ctx.lineWidth = currentUI.brushSize;
         ctx.stroke();

         ctx.fillStyle = currentUI.brushColor !== 'none' ? currentUI.brushColor : 'rgba(0,0,0,0.5)';
         polylinePoints.forEach((p, index) => {
            ctx.beginPath();
            const r = (index === 0) ? 5 : 3; 
            ctx.arc(p.x, p.y, r, 0, Math.PI * 2);
            ctx.fill();
         });
         ctx.globalAlpha = 1.0; 
      }

      // GIZMOS (using currentSelectionBounds if we had used a ref, but selectionBounds state triggers re-render so its fine)
      if (selectionBounds && currentUI.selectedTool === 'select' && currentUI.mode === 'edit') {
          const { cx, cy, width, height, rotation } = selectionBounds;

          ctx.save();
          ctx.translate(cx, cy);
          ctx.rotate(rotation);

          ctx.beginPath();
          ctx.strokeStyle = '#3B82F6';
          ctx.lineWidth = 1;
          ctx.rect(-width/2, -height/2, width, height);
          ctx.stroke();

          const HANDLE_SIZE = 8; 
          ctx.fillStyle = '#FFFFFF';
          ctx.strokeStyle = '#3B82F6';

          const drawHandle = (x: number, y: number) => {
              ctx.beginPath();
              ctx.rect(x - HANDLE_SIZE/2, y - HANDLE_SIZE/2, HANDLE_SIZE, HANDLE_SIZE);
              ctx.fill();
              ctx.stroke();
          };

          drawHandle(-width/2, -height/2); // TL
          drawHandle(width/2, -height/2);  // TR
          drawHandle(-width/2, height/2);  // BL
          drawHandle(width/2, height/2);   // BR

          ctx.beginPath();
          ctx.moveTo(0, -height/2);
          ctx.lineTo(0, -height/2 - 25);
          ctx.stroke();

          ctx.beginPath();
          ctx.arc(0, -height/2 - 25, 4, 0, Math.PI * 2);
          ctx.fillStyle = '#3B82F6';
          ctx.fill();

          ctx.restore();
      }

      animationFrameId = requestAnimationFrame(render);
    };

    animationFrameId = requestAnimationFrame(render);
    return () => cancelAnimationFrame(animationFrameId);
  }, [CANVAS_WIDTH, CANVAS_HEIGHT]); // Minimized dependencies for loop stability

  return (
    <div 
      ref={containerRef} 
      className="absolute inset-0 z-0 flex items-center justify-center bg-[#EAEAEA] touch-none"
    >
      <div 
        style={{ 
          width: CANVAS_WIDTH, 
          height: CANVAS_HEIGHT,
          transform: `scale(${scale})`,
          boxShadow: '0 20px 50px -12px rgba(0, 0, 0, 0.15)' 
        }}
        className="bg-white rounded-xl overflow-hidden relative transition-transform duration-200 ease-out origin-center ring-4 ring-white/50"
      >
          <canvas 
            ref={canvasRef} 
            className={`block w-full h-full ${ui.mode === 'play' ? 'cursor-move' : (ui.selectedTool === 'select' ? 'cursor-default' : 'cursor-crosshair')}`}
            onPointerDown={handlePointerDown}
            onPointerMove={handlePointerMove}
            onPointerUp={handlePointerUp}
            onDoubleClick={handleDoubleClick}
          />
      </div>
    </div>
  );
};

// components/Canvas.tsx
import React, { useRef, useLayoutEffect, useEffect, useState } from 'react';
import { useStore } from '../store/useStore';
import { interpolateStrokePoints, snapPointToGrid, isPointInStroke, calculateInterpolationWeights, distance, getBoundingBox, rotatePoint, lerp } from '../utils/math';
import { Point } from '../types';
import { APP_COLORS } from '../constants';

type InteractionMode = 'none' | 'drawing' | 'polyline' | 'dragging' | 'resizing' | 'rotating';
type ResizeHandle = 'tl' | 'tr' | 'bl' | 'br';

export const Canvas: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  const { 
      ui, project, updateAxisValue, updateMultipleAxisValues, 
      addStrokeToCurrentKeyframe, updateStrokeInCurrentKeyframe, selectStroke,
      undo, redo, deleteStroke 
  } = useStore();

  // -- Stable Refs for Animation Loop --
  const projectRef = useRef(project);
  const uiRef = useRef(ui);

  useEffect(() => { projectRef.current = project; }, [project]);
  useEffect(() => { uiRef.current = ui; }, [ui]);

  // -- Physics State (Refs to avoid re-renders) --
  const targetAxesRef = useRef<Record<string, number>>({ 'axis-x': 0.5, 'axis-y': 0.5 });
  const velocityRef = useRef<{ x: number, y: number }>({ x: 0, y: 0 });
  const lastFrameTimeRef = useRef<number>(0);

  // -- Interaction State (Refs needed for Loop access without stale closure) --
  const currentPointsRef = useRef<Point[]>([]); 
  const interactionModeRef = useRef<InteractionMode>('none');

  // -- SYNCED REFS FOR RENDERING --
  // We use State for React updates (UI), but Refs for the Canvas Loop to avoid stale closures.
  const [polylinePoints, setPolylinePoints] = useState<Point[]>([]);
  const polylinePointsRef = useRef<Point[]>([]);
  useEffect(() => { polylinePointsRef.current = polylinePoints; }, [polylinePoints]);

  const [mousePos, setMousePos] = useState<Point | null>(null);
  const mousePosRef = useRef<Point | null>(null);
  useEffect(() => { mousePosRef.current = mousePos; }, [mousePos]);

  const [selectionBounds, setSelectionBounds] = useState<{cx: number; cy: number; width: number; height: number; rotation: number;} | null>(null);
  const selectionBoundsRef = useRef(selectionBounds);
  useEffect(() => { selectionBoundsRef.current = selectionBounds; }, [selectionBounds]);

  const [transformStart, setTransformStart] = useState<{
      mouse: Point;
      center: Point;
      angle: number;
      width: number;
      height: number;
      points: Point[]; 
  } | null>(null);
  const transformStartRef = useRef(transformStart);
  useEffect(() => { transformStartRef.current = transformStart; }, [transformStart]);

  const [activeHandle, setActiveHandle] = useState<ResizeHandle | null>(null);

  // Helpers to sync Ref and State
  const setInteractionMode = (mode: InteractionMode) => {
      interactionModeRef.current = mode;
      setInteractionModeState(mode);
  };
  const [interactionModeState, setInteractionModeState] = useState<InteractionMode>('none');

  // Layout
  const [scale, setScale] = useState(1);
  const CANVAS_WIDTH = project.canvasSize.width;
  const CANVAS_HEIGHT = project.canvasSize.height;

  // -- Helpers --

  // Auto-Scale Canvas
  useEffect(() => {
    const handleResize = () => {
      if (!containerRef.current) return;
      const { width: contW, height: contH } = containerRef.current.getBoundingClientRect();
      const margin = 80;
      const newScale = Math.min((contW - margin) / CANVAS_WIDTH, (contH - margin) / CANVAS_HEIGHT, 1);
      setScale(Math.max(0.1, newScale));
    };
    window.addEventListener('resize', handleResize);
    handleResize();
    return () => window.removeEventListener('resize', handleResize);
  }, [CANVAS_WIDTH, CANVAS_HEIGHT]);

  const getCanvasPoint = (e: React.PointerEvent): Point => {
    if (!canvasRef.current) return { x: 0, y: 0 };
    const rect = canvasRef.current.getBoundingClientRect();
    const x = (e.clientX - rect.left) * (CANVAS_WIDTH / rect.width);
    const y = (e.clientY - rect.top) * (CANVAS_HEIGHT / rect.height);
    return { x, y, pressure: e.pressure || 0.5 };
  };

  const getSnappedPoint = (p: Point): Point => {
      if (ui.snapToGrid) return snapPointToGrid(p, ui.gridSize);
      return p;
  };

  // -- GLOBAL PLAY MODE TRACKING --
  useEffect(() => {
    if (ui.mode !== 'play') return;

    const handleWindowPointerMove = (e: PointerEvent) => {
        if (!canvasRef.current) return;
        const rect = canvasRef.current.getBoundingClientRect();

        let normX = (e.clientX - rect.left) / rect.width;
        let normY = (e.clientY - rect.top) / rect.height;

        // Clamp strictly to 0-1 for axis value logic
        normX = Math.max(0, Math.min(1, normX));
        normY = Math.max(0, Math.min(1, normY));

        if (ui.snapPlayMode) {
            normX = Math.round(normX * 10) / 10;
            normY = Math.round(normY * 10) / 10;
        }

        targetAxesRef.current = { 'axis-x': normX, 'axis-y': normY };
    };

    window.addEventListener('pointermove', handleWindowPointerMove);
    return () => {
        window.removeEventListener('pointermove', handleWindowPointerMove);
    };
  }, [ui.mode, ui.snapPlayMode]);

  const handleDoubleClick = () => {
      if (ui.selectedTool === 'polyline') {
          if (polylinePoints.length > 1) addStrokeToCurrentKeyframe(polylinePoints, false, true);
          setPolylinePoints([]);
      }
  };

  // -- KEYBOARD SHORTCUTS MANAGER --
  useEffect(() => {
      const handleKeyDown = (e: KeyboardEvent) => {
          // Ignore if user is typing in an input
          if ((e.target as HTMLElement).tagName === 'INPUT') return;

          // 1. Tool Shortcuts
          if (e.key === 'Enter') { 
              if (ui.selectedTool === 'polyline') handleDoubleClick(); 
          }
          if (e.key === 'Escape') { 
              setPolylinePoints([]); 
              setInteractionMode('none'); 
              selectStroke(null);
          }

          // 2. Undo / Redo
          if ((e.metaKey || e.ctrlKey) && e.key === 'z') {
              e.preventDefault();
              if (e.shiftKey) redo();
              else undo();
          }
          if ((e.metaKey || e.ctrlKey) && e.key === 'y') {
              e.preventDefault();
              redo();
          }

          // 3. Deletion
          if (e.key === 'Backspace' || e.key === 'Delete') {
              if (ui.selectedStrokeId) {
                  deleteStroke(ui.selectedStrokeId);
              }
          }

          // 4. Nudge (Arrow Keys)
          if (ui.selectedStrokeId && ui.selectedKeyframeId && ui.selectedLayerId && (e.key.startsWith('Arrow'))) {
              e.preventDefault();
              const kf = project.keyframes.find(k => k.id === ui.selectedKeyframeId);
              const ls = kf?.layerStates.find(s => s.layerId === ui.selectedLayerId);
              const stroke = ls?.strokes.find(s => s.id === ui.selectedStrokeId);

              if (stroke) {
                  const step = e.shiftKey ? ui.gridSize : 1;
                  let dx = 0;
                  let dy = 0;
                  if (e.key === 'ArrowUp') dy = -step;
                  if (e.key === 'ArrowDown') dy = step;
                  if (e.key === 'ArrowLeft') dx = -step;
                  if (e.key === 'ArrowRight') dx = step;

                  const newPoints = stroke.points.map(p => ({ ...p, x: p.x + dx, y: p.y + dy }));
                  updateStrokeInCurrentKeyframe(stroke.id, newPoints);
              }
          }
      };

      window.addEventListener('keydown', handleKeyDown);
      return () => window.removeEventListener('keydown', handleKeyDown);
  }, [ui.selectedTool, ui.selectedStrokeId, ui.selectedKeyframeId, ui.selectedLayerId, polylinePoints, project.keyframes]);

  // -- Selection Logic --
  useEffect(() => {
    if (ui.selectedTool !== 'select' || !ui.selectedStrokeId || !ui.selectedKeyframeId) {
        setSelectionBounds(null);
        return;
    }
    const kf = project.keyframes.find(k => k.id === ui.selectedKeyframeId);
    if (!kf) return;
    const layerState = kf.layerStates.find(ls => ls.layerId === ui.selectedLayerId);
    if (!layerState) return;
    const stroke = layerState.strokes.find(s => s.id === ui.selectedStrokeId);
    if (!stroke) return;
    const bbox = getBoundingBox(stroke.points);
    setSelectionBounds({
        cx: bbox.centerX, cy: bbox.centerY, width: bbox.width, height: bbox.height, rotation: 0
    });
  }, [ui.selectedStrokeId, ui.selectedKeyframeId, ui.selectedLayerId, ui.selectedTool, project.keyframes]);

  // -- Gizmo Hit Testing --
  const getGizmoHit = (p: Point, bounds: { cx: number, cy: number, width: number, height: number, rotation: number } | null) => {
      if (!bounds) return null;
      const { cx, cy, width, height, rotation } = bounds;
      const hw = width / 2; const hh = height / 2;
      const localP = rotatePoint(p, {x: cx, y: cy}, -rotation);
      const HANDLE_SIZE = 10 / scale;
      if (distance(localP, {x: cx, y: cy - hh - 25}) < HANDLE_SIZE) return 'rotator';
      if (distance(localP, {x: cx - hw, y: cy - hh}) < HANDLE_SIZE) return 'tl';
      if (distance(localP, {x: cx + hw, y: cy - hh}) < HANDLE_SIZE) return 'tr';
      if (distance(localP, {x: cx - hw, y: cy + hh}) < HANDLE_SIZE) return 'bl';
      if (distance(localP, {x: cx + hw, y: cy + hh}) < HANDLE_SIZE) return 'br';
      if (localP.x >= cx - hw && localP.x <= cx + hw && localP.y >= cy - hh && localP.y <= cy + hh) return 'body';
      return null;
  };

  const findHitStroke = (p: Point): string | null => {
     const kf = project.keyframes.find(k => k.id === ui.selectedKeyframeId);
     if (!kf) return null;
     const layerState = kf.layerStates.find(ls => ls.layerId === ui.selectedLayerId);
     if (!layerState) return null;
     for (let i = layerState.strokes.length - 1; i >= 0; i--) {
        const s = layerState.strokes[i];
        if (isPointInStroke(p, s.points)) return s.id;
     }
     return null;
  };

  // -- Event Handlers --

  const handlePointerDown = (e: React.PointerEvent) => {
    const p = getCanvasPoint(e);

    if (ui.mode === 'play') {
       return;
    }

    if (ui.selectedTool === 'select') {
        const hitGizmo = getGizmoHit(p, selectionBounds);
        if (hitGizmo && selectionBounds && ui.selectedStrokeId) {
            const kf = project.keyframes.find(k => k.id === ui.selectedKeyframeId);
            const ls = kf?.layerStates.find(s => s.layerId === ui.selectedLayerId);
            const stroke = ls?.strokes.find(s => s.id === ui.selectedStrokeId);
            if (stroke) {
                setTransformStart({
                    mouse: p, center: { x: selectionBounds.cx, y: selectionBounds.cy },
                    angle: selectionBounds.rotation, width: selectionBounds.width, height: selectionBounds.height, points: stroke.points
                });
                if (hitGizmo === 'body') setInteractionMode('dragging');
                else if (hitGizmo === 'rotator') setInteractionMode('rotating');
                else { setInteractionMode('resizing'); setActiveHandle(hitGizmo as ResizeHandle); }
                (e.target as Element).setPointerCapture(e.pointerId);
            }
            return;
        }
        const hitId = findHitStroke(p);
        if (hitId) selectStroke(hitId); else selectStroke(null);
        return;
    }

    if (ui.selectedTool === 'polyline') {
       const snappedP = getSnappedPoint(p);
       if (polylinePoints.length > 2 && distance(snappedP, polylinePoints[0]) < 15) {
           addStrokeToCurrentKeyframe(polylinePoints, true, true);
           setPolylinePoints([]);
           return;
       }
       if (polylinePoints.length > 0) {
           const lastPoint = polylinePoints[polylinePoints.length - 1];
           if (distance(snappedP, lastPoint) < 15) {
               addStrokeToCurrentKeyframe(polylinePoints, false, true);
               setPolylinePoints([]);
               return;
           }
       }
       setPolylinePoints(prev => [...prev, snappedP]);
       return;
    }

    if (ui.selectedTool === 'pen') {
      setInteractionMode('drawing'); // Updates Ref immediately
      currentPointsRef.current = [getSnappedPoint(p)];
      (e.target as Element).setPointerCapture(e.pointerId);
    } 
  };

  const handlePointerMove = (e: React.PointerEvent) => {
    const p = getCanvasPoint(e);
    setMousePos(getSnappedPoint(p));

    // PLAY MODE: Handled by global window listener now.
    if (ui.mode === 'play') return;

    if (interactionModeRef.current !== 'none' && transformStart && selectionBounds) {
        if (interactionModeRef.current === 'dragging') {
            let dx = p.x - transformStart.mouse.x; let dy = p.y - transformStart.mouse.y;
            if (ui.snapToGrid) {
                const targetX = transformStart.center.x + dx; const targetY = transformStart.center.y + dy;
                const snappedX = Math.round(targetX / ui.gridSize) * ui.gridSize; const snappedY = Math.round(targetY / ui.gridSize) * ui.gridSize;
                dx = snappedX - transformStart.center.x; dy = snappedY - transformStart.center.y;
            }
            setSelectionBounds({ ...selectionBounds, cx: transformStart.center.x + dx, cy: transformStart.center.y + dy });
        } else if (interactionModeRef.current === 'rotating') {
            const currentAngle = Math.atan2(p.y - selectionBounds.cy, p.x - selectionBounds.cx);
            const startAngle = Math.atan2(transformStart.mouse.y - selectionBounds.cy, transformStart.mouse.x - selectionBounds.cx);
            let dAngle = currentAngle - startAngle; let newRotation = transformStart.angle + dAngle;
            if (e.shiftKey) { const step = Math.PI / 12; newRotation = Math.round(newRotation / step) * step; }
            setSelectionBounds({ ...selectionBounds, rotation: newRotation });
        } else if (interactionModeRef.current === 'resizing' && activeHandle) {
            const unrotatedMouse = rotatePoint(p, transformStart.center, -transformStart.angle);
            const unrotatedStart = rotatePoint(transformStart.mouse, transformStart.center, -transformStart.angle);
            let dx = unrotatedMouse.x - unrotatedStart.x; let dy = unrotatedMouse.y - unrotatedStart.y;
            if (e.shiftKey) { const aspect = transformStart.width / transformStart.height; dy = (activeHandle === 'br' || activeHandle === 'tl') ? dx / aspect : -dx / aspect; }
            if (ui.snapToGrid && !e.shiftKey) { dx = Math.round(dx / ui.gridSize) * ui.gridSize; dy = Math.round(dy / ui.gridSize) * ui.gridSize; }
            let newW = transformStart.width; let newH = transformStart.height;
            if (activeHandle === 'br') { newW += dx * 2; newH += dy * 2; }
            if (activeHandle === 'tl') { newW -= dx * 2; newH -= dy * 2; }
            if (activeHandle === 'tr') { newW += dx * 2; newH -= dy * 2; }
            if (activeHandle === 'bl') { newW -= dx * 2; newH += dy * 2; }
            newW = Math.max(1, newW); newH = Math.max(1, newH);
            setSelectionBounds({ ...selectionBounds, width: newW, height: newH });
        }
        return;
    }

    if (interactionModeRef.current === 'drawing') {
        currentPointsRef.current.push(getSnappedPoint(p));
    }
  };

  const handlePointerUp = (e: React.PointerEvent) => {
    if (ui.mode !== 'play') {
       (e.target as Element).releasePointerCapture(e.pointerId);
    }

    if (interactionModeRef.current !== 'none' && transformStart && selectionBounds && ui.selectedStrokeId) {
        const scaleX = selectionBounds.width / transformStart.width;
        const scaleY = selectionBounds.height / transformStart.height;
        const dRot = selectionBounds.rotation - transformStart.angle;
        const dX = selectionBounds.cx - transformStart.center.x;
        const dY = selectionBounds.cy - transformStart.center.y;
        const newPoints = transformStart.points.map(pt => {
            let x = pt.x - transformStart.center.x; let y = pt.y - transformStart.center.y;
            x *= scaleX; y *= scaleY;
            const cos = Math.cos(dRot); const sin = Math.sin(dRot);
            const rx = x * cos - y * sin; const ry = x * sin + y * cos;
            return { x: rx + transformStart.center.x + dX, y: ry + transformStart.center.y + dY, pressure: pt.pressure };
        });
        updateStrokeInCurrentKeyframe(ui.selectedStrokeId, newPoints);
    }

    // DRAWING END
    if (interactionModeRef.current === 'drawing' && currentPointsRef.current.length > 1) {
        const points = [...currentPointsRef.current];
        const start = points[0];
        const end = points[points.length - 1];

        // AUTO-CLOSE LOGIC: 
        const isLoop = distance(start, end) < 20; 
        const shouldClose = isLoop && (ui.fillColor !== 'none');

        addStrokeToCurrentKeyframe(points, shouldClose);
    }
    setInteractionMode('none'); setActiveHandle(null); setTransformStart(null); currentPointsRef.current = [];
  };

  // -- THE RENDER LOOP --
  // This loop depends mainly on canvas size to restart, but reads data from Refs to stay fresh.
  useLayoutEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    let animationFrameId: number;

    const render = (time: number) => {
      // 1. Calculate Delta Time for Physics
      if (!lastFrameTimeRef.current) lastFrameTimeRef.current = time;
      const dt = Math.min((time - lastFrameTimeRef.current) / 1000, 0.1); 
      lastFrameTimeRef.current = time;

      // 2. Read Fresh State from Refs
      const currentProject = projectRef.current;
      const currentUI = uiRef.current;

      // READ INTERACTIVE STATE FROM REFS (Critical Fix for Visibility)
      const currentPolyline = polylinePointsRef.current;
      const currentSelectionBounds = selectionBoundsRef.current;
      const currentMousePos = mousePosRef.current;

      const dpr = currentUI.resolutionScale || window.devicePixelRatio || 1;
      const interpolationTargetCount = currentUI.performanceMode ? 80 : 200;

      // Ensure Canvas Size is correct 
      if (canvas.width !== CANVAS_WIDTH * dpr || canvas.height !== CANVAS_HEIGHT * dpr) {
          canvas.width = CANVAS_WIDTH * dpr;
          canvas.height = CANVAS_HEIGHT * dpr;
          ctx.scale(dpr, dpr);
      }

      // 3. PLAY MODE PHYSICS (Spring System)
      if (currentUI.mode === 'play') {
          const axisX = currentProject.axes.find(a => a.id === 'axis-x');
          const axisY = currentProject.axes.find(a => a.id === 'axis-y');

          if (axisX && axisY) {
              const targetX = targetAxesRef.current['axis-x'];
              const targetY = targetAxesRef.current['axis-y'];

              let nextX = axisX.currentValue;
              let nextY = axisY.currentValue;

              if (currentUI.playModePhysics) {
                  const stiffness = currentUI.springStiffness || 120;
                  const damping = currentUI.springDamping || 20;

                  const forceX = (targetX - nextX) * stiffness - velocityRef.current.x * damping;
                  const forceY = (targetY - nextY) * stiffness - velocityRef.current.y * damping;

                  velocityRef.current.x += forceX * dt;
                  velocityRef.current.y += forceY * dt;

                  nextX += velocityRef.current.x * dt;
                  nextY += velocityRef.current.y * dt;
              } else {
                  nextX = targetX;
                  nextY = targetY;
                  velocityRef.current = { x: 0, y: 0 };
              }

              if (Math.abs(nextX - axisX.currentValue) > 0.0001 || Math.abs(nextY - axisY.currentValue) > 0.0001) {
                  const clampedX = Math.max(0, Math.min(1, nextX));
                  const clampedY = Math.max(0, Math.min(1, nextY));
                  updateMultipleAxisValues({ 'axis-x': clampedX, 'axis-y': clampedY });
              }
          }
      } else {
           const curX = currentProject.axes.find(a => a.id === 'axis-x')?.currentValue || 0.5;
           const curY = currentProject.axes.find(a => a.id === 'axis-y')?.currentValue || 0.5;
           targetAxesRef.current = { 'axis-x': curX, 'axis-y': curY };
           velocityRef.current = { x: 0, y: 0 };
      }

      // 4. CLEAR & DRAW
      ctx.clearRect(0, 0, CANVAS_WIDTH, CANVAS_HEIGHT);
      ctx.fillStyle = '#FFFFFF';
      ctx.fillRect(0, 0, CANVAS_WIDTH, CANVAS_HEIGHT);

      // GRID
      if (currentUI.showGrid && currentUI.mode === 'edit') {
        ctx.fillStyle = '#D1D5DB';
        const gridSize = currentUI.gridSize;
        const centerX = CANVAS_WIDTH / 2;
        const centerY = CANVAS_HEIGHT / 2;
        const startX = (centerX % gridSize);
        const startY = (centerY % gridSize);
        for (let x = startX; x <= CANVAS_WIDTH; x += gridSize) {
           for (let y = startY; y <= CANVAS_HEIGHT; y += gridSize) {
              ctx.beginPath();
              ctx.arc(x, y, 1.5, 0, Math.PI * 2);
              ctx.fill();
           }
        }
      }

      // ONION SKIN
      if (currentUI.onionSkinEnabled && currentUI.mode === 'edit') {
         currentProject.keyframes.forEach(kf => {
           if (kf.id === currentUI.selectedKeyframeId) return; 
           ctx.globalAlpha = currentUI.onionSkinOpacity;
           kf.layerStates.forEach(ls => {
              if (ls.layerId !== currentUI.selectedLayerId) return;
              const stroke = ls.strokes[0];
              if (stroke && stroke.points.length > 1) {
                ctx.beginPath();
                ctx.moveTo(stroke.points[0].x, stroke.points[0].y);
                for (let i = 1; i < stroke.points.length; i++) ctx.lineTo(stroke.points[i].x, stroke.points[i].y);
                if (stroke.closed) ctx.closePath();
                ctx.strokeStyle = '#3B82F6'; 
                ctx.lineWidth = 1; 
                ctx.stroke();
              }
           });
           ctx.globalAlpha = 1.0;
         });
      }

      // INTERPOLATION RENDERING
      const currentAxesDict: Record<string, number> = {};
      currentProject.axes.forEach(a => currentAxesDict[a.id] = a.currentValue);

      currentProject.layers.forEach(layer => {
        if (!layer.visible) return;

        const layerRelevantKeyframes = currentProject.keyframes.filter(kf => {
            const ls = kf.layerStates.find(s => s.layerId === layer.id);
            return ls && ls.strokes.length > 0;
        });

        if (layerRelevantKeyframes.length === 0) return;

        const weights = calculateInterpolationWeights(currentAxesDict, layerRelevantKeyframes, currentUI.interpolationExponent, currentUI.interpolationStrategy);

        const activeKeyframes = layerRelevantKeyframes
             .map(k => ({ ...k, weight: weights[k.id] || 0 }))
             .filter(k => k.weight > 0.0001);

        const strokeId = `stroke-${layer.id}-unique`;
        const isLayerActive = layer.id === currentUI.selectedLayerId;
        const isCreatingNewState = currentUI.selectedKeyframeId === null;

        let layerGlobalAlpha = layer.opacity;
        if (!isLayerActive && currentUI.mode !== 'play') layerGlobalAlpha *= currentUI.inactiveLayerOpacity;
        if (isCreatingNewState && currentUI.mode === 'edit') layerGlobalAlpha *= currentUI.ghostStrokeOpacity;

        const strokeData = activeKeyframes.map(kf => {
            const state = kf.layerStates.find(ls => ls.layerId === layer.id);
            const s = state?.strokes[0]; 
            return { weight: kf.weight, points: s?.points, style: s, color: s?.color || 'none', fillColor: s?.fillColor, width: s?.width || 1 };
        });

        const sortedByWeight = [...strokeData].sort((a,b) => b.weight - a.weight);
        const primaryStroke = sortedByWeight.find(sd => sd.style)?.style;
        if (!primaryStroke) return;

        const { points: interpolatedPoints, color: interpolatedColor, fillColor: interpolatedFill, width: interpolatedWidth } = interpolateStrokePoints(
            strokeId, 
            primaryStroke.points, 
            strokeData, 
            layer.interpolationMode,
            interpolationTargetCount 
        );

        if (interpolatedPoints.length > 0) {
            ctx.beginPath();
            ctx.moveTo(interpolatedPoints[0].x, interpolatedPoints[0].y);
            for (let i = 1; i < interpolatedPoints.length; i++) ctx.lineTo(interpolatedPoints[i].x, interpolatedPoints[i].y);
            if (primaryStroke.closed) ctx.closePath();

            ctx.globalAlpha = layerGlobalAlpha;
            switch(layer.blendMode) {
                case 'multiply': ctx.globalCompositeOperation = 'multiply'; break;
                case 'screen': ctx.globalCompositeOperation = 'screen'; break;
                case 'overlay': ctx.globalCompositeOperation = 'overlay'; break;
                case 'difference': ctx.globalCompositeOperation = 'difference'; break;
                case 'exclusion': ctx.globalCompositeOperation = 'exclusion'; break;
                default: ctx.globalCompositeOperation = 'source-over';
            }

            if (interpolatedFill && interpolatedFill !== 'none') {
                ctx.fillStyle = interpolatedFill;
                ctx.fill();
            }
            if (interpolatedColor && interpolatedColor !== 'none') {
                ctx.lineCap = 'round';
                ctx.lineJoin = 'round';
                ctx.strokeStyle = interpolatedColor;
                ctx.lineWidth = interpolatedWidth;
                ctx.stroke();
            }

            ctx.globalAlpha = 1.0;
            ctx.globalCompositeOperation = 'source-over';
        }
      });

      // ACTIVE DRAWING (Using Refs)
      if (interactionModeRef.current === 'drawing' && currentPointsRef.current.length > 0) {
        const isGhostState = currentUI.selectedKeyframeId === null;
        ctx.globalAlpha = isGhostState ? currentUI.ghostStrokeOpacity : 1.0;

        ctx.beginPath();
        const pts = currentPointsRef.current;
        ctx.moveTo(pts[0].x, pts[0].y);
        for (let i = 1; i < pts.length; i++) ctx.lineTo(pts[i].x, pts[i].y);
        ctx.strokeStyle = currentUI.brushColor !== 'none' ? currentUI.brushColor : 'rgba(0,0,0,0.2)'; 
        ctx.lineWidth = currentUI.brushSize;
        ctx.lineCap = 'round';
        ctx.lineJoin = 'round';
        ctx.stroke();
        ctx.globalAlpha = 1.0; 
      }

      // ACTIVE POLYLINE (Using Synced Refs)
      if (currentPolyline.length > 0) {
         const isGhostState = currentUI.selectedKeyframeId === null;
         ctx.globalAlpha = isGhostState ? currentUI.ghostStrokeOpacity : 1.0;

         ctx.beginPath();
         ctx.moveTo(currentPolyline[0].x, currentPolyline[0].y);
         for (let i = 1; i < currentPolyline.length; i++) ctx.lineTo(currentPolyline[i].x, currentPolyline[i].y);

         if (currentMousePos) ctx.lineTo(currentMousePos.x, currentMousePos.y); 

         if (currentUI.fillColor !== 'none') {
             ctx.fillStyle = currentUI.fillColor;
             ctx.globalAlpha = isGhostState ? currentUI.ghostStrokeOpacity * 0.5 : 0.5;
             ctx.fill();
             ctx.globalAlpha = isGhostState ? currentUI.ghostStrokeOpacity : 1.0;
         }

         ctx.strokeStyle = currentUI.brushColor !== 'none' ? currentUI.brushColor : 'rgba(0,0,0,0.5)';
         ctx.lineWidth = currentUI.brushSize;
         ctx.stroke();

         ctx.fillStyle = currentUI.brushColor !== 'none' ? currentUI.brushColor : 'rgba(0,0,0,0.5)';
         currentPolyline.forEach((p, index) => {
            ctx.beginPath();
            const r = (index === 0) ? 5 : 3; 
            ctx.arc(p.x, p.y, r, 0, Math.PI * 2);
            ctx.fill();
         });
         ctx.globalAlpha = 1.0; 
      }

      // GIZMOS (Using Synced Refs)
      if (currentSelectionBounds && currentUI.selectedTool === 'select' && currentUI.mode === 'edit') {
          const { cx, cy, width, height, rotation } = currentSelectionBounds;

          ctx.save();
          ctx.translate(cx, cy);
          ctx.rotate(rotation);

          ctx.beginPath();
          ctx.strokeStyle = '#3B82F6';
          ctx.lineWidth = 1;
          ctx.rect(-width/2, -height/2, width, height);
          ctx.stroke();

          const HANDLE_SIZE = 8; 
          ctx.fillStyle = '#FFFFFF';
          ctx.strokeStyle = '#3B82F6';

          const drawHandle = (x: number, y: number) => {
              ctx.beginPath();
              ctx.rect(x - HANDLE_SIZE/2, y - HANDLE_SIZE/2, HANDLE_SIZE, HANDLE_SIZE);
              ctx.fill();
              ctx.stroke();
          };

          drawHandle(-width/2, -height/2); // TL
          drawHandle(width/2, -height/2);  // TR
          drawHandle(-width/2, height/2);  // BL
          drawHandle(width/2, height/2);   // BR

          ctx.beginPath();
          ctx.moveTo(0, -height/2);
          ctx.lineTo(0, -height/2 - 25);
          ctx.stroke();

          ctx.beginPath();
          ctx.arc(0, -height/2 - 25, 4, 0, Math.PI * 2);
          ctx.fillStyle = '#3B82F6';
          ctx.fill();

          ctx.restore();
      }

      animationFrameId = requestAnimationFrame(render);
    };

    animationFrameId = requestAnimationFrame(render);
    return () => cancelAnimationFrame(animationFrameId);
  }, [CANVAS_WIDTH, CANVAS_HEIGHT]); // Minimized dependencies for loop stability

  return (
    <div 
      ref={containerRef} 
      className="absolute inset-0 z-0 flex items-center justify-center bg-[#EAEAEA] touch-none"
    >
      <div 
        style={{ 
          width: CANVAS_WIDTH, 
          height: CANVAS_HEIGHT,
          transform: `scale(${scale})`,
          boxShadow: '0 20px 50px -12px rgba(0, 0, 0, 0.15)' 
        }}
        className="bg-white rounded-xl overflow-hidden relative transition-transform duration-200 ease-out origin-center ring-4 ring-white/50"
      >
          <canvas 
            ref={canvasRef} 
            className={`block w-full h-full ${ui.mode === 'play' ? 'cursor-move' : (ui.selectedTool === 'select' ? 'cursor-default' : 'cursor-crosshair')}`}
            onPointerDown={handlePointerDown}
            onPointerMove={handlePointerMove}
            onPointerUp={handlePointerUp}
            onDoubleClick={handleDoubleClick}
          />
      </div>
    </div>
  );
};

// utils/math.ts
import { Point, Stroke, InterpolationStrategy } from '../types';

export const distance = (p1: Point, p2: Point): number => {
  return Math.sqrt(Math.pow(p2.x - p1.x, 2) + Math.pow(p2.y - p1.y, 2));
};

export const lerp = (start: number, end: number, t: number): number => {
  return start * (1 - t) + end * t;
};

// --- Transformation Helpers ---

export const rotatePoint = (p: Point, center: Point, angleRad: number): Point => {
  const cos = Math.cos(angleRad);
  const sin = Math.sin(angleRad);
  const dx = p.x - center.x;
  const dy = p.y - center.y;
  return {
    x: center.x + (dx * cos - dy * sin),
    y: center.y + (dx * sin + dy * cos),
    pressure: p.pressure
  };
};

export const getBoundingBox = (points: Point[]): { minX: number, maxX: number, minY: number, maxY: number, width: number, height: number, centerX: number, centerY: number } => {
  if (points.length === 0) return { minX:0, maxX:0, minY:0, maxY:0, width:0, height:0, centerX:0, centerY:0 };

  let minX = Infinity, maxX = -Infinity, minY = Infinity, maxY = -Infinity;
  for (const p of points) {
    if (p.x < minX) minX = p.x;
    if (p.x > maxX) maxX = p.x;
    if (p.y < minY) minY = p.y;
    if (p.y > maxY) maxY = p.y;
  }

  return {
    minX, maxX, minY, maxY,
    width: maxX - minX,
    height: maxY - minY,
    centerX: minX + (maxX - minX) / 2,
    centerY: minY + (maxY - minY) / 2
  };
};

// --- Color Interpolation (RGBA) ---

const colorCache: Record<string, { r: number, g: number, b: number, a: number }> = {};

const parseColor = (color: string): { r: number, g: number, b: number, a: 1 } => {
  if (!color || color === 'none') return { r: 0, g: 0, b: 0, a: 1 }; // Return A=1 to avoid div zero, handle none upstream
  if (colorCache[color]) return colorCache[color] as any;

  let result = { r: 0, g: 0, b: 0, a: 1 };

  if (color.startsWith('#')) {
    let hex = color.slice(1);
    if (hex.length === 3) hex = hex.split('').map(c => c + c).join('');
    const bigint = parseInt(hex, 16);
    result = {
      r: (bigint >> 16) & 255,
      g: (bigint >> 8) & 255,
      b: bigint & 255,
      a: 1
    };
  }
  else if (color.startsWith('rgb')) {
    const match = color.match(/(\d+(\.\d+)?)/g);
    if (match) {
        result = {
            r: parseFloat(match[0]),
            g: parseFloat(match[1]),
            b: parseFloat(match[2]),
            a: match[3] ? parseFloat(match[3]) : 1
        };
    }
  }

  colorCache[color] = result;
  return result;
};

export const mixColors = (colors: { color: string | 'none', weight: number }[]): string => {
  let rSum = 0, gSum = 0, bSum = 0, aSum = 0;
  let hasColor = false;

  for (const c of colors) {
    const rgba = parseColor(c.color);
    const alpha = c.color === 'none' ? 0 : rgba.a;

    if (alpha > 0) {
        hasColor = true;
        rSum += rgba.r * c.weight * alpha;
        gSum += rgba.g * c.weight * alpha;
        bSum += rgba.b * c.weight * alpha;
    }
    aSum += alpha * c.weight;
  }

  if (!hasColor || aSum <= 0.001) return 'none';

  // Normalize RGB by total alpha weight to prevent darkening when mixing with transparent
  // Actually standard Porter-Duff / Straight alpha compositing:
  // We just output premultiplied or straight? CSS wants straight.
  // The simple weighted average above works if we consider 'none' as transparent black.

  // Correction: If we mix Red (100%) and None (0%), result should be Red with 50% opacity.
  // The current logic does: (255*0.5 + 0*0.5) = 127. That's Dark Red. Wrong.
  // We need to divide accumulated RGB by accumulated AlphaWeight (if > 0).

  let totalAlphaWeight = 0; 
  colors.forEach(c => {
     const rgba = parseColor(c.color);
     const alpha = c.color === 'none' ? 0 : rgba.a;
     totalAlphaWeight += c.weight * alpha;
  });

  if (totalAlphaWeight <= 0.0001) return 'rgba(0,0,0,0)';

  const finalR = rSum / totalAlphaWeight;
  const finalG = gSum / totalAlphaWeight;
  const finalB = bSum / totalAlphaWeight;

  return `rgba(${Math.round(finalR)}, ${Math.round(finalG)}, ${Math.round(finalB)}, ${aSum.toFixed(3)})`;
};

// --- Geometry Helpers ---

const getPathLength = (points: Point[]): number => {
  let len = 0;
  for (let i = 1; i < points.length; i++) {
    len += distance(points[i - 1], points[i]);
  }
  return len;
};

// STRICT Arc-Length Resampling (Percentage Mode)
export const resamplePoints = (points: Point[], targetCount: number): Point[] => {
  if (points.length < 2 || targetCount < 2) return points;

  const totalLength = getPathLength(points);
  if (totalLength === 0) return Array(targetCount).fill(points[0]);

  const step = totalLength / (targetCount - 1);
  const newPoints: Point[] = [points[0]];

  let currentDist = 0;
  let nextPointIndex = 1;

  for (let i = 1; i < targetCount; i++) {
    const targetDist = i * step;
    let distSoFar = currentDist;
    let p1 = points[nextPointIndex - 1];
    let p2 = points[nextPointIndex];
    let segmentDist = distance(p1, p2);

    while (distSoFar + segmentDist < targetDist && nextPointIndex < points.length - 1) {
      distSoFar += segmentDist;
      currentDist = distSoFar;
      nextPointIndex++;
      p1 = points[nextPointIndex - 1];
      p2 = points[nextPointIndex];
      segmentDist = distance(p1, p2);
    }

    const segmentLocalDist = targetDist - distSoFar;
    const t = segmentDist === 0 ? 0 : segmentLocalDist / segmentDist;

    newPoints.push({
      x: lerp(p1.x, p2.x, t),
      y: lerp(p1.y, p2.y, t),
      pressure: lerp(p1.pressure || 0.5, p2.pressure || 0.5, t)
    });
  }

  while (newPoints.length < targetCount) newPoints.push(points[points.length - 1]);
  if (newPoints.length > targetCount) newPoints.length = targetCount;

  return newPoints;
};

const getPointAtFractionalIndex = (points: Point[], index: number): Point => {
    if (points.length === 0) return { x: 0, y: 0, pressure: 0 };
    if (points.length === 1) return points[0];

    if (index <= 0) return points[0];
    if (index >= points.length - 1) return points[points.length - 1];

    const i = Math.floor(index);
    const t = index - i;
    const p1 = points[i];
    const p2 = points[i+1];

    return {
        x: lerp(p1.x, p2.x, t),
        y: lerp(p1.y, p2.y, t),
        pressure: lerp(p1.pressure || 0.5, p2.pressure || 0.5, t)
    };
};

export const snapPointToGrid = (p: Point, gridSize: number): Point => {
  return {
    x: Math.round(p.x / gridSize) * gridSize,
    y: Math.round(p.y / gridSize) * gridSize,
    pressure: p.pressure
  };
};

// --- Hit Testing ---

const distToSegment = (p: Point, v: Point, w: Point) => {
  const l2 = Math.pow(distance(v, w), 2);
  if (l2 === 0) return distance(p, v);
  let t = ((p.x - v.x) * (w.x - v.x) + (p.y - v.y) * (w.y - v.y)) / l2;
  t = Math.max(0, Math.min(1, t));
  const projection = { x: v.x + t * (w.x - v.x), y: v.y + t * (w.y - v.y) };
  return distance(p, projection);
};

export const isPointInStroke = (p: Point, points: Point[], threshold: number = 10): boolean => {
  for (let i = 0; i < points.length - 1; i++) {
    if (distToSegment(p, points[i], points[i+1]) < threshold) return true;
  }
  return false;
};

// --- Robust Alignment ---

const alignPoints = (reference: Point[], target: Point[], forceClosed: boolean): Point[] => {
    if (reference.length !== target.length || reference.length === 0) return target;

    const len = reference.length;

    const getError = (ptsA: Point[], ptsB: Point[]) => {
        let err = 0;
        for(let i=0; i<len; i++) {
            const dx = ptsA[i].x - ptsB[i].x;
            const dy = ptsA[i].y - ptsB[i].y;
            err += dx*dx + dy*dy;
        }
        return err;
    };

    let bestPoints = [...target];
    let minError = getError(reference, target);

    // 1. Check Reverse Direction
    const reversed = [...target].reverse();
    const reverseError = getError(reference, reversed);

    if (reverseError < minError * 0.95) { // Threshold to prefer stable direction
        minError = reverseError;
        bestPoints = reversed;
    }

    // 2. Check Cyclic Shift (ONLY if closed or forced closed)
    if (forceClosed) {
        let workingSet = [...bestPoints];
        for (let offset = 1; offset < len; offset++) {
             // Create shifted array without mutating workingSet per iteration in a costly way
             const shifted = new Array(len);
             for(let k=0; k<len; k++) {
                 shifted[k] = workingSet[(k + offset) % len];
             }

             const err = getError(reference, shifted);
             if (err < minError) {
                 minError = err;
                 bestPoints = shifted;
             }
        }
    } 

    return bestPoints;
};

// --- INTERPOLATION STRATEGIES ---

const calculateBilinearGridWeights = (
  currentAxes: Record<string, number>,
  keyframes: { id: string; axisValues: Record<string, number> }[]
) => {
  const weights: Record<string, number> = {};

  const curX = currentAxes['axis-x'] || 0;
  const curY = currentAxes['axis-y'] || 0;
  const EPSILON = 0.005;

  const distinctCoords = (arr: number[]) => {
      const sorted = [...arr].sort((a,b) => a - b);
      const result = [];
      if (sorted.length > 0) result.push(sorted[0]);
      for (let i = 1; i < sorted.length; i++) {
          if (sorted[i] > sorted[i-1] + EPSILON) result.push(sorted[i]);
      }
      return result;
  };
  const xCoords = distinctCoords(keyframes.map(k => k.axisValues['axis-x'] || 0));
  const yCoords = distinctCoords(keyframes.map(k => k.axisValues['axis-y'] || 0));

  if (xCoords.length === 0 || yCoords.length === 0) {
      if (keyframes.length > 0) weights[keyframes[0].id] = 1;
      return weights;
  }

  const findInterval = (val: number, grid: number[]) => {
      if (val <= grid[0]) return { lower: grid[0], upper: grid[0], t: 0 };
      if (val >= grid[grid.length - 1]) return { lower: grid[grid.length - 1], upper: grid[grid.length - 1], t: 0 };
      for (let i = 0; i < grid.length - 1; i++) {
          if (val >= grid[i] && val <= grid[i+1]) {
              const span = grid[i+1] - grid[i];
              return { lower: grid[i], upper: grid[i+1], t: span === 0 ? 0 : (val - grid[i]) / span };
          }
      }
      return { lower: grid[0], upper: grid[0], t: 0 };
  };

  const xInfo = findInterval(curX, xCoords);
  const yInfo = findInterval(curY, yCoords);

  const resolveCornerWeights = (targetX: number, targetY: number) => {
      const exact = keyframes.find(k => Math.abs((k.axisValues['axis-x']||0) - targetX) < EPSILON && Math.abs((k.axisValues['axis-y']||0) - targetY) < EPSILON);
      if (exact) return { [exact.id]: 1.0 };

      // Inverse Distance Weighting fallback for non-grid points
      let totalW = 0;
      const cornerWeights: Record<string, number> = {};

      keyframes.forEach(k => {
          const dx = (k.axisValues['axis-x']||0) - targetX;
          const dy = (k.axisValues['axis-y']||0) - targetY;
          const dist = Math.sqrt(dx*dx + dy*dy);
          if (dist < 0.001) { cornerWeights[k.id] = 1000; totalW += 1000; }
          else {
              const w = 1 / Math.pow(dist, 2);
              cornerWeights[k.id] = w;
              totalW += w;
          }
      });

      for(const id in cornerWeights) cornerWeights[id] /= totalW;
      return cornerWeights;
  };

  const corners = [
      { x: xInfo.lower, y: yInfo.lower, wBase: (1 - xInfo.t) * (1 - yInfo.t) },
      { x: xInfo.upper, y: yInfo.lower, wBase: xInfo.t * (1 - yInfo.t) },
      { x: xInfo.lower, y: yInfo.upper, wBase: (1 - xInfo.t) * yInfo.t },
      { x: xInfo.upper, y: yInfo.upper, wBase: xInfo.t * yInfo.t }
  ];

  corners.forEach(c => {
      if (c.wBase <= 0.0001) return;
      const cornerComposition = resolveCornerWeights(c.x, c.y);
      for (const kfId in cornerComposition) {
          weights[kfId] = (weights[kfId] || 0) + (cornerComposition[kfId] * c.wBase);
      }
  });

  return weights;
};

const calculateIDWWeights = (currentAxes: Record<string, number>, keyframes: { id: string; axisValues: Record<string, number> }[], exponent: number) => {
    // Standard IDW implementation
    const weights: Record<string, number> = {};
    let totalWeight = 0;
    for (const kf of keyframes) {
        let dist = 0;
        for (const axisId in currentAxes) dist += Math.pow((currentAxes[axisId] || 0) - (kf.axisValues[axisId] || 0), 2);
        dist = Math.sqrt(dist);
        if (dist < 0.001) {
             keyframes.forEach(k => weights[k.id] = 0);
             weights[kf.id] = 1; 
             return weights; 
        }
        const w = 1 / Math.pow(dist, exponent);
        weights[kf.id] = w;
        totalWeight += w;
    }
    for (const id in weights) weights[id] /= totalWeight;
    return weights;
};

export const calculateInterpolationWeights = (
  currentAxes: Record<string, number>,
  keyframes: { id: string; axisValues: Record<string, number> }[],
  exponent: number = 2,
  strategy: InterpolationStrategy = 'bilinear-grid'
): Record<string, number> => {
   if (keyframes.length === 0) return {};
   if (keyframes.length === 1) return { [keyframes[0].id]: 1.0 };
   if (strategy === 'bilinear-grid') return calculateBilinearGridWeights(currentAxes, keyframes);
   return calculateIDWWeights(currentAxes, keyframes, exponent);
};

// --- CORE INTERPOLATION ENGINE ---

export const interpolateStrokePoints = (
  strokeId: string,
  basePoints: Point[], 
  keyframesData: { weight: number; points: Point[] | undefined, style: Stroke | undefined }[],
  mode: 'resample' | 'points' = 'resample',
  targetCount: number = 200 
): { points: Point[], color: string, fillColor: string, width: number } => {

  // 1. Filter active keyframes
  const activeKeyframes = keyframesData.filter(k => k.weight > 0.0001 && k.points && k.points.length > 0);
  if (activeKeyframes.length === 0) return { points: [], color: 'rgba(0,0,0,0)', fillColor: 'none', width: 1 };

  // 2. Mix Properties
  const color = mixColors(activeKeyframes.map(k => ({ color: k.style?.color || 'none', weight: k.weight })));
  const fillColor = mixColors(activeKeyframes.map(k => ({ color: k.style?.fillColor || 'none', weight: k.weight })));

  let totalWidth = 0;
  let widthWeightDivisor = 0;
  activeKeyframes.forEach(k => {
      totalWidth += (k.style?.width || 1) * k.weight;
      widthWeightDivisor += k.weight;
  });
  const width = widthWeightDivisor > 0 ? totalWidth / widthWeightDivisor : 1;

  // 3. Topology Handling (Open vs Closed Glitch Fix)
  // Calculate if the RESULT should be closed based on weight dominance
  let closedWeight = 0;
  activeKeyframes.forEach(k => { if (k.style?.closed) closedWeight += k.weight; });
  const resultClosed = closedWeight > 0.5;

  // We force alignment to use Cyclic check if ANY of the active keyframes is closed.
  // This allows an Open shape to "rotate" to match a Closed shape's start point seamlessly.
  const anyClosed = activeKeyframes.some(k => k.style?.closed);

  // 4. Point Count Normalization (Polyline Jump Fix)
  // Even in 'points' mode, if counts differ, we MUST normalize to the MAX count to avoid index sliding.
  let ACTUAL_TARGET_COUNT = targetCount; 

  if (mode === 'points') {
      const maxPts = Math.max(...activeKeyframes.map(k => k.points!.length));
      // If counts match exactly across all active frames, keep it exact.
      // If they differ, we upscale to the Max to prevent truncation jumps.
      const allMatch = activeKeyframes.every(k => k.points!.length === maxPts);
      ACTUAL_TARGET_COUNT = allMatch ? maxPts : Math.max(maxPts, 50); // Fallback to higher count if mismatch to ensure smoothness
  }

  // Reference for alignment (usually the heaviest weight)
  const sortedByWeight = [...activeKeyframes].sort((a,b) => b.weight - a.weight);
  const referenceStroke = sortedByWeight[0].points!;

  // Resample Reference Once
  const referenceResampled = resamplePoints(referenceStroke, ACTUAL_TARGET_COUNT);

  const resultPoints: Point[] = [];

  for (let i = 0; i < ACTUAL_TARGET_COUNT; i++) {
      let x = 0;
      let y = 0;
      let pressure = 0;
      let totalWeight = 0;

      for (const kf of activeKeyframes) {
          const rawPoints = kf.points!;
          let processedPoints: Point[] = [];

          // NORMALIZATION:
          // Regardless of mode, if we are mixing counts or topologies, we use resamplePoints logic
          // to generate a comparable set of vertices.
          // Note: resamplePoints uses Arc-Length parametrization which is stable during morphs.

          if (mode === 'points' && rawPoints.length === ACTUAL_TARGET_COUNT) {
              // Perfect match case: use raw points directly (topology safe)
              processedPoints = rawPoints;
          } else {
              // Mismatch case (or resample mode): Resample to common denominator
              processedPoints = resamplePoints(rawPoints, ACTUAL_TARGET_COUNT);
          }

          // ALIGNMENT:
          // Align this keyframe's points to the reference (Heaviest keyframe)
          // passing 'anyClosed' to allow cyclic optimization if mixed topology.
          const alignedPoints = alignPoints(referenceResampled, processedPoints, anyClosed);

          const pt = alignedPoints[i];

          x += pt.x * kf.weight;
          y += pt.y * kf.weight;
          pressure += (pt.pressure || 0.5) * kf.weight;
          totalWeight += kf.weight;
      }

      if (totalWeight > 0) {
          resultPoints.push({
              x: x / totalWeight,
              y: y / totalWeight,
              pressure: pressure / totalWeight
          });
      }
  }

  // Force close visual if needed (replicate start at end?)
  // Canvas handles 'ctx.closePath()' so we don't strictly need to duplicate point,
  // but for physics stability it's better to leave as computed.

  return { points: resultPoints, color, fillColor, width };
};

// --- OPTIMIZATION & SMOOTHING ---

const perpendicularDistance = (point: Point, lineStart: Point, lineEnd: Point): number => {
  let dx = lineEnd.x - lineStart.x;
  let dy = lineEnd.y - lineStart.y;
  const mag = Math.sqrt(dx * dx + dy * dy);
  if (mag > 0.0) { dx /= mag; dy /= mag; }
  const pvx = point.x - lineStart.x;
  const pvy = point.y - lineStart.y;
  const pvdot = pvx * dx + pvy * dy;
  const dsx = pvdot * dx;
  const dsy = pvdot * dy;
  const ax = pvx - dsx;
  const ay = pvy - dsy;
  return Math.sqrt(ax * ax + ay * ay);
};

export const simplifyPoints = (points: Point[], epsilon: number = 2): Point[] => {
  if (points.length < 3) return points;
  let dmax = 0;
  let index = 0;
  const end = points.length - 1;
  for (let i = 1; i < end; i++) {
    const d = perpendicularDistance(points[i], points[0], points[end]);
    if (d > dmax) { index = i; dmax = d; }
  }
  if (dmax > epsilon) {
    const recResults1 = simplifyPoints(points.slice(0, index + 1), epsilon);
    const recResults2 = simplifyPoints(points.slice(index, end + 1), epsilon);
    return [...recResults1.slice(0, -1), ...recResults2];
  } else {
    return [points[0], points[end]];
  }
};

export const chaikinSmooth = (points: Point[], iterations: number = 2): Point[] => {
    if (points.length < 3) return points;
    let output = [...points];
    for (let i = 0; i < iterations; i++) {
        const next: Point[] = [];
        next.push(output[0]);
        for (let j = 0; j < output.length - 1; j++) {
            const p0 = output[j];
            const p1 = output[j + 1];
            next.push({
                x: 0.75 * p0.x + 0.25 * p1.x,
                y: 0.75 * p0.y + 0.25 * p1.y,
                pressure: lerp(p0.pressure || 0.5, p1.pressure || 0.5, 0.25)
            });
            next.push({
                x: 0.25 * p0.x + 0.75 * p1.x,
                y: 0.25 * p0.y + 0.75 * p1.y,
                pressure: lerp(p0.pressure || 0.5, p1.pressure || 0.5, 0.75)
            });
        }
        next.push(output[output.length - 1]);
        output = next;
    }
    return output;
};

// utils/math.ts
import { Point, Stroke, InterpolationStrategy } from '../types';

export const distance = (p1: Point, p2: Point): number => {
  return Math.sqrt(Math.pow(p2.x - p1.x, 2) + Math.pow(p2.y - p1.y, 2));
};

export const lerp = (start: number, end: number, t: number): number => {
  return start * (1 - t) + end * t;
};

// --- Transformation Helpers ---

export const rotatePoint = (p: Point, center: Point, angleRad: number): Point => {
  const cos = Math.cos(angleRad);
  const sin = Math.sin(angleRad);
  const dx = p.x - center.x;
  const dy = p.y - center.y;
  return {
    x: center.x + (dx * cos - dy * sin),
    y: center.y + (dx * sin + dy * cos),
    pressure: p.pressure
  };
};

export const getBoundingBox = (points: Point[]): { minX: number, maxX: number, minY: number, maxY: number, width: number, height: number, centerX: number, centerY: number } => {
  if (points.length === 0) return { minX:0, maxX:0, minY:0, maxY:0, width:0, height:0, centerX:0, centerY:0 };

  let minX = Infinity, maxX = -Infinity, minY = Infinity, maxY = -Infinity;
  for (const p of points) {
    if (p.x < minX) minX = p.x;
    if (p.x > maxX) maxX = p.x;
    if (p.y < minY) minY = p.y;
    if (p.y > maxY) maxY = p.y;
  }

  return {
    minX, maxX, minY, maxY,
    width: maxX - minX,
    height: maxY - minY,
    centerX: minX + (maxX - minX) / 2,
    centerY: minY + (maxY - minY) / 2
  };
};

// --- Color Interpolation (RGBA) ---

const colorCache: Record<string, { r: number, g: number, b: number, a: number }> = {};

const parseColor = (color: string): { r: number, g: number, b: number, a: number } => {
  if (!color || color === 'none') return { r: 0, g: 0, b: 0, a: 1 }; // Return A=1 to avoid div zero, handle none upstream
  if (colorCache[color]) return colorCache[color];

  let result = { r: 0, g: 0, b: 0, a: 1 };

  if (color.startsWith('#')) {
    let hex = color.slice(1);
    if (hex.length === 3) hex = hex.split('').map(c => c + c).join('');
    const bigint = parseInt(hex, 16);
    result = {
      r: (bigint >> 16) & 255,
      g: (bigint >> 8) & 255,
      b: bigint & 255,
      a: 1
    };
  }
  else if (color.startsWith('rgb')) {
    const match = color.match(/(\d+(\.\d+)?)/g);
    if (match) {
        result = {
            r: parseFloat(match[0]),
            g: parseFloat(match[1]),
            b: parseFloat(match[2]),
            a: match[3] ? parseFloat(match[3]) : 1
        };
    }
  }

  colorCache[color] = result;
  return result;
};

export const mixColors = (colors: { color: string | 'none', weight: number }[]): string => {
  let rSum = 0, gSum = 0, bSum = 0, aSum = 0;
  let hasColor = false;

  for (const c of colors) {
    const rgba = parseColor(c.color);
    const alpha = c.color === 'none' ? 0 : rgba.a;

    if (alpha > 0) {
        hasColor = true;
        rSum += rgba.r * c.weight * alpha;
        gSum += rgba.g * c.weight * alpha;
        bSum += rgba.b * c.weight * alpha;
    }
    aSum += alpha * c.weight;
  }

  if (!hasColor || aSum <= 0.001) return 'none';

  // Normalize RGB by total alpha weight to prevent darkening when mixing with transparent
  // Actually standard Porter-Duff / Straight alpha compositing:
  // We just output premultiplied or straight? CSS wants straight.
  // The simple weighted average above works if we consider 'none' as transparent black.

  // Correction: If we mix Red (100%) and None (0%), result should be Red with 50% opacity.
  // The current logic does: (255*0.5 + 0*0.5) = 127. That's Dark Red. Wrong.
  // We need to divide accumulated RGB by accumulated AlphaWeight (if > 0).

  let totalAlphaWeight = 0; 
  colors.forEach(c => {
     const rgba = parseColor(c.color);
     const alpha = c.color === 'none' ? 0 : rgba.a;
     totalAlphaWeight += c.weight * alpha;
  });

  if (totalAlphaWeight <= 0.0001) return 'rgba(0,0,0,0)';

  const finalR = rSum / totalAlphaWeight;
  const finalG = gSum / totalAlphaWeight;
  const finalB = bSum / totalAlphaWeight;

  return `rgba(${Math.round(finalR)}, ${Math.round(finalG)}, ${Math.round(finalB)}, ${aSum.toFixed(3)})`;
};

// --- Geometry Helpers ---

const getPathLength = (points: Point[]): number => {
  let len = 0;
  for (let i = 1; i < points.length; i++) {
    len += distance(points[i - 1], points[i]);
  }
  return len;
};

// STRICT Arc-Length Resampling (Percentage Mode)
export const resamplePoints = (points: Point[], targetCount: number): Point[] => {
  if (points.length < 2 || targetCount < 2) return points;

  const totalLength = getPathLength(points);
  if (totalLength === 0) return Array(targetCount).fill(points[0]);

  const step = totalLength / (targetCount - 1);
  const newPoints: Point[] = [points[0]];

  let currentDist = 0;
  let nextPointIndex = 1;

  for (let i = 1; i < targetCount; i++) {
    const targetDist = i * step;
    let distSoFar = currentDist;
    let p1 = points[nextPointIndex - 1];
    let p2 = points[nextPointIndex];
    let segmentDist = distance(p1, p2);

    while (distSoFar + segmentDist < targetDist && nextPointIndex < points.length - 1) {
      distSoFar += segmentDist;
      currentDist = distSoFar;
      nextPointIndex++;
      p1 = points[nextPointIndex - 1];
      p2 = points[nextPointIndex];
      segmentDist = distance(p1, p2);
    }

    const segmentLocalDist = targetDist - distSoFar;
    const t = segmentDist === 0 ? 0 : segmentLocalDist / segmentDist;

    newPoints.push({
      x: lerp(p1.x, p2.x, t),
      y: lerp(p1.y, p2.y, t),
      pressure: lerp(p1.pressure || 0.5, p2.pressure || 0.5, t)
    });
  }

  while (newPoints.length < targetCount) newPoints.push(points[points.length - 1]);
  if (newPoints.length > targetCount) newPoints.length = targetCount;

  return newPoints;
};

const getPointAtFractionalIndex = (points: Point[], index: number): Point => {
    if (points.length === 0) return { x: 0, y: 0, pressure: 0 };
    if (points.length === 1) return points[0];

    if (index <= 0) return points[0];
    if (index >= points.length - 1) return points[points.length - 1];

    const i = Math.floor(index);
    const t = index - i;
    const p1 = points[i];
    const p2 = points[i+1];

    return {
        x: lerp(p1.x, p2.x, t),
        y: lerp(p1.y, p2.y, t),
        pressure: lerp(p1.pressure || 0.5, p2.pressure || 0.5, t)
    };
};

export const snapPointToGrid = (p: Point, gridSize: number): Point => {
  return {
    x: Math.round(p.x / gridSize) * gridSize,
    y: Math.round(p.y / gridSize) * gridSize,
    pressure: p.pressure
  };
};

// --- Hit Testing ---

const distToSegment = (p: Point, v: Point, w: Point) => {
  const l2 = Math.pow(distance(v, w), 2);
  if (l2 === 0) return distance(p, v);
  let t = ((p.x - v.x) * (w.x - v.x) + (p.y - v.y) * (w.y - v.y)) / l2;
  t = Math.max(0, Math.min(1, t));
  const projection = { x: v.x + t * (w.x - v.x), y: v.y + t * (w.y - v.y) };
  return distance(p, projection);
};

export const isPointInStroke = (p: Point, points: Point[], threshold: number = 10): boolean => {
  for (let i = 0; i < points.length - 1; i++) {
    if (distToSegment(p, points[i], points[i+1]) < threshold) return true;
  }
  return false;
};

// --- Robust Alignment ---

const alignPoints = (reference: Point[], target: Point[], forceClosed: boolean): Point[] => {
    if (reference.length !== target.length || reference.length === 0) return target;

    const len = reference.length;

    const getError = (ptsA: Point[], ptsB: Point[]) => {
        let err = 0;
        for(let i=0; i<len; i++) {
            const dx = ptsA[i].x - ptsB[i].x;
            const dy = ptsA[i].y - ptsB[i].y;
            err += dx*dx + dy*dy;
        }
        return err;
    };

    let bestPoints = [...target];
    let minError = getError(reference, target);

    // 1. Check Reverse Direction
    const reversed = [...target].reverse();
    const reverseError = getError(reference, reversed);

    if (reverseError < minError * 0.95) { // Threshold to prefer stable direction
        minError = reverseError;
        bestPoints = reversed;
    }

    // 2. Check Cyclic Shift (ONLY if closed or forced closed)
    if (forceClosed) {
        let workingSet = [...bestPoints];
        for (let offset = 1; offset < len; offset++) {
             // Create shifted array without mutating workingSet per iteration in a costly way
             const shifted = new Array(len);
             for(let k=0; k<len; k++) {
                 shifted[k] = workingSet[(k + offset) % len];
             }

             const err = getError(reference, shifted);
             if (err < minError) {
                 minError = err;
                 bestPoints = shifted;
             }
        }
    } 

    return bestPoints;
};

// --- INTERPOLATION STRATEGIES ---

const calculateBilinearGridWeights = (
  currentAxes: Record<string, number>,
  keyframes: { id: string; axisValues: Record<string, number> }[]
) => {
  const weights: Record<string, number> = {};

  const curX = currentAxes['axis-x'] || 0;
  const curY = currentAxes['axis-y'] || 0;
  const EPSILON = 0.005;

  const distinctCoords = (arr: number[]) => {
      const sorted = [...arr].sort((a,b) => a - b);
      const result = [];
      if (sorted.length > 0) result.push(sorted[0]);
      for (let i = 1; i < sorted.length; i++) {
          if (sorted[i] > sorted[i-1] + EPSILON) result.push(sorted[i]);
      }
      return result;
  };
  const xCoords = distinctCoords(keyframes.map(k => k.axisValues['axis-x'] || 0));
  const yCoords = distinctCoords(keyframes.map(k => k.axisValues['axis-y'] || 0));

  if (xCoords.length === 0 || yCoords.length === 0) {
      if (keyframes.length > 0) weights[keyframes[0].id] = 1;
      return weights;
  }

  const findInterval = (val: number, grid: number[]) => {
      if (val <= grid[0]) return { lower: grid[0], upper: grid[0], t: 0 };
      if (val >= grid[grid.length - 1]) return { lower: grid[grid.length - 1], upper: grid[grid.length - 1], t: 0 };
      for (let i = 0; i < grid.length - 1; i++) {
          if (val >= grid[i] && val <= grid[i+1]) {
              const span = grid[i+1] - grid[i];
              return { lower: grid[i], upper: grid[i+1], t: span === 0 ? 0 : (val - grid[i]) / span };
          }
      }
      return { lower: grid[0], upper: grid[0], t: 0 };
  };

  const xInfo = findInterval(curX, xCoords);
  const yInfo = findInterval(curY, yCoords);

  const resolveCornerWeights = (targetX: number, targetY: number) => {
      const exact = keyframes.find(k => Math.abs((k.axisValues['axis-x']||0) - targetX) < EPSILON && Math.abs((k.axisValues['axis-y']||0) - targetY) < EPSILON);
      if (exact) return { [exact.id]: 1.0 };

      // Inverse Distance Weighting fallback for non-grid points
      let totalW = 0;
      const cornerWeights: Record<string, number> = {};

      keyframes.forEach(k => {
          const dx = (k.axisValues['axis-x']||0) - targetX;
          const dy = (k.axisValues['axis-y']||0) - targetY;
          const dist = Math.sqrt(dx*dx + dy*dy);
          if (dist < 0.001) { cornerWeights[k.id] = 1000; totalW += 1000; }
          else {
              const w = 1 / Math.pow(dist, 2);
              cornerWeights[k.id] = w;
              totalW += w;
          }
      });

      for(const id in cornerWeights) cornerWeights[id] /= totalW;
      return cornerWeights;
  };

  const corners = [
      { x: xInfo.lower, y: yInfo.lower, wBase: (1 - xInfo.t) * (1 - yInfo.t) },
      { x: xInfo.upper, y: yInfo.lower, wBase: xInfo.t * (1 - yInfo.t) },
      { x: xInfo.lower, y: yInfo.upper, wBase: (1 - xInfo.t) * yInfo.t },
      { x: xInfo.upper, y: yInfo.upper, wBase: xInfo.t * yInfo.t }
  ];

  corners.forEach(c => {
      if (c.wBase <= 0.0001) return;
      const cornerComposition = resolveCornerWeights(c.x, c.y);
      for (const kfId in cornerComposition) {
          weights[kfId] = (weights[kfId] || 0) + (cornerComposition[kfId] * c.wBase);
      }
  });

  return weights;
};

const calculateIDWWeights = (currentAxes: Record<string, number>, keyframes: { id: string; axisValues: Record<string, number> }[], exponent: number) => {
    // Standard IDW implementation
    const weights: Record<string, number> = {};
    let totalWeight = 0;
    for (const kf of keyframes) {
        let dist = 0;
        for (const axisId in currentAxes) dist += Math.pow((currentAxes[axisId] || 0) - (kf.axisValues[axisId] || 0), 2);
        dist = Math.sqrt(dist);
        if (dist < 0.001) {
             keyframes.forEach(k => weights[k.id] = 0);
             weights[kf.id] = 1; 
             return weights; 
        }
        const w = 1 / Math.pow(dist, exponent);
        weights[kf.id] = w;
        totalWeight += w;
    }
    for (const id in weights) weights[id] /= totalWeight;
    return weights;
};

export const calculateInterpolationWeights = (
  currentAxes: Record<string, number>,
  keyframes: { id: string; axisValues: Record<string, number> }[],
  exponent: number = 2,
  strategy: InterpolationStrategy = 'bilinear-grid'
): Record<string, number> => {
   if (keyframes.length === 0) return {};
   if (keyframes.length === 1) return { [keyframes[0].id]: 1.0 };
   if (strategy === 'bilinear-grid') return calculateBilinearGridWeights(currentAxes, keyframes);
   return calculateIDWWeights(currentAxes, keyframes, exponent);
};

// --- CORE INTERPOLATION ENGINE ---

export const interpolateStrokePoints = (
  strokeId: string,
  basePoints: Point[], 
  keyframesData: { weight: number; points: Point[] | undefined, style: Stroke | undefined }[],
  mode: 'resample' | 'points' = 'resample',
  targetCount: number = 200 
): { points: Point[], color: string, fillColor: string, width: number } => {

  // 1. Filter active keyframes
  const activeKeyframes = keyframesData.filter(k => k.weight > 0.0001 && k.points && k.points.length > 0);
  if (activeKeyframes.length === 0) return { points: [], color: 'rgba(0,0,0,0)', fillColor: 'none', width: 1 };

  // 2. Mix Properties
  const color = mixColors(activeKeyframes.map(k => ({ color: k.style?.color || 'none', weight: k.weight })));
  const fillColor = mixColors(activeKeyframes.map(k => ({ color: k.style?.fillColor || 'none', weight: k.weight })));

  let totalWidth = 0;
  let widthWeightDivisor = 0;
  activeKeyframes.forEach(k => {
      totalWidth += (k.style?.width || 1) * k.weight;
      widthWeightDivisor += k.weight;
  });
  const width = widthWeightDivisor > 0 ? totalWidth / widthWeightDivisor : 1;

  // 3. Topology Handling (Open vs Closed Glitch Fix)
  // Calculate if the RESULT should be closed based on weight dominance
  let closedWeight = 0;
  activeKeyframes.forEach(k => { if (k.style?.closed) closedWeight += k.weight; });
  const resultClosed = closedWeight > 0.5;

  // We force alignment to use Cyclic check if ANY of the active keyframes is closed.
  // This allows an Open shape to "rotate" to match a Closed shape's start point seamlessly.
  const anyClosed = activeKeyframes.some(k => k.style?.closed);

  // 4. Point Count Normalization (Polyline Jump Fix)
  // Even in 'points' mode, if counts differ, we MUST normalize to the MAX count to avoid index sliding.
  let ACTUAL_TARGET_COUNT = targetCount; 

  if (mode === 'points') {
      const maxPts = Math.max(...activeKeyframes.map(k => k.points!.length));
      // If counts match exactly across all active frames, keep it exact.
      // If they differ, we upscale to the Max to prevent truncation jumps.
      const allMatch = activeKeyframes.every(k => k.points!.length === maxPts);
      ACTUAL_TARGET_COUNT = allMatch ? maxPts : Math.max(maxPts, 50); // Fallback to higher count if mismatch to ensure smoothness
  }

  // Reference for alignment (usually the heaviest weight)
  const sortedByWeight = [...activeKeyframes].sort((a,b) => b.weight - a.weight);
  const referenceStroke = sortedByWeight[0].points!;

  // Resample Reference Once
  const referenceResampled = resamplePoints(referenceStroke, ACTUAL_TARGET_COUNT);

  const resultPoints: Point[] = [];

  for (let i = 0; i < ACTUAL_TARGET_COUNT; i++) {
      let x = 0;
      let y = 0;
      let pressure = 0;
      let totalWeight = 0;

      for (const kf of activeKeyframes) {
          const rawPoints = kf.points!;
          let processedPoints: Point[] = [];

          // NORMALIZATION:
          // Regardless of mode, if we are mixing counts or topologies, we use resamplePoints logic
          // to generate a comparable set of vertices.
          // Note: resamplePoints uses Arc-Length parametrization which is stable during morphs.

          if (mode === 'points' && rawPoints.length === ACTUAL_TARGET_COUNT) {
              // Perfect match case: use raw points directly (topology safe)
              processedPoints = rawPoints;
          } else {
              // Mismatch case (or resample mode): Resample to common denominator
              processedPoints = resamplePoints(rawPoints, ACTUAL_TARGET_COUNT);
          }

          // ALIGNMENT:
          // Align this keyframe's points to the reference (Heaviest keyframe)
          // passing 'anyClosed' to allow cyclic optimization if mixed topology.
          const alignedPoints = alignPoints(referenceResampled, processedPoints, anyClosed);

          const pt = alignedPoints[i];

          x += pt.x * kf.weight;
          y += pt.y * kf.weight;
          pressure += (pt.pressure || 0.5) * kf.weight;
          totalWeight += kf.weight;
      }

      if (totalWeight > 0) {
          resultPoints.push({
              x: x / totalWeight,
              y: y / totalWeight,
              pressure: pressure / totalWeight
          });
      }
  }

  // Force close visual if needed (replicate start at end?)
  // Canvas handles 'ctx.closePath()' so we don't strictly need to duplicate point,
  // but for physics stability it's better to leave as computed.

  return { points: resultPoints, color, fillColor, width };
};

// --- OPTIMIZATION & SMOOTHING ---

const perpendicularDistance = (point: Point, lineStart: Point, lineEnd: Point): number => {
  let dx = lineEnd.x - lineStart.x;
  let dy = lineEnd.y - lineStart.y;
  const mag = Math.sqrt(dx * dx + dy * dy);
  if (mag > 0.0) { dx /= mag; dy /= mag; }
  const pvx = point.x - lineStart.x;
  const pvy = point.y - lineStart.y;
  const pvdot = pvx * dx + pvy * dy;
  const dsx = pvdot * dx;
  const dsy = pvdot * dy;
  const ax = pvx - dsx;
  const ay = pvy - dsy;
  return Math.sqrt(ax * ax + ay * ay);
};

export const simplifyPoints = (points: Point[], epsilon: number = 2): Point[] => {
  if (points.length < 3) return points;
  let dmax = 0;
  let index = 0;
  const end = points.length - 1;
  for (let i = 1; i < end; i++) {
    const d = perpendicularDistance(points[i], points[0], points[end]);
    if (d > dmax) { index = i; dmax = d; }
  }
  if (dmax > epsilon) {
    const recResults1 = simplifyPoints(points.slice(0, index + 1), epsilon);
    const recResults2 = simplifyPoints(points.slice(index, end + 1), epsilon);
    return [...recResults1.slice(0, -1), ...recResults2];
  } else {
    return [points[0], points[end]];
  }
};

export const chaikinSmooth = (points: Point[], iterations: number = 2): Point[] => {
    if (points.length < 3) return points;
    let output = [...points];
    for (let i = 0; i < iterations; i++) {
        const next: Point[] = [];
        next.push(output[0]);
        for (let j = 0; j < output.length - 1; j++) {
            const p0 = output[j];
            const p1 = output[j + 1];
            next.push({
                x: 0.75 * p0.x + 0.25 * p1.x,
                y: 0.75 * p0.y + 0.25 * p1.y,
                pressure: lerp(p0.pressure || 0.5, p1.pressure || 0.5, 0.25)
            });
            next.push({
                x: 0.25 * p0.x + 0.75 * p1.x,
                y: 0.25 * p0.y + 0.75 * p1.y,
                pressure: lerp(p0.pressure || 0.5, p1.pressure || 0.5, 0.75)
            });
        }
        next.push(output[output.length - 1]);
        output = next;
    }
    return output;
};

// utils/math.ts
import { Point, Stroke, InterpolationStrategy } from '../types';

export const distance = (p1: Point, p2: Point): number => {
  return Math.sqrt(Math.pow(p2.x - p1.x, 2) + Math.pow(p2.y - p1.y, 2));
};

export const lerp = (start: number, end: number, t: number): number => {
  return start * (1 - t) + end * t;
};

// --- Transformation Helpers ---

export const rotatePoint = (p: Point, center: Point, angleRad: number): Point => {
  const cos = Math.cos(angleRad);
  const sin = Math.sin(angleRad);
  const dx = p.x - center.x;
  const dy = p.y - center.y;
  return {
    x: center.x + (dx * cos - dy * sin),
    y: center.y + (dx * sin + dy * cos),
    pressure: p.pressure
  };
};

export const getBoundingBox = (points: Point[]): { minX: number, maxX: number, minY: number, maxY: number, width: number, height: number, centerX: number, centerY: number } => {
  if (points.length === 0) return { minX:0, maxX:0, minY:0, maxY:0, width:0, height:0, centerX:0, centerY:0 };

  let minX = Infinity, maxX = -Infinity, minY = Infinity, maxY = -Infinity;
  for (const p of points) {
    if (p.x < minX) minX = p.x;
    if (p.x > maxX) maxX = p.x;
    if (p.y < minY) minY = p.y;
    if (p.y > maxY) maxY = p.y;
  }

  return {
    minX, maxX, minY, maxY,
    width: maxX - minX,
    height: maxY - minY,
    centerX: minX + (maxX - minX) / 2,
    centerY: minY + (maxY - minY) / 2
  };
};

// --- Color Interpolation (RGBA) ---

const colorCache: Record<string, { r: number, g: number, b: number, a: number }> = {};

const parseColor = (color: string): { r: number, g: number, b: number, a: number } => {
  if (!color || color === 'none') return { r: 0, g: 0, b: 0, a: 1 }; // Return A=1 to avoid div zero, handle none upstream
  if (colorCache[color]) return colorCache[color];

  let result = { r: 0, g: 0, b: 0, a: 1 };

  if (color.startsWith('#')) {
    let hex = color.slice(1);
    if (hex.length === 3) hex = hex.split('').map(c => c + c).join('');
    const bigint = parseInt(hex, 16);
    result = {
      r: (bigint >> 16) & 255,
      g: (bigint >> 8) & 255,
      b: bigint & 255,
      a: 1
    };
  }
  else if (color.startsWith('rgb')) {
    const match = color.match(/(\d+(\.\d+)?)/g);
    if (match) {
        result = {
            r: parseFloat(match[0]),
            g: parseFloat(match[1]),
            b: parseFloat(match[2]),
            a: match[3] ? parseFloat(match[3]) : 1
        };
    }
  }

  colorCache[color] = result;
  return result;
};

export const mixColors = (colors: { color: string | 'none', weight: number }[]): string => {
  let rSum = 0, gSum = 0, bSum = 0, aSum = 0;
  let hasColor = false;

  for (const c of colors) {
    const rgba = parseColor(c.color);
    const alpha = c.color === 'none' ? 0 : rgba.a;

    if (alpha > 0) {
        hasColor = true;
        rSum += rgba.r * c.weight * alpha;
        gSum += rgba.g * c.weight * alpha;
        bSum += rgba.b * c.weight * alpha;
    }
    aSum += alpha * c.weight;
  }

  if (!hasColor || aSum <= 0.001) return 'none';

  let totalAlphaWeight = 0; 
  colors.forEach(c => {
     const rgba = parseColor(c.color);
     const alpha = c.color === 'none' ? 0 : rgba.a;
     totalAlphaWeight += c.weight * alpha;
  });

  if (totalAlphaWeight <= 0.0001) return 'rgba(0,0,0,0)';

  const finalR = rSum / totalAlphaWeight;
  const finalG = gSum / totalAlphaWeight;
  const finalB = bSum / totalAlphaWeight;

  return `rgba(${Math.round(finalR)}, ${Math.round(finalG)}, ${Math.round(finalB)}, ${aSum.toFixed(3)})`;
};

// --- Geometry Helpers ---

const getPathLength = (points: Point[]): number => {
  let len = 0;
  for (let i = 1; i < points.length; i++) {
    len += distance(points[i - 1], points[i]);
  }
  return len;
};

// STRICT Arc-Length Resampling (Curve Mode)
export const resamplePoints = (points: Point[], targetCount: number): Point[] => {
  if (points.length < 2 || targetCount < 2) return points;

  const totalLength = getPathLength(points);
  if (totalLength === 0) return Array(targetCount).fill(points[0]);

  const step = totalLength / (targetCount - 1);
  const newPoints: Point[] = [points[0]];

  let currentDist = 0;
  let nextPointIndex = 1;

  for (let i = 1; i < targetCount; i++) {
    const targetDist = i * step;
    let distSoFar = currentDist;
    let p1 = points[nextPointIndex - 1];
    let p2 = points[nextPointIndex];
    let segmentDist = distance(p1, p2);

    while (distSoFar + segmentDist < targetDist && nextPointIndex < points.length - 1) {
      distSoFar += segmentDist;
      currentDist = distSoFar;
      nextPointIndex++;
      p1 = points[nextPointIndex - 1];
      p2 = points[nextPointIndex];
      segmentDist = distance(p1, p2);
    }

    const segmentLocalDist = targetDist - distSoFar;
    const t = segmentDist === 0 ? 0 : segmentLocalDist / segmentDist;

    newPoints.push({
      x: lerp(p1.x, p2.x, t),
      y: lerp(p1.y, p2.y, t),
      pressure: lerp(p1.pressure || 0.5, p2.pressure || 0.5, t)
    });
  }

  while (newPoints.length < targetCount) newPoints.push(points[points.length - 1]);
  if (newPoints.length > targetCount) newPoints.length = targetCount;

  return newPoints;
};

// LINEAR Index Resampling (Polyline/Points Mode)
// Distributes new points exactly along the segments of the original shape.
// Does NOT round corners. Preserves vertices.
export const upsamplePointsLinear = (points: Point[], targetCount: number): Point[] => {
    if (points.length === 0) return [];
    if (points.length === 1) return Array(targetCount).fill(points[0]);
    if (points.length >= targetCount) return points; // Should be handled upstream, but safe fallback

    const newPoints: Point[] = [];
    // We map the target range [0, targetCount-1] to source range [0, points.length-1]
    const step = (points.length - 1) / (targetCount - 1);

    for (let i = 0; i < targetCount; i++) {
        const preciseIndex = i * step;
        const index = Math.floor(preciseIndex);
        const nextIndex = Math.min(index + 1, points.length - 1);
        const t = preciseIndex - index;

        const p1 = points[index];
        const p2 = points[nextIndex];

        newPoints.push({
            x: p1.x * (1 - t) + p2.x * t,
            y: p1.y * (1 - t) + p2.y * t,
            pressure: (p1.pressure ?? 0.5) * (1 - t) + (p2.pressure ?? 0.5) * t
        });
    }
    return newPoints;
};

export const snapPointToGrid = (p: Point, gridSize: number): Point => {
  return {
    x: Math.round(p.x / gridSize) * gridSize,
    y: Math.round(p.y / gridSize) * gridSize,
    pressure: p.pressure
  };
};

// --- Hit Testing ---

const distToSegment = (p: Point, v: Point, w: Point) => {
  const l2 = Math.pow(distance(v, w), 2);
  if (l2 === 0) return distance(p, v);
  let t = ((p.x - v.x) * (w.x - v.x) + (p.y - v.y) * (w.y - v.y)) / l2;
  t = Math.max(0, Math.min(1, t));
  const projection = { x: v.x + t * (w.x - v.x), y: v.y + t * (w.y - v.y) };
  return distance(p, projection);
};

export const isPointInStroke = (p: Point, points: Point[], threshold: number = 10): boolean => {
  for (let i = 0; i < points.length - 1; i++) {
    if (distToSegment(p, points[i], points[i+1]) < threshold) return true;
  }
  return false;
};

// --- Robust Alignment ---

const alignPoints = (reference: Point[], target: Point[], forceClosed: boolean): Point[] => {
    if (reference.length !== target.length || reference.length === 0) return target;

    const len = reference.length;

    const getError = (ptsA: Point[], ptsB: Point[]) => {
        let err = 0;
        for(let i=0; i<len; i++) {
            const dx = ptsA[i].x - ptsB[i].x;
            const dy = ptsA[i].y - ptsB[i].y;
            err += dx*dx + dy*dy;
        }
        return err;
    };

    let bestPoints = [...target];
    let minError = getError(reference, target);

    // 1. Check Reverse Direction
    const reversed = [...target].reverse();
    const reverseError = getError(reference, reversed);

    if (reverseError < minError * 0.95) { 
        minError = reverseError;
        bestPoints = reversed;
    }

    // 2. Check Cyclic Shift (ONLY if closed or forced closed)
    if (forceClosed) {
        let workingSet = [...bestPoints];
        // Optimization: limit checks for very large arrays to avoid lag
        const checkCount = len; 

        for (let offset = 1; offset < checkCount; offset++) {
             const shifted = new Array(len);
             for(let k=0; k<len; k++) {
                 shifted[k] = workingSet[(k + offset) % len];
             }

             const err = getError(reference, shifted);
             if (err < minError) {
                 minError = err;
                 bestPoints = shifted;
             }
        }
    } 

    return bestPoints;
};

// --- INTERPOLATION STRATEGIES ---

const calculateBilinearGridWeights = (
  currentAxes: Record<string, number>,
  keyframes: { id: string; axisValues: Record<string, number> }[]
) => {
  const weights: Record<string, number> = {};

  const curX = currentAxes['axis-x'] || 0;
  const curY = currentAxes['axis-y'] || 0;
  const EPSILON = 0.005;

  const distinctCoords = (arr: number[]) => {
      const sorted = [...arr].sort((a,b) => a - b);
      const result = [];
      if (sorted.length > 0) result.push(sorted[0]);
      for (let i = 1; i < sorted.length; i++) {
          if (sorted[i] > sorted[i-1] + EPSILON) result.push(sorted[i]);
      }
      return result;
  };
  const xCoords = distinctCoords(keyframes.map(k => k.axisValues['axis-x'] || 0));
  const yCoords = distinctCoords(keyframes.map(k => k.axisValues['axis-y'] || 0));

  if (xCoords.length === 0 || yCoords.length === 0) {
      if (keyframes.length > 0) weights[keyframes[0].id] = 1;
      return weights;
  }

  const findInterval = (val: number, grid: number[]) => {
      if (val <= grid[0]) return { lower: grid[0], upper: grid[0], t: 0 };
      if (val >= grid[grid.length - 1]) return { lower: grid[grid.length - 1], upper: grid[grid.length - 1], t: 0 };
      for (let i = 0; i < grid.length - 1; i++) {
          if (val >= grid[i] && val <= grid[i+1]) {
              const span = grid[i+1] - grid[i];
              return { lower: grid[i], upper: grid[i+1], t: span === 0 ? 0 : (val - grid[i]) / span };
          }
      }
      return { lower: grid[0], upper: grid[0], t: 0 };
  };

  const xInfo = findInterval(curX, xCoords);
  const yInfo = findInterval(curY, yCoords);

  const resolveCornerWeights = (targetX: number, targetY: number) => {
      const exact = keyframes.find(k => Math.abs((k.axisValues['axis-x']||0) - targetX) < EPSILON && Math.abs((k.axisValues['axis-y']||0) - targetY) < EPSILON);
      if (exact) return { [exact.id]: 1.0 };

      let totalW = 0;
      const cornerWeights: Record<string, number> = {};

      keyframes.forEach(k => {
          const dx = (k.axisValues['axis-x']||0) - targetX;
          const dy = (k.axisValues['axis-y']||0) - targetY;
          const dist = Math.sqrt(dx*dx + dy*dy);
          if (dist < 0.001) { cornerWeights[k.id] = 1000; totalW += 1000; }
          else {
              const w = 1 / Math.pow(dist, 2);
              cornerWeights[k.id] = w;
              totalW += w;
          }
      });

      for(const id in cornerWeights) cornerWeights[id] /= totalW;
      return cornerWeights;
  };

  const corners = [
      { x: xInfo.lower, y: yInfo.lower, wBase: (1 - xInfo.t) * (1 - yInfo.t) },
      { x: xInfo.upper, y: yInfo.lower, wBase: xInfo.t * (1 - yInfo.t) },
      { x: xInfo.lower, y: yInfo.upper, wBase: (1 - xInfo.t) * yInfo.t },
      { x: xInfo.upper, y: yInfo.upper, wBase: xInfo.t * yInfo.t }
  ];

  corners.forEach(c => {
      if (c.wBase <= 0.0001) return;
      const cornerComposition = resolveCornerWeights(c.x, c.y);
      for (const kfId in cornerComposition) {
          weights[kfId] = (weights[kfId] || 0) + (cornerComposition[kfId] * c.wBase);
      }
  });

  return weights;
};

const calculateIDWWeights = (currentAxes: Record<string, number>, keyframes: { id: string; axisValues: Record<string, number> }[], exponent: number) => {
    const weights: Record<string, number> = {};
    let totalWeight = 0;
    for (const kf of keyframes) {
        let dist = 0;
        for (const axisId in currentAxes) dist += Math.pow((currentAxes[axisId] || 0) - (kf.axisValues[axisId] || 0), 2);
        dist = Math.sqrt(dist);
        if (dist < 0.001) {
             keyframes.forEach(k => weights[k.id] = 0);
             weights[kf.id] = 1; 
             return weights; 
        }
        const w = 1 / Math.pow(dist, exponent);
        weights[kf.id] = w;
        totalWeight += w;
    }
    for (const id in weights) weights[id] /= totalWeight;
    return weights;
};

export const calculateInterpolationWeights = (
  currentAxes: Record<string, number>,
  keyframes: { id: string; axisValues: Record<string, number> }[],
  exponent: number = 2,
  strategy: InterpolationStrategy = 'bilinear-grid'
): Record<string, number> => {
   if (keyframes.length === 0) return {};
   if (keyframes.length === 1) return { [keyframes[0].id]: 1.0 };
   if (strategy === 'bilinear-grid') return calculateBilinearGridWeights(currentAxes, keyframes);
   return calculateIDWWeights(currentAxes, keyframes, exponent);
};

// --- CORE INTERPOLATION ENGINE ---

export const interpolateStrokePoints = (
  strokeId: string,
  basePoints: Point[], 
  keyframesData: { weight: number; points: Point[] | undefined, style: Stroke | undefined }[],
  mode: 'resample' | 'points' = 'resample',
  targetCount: number = 200 
): { points: Point[], color: string, fillColor: string, width: number } => {

  // 1. Filter active keyframes
  const activeKeyframes = keyframesData.filter(k => k.weight > 0.0001 && k.points && k.points.length > 0);
  if (activeKeyframes.length === 0) return { points: [], color: 'rgba(0,0,0,0)', fillColor: 'none', width: 1 };

  // 2. Mix Properties
  const color = mixColors(activeKeyframes.map(k => ({ color: k.style?.color || 'none', weight: k.weight })));
  const fillColor = mixColors(activeKeyframes.map(k => ({ color: k.style?.fillColor || 'none', weight: k.weight })));

  let totalWidth = 0;
  let widthWeightDivisor = 0;
  activeKeyframes.forEach(k => {
      totalWidth += (k.style?.width || 1) * k.weight;
      widthWeightDivisor += k.weight;
  });
  const width = widthWeightDivisor > 0 ? totalWidth / widthWeightDivisor : 1;

  // 3. Topology Handling
  let closedWeight = 0;
  activeKeyframes.forEach(k => { if (k.style?.closed) closedWeight += k.weight; });
  const resultClosed = closedWeight > 0.5;
  const anyClosed = activeKeyframes.some(k => k.style?.closed);

  // 4. Point Count Normalization (CRITICAL JUMP FIX)
  let ACTUAL_TARGET_COUNT = targetCount; 

  // Determine MAX points across active frames
  const maxPts = Math.max(...activeKeyframes.map(k => k.points!.length));

  if (mode === 'points') {
      // In points mode, we want to respect the geometry of the most complex shape.
      // If we simply used targetCount (e.g. 200), we would smooth out the polyline.
      // Instead, we use the MAX point count found in the active frames.
      // This ensures we have enough vertices to represent the complex shape,
      // and we upsample the simple shapes to match.
      ACTUAL_TARGET_COUNT = maxPts;
  }

  // 5. Reference Selection (CRITICAL STABILITY FIX)
  // Instead of selecting the reference based on Weight (which flips at 50%),
  // we select the reference based on TOPOLOGY COMPLEXITY (Max Points).
  // This ensures the target shape structure remains constant during the transition.
  // If counts are equal, we fallback to weight or ID to be deterministic.
  const referenceKeyframe = activeKeyframes.reduce((prev, current) => {
      const prevLen = prev.points!.length;
      const currLen = current.points!.length;
      if (prevLen > currLen) return prev;
      if (currLen > prevLen) return current;
      // If equal length, prefer the one with higher weight to keep alignment "soft"
      return (prev.weight >= current.weight) ? prev : current;
  });

  const referenceStroke = referenceKeyframe.points!;

  // Resample Reference Once
  // Use the appropriate method based on mode
  let referenceResampled: Point[];
  if (mode === 'points') {
      referenceResampled = upsamplePointsLinear(referenceStroke, ACTUAL_TARGET_COUNT);
  } else {
      referenceResampled = resamplePoints(referenceStroke, ACTUAL_TARGET_COUNT);
  }

  const resultPoints: Point[] = [];

  for (let i = 0; i < ACTUAL_TARGET_COUNT; i++) {
      let x = 0;
      let y = 0;
      let pressure = 0;
      let totalWeight = 0;

      for (const kf of activeKeyframes) {
          const rawPoints = kf.points!;
          let processedPoints: Point[] = [];

          // NORMALIZATION:
          if (mode === 'points') {
             // Linear Upsampling for Polylines (Preserves corners)
             if (rawPoints.length === ACTUAL_TARGET_COUNT) {
                 processedPoints = rawPoints;
             } else {
                 processedPoints = upsamplePointsLinear(rawPoints, ACTUAL_TARGET_COUNT);
             }
          } else {
             // Arc-Length Resampling for Curves (Preserves flow)
             processedPoints = resamplePoints(rawPoints, ACTUAL_TARGET_COUNT);
          }

          // ALIGNMENT:
          const alignedPoints = alignPoints(referenceResampled, processedPoints, anyClosed);

          const pt = alignedPoints[i];

          x += pt.x * kf.weight;
          y += pt.y * kf.weight;
          pressure += (pt.pressure || 0.5) * kf.weight;
          totalWeight += kf.weight;
      }

      if (totalWeight > 0) {
          resultPoints.push({
              x: x / totalWeight,
              y: y / totalWeight,
              pressure: pressure / totalWeight
          });
      }
  }

  return { points: resultPoints, color, fillColor, width };
};

// --- OPTIMIZATION & SMOOTHING ---

const perpendicularDistance = (point: Point, lineStart: Point, lineEnd: Point): number => {
  let dx = lineEnd.x - lineStart.x;
  let dy = lineEnd.y - lineStart.y;
  const mag = Math.sqrt(dx * dx + dy * dy);
  if (mag > 0.0) { dx /= mag; dy /= mag; }
  const pvx = point.x - lineStart.x;
  const pvy = point.y - lineStart.y;
  const pvdot = pvx * dx + pvy * dy;
  const dsx = pvdot * dx;
  const dsy = pvdot * dy;
  const ax = pvx - dsx;
  const ay = pvy - dsy;
  return Math.sqrt(ax * ax + ay * ay);
};

export const simplifyPoints = (points: Point[], epsilon: number = 2): Point[] => {
  if (points.length < 3) return points;
  let dmax = 0;
  let index = 0;
  const end = points.length - 1;
  for (let i = 1; i < end; i++) {
    const d = perpendicularDistance(points[i], points[0], points[end]);
    if (d > dmax) { index = i; dmax = d; }
  }
  if (dmax > epsilon) {
    const recResults1 = simplifyPoints(points.slice(0, index + 1), epsilon);
    const recResults2 = simplifyPoints(points.slice(index, end + 1), epsilon);
    return [...recResults1.slice(0, -1), ...recResults2];
  } else {
    return [points[0], points[end]];
  }
};

export const chaikinSmooth = (points: Point[], iterations: number = 2): Point[] => {
    if (points.length < 3) return points;
    let output = [...points];
    for (let i = 0; i < iterations; i++) {
        const next: Point[] = [];
        next.push(output[0]);
        for (let j = 0; j < output.length - 1; j++) {
            const p0 = output[j];
            const p1 = output[j + 1];
            next.push({
                x: 0.75 * p0.x + 0.25 * p1.x,
                y: 0.75 * p0.y + 0.25 * p1.y,
                pressure: lerp(p0.pressure || 0.5, p1.pressure || 0.5, 0.25)
            });
            next.push({
                x: 0.25 * p0.x + 0.75 * p1.x,
                y: 0.25 * p0.y + 0.75 * p1.y,
                pressure: lerp(p0.pressure || 0.5, p1.pressure || 0.5, 0.75)
            });
        }
        next.push(output[output.length - 1]);
        output = next;
    }
    return output;
};

// utils/math.ts
import { Point, Stroke, InterpolationStrategy } from '../types';

export const distance = (p1: Point, p2: Point): number => {
  return Math.sqrt(Math.pow(p2.x - p1.x, 2) + Math.pow(p2.y - p1.y, 2));
};

export const lerp = (start: number, end: number, t: number): number => {
  return start * (1 - t) + end * t;
};

// --- Transformation Helpers ---

export const rotatePoint = (p: Point, center: Point, angleRad: number): Point => {
  const cos = Math.cos(angleRad);
  const sin = Math.sin(angleRad);
  const dx = p.x - center.x;
  const dy = p.y - center.y;
  return {
    x: center.x + (dx * cos - dy * sin),
    y: center.y + (dx * sin + dy * cos),
    pressure: p.pressure
  };
};

export const getBoundingBox = (points: Point[]): { minX: number, maxX: number, minY: number, maxY: number, width: number, height: number, centerX: number, centerY: number } => {
  if (points.length === 0) return { minX:0, maxX:0, minY:0, maxY:0, width:0, height:0, centerX:0, centerY:0 };

  let minX = Infinity, maxX = -Infinity, minY = Infinity, maxY = -Infinity;
  for (const p of points) {
    if (p.x < minX) minX = p.x;
    if (p.x > maxX) maxX = p.x;
    if (p.y < minY) minY = p.y;
    if (p.y > maxY) maxY = p.y;
  }

  return {
    minX, maxX, minY, maxY,
    width: maxX - minX,
    height: maxY - minY,
    centerX: minX + (maxX - minX) / 2,
    centerY: minY + (maxY - minY) / 2
  };
};

// --- Color Interpolation (RGBA) ---

const colorCache: Record<string, { r: number, g: number, b: number, a: number }> = {};

const parseColor = (color: string): { r: number, g: number, b: number, a: number } => {
  if (!color || color === 'none') return { r: 0, g: 0, b: 0, a: 1 }; 
  if (colorCache[color]) return colorCache[color];

  let result = { r: 0, g: 0, b: 0, a: 1 };

  if (color.startsWith('#')) {
    let hex = color.slice(1);
    if (hex.length === 3) hex = hex.split('').map(c => c + c).join('');
    const bigint = parseInt(hex, 16);
    result = {
      r: (bigint >> 16) & 255,
      g: (bigint >> 8) & 255,
      b: bigint & 255,
      a: 1
    };
  }
  else if (color.startsWith('rgb')) {
    const match = color.match(/(\d+(\.\d+)?)/g);
    if (match) {
        result = {
            r: parseFloat(match[0]),
            g: parseFloat(match[1]),
            b: parseFloat(match[2]),
            a: match[3] ? parseFloat(match[3]) : 1
        };
    }
  }

  colorCache[color] = result;
  return result;
};

export const mixColors = (colors: { color: string | 'none', weight: number }[]): string => {
  let rSum = 0, gSum = 0, bSum = 0, aSum = 0;
  let hasColor = false;

  for (const c of colors) {
    const rgba = parseColor(c.color);
    const alpha = c.color === 'none' ? 0 : rgba.a;

    if (alpha > 0) {
        hasColor = true;
        rSum += rgba.r * c.weight * alpha;
        gSum += rgba.g * c.weight * alpha;
        bSum += rgba.b * c.weight * alpha;
    }
    aSum += alpha * c.weight;
  }

  if (!hasColor || aSum <= 0.001) return 'none';

  let totalAlphaWeight = 0; 
  colors.forEach(c => {
     const rgba = parseColor(c.color);
     const alpha = c.color === 'none' ? 0 : rgba.a;
     totalAlphaWeight += c.weight * alpha;
  });

  if (totalAlphaWeight <= 0.0001) return 'rgba(0,0,0,0)';

  const finalR = rSum / totalAlphaWeight;
  const finalG = gSum / totalAlphaWeight;
  const finalB = bSum / totalAlphaWeight;

  return `rgba(${Math.round(finalR)}, ${Math.round(finalG)}, ${Math.round(finalB)}, ${aSum.toFixed(3)})`;
};

// --- Geometry Helpers ---

const getPathLength = (points: Point[]): number => {
  let len = 0;
  for (let i = 1; i < points.length; i++) {
    len += distance(points[i - 1], points[i]);
  }
  return len;
};

// Curve Resampling (Arc-Length)
export const resamplePoints = (points: Point[], targetCount: number): Point[] => {
  if (points.length < 2 || targetCount < 2) return points;

  const totalLength = getPathLength(points);
  if (totalLength === 0) return Array(targetCount).fill(points[0]);

  const step = totalLength / (targetCount - 1);
  const newPoints: Point[] = [points[0]];

  let currentDist = 0;
  let nextPointIndex = 1;

  for (let i = 1; i < targetCount; i++) {
    const targetDist = i * step;
    let distSoFar = currentDist;
    let p1 = points[nextPointIndex - 1];
    let p2 = points[nextPointIndex];
    let segmentDist = distance(p1, p2);

    while (distSoFar + segmentDist < targetDist && nextPointIndex < points.length - 1) {
      distSoFar += segmentDist;
      currentDist = distSoFar;
      nextPointIndex++;
      p1 = points[nextPointIndex - 1];
      p2 = points[nextPointIndex];
      segmentDist = distance(p1, p2);
    }

    const segmentLocalDist = targetDist - distSoFar;
    const t = segmentDist === 0 ? 0 : segmentLocalDist / segmentDist;

    newPoints.push({
      x: lerp(p1.x, p2.x, t),
      y: lerp(p1.y, p2.y, t),
      pressure: lerp(p1.pressure || 0.5, p2.pressure || 0.5, t)
    });
  }

  while (newPoints.length < targetCount) newPoints.push(points[points.length - 1]);
  if (newPoints.length > targetCount) newPoints.length = targetCount;

  return newPoints;
};

// --- NEW ALGORITHM: CORNER-PRESERVING UPSAMPLING ---
// This injects points into segments without moving original vertices.
// Fixes the "sliding corners" or "jumps" when point counts differ.
export const upsamplePreservingCorners = (points: Point[], targetCount: number): Point[] => {
    if (points.length === 0) return [];
    if (points.length >= targetCount) return points; // Should be handled upstream

    const pointsToAdd = targetCount - points.length;
    const segments = points.length - 1;
    if (segments < 1) return Array(targetCount).fill(points[0]);

    // Distribute extra points as evenly as possible among segments
    const baseAdd = Math.floor(pointsToAdd / segments);
    const remainder = pointsToAdd % segments;

    const newPoints: Point[] = [];

    for (let i = 0; i < segments; i++) {
        // Always add the start point of the segment (Preserves Vertex)
        newPoints.push(points[i]);

        // How many internal points to add to this segment?
        // Distribute remainder to the first few segments
        const count = baseAdd + (i < remainder ? 1 : 0);

        if (count > 0) {
            const pStart = points[i];
            const pEnd = points[i+1];
            // Add internal points
            for (let k = 1; k <= count; k++) {
                const t = k / (count + 1);
                newPoints.push({
                    x: lerp(pStart.x, pEnd.x, t),
                    y: lerp(pStart.y, pEnd.y, t),
                    pressure: lerp(pStart.pressure||0.5, pEnd.pressure||0.5, t)
                });
            }
        }
    }
    // Always add the very last point
    newPoints.push(points[points.length - 1]);

    return newPoints;
};

export const snapPointToGrid = (p: Point, gridSize: number): Point => {
  return {
    x: Math.round(p.x / gridSize) * gridSize,
    y: Math.round(p.y / gridSize) * gridSize,
    pressure: p.pressure
  };
};

// --- Hit Testing ---

const distToSegment = (p: Point, v: Point, w: Point) => {
  const l2 = Math.pow(distance(v, w), 2);
  if (l2 === 0) return distance(p, v);
  let t = ((p.x - v.x) * (w.x - v.x) + (p.y - v.y) * (w.y - v.y)) / l2;
  t = Math.max(0, Math.min(1, t));
  const projection = { x: v.x + t * (w.x - v.x), y: v.y + t * (w.y - v.y) };
  return distance(p, projection);
};

export const isPointInStroke = (p: Point, points: Point[], threshold: number = 10): boolean => {
  for (let i = 0; i < points.length - 1; i++) {
    if (distToSegment(p, points[i], points[i+1]) < threshold) return true;
  }
  return false;
};

// --- Robust Alignment ---

const alignPoints = (reference: Point[], target: Point[], allowCyclicShift: boolean): Point[] => {
    if (reference.length !== target.length || reference.length === 0) return target;

    const len = reference.length;

    const getError = (ptsA: Point[], ptsB: Point[]) => {
        let err = 0;
        for(let i=0; i<len; i++) {
            const dx = ptsA[i].x - ptsB[i].x;
            const dy = ptsA[i].y - ptsB[i].y;
            err += dx*dx + dy*dy;
        }
        return err;
    };

    let bestPoints = [...target];
    let minError = getError(reference, target);

    // 1. Check Reverse Direction
    const reversed = [...target].reverse();
    const reverseError = getError(reference, reversed);

    if (reverseError < minError * 0.95) { 
        minError = reverseError;
        bestPoints = reversed;
    }

    // 2. Check Cyclic Shift 
    // CRITICAL FIX: Only allow cyclic shift if we are dealing with loops (Closed shapes).
    // Shifting an Open Polyline destroys its structure.
    if (allowCyclicShift) {
        let workingSet = [...bestPoints];
        const checkCount = len; 

        for (let offset = 1; offset < checkCount; offset++) {
             const shifted = new Array(len);
             for(let k=0; k<len; k++) {
                 shifted[k] = workingSet[(k + offset) % len];
             }

             const err = getError(reference, shifted);
             if (err < minError) {
                 minError = err;
                 bestPoints = shifted;
             }
        }
    } 

    return bestPoints;
};

// --- INTERPOLATION STRATEGIES ---

const calculateBilinearGridWeights = (
  currentAxes: Record<string, number>,
  keyframes: { id: string; axisValues: Record<string, number> }[]
) => {
  const weights: Record<string, number> = {};

  const curX = currentAxes['axis-x'] || 0;
  const curY = currentAxes['axis-y'] || 0;
  const EPSILON = 0.005;

  const distinctCoords = (arr: number[]) => {
      const sorted = [...arr].sort((a,b) => a - b);
      const result = [];
      if (sorted.length > 0) result.push(sorted[0]);
      for (let i = 1; i < sorted.length; i++) {
          if (sorted[i] > sorted[i-1] + EPSILON) result.push(sorted[i]);
      }
      return result;
  };
  const xCoords = distinctCoords(keyframes.map(k => k.axisValues['axis-x'] || 0));
  const yCoords = distinctCoords(keyframes.map(k => k.axisValues['axis-y'] || 0));

  if (xCoords.length === 0 || yCoords.length === 0) {
      if (keyframes.length > 0) weights[keyframes[0].id] = 1;
      return weights;
  }

  const findInterval = (val: number, grid: number[]) => {
      if (val <= grid[0]) return { lower: grid[0], upper: grid[0], t: 0 };
      if (val >= grid[grid.length - 1]) return { lower: grid[grid.length - 1], upper: grid[grid.length - 1], t: 0 };
      for (let i = 0; i < grid.length - 1; i++) {
          if (val >= grid[i] && val <= grid[i+1]) {
              const span = grid[i+1] - grid[i];
              return { lower: grid[i], upper: grid[i+1], t: span === 0 ? 0 : (val - grid[i]) / span };
          }
      }
      return { lower: grid[0], upper: grid[0], t: 0 };
  };

  const xInfo = findInterval(curX, xCoords);
  const yInfo = findInterval(curY, yCoords);

  const resolveCornerWeights = (targetX: number, targetY: number) => {
      const exact = keyframes.find(k => Math.abs((k.axisValues['axis-x']||0) - targetX) < EPSILON && Math.abs((k.axisValues['axis-y']||0) - targetY) < EPSILON);
      if (exact) return { [exact.id]: 1.0 };

      let totalW = 0;
      const cornerWeights: Record<string, number> = {};

      keyframes.forEach(k => {
          const dx = (k.axisValues['axis-x']||0) - targetX;
          const dy = (k.axisValues['axis-y']||0) - targetY;
          const dist = Math.sqrt(dx*dx + dy*dy);
          if (dist < 0.001) { cornerWeights[k.id] = 1000; totalW += 1000; }
          else {
              const w = 1 / Math.pow(dist, 2);
              cornerWeights[k.id] = w;
              totalW += w;
          }
      });

      for(const id in cornerWeights) cornerWeights[id] /= totalW;
      return cornerWeights;
  };

  const corners = [
      { x: xInfo.lower, y: yInfo.lower, wBase: (1 - xInfo.t) * (1 - yInfo.t) },
      { x: xInfo.upper, y: yInfo.lower, wBase: xInfo.t * (1 - yInfo.t) },
      { x: xInfo.lower, y: yInfo.upper, wBase: (1 - xInfo.t) * yInfo.t },
      { x: xInfo.upper, y: yInfo.upper, wBase: xInfo.t * yInfo.t }
  ];

  corners.forEach(c => {
      if (c.wBase <= 0.0001) return;
      const cornerComposition = resolveCornerWeights(c.x, c.y);
      for (const kfId in cornerComposition) {
          weights[kfId] = (weights[kfId] || 0) + (cornerComposition[kfId] * c.wBase);
      }
  });

  return weights;
};

const calculateIDWWeights = (currentAxes: Record<string, number>, keyframes: { id: string; axisValues: Record<string, number> }[], exponent: number) => {
    const weights: Record<string, number> = {};
    let totalWeight = 0;
    for (const kf of keyframes) {
        let dist = 0;
        for (const axisId in currentAxes) dist += Math.pow((currentAxes[axisId] || 0) - (kf.axisValues[axisId] || 0), 2);
        dist = Math.sqrt(dist);
        if (dist < 0.001) {
             keyframes.forEach(k => weights[k.id] = 0);
             weights[kf.id] = 1; 
             return weights; 
        }
        const w = 1 / Math.pow(dist, exponent);
        weights[kf.id] = w;
        totalWeight += w;
    }
    for (const id in weights) weights[id] /= totalWeight;
    return weights;
};

export const calculateInterpolationWeights = (
  currentAxes: Record<string, number>,
  keyframes: { id: string; axisValues: Record<string, number> }[],
  exponent: number = 2,
  strategy: InterpolationStrategy = 'bilinear-grid'
): Record<string, number> => {
   if (keyframes.length === 0) return {};
   if (keyframes.length === 1) return { [keyframes[0].id]: 1.0 };
   if (strategy === 'bilinear-grid') return calculateBilinearGridWeights(currentAxes, keyframes);
   return calculateIDWWeights(currentAxes, keyframes, exponent);
};

// --- CORE INTERPOLATION ENGINE ---

export const interpolateStrokePoints = (
  strokeId: string,
  basePoints: Point[], 
  keyframesData: { weight: number; points: Point[] | undefined, style: Stroke | undefined }[],
  mode: 'resample' | 'points' = 'resample',
  targetCount: number = 200 
): { points: Point[], color: string, fillColor: string, width: number } => {

  // 1. Filter active keyframes
  const activeKeyframes = keyframesData.filter(k => k.weight > 0.0001 && k.points && k.points.length > 0);
  if (activeKeyframes.length === 0) return { points: [], color: 'rgba(0,0,0,0)', fillColor: 'none', width: 1 };

  // 2. Mix Properties
  const color = mixColors(activeKeyframes.map(k => ({ color: k.style?.color || 'none', weight: k.weight })));
  const fillColor = mixColors(activeKeyframes.map(k => ({ color: k.style?.fillColor || 'none', weight: k.weight })));

  let totalWidth = 0;
  let widthWeightDivisor = 0;
  activeKeyframes.forEach(k => {
      totalWidth += (k.style?.width || 1) * k.weight;
      widthWeightDivisor += k.weight;
  });
  const width = widthWeightDivisor > 0 ? totalWidth / widthWeightDivisor : 1;

  // 3. Topology Decision & Normalization (FIX: Stray Lines)
  // Calculate if the RESULT should be closed based on weight dominance
  let closedWeight = 0;
  activeKeyframes.forEach(k => { if (k.style?.closed) closedWeight += k.weight; });
  const resultClosed = closedWeight > 0.5;

  // Pre-processing: If we are creating a closed shape, FORCE all open inputs
  // to act as closed shapes by duplicating their first point at the end.
  // This ensures A->B->C morphs to A->B->C->A (Loop) without artifact.
  const normalizedKeyframes = activeKeyframes.map(kf => {
      if (mode === 'points' && resultClosed && !kf.style?.closed) {
          // Clone points to avoid mutation
          const closedPoints = [...kf.points!, kf.points![0]];
          return { ...kf, points: closedPoints };
      }
      return kf;
  });

  // 4. Point Count Normalization (FIX: Jumping)
  let ACTUAL_TARGET_COUNT = targetCount; 

  // Determine MAX points across active frames (using normalized versions)
  const maxPts = Math.max(...normalizedKeyframes.map(k => k.points!.length));

  if (mode === 'points') {
      ACTUAL_TARGET_COUNT = maxPts;
  }

  // 5. Reference Selection
  // Use Normalized frames for selection to be consistent
  const referenceKeyframe = normalizedKeyframes.reduce((prev, current) => {
      const prevLen = prev.points!.length;
      const currLen = current.points!.length;
      if (prevLen > currLen) return prev;
      if (currLen > prevLen) return current;
      return (prev.weight >= current.weight) ? prev : current;
  });

  const referenceStroke = referenceKeyframe.points!;

  // Resample Reference
  let referenceResampled: Point[];
  if (mode === 'points') {
      referenceResampled = upsamplePreservingCorners(referenceStroke, ACTUAL_TARGET_COUNT);
  } else {
      referenceResampled = resamplePoints(referenceStroke, ACTUAL_TARGET_COUNT);
  }

  const resultPoints: Point[] = [];

  for (let i = 0; i < ACTUAL_TARGET_COUNT; i++) {
      let x = 0;
      let y = 0;
      let pressure = 0;
      let totalWeight = 0;

      for (const kf of normalizedKeyframes) {
          const rawPoints = kf.points!;
          let processedPoints: Point[] = [];

          if (mode === 'points') {
             // CORNER-PRESERVING UPSAMPLING
             if (rawPoints.length === ACTUAL_TARGET_COUNT) {
                 processedPoints = rawPoints;
             } else {
                 processedPoints = upsamplePreservingCorners(rawPoints, ACTUAL_TARGET_COUNT);
             }
          } else {
             // ARC-LENGTH RESAMPLING (Curves)
             processedPoints = resamplePoints(rawPoints, ACTUAL_TARGET_COUNT);
          }

          // ALIGNMENT
          // Only allow cyclic shift if the RESULT is closed. 
          // If result is Open, we must respect endpoints.
          const alignedPoints = alignPoints(referenceResampled, processedPoints, resultClosed);

          const pt = alignedPoints[i];

          x += pt.x * kf.weight;
          y += pt.y * kf.weight;
          pressure += (pt.pressure || 0.5) * kf.weight;
          totalWeight += kf.weight;
      }

      if (totalWeight > 0) {
          resultPoints.push({
              x: x / totalWeight,
              y: y / totalWeight,
              pressure: pressure / totalWeight
          });
      }
  }

  return { points: resultPoints, color, fillColor, width };
};

// --- OPTIMIZATION & SMOOTHING ---

const perpendicularDistance = (point: Point, lineStart: Point, lineEnd: Point): number => {
  let dx = lineEnd.x - lineStart.x;
  let dy = lineEnd.y - lineStart.y;
  const mag = Math.sqrt(dx * dx + dy * dy);
  if (mag > 0.0) { dx /= mag; dy /= mag; }
  const pvx = point.x - lineStart.x;
  const pvy = point.y - lineStart.y;
  const pvdot = pvx * dx + pvy * dy;
  const dsx = pvdot * dx;
  const dsy = pvdot * dy;
  const ax = pvx - dsx;
  const ay = pvy - dsy;
  return Math.sqrt(ax * ax + ay * ay);
};

export const simplifyPoints = (points: Point[], epsilon: number = 2): Point[] => {
  if (points.length < 3) return points;
  let dmax = 0;
  let index = 0;
  const end = points.length - 1;
  for (let i = 1; i < end; i++) {
    const d = perpendicularDistance(points[i], points[0], points[end]);
    if (d > dmax) { index = i; dmax = d; }
  }
  if (dmax > epsilon) {
    const recResults1 = simplifyPoints(points.slice(0, index + 1), epsilon);
    const recResults2 = simplifyPoints(points.slice(index, end + 1), epsilon);
    return [...recResults1.slice(0, -1), ...recResults2];
  } else {
    return [points[0], points[end]];
  }
};

export const chaikinSmooth = (points: Point[], iterations: number = 2): Point[] => {
    if (points.length < 3) return points;
    let output = [...points];
    for (let i = 0; i < iterations; i++) {
        const next: Point[] = [];
        next.push(output[0]);
        for (let j = 0; j < output.length - 1; j++) {
            const p0 = output[j];
            const p1 = output[j + 1];
            next.push({
                x: 0.75 * p0.x + 0.25 * p1.x,
                y: 0.75 * p0.y + 0.25 * p1.y,
                pressure: lerp(p0.pressure || 0.5, p1.pressure || 0.5, 0.25)
            });
            next.push({
                x: 0.25 * p0.x + 0.75 * p1.x,
                y: 0.25 * p0.y + 0.75 * p1.y,
                pressure: lerp(p0.pressure || 0.5, p1.pressure || 0.5, 0.75)
            });
        }
        next.push(output[output.length - 1]);
        output = next;
    }
    return output;
};

// utils/math.ts
import { Point, Stroke, InterpolationStrategy } from '../types';

export const distance = (p1: Point, p2: Point): number => {
  return Math.sqrt(Math.pow(p2.x - p1.x, 2) + Math.pow(p2.y - p1.y, 2));
};

export const lerp = (start: number, end: number, t: number): number => {
  return start * (1 - t) + end * t;
};

// --- Transformation Helpers ---

export const rotatePoint = (p: Point, center: Point, angleRad: number): Point => {
  const cos = Math.cos(angleRad);
  const sin = Math.sin(angleRad);
  const dx = p.x - center.x;
  const dy = p.y - center.y;
  return {
    x: center.x + (dx * cos - dy * sin),
    y: center.y + (dx * sin + dy * cos),
    pressure: p.pressure
  };
};

export const getBoundingBox = (points: Point[]): { minX: number, maxX: number, minY: number, maxY: number, width: number, height: number, centerX: number, centerY: number } => {
  if (points.length === 0) return { minX:0, maxX:0, minY:0, maxY:0, width:0, height:0, centerX:0, centerY:0 };

  let minX = Infinity, maxX = -Infinity, minY = Infinity, maxY = -Infinity;
  for (const p of points) {
    if (p.x < minX) minX = p.x;
    if (p.x > maxX) maxX = p.x;
    if (p.y < minY) minY = p.y;
    if (p.y > maxY) maxY = p.y;
  }

  return {
    minX, maxX, minY, maxY,
    width: maxX - minX,
    height: maxY - minY,
    centerX: minX + (maxX - minX) / 2,
    centerY: minY + (maxY - minY) / 2
  };
};

// --- Color Interpolation (RGBA) ---

const colorCache: Record<string, { r: number, g: number, b: number, a: number }> = {};

const parseColor = (color: string): { r: number, g: number, b: number, a: number } => {
  if (!color || color === 'none') return { r: 0, g: 0, b: 0, a: 1 }; 
  if (colorCache[color]) return colorCache[color];

  let result = { r: 0, g: 0, b: 0, a: 1 };

  if (color.startsWith('#')) {
    let hex = color.slice(1);
    if (hex.length === 3) hex = hex.split('').map(c => c + c).join('');
    const bigint = parseInt(hex, 16);
    result = {
      r: (bigint >> 16) & 255,
      g: (bigint >> 8) & 255,
      b: bigint & 255,
      a: 1
    };
  }
  else if (color.startsWith('rgb')) {
    const match = color.match(/(\d+(\.\d+)?)/g);
    if (match) {
        result = {
            r: parseFloat(match[0]),
            g: parseFloat(match[1]),
            b: parseFloat(match[2]),
            a: match[3] ? parseFloat(match[3]) : 1
        };
    }
  }

  colorCache[color] = result;
  return result;
};

export const mixColors = (colors: { color: string | 'none', weight: number }[]): string => {
  let rSum = 0, gSum = 0, bSum = 0, aSum = 0;
  let hasColor = false;

  for (const c of colors) {
    const rgba = parseColor(c.color);
    const alpha = c.color === 'none' ? 0 : rgba.a;

    if (alpha > 0) {
        hasColor = true;
        rSum += rgba.r * c.weight * alpha;
        gSum += rgba.g * c.weight * alpha;
        bSum += rgba.b * c.weight * alpha;
    }
    aSum += alpha * c.weight;
  }

  if (!hasColor || aSum <= 0.001) return 'none';

  let totalAlphaWeight = 0; 
  colors.forEach(c => {
     const rgba = parseColor(c.color);
     const alpha = c.color === 'none' ? 0 : rgba.a;
     totalAlphaWeight += c.weight * alpha;
  });

  if (totalAlphaWeight <= 0.0001) return 'rgba(0,0,0,0)';

  const finalR = rSum / totalAlphaWeight;
  const finalG = gSum / totalAlphaWeight;
  const finalB = bSum / totalAlphaWeight;

  return `rgba(${Math.round(finalR)}, ${Math.round(finalG)}, ${Math.round(finalB)}, ${aSum.toFixed(3)})`;
};

// --- Geometry Helpers ---

const getPathLength = (points: Point[]): number => {
  let len = 0;
  for (let i = 1; i < points.length; i++) {
    len += distance(points[i - 1], points[i]);
  }
  return len;
};

// Curve Resampling (Arc-Length)
export const resamplePoints = (points: Point[], targetCount: number): Point[] => {
  if (points.length < 2 || targetCount < 2) return points;

  const totalLength = getPathLength(points);
  if (totalLength === 0) return Array(targetCount).fill(points[0]);

  const step = totalLength / (targetCount - 1);
  const newPoints: Point[] = [points[0]];

  let currentDist = 0;
  let nextPointIndex = 1;

  for (let i = 1; i < targetCount; i++) {
    const targetDist = i * step;
    let distSoFar = currentDist;
    let p1 = points[nextPointIndex - 1];
    let p2 = points[nextPointIndex];
    let segmentDist = distance(p1, p2);

    while (distSoFar + segmentDist < targetDist && nextPointIndex < points.length - 1) {
      distSoFar += segmentDist;
      currentDist = distSoFar;
      nextPointIndex++;
      p1 = points[nextPointIndex - 1];
      p2 = points[nextPointIndex];
      segmentDist = distance(p1, p2);
    }

    const segmentLocalDist = targetDist - distSoFar;
    const t = segmentDist === 0 ? 0 : segmentLocalDist / segmentDist;

    newPoints.push({
      x: lerp(p1.x, p2.x, t),
      y: lerp(p1.y, p2.y, t),
      pressure: lerp(p1.pressure || 0.5, p2.pressure || 0.5, t)
    });
  }

  while (newPoints.length < targetCount) newPoints.push(points[points.length - 1]);
  if (newPoints.length > targetCount) newPoints.length = targetCount;

  return newPoints;
};

// --- CORNER-PRESERVING UPSAMPLING ---
// Injects points into existing segments to reach target count without moving vertices.
export const upsamplePreservingCorners = (points: Point[], targetCount: number): Point[] => {
    if (points.length === 0) return [];
    if (points.length >= targetCount) return points; 

    const pointsToAdd = targetCount - points.length;
    const segments = points.length - 1;
    if (segments < 1) return Array(targetCount).fill(points[0]);

    const baseAdd = Math.floor(pointsToAdd / segments);
    const remainder = pointsToAdd % segments;

    const newPoints: Point[] = [];

    for (let i = 0; i < segments; i++) {
        newPoints.push(points[i]);

        const count = baseAdd + (i < remainder ? 1 : 0);

        if (count > 0) {
            const pStart = points[i];
            const pEnd = points[i+1];
            for (let k = 1; k <= count; k++) {
                const t = k / (count + 1);
                newPoints.push({
                    x: lerp(pStart.x, pEnd.x, t),
                    y: lerp(pStart.y, pEnd.y, t),
                    pressure: lerp(pStart.pressure||0.5, pEnd.pressure||0.5, t)
                });
            }
        }
    }
    // Always add the very last point
    newPoints.push(points[points.length - 1]);

    return newPoints;
};

export const snapPointToGrid = (p: Point, gridSize: number): Point => {
  return {
    x: Math.round(p.x / gridSize) * gridSize,
    y: Math.round(p.y / gridSize) * gridSize,
    pressure: p.pressure
  };
};

// --- Hit Testing ---

const distToSegment = (p: Point, v: Point, w: Point) => {
  const l2 = Math.pow(distance(v, w), 2);
  if (l2 === 0) return distance(p, v);
  let t = ((p.x - v.x) * (w.x - v.x) + (p.y - v.y) * (w.y - v.y)) / l2;
  t = Math.max(0, Math.min(1, t));
  const projection = { x: v.x + t * (w.x - v.x), y: v.y + t * (w.y - v.y) };
  return distance(p, projection);
};

export const isPointInStroke = (p: Point, points: Point[], threshold: number = 10): boolean => {
  for (let i = 0; i < points.length - 1; i++) {
    if (distToSegment(p, points[i], points[i+1]) < threshold) return true;
  }
  return false;
};

// --- Robust Alignment ---

const alignPoints = (reference: Point[], target: Point[], allowCyclicShift: boolean): Point[] => {
    if (reference.length !== target.length || reference.length === 0) return target;

    const len = reference.length;

    const getError = (ptsA: Point[], ptsB: Point[]) => {
        let err = 0;
        for(let i=0; i<len; i++) {
            const dx = ptsA[i].x - ptsB[i].x;
            const dy = ptsA[i].y - ptsB[i].y;
            err += dx*dx + dy*dy;
        }
        return err;
    };

    let bestPoints = [...target];
    let minError = getError(reference, target);

    // 1. Check Reverse Direction
    const reversed = [...target].reverse();
    const reverseError = getError(reference, reversed);

    if (reverseError < minError * 0.95) { 
        minError = reverseError;
        bestPoints = reversed;
    }

    // 2. Check Cyclic Shift 
    // Only applied if the TARGET was originally closed (passed via allowCyclicShift).
    // This allows a closed shape to rotate to match the orientation of the reference (even if reference is open).
    if (allowCyclicShift) {
        let workingSet = [...bestPoints];
        // Optimization: limit precision scan if too many points
        const step = len > 100 ? 2 : 1; 

        for (let offset = 1; offset < len; offset += step) {
             const shifted = new Array(len);
             for(let k=0; k<len; k++) {
                 shifted[k] = workingSet[(k + offset) % len];
             }

             const err = getError(reference, shifted);
             if (err < minError) {
                 minError = err;
                 bestPoints = shifted;
             }
        }
    } 

    return bestPoints;
};

// --- INTERPOLATION STRATEGIES ---

const calculateBilinearGridWeights = (
  currentAxes: Record<string, number>,
  keyframes: { id: string; axisValues: Record<string, number> }[]
) => {
  const weights: Record<string, number> = {};

  const curX = currentAxes['axis-x'] || 0;
  const curY = currentAxes['axis-y'] || 0;
  const EPSILON = 0.005;

  const distinctCoords = (arr: number[]) => {
      const sorted = [...arr].sort((a,b) => a - b);
      const result = [];
      if (sorted.length > 0) result.push(sorted[0]);
      for (let i = 1; i < sorted.length; i++) {
          if (sorted[i] > sorted[i-1] + EPSILON) result.push(sorted[i]);
      }
      return result;
  };
  const xCoords = distinctCoords(keyframes.map(k => k.axisValues['axis-x'] || 0));
  const yCoords = distinctCoords(keyframes.map(k => k.axisValues['axis-y'] || 0));

  if (xCoords.length === 0 || yCoords.length === 0) {
      if (keyframes.length > 0) weights[keyframes[0].id] = 1;
      return weights;
  }

  const findInterval = (val: number, grid: number[]) => {
      if (val <= grid[0]) return { lower: grid[0], upper: grid[0], t: 0 };
      if (val >= grid[grid.length - 1]) return { lower: grid[grid.length - 1], upper: grid[grid.length - 1], t: 0 };
      for (let i = 0; i < grid.length - 1; i++) {
          if (val >= grid[i] && val <= grid[i+1]) {
              const span = grid[i+1] - grid[i];
              return { lower: grid[i], upper: grid[i+1], t: span === 0 ? 0 : (val - grid[i]) / span };
          }
      }
      return { lower: grid[0], upper: grid[0], t: 0 };
  };

  const xInfo = findInterval(curX, xCoords);
  const yInfo = findInterval(curY, yCoords);

  const resolveCornerWeights = (targetX: number, targetY: number) => {
      const exact = keyframes.find(k => Math.abs((k.axisValues['axis-x']||0) - targetX) < EPSILON && Math.abs((k.axisValues['axis-y']||0) - targetY) < EPSILON);
      if (exact) return { [exact.id]: 1.0 };

      let totalW = 0;
      const cornerWeights: Record<string, number> = {};

      keyframes.forEach(k => {
          const dx = (k.axisValues['axis-x']||0) - targetX;
          const dy = (k.axisValues['axis-y']||0) - targetY;
          const dist = Math.sqrt(dx*dx + dy*dy);
          if (dist < 0.001) { cornerWeights[k.id] = 1000; totalW += 1000; }
          else {
              const w = 1 / Math.pow(dist, 2);
              cornerWeights[k.id] = w;
              totalW += w;
          }
      });

      for(const id in cornerWeights) cornerWeights[id] /= totalW;
      return cornerWeights;
  };

  const corners = [
      { x: xInfo.lower, y: yInfo.lower, wBase: (1 - xInfo.t) * (1 - yInfo.t) },
      { x: xInfo.upper, y: yInfo.lower, wBase: xInfo.t * (1 - yInfo.t) },
      { x: xInfo.lower, y: yInfo.upper, wBase: (1 - xInfo.t) * yInfo.t },
      { x: xInfo.upper, y: yInfo.upper, wBase: xInfo.t * yInfo.t }
  ];

  corners.forEach(c => {
      if (c.wBase <= 0.0001) return;
      const cornerComposition = resolveCornerWeights(c.x, c.y);
      for (const kfId in cornerComposition) {
          weights[kfId] = (weights[kfId] || 0) + (cornerComposition[kfId] * c.wBase);
      }
  });

  return weights;
};

const calculateIDWWeights = (currentAxes: Record<string, number>, keyframes: { id: string; axisValues: Record<string, number> }[], exponent: number) => {
    const weights: Record<string, number> = {};
    let totalWeight = 0;
    for (const kf of keyframes) {
        let dist = 0;
        for (const axisId in currentAxes) dist += Math.pow((currentAxes[axisId] || 0) - (kf.axisValues[axisId] || 0), 2);
        dist = Math.sqrt(dist);
        if (dist < 0.001) {
             keyframes.forEach(k => weights[k.id] = 0);
             weights[kf.id] = 1; 
             return weights; 
        }
        const w = 1 / Math.pow(dist, exponent);
        weights[kf.id] = w;
        totalWeight += w;
    }
    for (const id in weights) weights[id] /= totalWeight;
    return weights;
};

export const calculateInterpolationWeights = (
  currentAxes: Record<string, number>,
  keyframes: { id: string; axisValues: Record<string, number> }[],
  exponent: number = 2,
  strategy: InterpolationStrategy = 'bilinear-grid'
): Record<string, number> => {
   if (keyframes.length === 0) return {};
   if (keyframes.length === 1) return { [keyframes[0].id]: 1.0 };
   if (strategy === 'bilinear-grid') return calculateBilinearGridWeights(currentAxes, keyframes);
   return calculateIDWWeights(currentAxes, keyframes, exponent);
};

// --- CORE INTERPOLATION ENGINE ---

export const interpolateStrokePoints = (
  strokeId: string,
  basePoints: Point[], 
  keyframesData: { weight: number; points: Point[] | undefined, style: Stroke | undefined }[],
  mode: 'resample' | 'points' = 'resample',
  targetCount: number = 200 
): { points: Point[], color: string, fillColor: string, width: number } => {

  // 1. Filter active keyframes
  const activeKeyframes = keyframesData.filter(k => k.weight > 0.0001 && k.points && k.points.length > 0);
  if (activeKeyframes.length === 0) return { points: [], color: 'rgba(0,0,0,0)', fillColor: 'none', width: 1 };

  // 2. Mix Properties
  const color = mixColors(activeKeyframes.map(k => ({ color: k.style?.color || 'none', weight: k.weight })));
  const fillColor = mixColors(activeKeyframes.map(k => ({ color: k.style?.fillColor || 'none', weight: k.weight })));

  let totalWidth = 0;
  let widthWeightDivisor = 0;
  activeKeyframes.forEach(k => {
      totalWidth += (k.style?.width || 1) * k.weight;
      widthWeightDivisor += k.weight;
  });
  const width = widthWeightDivisor > 0 ? totalWidth / widthWeightDivisor : 1;

  // 3. Topology Normalization (CRITICAL FIX FOR STRAY LINES)
  // Instead of handling "Open vs Closed" as a binary flag switch (which causes lines to snap),
  // we treat Closed shapes as Open Polylines that loop back to the start (A -> B -> C -> A).
  // This unifies the geometry: everything becomes an open line for the interpolator.

  const normalizedKeyframes = activeKeyframes.map(kf => {
      if (kf.style?.closed) {
          // Explicitly close the loop geometry by duplicating the first point at the end
          const closedPoints = [...kf.points!, kf.points![0]];
          // We mark it so 'alignPoints' knows it can cycle this shape
          return { ...kf, points: closedPoints, _isClosedGeometry: true };
      }
      return { ...kf, _isClosedGeometry: false };
  });

  // 4. Point Count Calculation
  // We use the MAX count from our normalized set. 
  // e.g. Triangle (3pts) -> Normalized (4pts). Line (3pts). Max = 4.
  // The line will be upsampled to 4 pts to match the triangle loop.
  let ACTUAL_TARGET_COUNT = targetCount; 
  const maxPts = Math.max(...normalizedKeyframes.map(k => k.points!.length));

  if (mode === 'points') {
      ACTUAL_TARGET_COUNT = maxPts;
  }

  // 5. Reference Selection (Stability)
  // We select reference from the normalized set based on point count
  const referenceKeyframe = normalizedKeyframes.reduce((prev, current) => {
      const prevLen = prev.points!.length;
      const currLen = current.points!.length;
      if (prevLen > currLen) return prev;
      if (currLen > prevLen) return current;
      return (prev.weight >= current.weight) ? prev : current;
  });

  const referenceStroke = referenceKeyframe.points!;

  // Resample Reference
  let referenceResampled: Point[];
  if (mode === 'points') {
      referenceResampled = upsamplePreservingCorners(referenceStroke, ACTUAL_TARGET_COUNT);
  } else {
      referenceResampled = resamplePoints(referenceStroke, ACTUAL_TARGET_COUNT);
  }

  const resultPoints: Point[] = [];

  for (let i = 0; i < ACTUAL_TARGET_COUNT; i++) {
      let x = 0;
      let y = 0;
      let pressure = 0;
      let totalWeight = 0;

      for (const kf of normalizedKeyframes) {
          const rawPoints = kf.points!;
          let processedPoints: Point[] = [];

          if (mode === 'points') {
             if (rawPoints.length === ACTUAL_TARGET_COUNT) {
                 processedPoints = rawPoints;
             } else {
                 processedPoints = upsamplePreservingCorners(rawPoints, ACTUAL_TARGET_COUNT);
             }
          } else {
             processedPoints = resamplePoints(rawPoints, ACTUAL_TARGET_COUNT);
          }

          // ALIGNMENT
          // Only allow cyclic shifting if THIS specific keyframe was originally closed geometry.
          // This allows a Triangle (Closed) to rotate to align with a Line (Open),
          // but prevents a Line (Open) from scrambling its start/end order.
          const alignedPoints = alignPoints(referenceResampled, processedPoints, kf._isClosedGeometry);

          const pt = alignedPoints[i];

          x += pt.x * kf.weight;
          y += pt.y * kf.weight;
          pressure += (pt.pressure || 0.5) * kf.weight;
          totalWeight += kf.weight;
      }

      if (totalWeight > 0) {
          resultPoints.push({
              x: x / totalWeight,
              y: y / totalWeight,
              pressure: pressure / totalWeight
          });
      }
  }

  return { points: resultPoints, color, fillColor, width };
};

// --- OPTIMIZATION & SMOOTHING ---

const perpendicularDistance = (point: Point, lineStart: Point, lineEnd: Point): number => {
  let dx = lineEnd.x - lineStart.x;
  let dy = lineEnd.y - lineStart.y;
  const mag = Math.sqrt(dx * dx + dy * dy);
  if (mag > 0.0) { dx /= mag; dy /= mag; }
  const pvx = point.x - lineStart.x;
  const pvy = point.y - lineStart.y;
  const pvdot = pvx * dx + pvy * dy;
  const dsx = pvdot * dx;
  const dsy = pvdot * dy;
  const ax = pvx - dsx;
  const ay = pvy - dsy;
  return Math.sqrt(ax * ax + ay * ay);
};

export const simplifyPoints = (points: Point[], epsilon: number = 2): Point[] => {
  if (points.length < 3) return points;
  let dmax = 0;
  let index = 0;
  const end = points.length - 1;
  for (let i = 1; i < end; i++) {
    const d = perpendicularDistance(points[i], points[0], points[end]);
    if (d > dmax) { index = i; dmax = d; }
  }
  if (dmax > epsilon) {
    const recResults1 = simplifyPoints(points.slice(0, index + 1), epsilon);
    const recResults2 = simplifyPoints(points.slice(index, end + 1), epsilon);
    return [...recResults1.slice(0, -1), ...recResults2];
  } else {
    return [points[0], points[end]];
  }
};

export const chaikinSmooth = (points: Point[], iterations: number = 2): Point[] => {
    if (points.length < 3) return points;
    let output = [...points];
    for (let i = 0; i < iterations; i++) {
        const next: Point[] = [];
        next.push(output[0]);
        for (let j = 0; j < output.length - 1; j++) {
            const p0 = output[j];
            const p1 = output[j + 1];
            next.push({
                x: 0.75 * p0.x + 0.25 * p1.x,
                y: 0.75 * p0.y + 0.25 * p1.y,
                pressure: lerp(p0.pressure || 0.5, p1.pressure || 0.5, 0.25)
            });
            next.push({
                x: 0.25 * p0.x + 0.75 * p1.x,
                y: 0.25 * p0.y + 0.75 * p1.y,
                pressure: lerp(p0.pressure || 0.5, p1.pressure || 0.5, 0.75)
            });
        }
        next.push(output[output.length - 1]);
        output = next;
    }
    return output;
};

// store/useStore.ts
import { create } from 'zustand';
import { Project, UIState, ToolType, Axis, Layer, Keyframe, Point, Stroke, LayerState, BlendMode, UIMode, InterpolationMode, InterpolationStrategy } from '../types';
import { DEFAULT_PROJECT, INITIAL_UI_STATE, DEFAULT_LAYER, DEFAULT_KEYFRAME } from '../constants';
import { simplifyPoints, distance, chaikinSmooth } from '../utils/math';

interface StoreState {
  project: Project;
  ui: UIState;

  history: {
    past: Project[];
    future: Project[];
  };

  isSettingsOpen: boolean;

  // Actions
  undo: () => void;
  redo: () => void;

  // Project Actions
  resetProject: () => void;
  loadProject: (project: Project) => void;

  toggleSettings: () => void;
  toggleLayerPanel: () => void;
  closeAllPanels: () => void; // Used for clicking outside

  setMode: (mode: UIMode) => void;

  setTool: (tool: ToolType) => void;
  setBrushColor: (color: string) => void;
  setFillColor: (color: string) => void;
  setBrushSize: (size: number) => void;

  // Config Actions
  toggleGrid: () => void;
  toggleSnapToGrid: () => void;

  toggleSnapPlayMode: () => void;
  toggleSnapMatrixGrid: () => void;
  setAxisMatrixDivisions: (val: number) => void;
  setAxisMatrixPadding: (val: number) => void;
  setInterpolationExponent: (val: number) => void;
  setInterpolationStrategy: (val: InterpolationStrategy) => void;

  togglePlayModePhysics: () => void;
  setSpringStiffness: (val: number) => void;
  setSpringDamping: (val: number) => void;

  setGridSize: (size: number) => void;
  toggleSmoothing: () => void; // Renamed from toggleSimplifyStrokes

  toggleOnionSkin: () => void;
  setOnionSkinOpacity: (opacity: number) => void;
  setInactiveLayerOpacity: (opacity: number) => void;
  setGhostStrokeOpacity: (opacity: number) => void;

  // Performance Actions
  setResolutionScale: (scale: number) => void;
  togglePerformanceMode: () => void;

  // Layer Actions
  addLayer: () => void;
  deleteLayer: (layerId: string) => void;
  renameLayer: (layerId: string, name: string) => void;
  reorderLayers: (fromIndex: number, toIndex: number) => void;
  toggleLayerVisibility: (layerId: string) => void;
  toggleLayerLock: (layerId: string) => void;
  setLayerBlendMode: (layerId: string, mode: BlendMode) => void;
  setLayerInterpolationMode: (layerId: string, mode: InterpolationMode) => void;
  selectLayer: (layerId: string) => void;

  updateAxisValue: (axisId: string, value: number) => void;
  updateMultipleAxisValues: (values: Record<string, number>) => void; // Batch update

  addStrokeToCurrentKeyframe: (points: Point[], closed?: boolean, skipSimplify?: boolean) => void; 
  updateStrokeInCurrentKeyframe: (strokeId: string, newPoints: Point[]) => void;
  deleteStroke: (strokeId: string) => void; // NEW ACTION

  createKeyframeAtCurrentAxes: () => void;
  deleteKeyframe: (keyframeId: string) => void;
  selectKeyframe: (keyframeId: string) => void;

  selectStroke: (strokeId: string | null) => void;
}

const MAX_HISTORY = 50;

export const useStore = create<StoreState>((set, get) => ({
  project: DEFAULT_PROJECT,
  ui: INITIAL_UI_STATE,
  isSettingsOpen: false,

  history: {
    past: [],
    future: []
  },

  resetProject: () => set(() => ({
      project: {
          ...DEFAULT_PROJECT,
          id: `project-${Date.now()}`,
          created: Date.now(),
          modified: Date.now(),
          // Ensure distinct instances for object references
          layers: [{...DEFAULT_LAYER, id: `layer-${Date.now()}`}],
          keyframes: [{...DEFAULT_KEYFRAME, id: `kf-${Date.now()}`, layerStates: [{ layerId: `layer-${Date.now()}`, strokes: [] }] }]
      },
      ui: {
          ...INITIAL_UI_STATE,
          selectedLayerId: `layer-${Date.now()}`,
          selectedKeyframeId: `kf-${Date.now()}`
      },
      history: { past: [], future: [] }
  })),

  loadProject: (project) => set(() => ({
      project: project,
      ui: {
          ...INITIAL_UI_STATE,
          selectedLayerId: project.layers[0]?.id || null,
          selectedKeyframeId: project.keyframes[0]?.id || null
      },
      history: { past: [], future: [] }
  })),

  toggleSettings: () => set((state) => ({ isSettingsOpen: !state.isSettingsOpen, ui: { ...state.ui, isLayerPanelOpen: false } })),
  toggleLayerPanel: () => set((state) => ({ ui: { ...state.ui, isLayerPanelOpen: !state.ui.isLayerPanelOpen }, isSettingsOpen: false })),
  closeAllPanels: () => set((state) => ({ isSettingsOpen: false, ui: { ...state.ui, isLayerPanelOpen: false } })),

  setMode: (mode) => set((state) => ({ ui: { ...state.ui, mode } })),

  undo: () => set((state) => {
    if (state.history.past.length === 0) return state;
    const previous = state.history.past[state.history.past.length - 1];
    const newPast = state.history.past.slice(0, -1);
    return {
      project: previous,
      history: {
        past: newPast,
        future: [state.project, ...state.history.future]
      }
    };
  }),

  redo: () => set((state) => {
    if (state.history.future.length === 0) return state;
    const next = state.history.future[0];
    const newFuture = state.history.future.slice(1);
    return {
      project: next,
      history: {
        past: [...state.history.past, state.project],
        future: newFuture
      }
    };
  }),

  setTool: (tool) => set((state) => ({ ui: { ...state.ui, selectedTool: tool, selectedStrokeId: null } })),

  setBrushColor: (color) => set((state) => {
    let project = state.project;
    let history = state.history;

    // Try to update existing stroke if we are on a keyframe
    if (state.ui.selectedKeyframeId && state.ui.selectedLayerId) {
        const kfId = state.ui.selectedKeyframeId;
        const layerId = state.ui.selectedLayerId;

        const kfIndex = project.keyframes.findIndex(k => k.id === kfId);
        if (kfIndex > -1) {
             const kf = project.keyframes[kfIndex];
             const lsIndex = kf.layerStates.findIndex(ls => ls.layerId === layerId);

             if (lsIndex > -1 && kf.layerStates[lsIndex].strokes.length > 0) {
                 // Push to history
                 const past = [...state.history.past, state.project].slice(-MAX_HISTORY);

                 const newKeyframes = [...project.keyframes];
                 const newKf = { ...newKeyframes[kfIndex] };
                 const newLayerStates = [...newKf.layerStates];
                 const newLs = { ...newLayerStates[lsIndex] };
                 const newStrokes = [...newLs.strokes];

                 newStrokes[0] = { ...newStrokes[0], color: color === 'none' ? 'rgba(0,0,0,0)' : color };

                 newLs.strokes = newStrokes;
                 newLayerStates[lsIndex] = newLs;
                 newKf.layerStates = newLayerStates;
                 newKeyframes[kfIndex] = newKf;

                 project = { ...project, keyframes: newKeyframes };
                 history = { past, future: [] };
             }
        }
    }

    return { 
       ui: { ...state.ui, brushColor: color },
       project,
       history
    };
  }),

  setFillColor: (color) => set((state) => {
    let project = state.project;
    let history = state.history;

    if (state.ui.selectedKeyframeId && state.ui.selectedLayerId) {
        const kfId = state.ui.selectedKeyframeId;
        const layerId = state.ui.selectedLayerId;

        const kfIndex = project.keyframes.findIndex(k => k.id === kfId);
        if (kfIndex > -1) {
             const kf = project.keyframes[kfIndex];
             const lsIndex = kf.layerStates.findIndex(ls => ls.layerId === layerId);

             if (lsIndex > -1 && kf.layerStates[lsIndex].strokes.length > 0) {
                 const past = [...state.history.past, state.project].slice(-MAX_HISTORY);

                 const newKeyframes = [...project.keyframes];
                 const newKf = { ...newKeyframes[kfIndex] };
                 const newLayerStates = [...newKf.layerStates];
                 const newLs = { ...newLayerStates[lsIndex] };
                 const newStrokes = [...newLs.strokes];

                 newStrokes[0] = { ...newStrokes[0], fillColor: color };

                 newLs.strokes = newStrokes;
                 newLayerStates[lsIndex] = newLs;
                 newKf.layerStates = newLayerStates;
                 newKeyframes[kfIndex] = newKf;

                 project = { ...project, keyframes: newKeyframes };
                 history = { past, future: [] };
             }
        }
    }

    return { 
        ui: { ...state.ui, fillColor: color },
        project,
        history
    };
  }),

  setBrushSize: (size) => set((state) => {
    let project = state.project;
    let history = state.history;

    if (state.ui.selectedKeyframeId && state.ui.selectedLayerId) {
        const kfId = state.ui.selectedKeyframeId;
        const layerId = state.ui.selectedLayerId;

        const kfIndex = project.keyframes.findIndex(k => k.id === kfId);
        if (kfIndex > -1) {
             const kf = project.keyframes[kfIndex];
             const lsIndex = kf.layerStates.findIndex(ls => ls.layerId === layerId);

             if (lsIndex > -1 && kf.layerStates[lsIndex].strokes.length > 0) {
                 const past = [...state.history.past, state.project].slice(-MAX_HISTORY);

                 const newKeyframes = [...project.keyframes];
                 const newKf = { ...newKeyframes[kfIndex] };
                 const newLayerStates = [...newKf.layerStates];
                 const newLs = { ...newLayerStates[lsIndex] };
                 const newStrokes = [...newLs.strokes];

                 newStrokes[0] = { ...newStrokes[0], width: size };

                 newLs.strokes = newStrokes;
                 newLayerStates[lsIndex] = newLs;
                 newKf.layerStates = newLayerStates;
                 newKeyframes[kfIndex] = newKf;

                 project = { ...project, keyframes: newKeyframes };
                 history = { past, future: [] };
             }
        }
    }

    return { 
        ui: { ...state.ui, brushSize: size },
        project,
        history
    };
  }),

  toggleGrid: () => set((state) => ({ ui: { ...state.ui, showGrid: !state.ui.showGrid } })),
  toggleSnapToGrid: () => set((state) => ({ ui: { ...state.ui, snapToGrid: !state.ui.snapToGrid } })),

  toggleSnapPlayMode: () => set((state) => ({ ui: { ...state.ui, snapPlayMode: !state.ui.snapPlayMode } })),
  toggleSnapMatrixGrid: () => set((state) => ({ ui: { ...state.ui, snapMatrixGrid: !state.ui.snapMatrixGrid } })),
  setAxisMatrixDivisions: (val) => set((state) => ({ ui: { ...state.ui, axisMatrixDivisions: val } })),
  setAxisMatrixPadding: (val) => set((state) => ({ ui: { ...state.ui, axisMatrixPadding: val } })),
  setInterpolationExponent: (val) => set((state) => ({ ui: { ...state.ui, interpolationExponent: val } })),
  setInterpolationStrategy: (val) => set((state) => ({ ui: { ...state.ui, interpolationStrategy: val } })),

  togglePlayModePhysics: () => set((state) => ({ ui: { ...state.ui, playModePhysics: !state.ui.playModePhysics } })),
  setSpringStiffness: (val) => set((state) => ({ ui: { ...state.ui, springStiffness: val } })),
  setSpringDamping: (val) => set((state) => ({ ui: { ...state.ui, springDamping: val } })),

  setGridSize: (size) => set((state) => ({ ui: { ...state.ui, gridSize: size } })),
  toggleSmoothing: () => set((state) => ({ ui: { ...state.ui, smoothingEnabled: !state.ui.smoothingEnabled } })),

  toggleOnionSkin: () => set((state) => ({ ui: { ...state.ui, onionSkinEnabled: !state.ui.onionSkinEnabled } })),
  setOnionSkinOpacity: (opacity) => set((state) => ({ ui: { ...state.ui, onionSkinOpacity: opacity } })),
  setInactiveLayerOpacity: (opacity) => set((state) => ({ ui: { ...state.ui, inactiveLayerOpacity: opacity } })),
  setGhostStrokeOpacity: (opacity) => set((state) => ({ ui: { ...state.ui, ghostStrokeOpacity: opacity } })),

  setResolutionScale: (scale) => set((state) => ({ ui: { ...state.ui, resolutionScale: scale } })),
  togglePerformanceMode: () => set((state) => ({ ui: { ...state.ui, performanceMode: !state.ui.performanceMode } })),

  updateAxisValue: (axisId, value) => set((state) => {
    // Smooth value
    const cleanValue = Math.max(0, Math.min(1, value));

    const newAxes = state.project.axes.map(a => 
      a.id === axisId ? { ...a, currentValue: cleanValue } : a
    );

    const currentAxisValues: Record<string, number> = {};
    newAxes.forEach(a => currentAxisValues[a.id] = a.currentValue);

    // Strict Selection Logic:
    let matchingKfId = null;

    const exactMatch = state.project.keyframes.find(kf => {
      let dist = 0;
      for (const id in currentAxisValues) {
        dist += Math.abs((kf.axisValues[id] || 0) - currentAxisValues[id]);
      }
      return dist < 0.02; // Slightly wider threshold for snapping comfort
    });

    if (exactMatch) {
      matchingKfId = exactMatch.id;
    }

    return { 
      project: { ...state.project, axes: newAxes },
      ui: { ...state.ui, selectedKeyframeId: matchingKfId }
    };
  }),

  updateMultipleAxisValues: (values) => set((state) => {
    const newAxes = state.project.axes.map(a => 
       values[a.id] !== undefined ? { ...a, currentValue: Math.max(0, Math.min(1, values[a.id])) } : a
    );

    // No strict selection logic during fast playback updates to save cycles
    return {
        project: { ...state.project, axes: newAxes }
    };
  }),

  selectLayer: (layerId) => set((state) => ({ ui: { ...state.ui, selectedLayerId: layerId } })),
  selectKeyframe: (keyframeId) => set((state) => ({ ui: { ...state.ui, selectedKeyframeId: keyframeId } })),
  selectStroke: (strokeId) => set((state) => ({ ui: { ...state.ui, selectedStrokeId: strokeId } })),

  addLayer: () => set((state) => {
    const past = [...state.history.past, state.project].slice(-MAX_HISTORY);
    const newId = `layer-${Date.now()}`;
    const newLayer: Layer = {
      id: newId,
      name: `Layer ${state.project.layers.length + 1}`,
      visible: true,
      locked: false,
      blendMode: 'normal',
      opacity: 1,
      interpolationMode: 'resample'
    };
    return {
      project: { ...state.project, layers: [...state.project.layers, newLayer] },
      ui: { ...state.ui, selectedLayerId: newId },
      history: { past, future: [] }
    };
  }),

  reorderLayers: (fromIndex, toIndex) => set((state) => {
    if (fromIndex === toIndex) return state;
    const past = [...state.history.past, state.project].slice(-MAX_HISTORY);
    const newLayers = [...state.project.layers];
    const [moved] = newLayers.splice(fromIndex, 1);
    newLayers.splice(toIndex, 0, moved);

    return {
       project: { ...state.project, layers: newLayers },
       history: { past, future: [] }
    };
  }),

  deleteLayer: (layerId) => set((state) => {
    if (state.project.layers.length <= 1) return state; 
    const past = [...state.history.past, state.project].slice(-MAX_HISTORY);
    const newLayers = state.project.layers.filter(l => l.id !== layerId);

    const newKeyframes = state.project.keyframes.map(kf => ({
       ...kf,
       layerStates: kf.layerStates.filter(ls => ls.layerId !== layerId)
    }));

    return {
      project: { ...state.project, layers: newLayers, keyframes: newKeyframes },
      ui: { ...state.ui, selectedLayerId: newLayers[newLayers.length - 1].id },
      history: { past, future: [] }
    };
  }),

  renameLayer: (layerId, name) => set((state) => ({
    project: {
      ...state.project,
      layers: state.project.layers.map(l => l.id === layerId ? { ...l, name } : l)
    }
  })),

  toggleLayerVisibility: (layerId) => set((state) => ({
    project: {
      ...state.project,
      layers: state.project.layers.map(l => 
        l.id === layerId ? { ...l, visible: !l.visible } : l
      )
    }
  })),

  toggleLayerLock: (layerId) => set((state) => ({
    project: {
      ...state.project,
      layers: state.project.layers.map(l => 
        l.id === layerId ? { ...l, locked: !l.locked } : l
      )
    }
  })),

  setLayerBlendMode: (layerId, mode) => set((state) => {
    return {
      project: {
        ...state.project,
        layers: state.project.layers.map(l => 
          l.id === layerId ? { ...l, blendMode: mode } : l
        )
      }
    };
  }),

  setLayerInterpolationMode: (layerId, mode) => set((state) => {
    return {
      project: {
        ...state.project,
        layers: state.project.layers.map(l => 
          l.id === layerId ? { ...l, interpolationMode: mode } : l
        )
      }
    };
  }),

  addStrokeToCurrentKeyframe: (rawPoints, closed = false, skipSimplify = false) => set((state) => {
    const { selectedLayerId, brushColor, fillColor, brushSize, smoothingEnabled, snapToGrid } = state.ui;
    if (!selectedLayerId) return state;

    const layer = state.project.layers.find(l => l.id === selectedLayerId);
    if (layer?.locked || !layer?.visible) return state;

    // --- SMART SMOOTHING (CHAIKIN) ---
    let points = rawPoints;
    let shouldUpdateLayerMode = false;

    if (snapToGrid) {
        points = simplifyPoints(rawPoints, 2.5);
        if (layer.interpolationMode === 'resample') {
            shouldUpdateLayerMode = true;
        }
    } else if (!skipSimplify && smoothingEnabled) { 
       const preSimplified = simplifyPoints(rawPoints, 1.5);
       points = chaikinSmooth(preSimplified, 2);
    } else if (!skipSimplify && !smoothingEnabled) {
       points = simplifyPoints(rawPoints, 1.5);
    }

    // --- GEOMETRIC CLOSURE ---
    // If 'closed' was requested (via UI or loop detection), we physically append 
    // the start point to the end to close the geometry.
    // We then set the 'closed' flag to FALSE because logically it is now an open line that loops.
    if (closed && points.length > 0) {
        points = [...points, points[0]];
    }

    const past = [...state.history.past, state.project].slice(-MAX_HISTORY);

    // --- STATE PREPARATION ---

    let updatedLayers = [...state.project.layers];
    if (shouldUpdateLayerMode) {
        updatedLayers = updatedLayers.map(l => 
            l.id === selectedLayerId ? { ...l, interpolationMode: 'points' } : l
        );
    }

    const currentAxisValues: Record<string, number> = {};
    state.project.axes.forEach(a => currentAxisValues[a.id] = a.currentValue);

    let targetKeyframeId = state.ui.selectedKeyframeId;
    let keyframes = [...state.project.keyframes];

    if (targetKeyframeId === null) {
      const newKfId = `kf-${Date.now()}`;
      const newKeyframe: Keyframe = {
        id: newKfId,
        name: `Keyframe ${keyframes.length}`,
        axisValues: currentAxisValues,
        layerStates: [] 
      };
      keyframes.push(newKeyframe);
      targetKeyframeId = newKfId;
    }

    const newStroke: Stroke = {
      id: `stroke-${selectedLayerId}-unique`,
      points,
      color: brushColor as string, 
      fillColor: fillColor,
      width: brushSize,
      style: 'solid',
      closed: false // FORCE FALSE: We rely on geometric closure (A...A)
    };

    const newKeyframes = keyframes.map(kf => {
      if (kf.id === targetKeyframeId) {
        const existingLayerStateIndex = kf.layerStates.findIndex(ls => ls.layerId === selectedLayerId);
        let newLayerStates = [...kf.layerStates];

        if (existingLayerStateIndex >= 0) {
          newLayerStates[existingLayerStateIndex] = {
            ...newLayerStates[existingLayerStateIndex],
            strokes: [newStroke]
          };
        } else {
          newLayerStates.push({
            layerId: selectedLayerId,
            strokes: [newStroke]
          });
        }
        return { ...kf, layerStates: newLayerStates };
      }
      return kf;
    });

    return { 
      project: { ...state.project, keyframes: newKeyframes, layers: updatedLayers },
      ui: { ...state.ui, selectedKeyframeId: targetKeyframeId },
      history: { past, future: [] }
    };
  }),

  updateStrokeInCurrentKeyframe: (strokeId, newPoints) => set((state) => {
    const kfId = state.ui.selectedKeyframeId;
    if (!kfId) return state;

    const keyframes = state.project.keyframes.map(kf => {
      if (kf.id === kfId) {
         const newLayerStates = kf.layerStates.map(ls => {
            if (ls.layerId === state.ui.selectedLayerId) {
               return {
                  ...ls,
                  strokes: ls.strokes.map(s => ({ ...s, points: newPoints }))
               };
            }
            return ls;
         });
         return { ...kf, layerStates: newLayerStates };
      }
      return kf;
    });

    return { project: { ...state.project, keyframes }};
  }),

  deleteStroke: (strokeId) => set((state) => {
     const kfId = state.ui.selectedKeyframeId;
     const layerId = state.ui.selectedLayerId;
     if (!kfId || !layerId) return state;

     const past = [...state.history.past, state.project].slice(-MAX_HISTORY);

     const newKeyframes = state.project.keyframes.map(kf => {
         if (kf.id === kfId) {
             const newLayerStates = kf.layerStates.map(ls => {
                 if (ls.layerId === layerId) {
                     return {
                         ...ls,
                         strokes: ls.strokes.filter(s => s.id !== strokeId)
                     };
                 }
                 return ls;
             });
             return { ...kf, layerStates: newLayerStates };
         }
         return kf;
     });

     return {
         project: { ...state.project, keyframes: newKeyframes },
         ui: { ...state.ui, selectedStrokeId: null }, // Clear selection
         history: { past, future: [] }
     };
  }),

  createKeyframeAtCurrentAxes: () => set((state) => {
     const currentAxisValues: Record<string, number> = {};
     state.project.axes.forEach(a => currentAxisValues[a.id] = a.currentValue);

     const newKeyframe: Keyframe = {
        id: `kf-${Date.now()}`,
        name: `Keyframe ${state.project.keyframes.length}`,
        axisValues: currentAxisValues,
        layerStates: []
      };

      return {
        project: { ...state.project, keyframes: [...state.project.keyframes, newKeyframe] },
        ui: { ...state.ui, selectedKeyframeId: newKeyframe.id }
      };
  }),

  deleteKeyframe: (keyframeId) => set((state) => {
    if (state.project.keyframes.length <= 1) return state; 
    const past = [...state.history.past, state.project].slice(-MAX_HISTORY);
    const newKeyframes = state.project.keyframes.filter(k => k.id !== keyframeId);

    let newSelectedId = state.ui.selectedKeyframeId;
    if (keyframeId === newSelectedId) {
      newSelectedId = newKeyframes[0].id;
    }

    return {
      project: { ...state.project, keyframes: newKeyframes },
      ui: { ...state.ui, selectedKeyframeId: newSelectedId },
      history: { past, future: [] }
    };
  })
}));

// utils/math.ts
import { Point, Stroke, InterpolationStrategy } from '../types';

export const distance = (p1: Point, p2: Point): number => {
  return Math.sqrt(Math.pow(p2.x - p1.x, 2) + Math.pow(p2.y - p1.y, 2));
};

export const lerp = (start: number, end: number, t: number): number => {
  return start * (1 - t) + end * t;
};

// --- Transformation Helpers ---

export const rotatePoint = (p: Point, center: Point, angleRad: number): Point => {
  const cos = Math.cos(angleRad);
  const sin = Math.sin(angleRad);
  const dx = p.x - center.x;
  const dy = p.y - center.y;
  return {
    x: center.x + (dx * cos - dy * sin),
    y: center.y + (dx * sin + dy * cos),
    pressure: p.pressure
  };
};

export const getBoundingBox = (points: Point[]): { minX: number, maxX: number, minY: number, maxY: number, width: number, height: number, centerX: number, centerY: number } => {
  if (points.length === 0) return { minX:0, maxX:0, minY:0, maxY:0, width:0, height:0, centerX:0, centerY:0 };

  let minX = Infinity, maxX = -Infinity, minY = Infinity, maxY = -Infinity;
  for (const p of points) {
    if (p.x < minX) minX = p.x;
    if (p.x > maxX) maxX = p.x;
    if (p.y < minY) minY = p.y;
    if (p.y > maxY) maxY = p.y;
  }

  return {
    minX, maxX, minY, maxY,
    width: maxX - minX,
    height: maxY - minY,
    centerX: minX + (maxX - minX) / 2,
    centerY: minY + (maxY - minY) / 2
  };
};

// --- Color Interpolation (RGBA) ---

const colorCache: Record<string, { r: number, g: number, b: number, a: number }> = {};

const parseColor = (color: string): { r: number, g: number, b: number, a: number } => {
  if (!color || color === 'none') return { r: 0, g: 0, b: 0, a: 1 }; 
  if (colorCache[color]) return colorCache[color];

  let result = { r: 0, g: 0, b: 0, a: 1 };

  if (color.startsWith('#')) {
    let hex = color.slice(1);
    if (hex.length === 3) hex = hex.split('').map(c => c + c).join('');
    const bigint = parseInt(hex, 16);
    result = {
      r: (bigint >> 16) & 255,
      g: (bigint >> 8) & 255,
      b: bigint & 255,
      a: 1
    };
  }
  else if (color.startsWith('rgb')) {
    const match = color.match(/(\d+(\.\d+)?)/g);
    if (match) {
        result = {
            r: parseFloat(match[0]),
            g: parseFloat(match[1]),
            b: parseFloat(match[2]),
            a: match[3] ? parseFloat(match[3]) : 1
        };
    }
  }

  colorCache[color] = result;
  return result;
};

export const mixColors = (colors: { color: string | 'none', weight: number }[]): string => {
  let rSum = 0, gSum = 0, bSum = 0, aSum = 0;
  let hasColor = false;

  for (const c of colors) {
    const rgba = parseColor(c.color);
    const alpha = c.color === 'none' ? 0 : rgba.a;

    if (alpha > 0) {
        hasColor = true;
        rSum += rgba.r * c.weight * alpha;
        gSum += rgba.g * c.weight * alpha;
        bSum += rgba.b * c.weight * alpha;
    }
    aSum += alpha * c.weight;
  }

  if (!hasColor || aSum <= 0.001) return 'none';

  let totalAlphaWeight = 0; 
  colors.forEach(c => {
     const rgba = parseColor(c.color);
     const alpha = c.color === 'none' ? 0 : rgba.a;
     totalAlphaWeight += c.weight * alpha;
  });

  if (totalAlphaWeight <= 0.0001) return 'rgba(0,0,0,0)';

  const finalR = rSum / totalAlphaWeight;
  const finalG = gSum / totalAlphaWeight;
  const finalB = bSum / totalAlphaWeight;

  return `rgba(${Math.round(finalR)}, ${Math.round(finalG)}, ${Math.round(finalB)}, ${aSum.toFixed(3)})`;
};

// --- Geometry Helpers ---

const getPathLength = (points: Point[]): number => {
  let len = 0;
  for (let i = 1; i < points.length; i++) {
    len += distance(points[i - 1], points[i]);
  }
  return len;
};

// Curve Resampling (Arc-Length)
export const resamplePoints = (points: Point[], targetCount: number): Point[] => {
  if (points.length < 2 || targetCount < 2) return points;

  const totalLength = getPathLength(points);
  if (totalLength === 0) return Array(targetCount).fill(points[0]);

  const step = totalLength / (targetCount - 1);
  const newPoints: Point[] = [points[0]];

  let currentDist = 0;
  let nextPointIndex = 1;

  for (let i = 1; i < targetCount; i++) {
    const targetDist = i * step;
    let distSoFar = currentDist;
    let p1 = points[nextPointIndex - 1];
    let p2 = points[nextPointIndex];
    let segmentDist = distance(p1, p2);

    while (distSoFar + segmentDist < targetDist && nextPointIndex < points.length - 1) {
      distSoFar += segmentDist;
      currentDist = distSoFar;
      nextPointIndex++;
      p1 = points[nextPointIndex - 1];
      p2 = points[nextPointIndex];
      segmentDist = distance(p1, p2);
    }

    const segmentLocalDist = targetDist - distSoFar;
    const t = segmentDist === 0 ? 0 : segmentLocalDist / segmentDist;

    newPoints.push({
      x: lerp(p1.x, p2.x, t),
      y: lerp(p1.y, p2.y, t),
      pressure: lerp(p1.pressure || 0.5, p2.pressure || 0.5, t)
    });
  }

  while (newPoints.length < targetCount) newPoints.push(points[points.length - 1]);
  if (newPoints.length > targetCount) newPoints.length = targetCount;

  return newPoints;
};

// --- CORNER-PRESERVING UPSAMPLING ---
export const upsamplePreservingCorners = (points: Point[], targetCount: number): Point[] => {
    if (points.length === 0) return [];
    if (points.length >= targetCount) return points; 

    const pointsToAdd = targetCount - points.length;
    const segments = points.length - 1;
    if (segments < 1) return Array(targetCount).fill(points[0]);

    const baseAdd = Math.floor(pointsToAdd / segments);
    const remainder = pointsToAdd % segments;

    const newPoints: Point[] = [];

    for (let i = 0; i < segments; i++) {
        newPoints.push(points[i]);

        const count = baseAdd + (i < remainder ? 1 : 0);

        if (count > 0) {
            const pStart = points[i];
            const pEnd = points[i+1];
            for (let k = 1; k <= count; k++) {
                const t = k / (count + 1);
                newPoints.push({
                    x: lerp(pStart.x, pEnd.x, t),
                    y: lerp(pStart.y, pEnd.y, t),
                    pressure: lerp(pStart.pressure||0.5, pEnd.pressure||0.5, t)
                });
            }
        }
    }
    // Always add the very last point
    newPoints.push(points[points.length - 1]);

    return newPoints;
};

export const snapPointToGrid = (p: Point, gridSize: number): Point => {
  return {
    x: Math.round(p.x / gridSize) * gridSize,
    y: Math.round(p.y / gridSize) * gridSize,
    pressure: p.pressure
  };
};

// --- Hit Testing ---

const distToSegment = (p: Point, v: Point, w: Point) => {
  const l2 = Math.pow(distance(v, w), 2);
  if (l2 === 0) return distance(p, v);
  let t = ((p.x - v.x) * (w.x - v.x) + (p.y - v.y) * (w.y - v.y)) / l2;
  t = Math.max(0, Math.min(1, t));
  const projection = { x: v.x + t * (w.x - v.x), y: v.y + t * (w.y - v.y) };
  return distance(p, projection);
};

export const isPointInStroke = (p: Point, points: Point[], threshold: number = 10): boolean => {
  for (let i = 0; i < points.length - 1; i++) {
    if (distToSegment(p, points[i], points[i+1]) < threshold) return true;
  }
  return false;
};

// --- Robust Alignment ---

const alignPoints = (reference: Point[], target: Point[]): Point[] => {
    if (reference.length !== target.length || reference.length === 0) return target;

    const len = reference.length;

    const getError = (ptsA: Point[], ptsB: Point[]) => {
        let err = 0;
        for(let i=0; i<len; i++) {
            const dx = ptsA[i].x - ptsB[i].x;
            const dy = ptsA[i].y - ptsB[i].y;
            err += dx*dx + dy*dy;
        }
        return err;
    };

    let bestPoints = [...target];
    let minError = getError(reference, target);

    // 1. Check Reverse Direction
    const reversed = [...target].reverse();
    const reverseError = getError(reference, reversed);

    if (reverseError < minError * 0.95) { 
        minError = reverseError;
        bestPoints = reversed;
    }

    // 2. Check Cyclic Shift ONLY if Geometry Loop is detected
    // We only allow shifting points if the start and end points are effectively the same.
    // This allows "closed" shapes (A...A) to rotate, but prevents open lines (A...B) from scrambling.
    const isGeometricLoop = distance(bestPoints[0], bestPoints[bestPoints.length - 1]) < 5.0; // 5px tolerance

    if (isGeometricLoop) {
        let workingSet = [...bestPoints];
        const step = len > 100 ? 2 : 1; 

        for (let offset = 1; offset < len; offset += step) {
             const shifted = new Array(len);
             for(let k=0; k<len; k++) {
                 shifted[k] = workingSet[(k + offset) % len];
             }

             // Ensure the shifted loop stays closed geometrically
             // (Though mathematically simpler to just shift)

             const err = getError(reference, shifted);
             if (err < minError) {
                 minError = err;
                 bestPoints = shifted;
             }
        }
    } 

    return bestPoints;
};

// --- INTERPOLATION STRATEGIES ---

const calculateBilinearGridWeights = (
  currentAxes: Record<string, number>,
  keyframes: { id: string; axisValues: Record<string, number> }[]
) => {
  const weights: Record<string, number> = {};

  const curX = currentAxes['axis-x'] || 0;
  const curY = currentAxes['axis-y'] || 0;
  const EPSILON = 0.005;

  const distinctCoords = (arr: number[]) => {
      const sorted = [...arr].sort((a,b) => a - b);
      const result = [];
      if (sorted.length > 0) result.push(sorted[0]);
      for (let i = 1; i < sorted.length; i++) {
          if (sorted[i] > sorted[i-1] + EPSILON) result.push(sorted[i]);
      }
      return result;
  };
  const xCoords = distinctCoords(keyframes.map(k => k.axisValues['axis-x'] || 0));
  const yCoords = distinctCoords(keyframes.map(k => k.axisValues['axis-y'] || 0));

  if (xCoords.length === 0 || yCoords.length === 0) {
      if (keyframes.length > 0) weights[keyframes[0].id] = 1;
      return weights;
  }

  const findInterval = (val: number, grid: number[]) => {
      if (val <= grid[0]) return { lower: grid[0], upper: grid[0], t: 0 };
      if (val >= grid[grid.length - 1]) return { lower: grid[grid.length - 1], upper: grid[grid.length - 1], t: 0 };
      for (let i = 0; i < grid.length - 1; i++) {
          if (val >= grid[i] && val <= grid[i+1]) {
              const span = grid[i+1] - grid[i];
              return { lower: grid[i], upper: grid[i+1], t: span === 0 ? 0 : (val - grid[i]) / span };
          }
      }
      return { lower: grid[0], upper: grid[0], t: 0 };
  };

  const xInfo = findInterval(curX, xCoords);
  const yInfo = findInterval(curY, yCoords);

  const resolveCornerWeights = (targetX: number, targetY: number) => {
      const exact = keyframes.find(k => Math.abs((k.axisValues['axis-x']||0) - targetX) < EPSILON && Math.abs((k.axisValues['axis-y']||0) - targetY) < EPSILON);
      if (exact) return { [exact.id]: 1.0 };

      let totalW = 0;
      const cornerWeights: Record<string, number> = {};

      keyframes.forEach(k => {
          const dx = (k.axisValues['axis-x']||0) - targetX;
          const dy = (k.axisValues['axis-y']||0) - targetY;
          const dist = Math.sqrt(dx*dx + dy*dy);
          if (dist < 0.001) { cornerWeights[k.id] = 1000; totalW += 1000; }
          else {
              const w = 1 / Math.pow(dist, 2);
              cornerWeights[k.id] = w;
              totalW += w;
          }
      });

      for(const id in cornerWeights) cornerWeights[id] /= totalW;
      return cornerWeights;
  };

  const corners = [
      { x: xInfo.lower, y: yInfo.lower, wBase: (1 - xInfo.t) * (1 - yInfo.t) },
      { x: xInfo.upper, y: yInfo.lower, wBase: xInfo.t * (1 - yInfo.t) },
      { x: xInfo.lower, y: yInfo.upper, wBase: (1 - xInfo.t) * yInfo.t },
      { x: xInfo.upper, y: yInfo.upper, wBase: xInfo.t * yInfo.t }
  ];

  corners.forEach(c => {
      if (c.wBase <= 0.0001) return;
      const cornerComposition = resolveCornerWeights(c.x, c.y);
      for (const kfId in cornerComposition) {
          weights[kfId] = (weights[kfId] || 0) + (cornerComposition[kfId] * c.wBase);
      }
  });

  return weights;
};

const calculateIDWWeights = (currentAxes: Record<string, number>, keyframes: { id: string; axisValues: Record<string, number> }[], exponent: number) => {
    const weights: Record<string, number> = {};
    let totalWeight = 0;
    for (const kf of keyframes) {
        let dist = 0;
        for (const axisId in currentAxes) dist += Math.pow((currentAxes[axisId] || 0) - (kf.axisValues[axisId] || 0), 2);
        dist = Math.sqrt(dist);
        if (dist < 0.001) {
             keyframes.forEach(k => weights[k.id] = 0);
             weights[kf.id] = 1; 
             return weights; 
        }
        const w = 1 / Math.pow(dist, exponent);
        weights[kf.id] = w;
        totalWeight += w;
    }
    for (const id in weights) weights[id] /= totalWeight;
    return weights;
};

export const calculateInterpolationWeights = (
  currentAxes: Record<string, number>,
  keyframes: { id: string; axisValues: Record<string, number> }[],
  exponent: number = 2,
  strategy: InterpolationStrategy = 'bilinear-grid'
): Record<string, number> => {
   if (keyframes.length === 0) return {};
   if (keyframes.length === 1) return { [keyframes[0].id]: 1.0 };
   if (strategy === 'bilinear-grid') return calculateBilinearGridWeights(currentAxes, keyframes);
   return calculateIDWWeights(currentAxes, keyframes, exponent);
};

// --- CORE INTERPOLATION ENGINE ---

export const interpolateStrokePoints = (
  strokeId: string,
  basePoints: Point[], 
  keyframesData: { weight: number; points: Point[] | undefined, style: Stroke | undefined }[],
  mode: 'resample' | 'points' = 'resample',
  targetCount: number = 200 
): { points: Point[], color: string, fillColor: string, width: number } => {

  // 1. Filter active keyframes
  const activeKeyframes = keyframesData.filter(k => k.weight > 0.0001 && k.points && k.points.length > 0);
  if (activeKeyframes.length === 0) return { points: [], color: 'rgba(0,0,0,0)', fillColor: 'none', width: 1 };

  // 2. Mix Properties
  const color = mixColors(activeKeyframes.map(k => ({ color: k.style?.color || 'none', weight: k.weight })));
  const fillColor = mixColors(activeKeyframes.map(k => ({ color: k.style?.fillColor || 'none', weight: k.weight })));

  let totalWidth = 0;
  let widthWeightDivisor = 0;
  activeKeyframes.forEach(k => {
      totalWidth += (k.style?.width || 1) * k.weight;
      widthWeightDivisor += k.weight;
  });
  const width = widthWeightDivisor > 0 ? totalWidth / widthWeightDivisor : 1;

  // 3. Point Count Calculation
  let ACTUAL_TARGET_COUNT = targetCount; 
  const maxPts = Math.max(...activeKeyframes.map(k => k.points!.length));

  if (mode === 'points') {
      ACTUAL_TARGET_COUNT = maxPts;
  }

  // 4. Reference Selection
  const referenceKeyframe = activeKeyframes.reduce((prev, current) => {
      const prevLen = prev.points!.length;
      const currLen = current.points!.length;
      if (prevLen > currLen) return prev;
      if (currLen > prevLen) return current;
      return (prev.weight >= current.weight) ? prev : current;
  });

  const referenceStroke = referenceKeyframe.points!;

  // Resample Reference
  let referenceResampled: Point[];
  if (mode === 'points') {
      referenceResampled = upsamplePreservingCorners(referenceStroke, ACTUAL_TARGET_COUNT);
  } else {
      referenceResampled = resamplePoints(referenceStroke, ACTUAL_TARGET_COUNT);
  }

  const resultPoints: Point[] = [];

  for (let i = 0; i < ACTUAL_TARGET_COUNT; i++) {
      let x = 0;
      let y = 0;
      let pressure = 0;
      let totalWeight = 0;

      for (const kf of activeKeyframes) {
          const rawPoints = kf.points!;
          let processedPoints: Point[] = [];

          if (mode === 'points') {
             if (rawPoints.length === ACTUAL_TARGET_COUNT) {
                 processedPoints = rawPoints;
             } else {
                 processedPoints = upsamplePreservingCorners(rawPoints, ACTUAL_TARGET_COUNT);
             }
          } else {
             processedPoints = resamplePoints(rawPoints, ACTUAL_TARGET_COUNT);
          }

          // ALIGNMENT
          // We rely on geometric detection of loops inside alignPoints to decide if we can shift.
          const alignedPoints = alignPoints(referenceResampled, processedPoints);

          const pt = alignedPoints[i];

          x += pt.x * kf.weight;
          y += pt.y * kf.weight;
          pressure += (pt.pressure || 0.5) * kf.weight;
          totalWeight += kf.weight;
      }

      if (totalWeight > 0) {
          resultPoints.push({
              x: x / totalWeight,
              y: y / totalWeight,
              pressure: pressure / totalWeight
          });
      }
  }

  return { points: resultPoints, color, fillColor, width };
};

// --- OPTIMIZATION & SMOOTHING ---

const perpendicularDistance = (point: Point, lineStart: Point, lineEnd: Point): number => {
  let dx = lineEnd.x - lineStart.x;
  let dy = lineEnd.y - lineStart.y;
  const mag = Math.sqrt(dx * dx + dy * dy);
  if (mag > 0.0) { dx /= mag; dy /= mag; }
  const pvx = point.x - lineStart.x;
  const pvy = point.y - lineStart.y;
  const pvdot = pvx * dx + pvy * dy;
  const dsx = pvdot * dx;
  const dsy = pvdot * dy;
  const ax = pvx - dsx;
  const ay = pvy - dsy;
  return Math.sqrt(ax * ax + ay * ay);
};

export const simplifyPoints = (points: Point[], epsilon: number = 2): Point[] => {
  if (points.length < 3) return points;
  let dmax = 0;
  let index = 0;
  const end = points.length - 1;
  for (let i = 1; i < end; i++) {
    const d = perpendicularDistance(points[i], points[0], points[end]);
    if (d > dmax) { index = i; dmax = d; }
  }
  if (dmax > epsilon) {
    const recResults1 = simplifyPoints(points.slice(0, index + 1), epsilon);
    const recResults2 = simplifyPoints(points.slice(index, end + 1), epsilon);
    return [...recResults1.slice(0, -1), ...recResults2];
  } else {
    return [points[0], points[end]];
  }
};

export const chaikinSmooth = (points: Point[], iterations: number = 2): Point[] => {
    if (points.length < 3) return points;
    let output = [...points];
    for (let i = 0; i < iterations; i++) {
        const next: Point[] = [];
        next.push(output[0]);
        for (let j = 0; j < output.length - 1; j++) {
            const p0 = output[j];
            const p1 = output[j + 1];
            next.push({
                x: 0.75 * p0.x + 0.25 * p1.x,
                y: 0.75 * p0.y + 0.25 * p1.y,
                pressure: lerp(p0.pressure || 0.5, p1.pressure || 0.5, 0.25)
            });
            next.push({
                x: 0.25 * p0.x + 0.75 * p1.x,
                y: 0.25 * p0.y + 0.75 * p1.y,
                pressure: lerp(p0.pressure || 0.5, p1.pressure || 0.5, 0.75)
            });
        }
        next.push(output[output.length - 1]);
        output = next;
    }
    return output;
};

// components/Canvas.tsx
import React, { useRef, useLayoutEffect, useEffect, useState } from 'react';
import { useStore } from '../store/useStore';
import { interpolateStrokePoints, snapPointToGrid, isPointInStroke, calculateInterpolationWeights, distance, getBoundingBox, rotatePoint, lerp } from '../utils/math';
import { Point } from '../types';
import { APP_COLORS } from '../constants';

type InteractionMode = 'none' | 'drawing' | 'polyline' | 'dragging' | 'resizing' | 'rotating';
type ResizeHandle = 'tl' | 'tr' | 'bl' | 'br';

export const Canvas: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  const { 
      ui, project, updateAxisValue, updateMultipleAxisValues, 
      addStrokeToCurrentKeyframe, updateStrokeInCurrentKeyframe, selectStroke,
      undo, redo, deleteStroke 
  } = useStore();

  // -- Stable Refs for Animation Loop --
  const projectRef = useRef(project);
  const uiRef = useRef(ui);

  useEffect(() => { projectRef.current = project; }, [project]);
  useEffect(() => { uiRef.current = ui; }, [ui]);

  // -- Physics State (Refs to avoid re-renders) --
  const targetAxesRef = useRef<Record<string, number>>({ 'axis-x': 0.5, 'axis-y': 0.5 });
  const velocityRef = useRef<{ x: number, y: number }>({ x: 0, y: 0 });
  const lastFrameTimeRef = useRef<number>(0);

  // -- Interaction State (Refs needed for Loop access without stale closure) --
  const currentPointsRef = useRef<Point[]>([]); 
  const interactionModeRef = useRef<InteractionMode>('none');

  // -- SYNCED REFS FOR RENDERING --
  // We use State for React updates (UI), but Refs for the Canvas Loop to avoid stale closures.
  const [polylinePoints, setPolylinePoints] = useState<Point[]>([]);
  const polylinePointsRef = useRef<Point[]>([]);
  useEffect(() => { polylinePointsRef.current = polylinePoints; }, [polylinePoints]);

  const [mousePos, setMousePos] = useState<Point | null>(null);
  const mousePosRef = useRef<Point | null>(null);
  useEffect(() => { mousePosRef.current = mousePos; }, [mousePos]);

  const [selectionBounds, setSelectionBounds] = useState<{cx: number; cy: number; width: number; height: number; rotation: number;} | null>(null);
  const selectionBoundsRef = useRef(selectionBounds);
  useEffect(() => { selectionBoundsRef.current = selectionBounds; }, [selectionBounds]);

  const [transformStart, setTransformStart] = useState<{
      mouse: Point;
      center: Point;
      angle: number;
      width: number;
      height: number;
      points: Point[]; 
  } | null>(null);
  const transformStartRef = useRef(transformStart);
  useEffect(() => { transformStartRef.current = transformStart; }, [transformStart]);

  const [activeHandle, setActiveHandle] = useState<ResizeHandle | null>(null);

  // Helpers to sync Ref and State
  const setInteractionMode = (mode: InteractionMode) => {
      interactionModeRef.current = mode;
      setInteractionModeState(mode);
  };
  const [interactionModeState, setInteractionModeState] = useState<InteractionMode>('none');

  // Layout
  const [scale, setScale] = useState(1);
  const CANVAS_WIDTH = project.canvasSize.width;
  const CANVAS_HEIGHT = project.canvasSize.height;

  // -- Helpers --

  // Auto-Scale Canvas
  useEffect(() => {
    const handleResize = () => {
      if (!containerRef.current) return;
      const { width: contW, height: contH } = containerRef.current.getBoundingClientRect();
      const margin = 80;
      const newScale = Math.min((contW - margin) / CANVAS_WIDTH, (contH - margin) / CANVAS_HEIGHT, 1);
      setScale(Math.max(0.1, newScale));
    };
    window.addEventListener('resize', handleResize);
    handleResize();
    return () => window.removeEventListener('resize', handleResize);
  }, [CANVAS_WIDTH, CANVAS_HEIGHT]);

  const getCanvasPoint = (e: React.PointerEvent): Point => {
    if (!canvasRef.current) return { x: 0, y: 0 };
    const rect = canvasRef.current.getBoundingClientRect();
    const x = (e.clientX - rect.left) * (CANVAS_WIDTH / rect.width);
    const y = (e.clientY - rect.top) * (CANVAS_HEIGHT / rect.height);
    return { x, y, pressure: e.pressure || 0.5 };
  };

  const getSnappedPoint = (p: Point): Point => {
      if (ui.snapToGrid) return snapPointToGrid(p, ui.gridSize);
      return p;
  };

  // -- GLOBAL PLAY MODE TRACKING --
  useEffect(() => {
    if (ui.mode !== 'play') return;

    const handleWindowPointerMove = (e: PointerEvent) => {
        if (!canvasRef.current) return;
        const rect = canvasRef.current.getBoundingClientRect();

        let normX = (e.clientX - rect.left) / rect.width;
        let normY = (e.clientY - rect.top) / rect.height;

        // Clamp strictly to 0-1 for axis value logic
        normX = Math.max(0, Math.min(1, normX));
        normY = Math.max(0, Math.min(1, normY));

        if (ui.snapPlayMode) {
            normX = Math.round(normX * 10) / 10;
            normY = Math.round(normY * 10) / 10;
        }

        targetAxesRef.current = { 'axis-x': normX, 'axis-y': normY };
    };

    window.addEventListener('pointermove', handleWindowPointerMove);
    return () => {
        window.removeEventListener('pointermove', handleWindowPointerMove);
    };
  }, [ui.mode, ui.snapPlayMode]);

  const handleDoubleClick = () => {
      if (ui.selectedTool === 'polyline') {
          if (polylinePoints.length > 1) addStrokeToCurrentKeyframe(polylinePoints, false, true);
          setPolylinePoints([]);
      }
  };

  // -- KEYBOARD SHORTCUTS MANAGER --
  useEffect(() => {
      const handleKeyDown = (e: KeyboardEvent) => {
          // Ignore if user is typing in an input
          if ((e.target as HTMLElement).tagName === 'INPUT') return;

          // 1. Tool Shortcuts
          if (e.key === 'Enter') { 
              if (ui.selectedTool === 'polyline') handleDoubleClick(); 
          }
          if (e.key === 'Escape') { 
              setPolylinePoints([]); 
              setInteractionMode('none'); 
              selectStroke(null);
          }

          // 2. Undo / Redo
          if ((e.metaKey || e.ctrlKey) && e.key === 'z') {
              e.preventDefault();
              if (e.shiftKey) redo();
              else undo();
          }
          if ((e.metaKey || e.ctrlKey) && e.key === 'y') {
              e.preventDefault();
              redo();
          }

          // 3. Deletion
          if (e.key === 'Backspace' || e.key === 'Delete') {
              if (ui.selectedStrokeId) {
                  deleteStroke(ui.selectedStrokeId);
              }
          }

          // 4. Nudge (Arrow Keys)
          if (ui.selectedStrokeId && ui.selectedKeyframeId && ui.selectedLayerId && (e.key.startsWith('Arrow'))) {
              e.preventDefault();
              const kf = project.keyframes.find(k => k.id === ui.selectedKeyframeId);
              const ls = kf?.layerStates.find(s => s.layerId === ui.selectedLayerId);
              const stroke = ls?.strokes.find(s => s.id === ui.selectedStrokeId);

              if (stroke) {
                  const step = e.shiftKey ? ui.gridSize : 1;
                  let dx = 0;
                  let dy = 0;
                  if (e.key === 'ArrowUp') dy = -step;
                  if (e.key === 'ArrowDown') dy = step;
                  if (e.key === 'ArrowLeft') dx = -step;
                  if (e.key === 'ArrowRight') dx = step;

                  const newPoints = stroke.points.map(p => ({ ...p, x: p.x + dx, y: p.y + dy }));
                  updateStrokeInCurrentKeyframe(stroke.id, newPoints);
              }
          }
      };

      window.addEventListener('keydown', handleKeyDown);
      return () => window.removeEventListener('keydown', handleKeyDown);
  }, [ui.selectedTool, ui.selectedStrokeId, ui.selectedKeyframeId, ui.selectedLayerId, polylinePoints, project.keyframes]);

  // -- Selection Logic --
  useEffect(() => {
    if (ui.selectedTool !== 'select' || !ui.selectedStrokeId || !ui.selectedKeyframeId) {
        setSelectionBounds(null);
        return;
    }
    const kf = project.keyframes.find(k => k.id === ui.selectedKeyframeId);
    if (!kf) return;
    const layerState = kf.layerStates.find(ls => ls.layerId === ui.selectedLayerId);
    if (!layerState) return;
    const stroke = layerState.strokes.find(s => s.id === ui.selectedStrokeId);
    if (!stroke) return;
    const bbox = getBoundingBox(stroke.points);
    setSelectionBounds({
        cx: bbox.centerX, cy: bbox.centerY, width: bbox.width, height: bbox.height, rotation: 0
    });
  }, [ui.selectedStrokeId, ui.selectedKeyframeId, ui.selectedLayerId, ui.selectedTool, project.keyframes]);

  // -- Gizmo Hit Testing --
  const getGizmoHit = (p: Point, bounds: { cx: number, cy: number, width: number, height: number, rotation: number } | null) => {
      if (!bounds) return null;
      const { cx, cy, width, height, rotation } = bounds;
      const hw = width / 2; const hh = height / 2;
      const localP = rotatePoint(p, {x: cx, y: cy}, -rotation);
      const HANDLE_SIZE = 10 / scale;
      if (distance(localP, {x: cx, y: cy - hh - 25}) < HANDLE_SIZE) return 'rotator';
      if (distance(localP, {x: cx - hw, y: cy - hh}) < HANDLE_SIZE) return 'tl';
      if (distance(localP, {x: cx + hw, y: cy - hh}) < HANDLE_SIZE) return 'tr';
      if (distance(localP, {x: cx - hw, y: cy + hh}) < HANDLE_SIZE) return 'bl';
      if (distance(localP, {x: cx + hw, y: cy + hh}) < HANDLE_SIZE) return 'br';
      if (localP.x >= cx - hw && localP.x <= cx + hw && localP.y >= cy - hh && localP.y <= cy + hh) return 'body';
      return null;
  };

  const findHitStroke = (p: Point): string | null => {
     const kf = project.keyframes.find(k => k.id === ui.selectedKeyframeId);
     if (!kf) return null;
     const layerState = kf.layerStates.find(ls => ls.layerId === ui.selectedLayerId);
     if (!layerState) return null;
     for (let i = layerState.strokes.length - 1; i >= 0; i--) {
        const s = layerState.strokes[i];
        if (isPointInStroke(p, s.points)) return s.id;
     }
     return null;
  };

  // -- Event Handlers --

  const handlePointerDown = (e: React.PointerEvent) => {
    const p = getCanvasPoint(e);

    if (ui.mode === 'play') {
       return;
    }

    if (ui.selectedTool === 'select') {
        const hitGizmo = getGizmoHit(p, selectionBounds);
        if (hitGizmo && selectionBounds && ui.selectedStrokeId) {
            const kf = project.keyframes.find(k => k.id === ui.selectedKeyframeId);
            const ls = kf?.layerStates.find(s => s.layerId === ui.selectedLayerId);
            const stroke = ls?.strokes.find(s => s.id === ui.selectedStrokeId);
            if (stroke) {
                setTransformStart({
                    mouse: p, center: { x: selectionBounds.cx, y: selectionBounds.cy },
                    angle: selectionBounds.rotation, width: selectionBounds.width, height: selectionBounds.height, points: stroke.points
                });
                if (hitGizmo === 'body') setInteractionMode('dragging');
                else if (hitGizmo === 'rotator') setInteractionMode('rotating');
                else { setInteractionMode('resizing'); setActiveHandle(hitGizmo as ResizeHandle); }
                (e.target as Element).setPointerCapture(e.pointerId);
            }
            return;
        }
        const hitId = findHitStroke(p);
        if (hitId) selectStroke(hitId); else selectStroke(null);
        return;
    }

    if (ui.selectedTool === 'polyline') {
       const snappedP = getSnappedPoint(p);
       if (polylinePoints.length > 2 && distance(snappedP, polylinePoints[0]) < 15) {
           addStrokeToCurrentKeyframe(polylinePoints, true, true);
           setPolylinePoints([]);
           return;
       }
       if (polylinePoints.length > 0) {
           const lastPoint = polylinePoints[polylinePoints.length - 1];
           if (distance(snappedP, lastPoint) < 15) {
               addStrokeToCurrentKeyframe(polylinePoints, false, true);
               setPolylinePoints([]);
               return;
           }
       }
       setPolylinePoints(prev => [...prev, snappedP]);
       return;
    }

    if (ui.selectedTool === 'pen') {
      setInteractionMode('drawing'); // Updates Ref immediately
      currentPointsRef.current = [getSnappedPoint(p)];
      (e.target as Element).setPointerCapture(e.pointerId);
    } 
  };

  const handlePointerMove = (e: React.PointerEvent) => {
    const p = getCanvasPoint(e);
    setMousePos(getSnappedPoint(p));

    // PLAY MODE: Handled by global window listener now.
    if (ui.mode === 'play') return;

    if (interactionModeRef.current !== 'none' && transformStart && selectionBounds) {
        if (interactionModeRef.current === 'dragging') {
            let dx = p.x - transformStart.mouse.x; let dy = p.y - transformStart.mouse.y;
            if (ui.snapToGrid) {
                const targetX = transformStart.center.x + dx; const targetY = transformStart.center.y + dy;
                const snappedX = Math.round(targetX / ui.gridSize) * ui.gridSize; const snappedY = Math.round(targetY / ui.gridSize) * ui.gridSize;
                dx = snappedX - transformStart.center.x; dy = snappedY - transformStart.center.y;
            }
            setSelectionBounds({ ...selectionBounds, cx: transformStart.center.x + dx, cy: transformStart.center.y + dy });
        } else if (interactionModeRef.current === 'rotating') {
            const currentAngle = Math.atan2(p.y - selectionBounds.cy, p.x - selectionBounds.cx);
            const startAngle = Math.atan2(transformStart.mouse.y - selectionBounds.cy, transformStart.mouse.x - selectionBounds.cx);
            let dAngle = currentAngle - startAngle; let newRotation = transformStart.angle + dAngle;
            if (e.shiftKey) { const step = Math.PI / 12; newRotation = Math.round(newRotation / step) * step; }
            setSelectionBounds({ ...selectionBounds, rotation: newRotation });
        } else if (interactionModeRef.current === 'resizing' && activeHandle) {
            const unrotatedMouse = rotatePoint(p, transformStart.center, -transformStart.angle);
            const unrotatedStart = rotatePoint(transformStart.mouse, transformStart.center, -transformStart.angle);
            let dx = unrotatedMouse.x - unrotatedStart.x; let dy = unrotatedMouse.y - unrotatedStart.y;
            if (e.shiftKey) { const aspect = transformStart.width / transformStart.height; dy = (activeHandle === 'br' || activeHandle === 'tl') ? dx / aspect : -dx / aspect; }
            if (ui.snapToGrid && !e.shiftKey) { dx = Math.round(dx / ui.gridSize) * ui.gridSize; dy = Math.round(dy / ui.gridSize) * ui.gridSize; }
            let newW = transformStart.width; let newH = transformStart.height;
            if (activeHandle === 'br') { newW += dx * 2; newH += dy * 2; }
            if (activeHandle === 'tl') { newW -= dx * 2; newH -= dy * 2; }
            if (activeHandle === 'tr') { newW += dx * 2; newH -= dy * 2; }
            if (activeHandle === 'bl') { newW -= dx * 2; newH += dy * 2; }
            newW = Math.max(1, newW); newH = Math.max(1, newH);
            setSelectionBounds({ ...selectionBounds, width: newW, height: newH });
        }
        return;
    }

    if (interactionModeRef.current === 'drawing') {
        currentPointsRef.current.push(getSnappedPoint(p));
    }
  };

  const handlePointerUp = (e: React.PointerEvent) => {
    if (ui.mode !== 'play') {
       (e.target as Element).releasePointerCapture(e.pointerId);
    }

    if (interactionModeRef.current !== 'none' && transformStart && selectionBounds && ui.selectedStrokeId) {
        const scaleX = selectionBounds.width / transformStart.width;
        const scaleY = selectionBounds.height / transformStart.height;
        const dRot = selectionBounds.rotation - transformStart.angle;
        const dX = selectionBounds.cx - transformStart.center.x;
        const dY = selectionBounds.cy - transformStart.center.y;
        const newPoints = transformStart.points.map(pt => {
            let x = pt.x - transformStart.center.x; let y = pt.y - transformStart.center.y;
            x *= scaleX; y *= scaleY;
            const cos = Math.cos(dRot); const sin = Math.sin(dRot);
            const rx = x * cos - y * sin; const ry = x * sin + y * cos;
            return { x: rx + transformStart.center.x + dX, y: ry + transformStart.center.y + dY, pressure: pt.pressure };
        });
        updateStrokeInCurrentKeyframe(ui.selectedStrokeId, newPoints);
    }

    // DRAWING END
    if (interactionModeRef.current === 'drawing' && currentPointsRef.current.length > 1) {
        const points = [...currentPointsRef.current];
        const start = points[0];
        const end = points[points.length - 1];

        // AUTO-CLOSE LOGIC: 
        const isLoop = distance(start, end) < 20; 
        const shouldClose = isLoop && (ui.fillColor !== 'none');

        addStrokeToCurrentKeyframe(points, shouldClose);
    }
    setInteractionMode('none'); setActiveHandle(null); setTransformStart(null); currentPointsRef.current = [];
  };

  // -- THE RENDER LOOP --
  // This loop depends mainly on canvas size to restart, but reads data from Refs to stay fresh.
  useLayoutEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    let animationFrameId: number;

    const render = (time: number) => {
      // 1. Calculate Delta Time for Physics
      if (!lastFrameTimeRef.current) lastFrameTimeRef.current = time;
      const dt = Math.min((time - lastFrameTimeRef.current) / 1000, 0.1); 
      lastFrameTimeRef.current = time;

      // 2. Read Fresh State from Refs
      const currentProject = projectRef.current;
      const currentUI = uiRef.current;

      // READ INTERACTIVE STATE FROM REFS
      const currentPolyline = polylinePointsRef.current;
      const currentSelectionBounds = selectionBoundsRef.current;
      const currentMousePos = mousePosRef.current;

      const dpr = currentUI.resolutionScale || window.devicePixelRatio || 1;
      const interpolationTargetCount = currentUI.performanceMode ? 80 : 200;

      // Ensure Canvas Size is correct 
      if (canvas.width !== CANVAS_WIDTH * dpr || canvas.height !== CANVAS_HEIGHT * dpr) {
          canvas.width = CANVAS_WIDTH * dpr;
          canvas.height = CANVAS_HEIGHT * dpr;
          ctx.scale(dpr, dpr);
      }

      // 3. PLAY MODE PHYSICS
      if (currentUI.mode === 'play') {
          const axisX = currentProject.axes.find(a => a.id === 'axis-x');
          const axisY = currentProject.axes.find(a => a.id === 'axis-y');

          if (axisX && axisY) {
              const targetX = targetAxesRef.current['axis-x'];
              const targetY = targetAxesRef.current['axis-y'];

              let nextX = axisX.currentValue;
              let nextY = axisY.currentValue;

              if (currentUI.playModePhysics) {
                  const stiffness = currentUI.springStiffness || 120;
                  const damping = currentUI.springDamping || 20;

                  const forceX = (targetX - nextX) * stiffness - velocityRef.current.x * damping;
                  const forceY = (targetY - nextY) * stiffness - velocityRef.current.y * damping;

                  velocityRef.current.x += forceX * dt;
                  velocityRef.current.y += forceY * dt;

                  nextX += velocityRef.current.x * dt;
                  nextY += velocityRef.current.y * dt;
              } else {
                  nextX = targetX;
                  nextY = targetY;
                  velocityRef.current = { x: 0, y: 0 };
              }

              if (Math.abs(nextX - axisX.currentValue) > 0.0001 || Math.abs(nextY - axisY.currentValue) > 0.0001) {
                  const clampedX = Math.max(0, Math.min(1, nextX));
                  const clampedY = Math.max(0, Math.min(1, nextY));
                  updateMultipleAxisValues({ 'axis-x': clampedX, 'axis-y': clampedY });
              }
          }
      } else {
           const curX = currentProject.axes.find(a => a.id === 'axis-x')?.currentValue || 0.5;
           const curY = currentProject.axes.find(a => a.id === 'axis-y')?.currentValue || 0.5;
           targetAxesRef.current = { 'axis-x': curX, 'axis-y': curY };
           velocityRef.current = { x: 0, y: 0 };
      }

      // 4. CLEAR & DRAW
      ctx.clearRect(0, 0, CANVAS_WIDTH, CANVAS_HEIGHT);
      ctx.fillStyle = '#FFFFFF';
      ctx.fillRect(0, 0, CANVAS_WIDTH, CANVAS_HEIGHT);

      // GRID
      if (currentUI.showGrid && currentUI.mode === 'edit') {
        ctx.fillStyle = '#D1D5DB';
        const gridSize = currentUI.gridSize;
        const centerX = CANVAS_WIDTH / 2;
        const centerY = CANVAS_HEIGHT / 2;
        const startX = (centerX % gridSize);
        const startY = (centerY % gridSize);
        for (let x = startX; x <= CANVAS_WIDTH; x += gridSize) {
           for (let y = startY; y <= CANVAS_HEIGHT; y += gridSize) {
              ctx.beginPath();
              ctx.arc(x, y, 1.5, 0, Math.PI * 2);
              ctx.fill();
           }
        }
      }

      // ONION SKIN
      if (currentUI.onionSkinEnabled && currentUI.mode === 'edit') {
         currentProject.keyframes.forEach(kf => {
           if (kf.id === currentUI.selectedKeyframeId) return; 
           ctx.globalAlpha = currentUI.onionSkinOpacity;
           kf.layerStates.forEach(ls => {
              if (ls.layerId !== currentUI.selectedLayerId) return;
              const stroke = ls.strokes[0];
              if (stroke && stroke.points.length > 1) {
                ctx.beginPath();
                ctx.moveTo(stroke.points[0].x, stroke.points[0].y);
                for (let i = 1; i < stroke.points.length; i++) ctx.lineTo(stroke.points[i].x, stroke.points[i].y);
                // NO CLOSE PATH
                ctx.strokeStyle = '#3B82F6'; 
                ctx.lineWidth = 1; 
                ctx.stroke();
              }
           });
           ctx.globalAlpha = 1.0;
         });
      }

      // INTERPOLATION RENDERING
      const currentAxesDict: Record<string, number> = {};
      currentProject.axes.forEach(a => currentAxesDict[a.id] = a.currentValue);

      currentProject.layers.forEach(layer => {
        if (!layer.visible) return;

        const layerRelevantKeyframes = currentProject.keyframes.filter(kf => {
            const ls = kf.layerStates.find(s => s.layerId === layer.id);
            return ls && ls.strokes.length > 0;
        });

        if (layerRelevantKeyframes.length === 0) return;

        const weights = calculateInterpolationWeights(currentAxesDict, layerRelevantKeyframes, currentUI.interpolationExponent, currentUI.interpolationStrategy);

        const activeKeyframes = layerRelevantKeyframes
             .map(k => ({ ...k, weight: weights[k.id] || 0 }))
             .filter(k => k.weight > 0.0001);

        const strokeId = `stroke-${layer.id}-unique`;
        const isLayerActive = layer.id === currentUI.selectedLayerId;
        const isCreatingNewState = currentUI.selectedKeyframeId === null;

        let layerGlobalAlpha = layer.opacity;
        if (!isLayerActive && currentUI.mode !== 'play') layerGlobalAlpha *= currentUI.inactiveLayerOpacity;
        if (isCreatingNewState && currentUI.mode === 'edit') layerGlobalAlpha *= currentUI.ghostStrokeOpacity;

        const strokeData = activeKeyframes.map(kf => {
            const state = kf.layerStates.find(ls => ls.layerId === layer.id);
            const s = state?.strokes[0]; 
            return { weight: kf.weight, points: s?.points, style: s, color: s?.color || 'none', fillColor: s?.fillColor, width: s?.width || 1 };
        });

        const sortedByWeight = [...strokeData].sort((a,b) => b.weight - a.weight);
        const primaryStroke = sortedByWeight.find(sd => sd.style)?.style;
        if (!primaryStroke) return;

        const { points: interpolatedPoints, color: interpolatedColor, fillColor: interpolatedFill, width: interpolatedWidth } = interpolateStrokePoints(
            strokeId, 
            primaryStroke.points, 
            strokeData, 
            layer.interpolationMode,
            interpolationTargetCount 
        );

        if (interpolatedPoints.length > 0) {
            ctx.beginPath();
            ctx.moveTo(interpolatedPoints[0].x, interpolatedPoints[0].y);
            for (let i = 1; i < interpolatedPoints.length; i++) ctx.lineTo(interpolatedPoints[i].x, interpolatedPoints[i].y);

            // REMOVED ctx.closePath() - Pure geometric closure only

            ctx.globalAlpha = layerGlobalAlpha;
            switch(layer.blendMode) {
                case 'multiply': ctx.globalCompositeOperation = 'multiply'; break;
                case 'screen': ctx.globalCompositeOperation = 'screen'; break;
                case 'overlay': ctx.globalCompositeOperation = 'overlay'; break;
                case 'difference': ctx.globalCompositeOperation = 'difference'; break;
                case 'exclusion': ctx.globalCompositeOperation = 'exclusion'; break;
                default: ctx.globalCompositeOperation = 'source-over';
            }

            if (interpolatedFill && interpolatedFill !== 'none') {
                ctx.fillStyle = interpolatedFill;
                ctx.fill();
            }
            if (interpolatedColor && interpolatedColor !== 'none') {
                ctx.lineCap = 'round';
                ctx.lineJoin = 'round';
                ctx.strokeStyle = interpolatedColor;
                ctx.lineWidth = interpolatedWidth;
                ctx.stroke();
            }

            ctx.globalAlpha = 1.0;
            ctx.globalCompositeOperation = 'source-over';
        }
      });

      // ACTIVE DRAWING (Using Refs)
      if (interactionModeRef.current === 'drawing' && currentPointsRef.current.length > 0) {
        const isGhostState = currentUI.selectedKeyframeId === null;
        ctx.globalAlpha = isGhostState ? currentUI.ghostStrokeOpacity : 1.0;

        ctx.beginPath();
        const pts = currentPointsRef.current;
        ctx.moveTo(pts[0].x, pts[0].y);
        for (let i = 1; i < pts.length; i++) ctx.lineTo(pts[i].x, pts[i].y);
        ctx.strokeStyle = currentUI.brushColor !== 'none' ? currentUI.brushColor : 'rgba(0,0,0,0.2)'; 
        ctx.lineWidth = currentUI.brushSize;
        ctx.lineCap = 'round';
        ctx.lineJoin = 'round';
        ctx.stroke();
        ctx.globalAlpha = 1.0; 
      }

      // ACTIVE POLYLINE (Using Synced Refs)
      if (currentPolyline.length > 0) {
         const isGhostState = currentUI.selectedKeyframeId === null;
         ctx.globalAlpha = isGhostState ? currentUI.ghostStrokeOpacity : 1.0;

         ctx.beginPath();
         ctx.moveTo(currentPolyline[0].x, currentPolyline[0].y);
         for (let i = 1; i < currentPolyline.length; i++) ctx.lineTo(currentPolyline[i].x, currentPolyline[i].y);

         if (currentMousePos) ctx.lineTo(currentMousePos.x, currentMousePos.y); 

         if (currentUI.fillColor !== 'none') {
             ctx.fillStyle = currentUI.fillColor;
             ctx.globalAlpha = isGhostState ? currentUI.ghostStrokeOpacity * 0.5 : 0.5;
             ctx.fill();
             ctx.globalAlpha = isGhostState ? currentUI.ghostStrokeOpacity : 1.0;
         }

         ctx.strokeStyle = currentUI.brushColor !== 'none' ? currentUI.brushColor : 'rgba(0,0,0,0.5)';
         ctx.lineWidth = currentUI.brushSize;
         ctx.stroke();

         ctx.fillStyle = currentUI.brushColor !== 'none' ? currentUI.brushColor : 'rgba(0,0,0,0.5)';
         currentPolyline.forEach((p, index) => {
            ctx.beginPath();
            const r = (index === 0) ? 5 : 3; 
            ctx.arc(p.x, p.y, r, 0, Math.PI * 2);
            ctx.fill();
         });
         ctx.globalAlpha = 1.0; 
      }

      // GIZMOS (Using Synced Refs)
      if (currentSelectionBounds && currentUI.selectedTool === 'select' && currentUI.mode === 'edit') {
          const { cx, cy, width, height, rotation } = currentSelectionBounds;

          ctx.save();
          ctx.translate(cx, cy);
          ctx.rotate(rotation);

          ctx.beginPath();
          ctx.strokeStyle = '#3B82F6';
          ctx.lineWidth = 1;
          ctx.rect(-width/2, -height/2, width, height);
          ctx.stroke();

          const HANDLE_SIZE = 8; 
          ctx.fillStyle = '#FFFFFF';
          ctx.strokeStyle = '#3B82F6';

          const drawHandle = (x: number, y: number) => {
              ctx.beginPath();
              ctx.rect(x - HANDLE_SIZE/2, y - HANDLE_SIZE/2, HANDLE_SIZE, HANDLE_SIZE);
              ctx.fill();
              ctx.stroke();
          };

          drawHandle(-width/2, -height/2); // TL
          drawHandle(width/2, -height/2);  // TR
          drawHandle(-width/2, height/2);  // BL
          drawHandle(width/2, height/2);   // BR

          ctx.beginPath();
          ctx.moveTo(0, -height/2);
          ctx.lineTo(0, -height/2 - 25);
          ctx.stroke();

          ctx.beginPath();
          ctx.arc(0, -height/2 - 25, 4, 0, Math.PI * 2);
          ctx.fillStyle = '#3B82F6';
          ctx.fill();

          ctx.restore();
      }

      animationFrameId = requestAnimationFrame(render);
    };

    animationFrameId = requestAnimationFrame(render);
    return () => cancelAnimationFrame(animationFrameId);
  }, [CANVAS_WIDTH, CANVAS_HEIGHT]); // Minimized dependencies for loop stability

  return (
    <div 
      ref={containerRef} 
      className="absolute inset-0 z-0 flex items-center justify-center bg-[#EAEAEA] touch-none"
    >
      <div 
        style={{ 
          width: CANVAS_WIDTH, 
          height: CANVAS_HEIGHT,
          transform: `scale(${scale})`,
          boxShadow: '0 20px 50px -12px rgba(0, 0, 0, 0.15)' 
        }}
        className="bg-white rounded-xl overflow-hidden relative transition-transform duration-200 ease-out origin-center ring-4 ring-white/50"
      >
          <canvas 
            ref={canvasRef} 
            className={`block w-full h-full ${ui.mode === 'play' ? 'cursor-move' : (ui.selectedTool === 'select' ? 'cursor-default' : 'cursor-crosshair')}`}
            onPointerDown={handlePointerDown}
            onPointerMove={handlePointerMove}
            onPointerUp={handlePointerUp}
            onDoubleClick={handleDoubleClick}
          />
      </div>
    </div>
  );
};

// components/Canvas.tsx
import React, { useRef, useLayoutEffect, useEffect, useState } from 'react';
import { useStore } from '../store/useStore';
import { interpolateStrokePoints, snapPointToGrid, isPointInStroke, calculateInterpolationWeights, distance, getBoundingBox, rotatePoint, lerp } from '../utils/math';
import { Point } from '../types';
import { APP_COLORS } from '../constants';

type InteractionMode = 'none' | 'drawing' | 'polyline' | 'dragging' | 'resizing' | 'rotating' | 'draggingVertex';
type ResizeHandle = 'tl' | 'tr' | 'bl' | 'br';

export const Canvas: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  const { 
      ui, project, updateAxisValue, updateMultipleAxisValues, 
      addStrokeToCurrentKeyframe, updateStrokeInCurrentKeyframe, selectStroke,
      undo, redo, deleteStroke 
  } = useStore();

  // -- Stable Refs for Animation Loop --
  const projectRef = useRef(project);
  const uiRef = useRef(ui);

  useEffect(() => { projectRef.current = project; }, [project]);
  useEffect(() => { uiRef.current = ui; }, [ui]);

  // -- Physics State (Refs to avoid re-renders) --
  const targetAxesRef = useRef<Record<string, number>>({ 'axis-x': 0.5, 'axis-y': 0.5 });
  const velocityRef = useRef<{ x: number, y: number }>({ x: 0, y: 0 });
  const lastFrameTimeRef = useRef<number>(0);

  // -- Interaction State (Refs needed for Loop access without stale closure) --
  const currentPointsRef = useRef<Point[]>([]); 
  const interactionModeRef = useRef<InteractionMode>('none');

  // -- SYNCED REFS FOR RENDERING --
  // We use State for React updates (UI), but Refs for the Canvas Loop to avoid stale closures.
  const [polylinePoints, setPolylinePoints] = useState<Point[]>([]);
  const polylinePointsRef = useRef<Point[]>([]);
  useEffect(() => { polylinePointsRef.current = polylinePoints; }, [polylinePoints]);

  const [mousePos, setMousePos] = useState<Point | null>(null);
  const mousePosRef = useRef<Point | null>(null);
  useEffect(() => { mousePosRef.current = mousePos; }, [mousePos]);

  const [selectionBounds, setSelectionBounds] = useState<{cx: number; cy: number; width: number; height: number; rotation: number;} | null>(null);
  const selectionBoundsRef = useRef(selectionBounds);
  useEffect(() => { selectionBoundsRef.current = selectionBounds; }, [selectionBounds]);

  const [transformStart, setTransformStart] = useState<{
      mouse: Point;
      center: Point;
      angle: number;
      width: number;
      height: number;
      points: Point[]; 
  } | null>(null);
  const transformStartRef = useRef(transformStart);
  useEffect(() => { transformStartRef.current = transformStart; }, [transformStart]);

  const [activeHandle, setActiveHandle] = useState<ResizeHandle | null>(null);
  const [activeVertexIndex, setActiveVertexIndex] = useState<number | null>(null);
  const activeVertexIndexRef = useRef<number | null>(null);
  useEffect(() => { activeVertexIndexRef.current = activeVertexIndex; }, [activeVertexIndex]);

  // Helpers to sync Ref and State
  const setInteractionMode = (mode: InteractionMode) => {
      interactionModeRef.current = mode;
      setInteractionModeState(mode);
  };
  const [interactionModeState, setInteractionModeState] = useState<InteractionMode>('none');

  // Layout
  const [scale, setScale] = useState(1);
  const CANVAS_WIDTH = project.canvasSize.width;
  const CANVAS_HEIGHT = project.canvasSize.height;

  // -- Helpers --

  // Auto-Scale Canvas
  useEffect(() => {
    const handleResize = () => {
      if (!containerRef.current) return;
      const { width: contW, height: contH } = containerRef.current.getBoundingClientRect();
      const margin = 80;
      const newScale = Math.min((contW - margin) / CANVAS_WIDTH, (contH - margin) / CANVAS_HEIGHT, 1);
      setScale(Math.max(0.1, newScale));
    };
    window.addEventListener('resize', handleResize);
    handleResize();
    return () => window.removeEventListener('resize', handleResize);
  }, [CANVAS_WIDTH, CANVAS_HEIGHT]);

  const getCanvasPoint = (e: React.PointerEvent): Point => {
    if (!canvasRef.current) return { x: 0, y: 0 };
    const rect = canvasRef.current.getBoundingClientRect();
    const x = (e.clientX - rect.left) * (CANVAS_WIDTH / rect.width);
    const y = (e.clientY - rect.top) * (CANVAS_HEIGHT / rect.height);
    return { x, y, pressure: e.pressure || 0.5 };
  };

  const getSnappedPoint = (p: Point): Point => {
      if (ui.snapToGrid) return snapPointToGrid(p, ui.gridSize);
      return p;
  };

  // -- GLOBAL PLAY MODE TRACKING --
  useEffect(() => {
    if (ui.mode !== 'play') return;

    const handleWindowPointerMove = (e: PointerEvent) => {
        if (!canvasRef.current) return;
        const rect = canvasRef.current.getBoundingClientRect();

        let normX = (e.clientX - rect.left) / rect.width;
        let normY = (e.clientY - rect.top) / rect.height;

        // Clamp strictly to 0-1 for axis value logic
        normX = Math.max(0, Math.min(1, normX));
        normY = Math.max(0, Math.min(1, normY));

        if (ui.snapPlayMode) {
            normX = Math.round(normX * 10) / 10;
            normY = Math.round(normY * 10) / 10;
        }

        targetAxesRef.current = { 'axis-x': normX, 'axis-y': normY };
    };

    window.addEventListener('pointermove', handleWindowPointerMove);
    return () => {
        window.removeEventListener('pointermove', handleWindowPointerMove);
    };
  }, [ui.mode, ui.snapPlayMode]);

  const handleDoubleClick = () => {
      if (ui.selectedTool === 'polyline') {
          if (polylinePoints.length > 1) addStrokeToCurrentKeyframe(polylinePoints, false, true);
          setPolylinePoints([]);
      }
  };

  // -- KEYBOARD SHORTCUTS MANAGER --
  useEffect(() => {
      const handleKeyDown = (e: KeyboardEvent) => {
          // Ignore if user is typing in an input
          if ((e.target as HTMLElement).tagName === 'INPUT') return;

          // 1. Tool Shortcuts
          if (e.key === 'Enter') { 
              if (ui.selectedTool === 'polyline') handleDoubleClick(); 
          }
          if (e.key === 'Escape') { 
              setPolylinePoints([]); 
              setInteractionMode('none'); 
              selectStroke(null);
          }

          // 2. Undo / Redo
          if ((e.metaKey || e.ctrlKey) && e.key === 'z') {
              e.preventDefault();
              if (e.shiftKey) redo();
              else undo();
          }
          if ((e.metaKey || e.ctrlKey) && e.key === 'y') {
              e.preventDefault();
              redo();
          }

          // 3. Deletion
          if (e.key === 'Backspace' || e.key === 'Delete') {
              if (ui.selectedStrokeId) {
                  deleteStroke(ui.selectedStrokeId);
              }
          }

          // 4. Nudge (Arrow Keys)
          if (ui.selectedStrokeId && ui.selectedKeyframeId && ui.selectedLayerId && (e.key.startsWith('Arrow'))) {
              e.preventDefault();
              const kf = project.keyframes.find(k => k.id === ui.selectedKeyframeId);
              const ls = kf?.layerStates.find(s => s.layerId === ui.selectedLayerId);
              const stroke = ls?.strokes.find(s => s.id === ui.selectedStrokeId);

              if (stroke) {
                  const step = e.shiftKey ? ui.gridSize : 1;
                  let dx = 0;
                  let dy = 0;
                  if (e.key === 'ArrowUp') dy = -step;
                  if (e.key === 'ArrowDown') dy = step;
                  if (e.key === 'ArrowLeft') dx = -step;
                  if (e.key === 'ArrowRight') dx = step;

                  const newPoints = stroke.points.map(p => ({ ...p, x: p.x + dx, y: p.y + dy }));
                  updateStrokeInCurrentKeyframe(stroke.id, newPoints);
              }
          }
      };

      window.addEventListener('keydown', handleKeyDown);
      return () => window.removeEventListener('keydown', handleKeyDown);
  }, [ui.selectedTool, ui.selectedStrokeId, ui.selectedKeyframeId, ui.selectedLayerId, polylinePoints, project.keyframes]);

  // -- Selection Logic --
  useEffect(() => {
    if (ui.selectedTool !== 'select' || !ui.selectedStrokeId || !ui.selectedKeyframeId) {
        setSelectionBounds(null);
        return;
    }
    const kf = project.keyframes.find(k => k.id === ui.selectedKeyframeId);
    if (!kf) return;
    const layerState = kf.layerStates.find(ls => ls.layerId === ui.selectedLayerId);
    if (!layerState) return;
    const stroke = layerState.strokes.find(s => s.id === ui.selectedStrokeId);
    if (!stroke) return;
    const bbox = getBoundingBox(stroke.points);
    setSelectionBounds({
        cx: bbox.centerX, cy: bbox.centerY, width: bbox.width, height: bbox.height, rotation: 0
    });
  }, [ui.selectedStrokeId, ui.selectedKeyframeId, ui.selectedLayerId, ui.selectedTool, project.keyframes]);

  // -- Gizmo Hit Testing --
  const getGizmoHit = (p: Point, bounds: { cx: number, cy: number, width: number, height: number, rotation: number } | null) => {
      if (!bounds) return null;
      const { cx, cy, width, height, rotation } = bounds;
      const hw = width / 2; const hh = height / 2;
      const localP = rotatePoint(p, {x: cx, y: cy}, -rotation);
      const HANDLE_SIZE = 10 / scale;
      if (distance(localP, {x: cx, y: cy - hh - 25}) < HANDLE_SIZE) return 'rotator';
      if (distance(localP, {x: cx - hw, y: cy - hh}) < HANDLE_SIZE) return 'tl';
      if (distance(localP, {x: cx + hw, y: cy - hh}) < HANDLE_SIZE) return 'tr';
      if (distance(localP, {x: cx - hw, y: cy + hh}) < HANDLE_SIZE) return 'bl';
      if (distance(localP, {x: cx + hw, y: cy + hh}) < HANDLE_SIZE) return 'br';
      if (localP.x >= cx - hw && localP.x <= cx + hw && localP.y >= cy - hh && localP.y <= cy + hh) return 'body';
      return null;
  };

  const getVertexHit = (p: Point, strokePoints: Point[]): number => {
      const HIT_THRESHOLD = 8 / scale;
      // Check in reverse to grab top-most if overlapping
      for (let i = strokePoints.length - 1; i >= 0; i--) {
          if (distance(p, strokePoints[i]) < HIT_THRESHOLD) return i;
      }
      return -1;
  };

  const findHitStroke = (p: Point): string | null => {
     const kf = project.keyframes.find(k => k.id === ui.selectedKeyframeId);
     if (!kf) return null;
     const layerState = kf.layerStates.find(ls => ls.layerId === ui.selectedLayerId);
     if (!layerState) return null;
     for (let i = layerState.strokes.length - 1; i >= 0; i--) {
        const s = layerState.strokes[i];
        if (isPointInStroke(p, s.points)) return s.id;
     }
     return null;
  };

  // -- Event Handlers --

  const handlePointerDown = (e: React.PointerEvent) => {
    const p = getCanvasPoint(e);

    if (ui.mode === 'play') {
       return;
    }

    if (ui.selectedTool === 'select') {

        // 1. VERTEX EDITING CHECK (If a stroke is already selected)
        if (ui.selectedStrokeId && selectionBounds) {
             const kf = project.keyframes.find(k => k.id === ui.selectedKeyframeId);
             const ls = kf?.layerStates.find(s => s.layerId === ui.selectedLayerId);
             const stroke = ls?.strokes.find(s => s.id === ui.selectedStrokeId);

             if (stroke) {
                 const vertexIndex = getVertexHit(p, stroke.points);
                 if (vertexIndex !== -1) {
                     setInteractionMode('draggingVertex');
                     setActiveVertexIndex(vertexIndex);
                     setTransformStart({
                        mouse: p, center: {x:0,y:0}, angle: 0, width: 0, height: 0, 
                        points: stroke.points // Store initial state
                     });
                     (e.target as Element).setPointerCapture(e.pointerId);
                     return;
                 }
             }
        }

        // 2. GIZMO CHECK
        const hitGizmo = getGizmoHit(p, selectionBounds);
        if (hitGizmo && selectionBounds && ui.selectedStrokeId) {
            const kf = project.keyframes.find(k => k.id === ui.selectedKeyframeId);
            const ls = kf?.layerStates.find(s => s.layerId === ui.selectedLayerId);
            const stroke = ls?.strokes.find(s => s.id === ui.selectedStrokeId);
            if (stroke) {
                setTransformStart({
                    mouse: p, center: { x: selectionBounds.cx, y: selectionBounds.cy },
                    angle: selectionBounds.rotation, width: selectionBounds.width, height: selectionBounds.height, points: stroke.points
                });
                if (hitGizmo === 'body') setInteractionMode('dragging');
                else if (hitGizmo === 'rotator') setInteractionMode('rotating');
                else { setInteractionMode('resizing'); setActiveHandle(hitGizmo as ResizeHandle); }
                (e.target as Element).setPointerCapture(e.pointerId);
            }
            return;
        }

        // 3. NEW SELECTION
        const hitId = findHitStroke(p);
        if (hitId) selectStroke(hitId); else selectStroke(null);
        return;
    }

    if (ui.selectedTool === 'polyline') {
       const snappedP = getSnappedPoint(p);
       if (polylinePoints.length > 2 && distance(snappedP, polylinePoints[0]) < 15) {
           addStrokeToCurrentKeyframe(polylinePoints, true, true);
           setPolylinePoints([]);
           return;
       }
       if (polylinePoints.length > 0) {
           const lastPoint = polylinePoints[polylinePoints.length - 1];
           if (distance(snappedP, lastPoint) < 15) {
               addStrokeToCurrentKeyframe(polylinePoints, false, true);
               setPolylinePoints([]);
               return;
           }
       }
       setPolylinePoints(prev => [...prev, snappedP]);
       return;
    }

    if (ui.selectedTool === 'pen') {
      setInteractionMode('drawing'); // Updates Ref immediately
      currentPointsRef.current = [getSnappedPoint(p)];
      (e.target as Element).setPointerCapture(e.pointerId);
    } 
  };

  const handlePointerMove = (e: React.PointerEvent) => {
    const p = getCanvasPoint(e);
    setMousePos(getSnappedPoint(p));

    // PLAY MODE: Handled by global window listener now.
    if (ui.mode === 'play') return;

    // VERTEX DRAGGING
    if (interactionModeRef.current === 'draggingVertex' && transformStart && activeVertexIndex !== null) {
        let draggedPos = p;
        if (ui.snapToGrid) draggedPos = snapPointToGrid(p, ui.gridSize);

        const newPoints = [...transformStart.points];

        // UNIFIED GEOMETRY LOGIC: Maintain loop closure
        // If geometry was closed (A == Z), we must move both A and Z if one of them is grabbed.
        const len = newPoints.length;
        const isClosedGeometry = distance(newPoints[0], newPoints[len-1]) < 0.1;

        newPoints[activeVertexIndex] = { ...newPoints[activeVertexIndex], x: draggedPos.x, y: draggedPos.y };

        if (isClosedGeometry) {
            if (activeVertexIndex === 0) newPoints[len-1] = { ...newPoints[len-1], x: draggedPos.x, y: draggedPos.y };
            else if (activeVertexIndex === len-1) newPoints[0] = { ...newPoints[0], x: draggedPos.x, y: draggedPos.y };
        }

        if (ui.selectedStrokeId) {
            updateStrokeInCurrentKeyframe(ui.selectedStrokeId, newPoints);
            // Update local ref to keep editing fluid without re-setting transformStart
             setTransformStart({
                 ...transformStart,
                 points: newPoints
             });
        }
        return;
    }

    if (interactionModeRef.current !== 'none' && transformStart && selectionBounds) {
        if (interactionModeRef.current === 'dragging') {
            let dx = p.x - transformStart.mouse.x; let dy = p.y - transformStart.mouse.y;
            if (ui.snapToGrid) {
                const targetX = transformStart.center.x + dx; const targetY = transformStart.center.y + dy;
                const snappedX = Math.round(targetX / ui.gridSize) * ui.gridSize; const snappedY = Math.round(targetY / ui.gridSize) * ui.gridSize;
                dx = snappedX - transformStart.center.x; dy = snappedY - transformStart.center.y;
            }
            setSelectionBounds({ ...selectionBounds, cx: transformStart.center.x + dx, cy: transformStart.center.y + dy });
        } else if (interactionModeRef.current === 'rotating') {
            const currentAngle = Math.atan2(p.y - selectionBounds.cy, p.x - selectionBounds.cx);
            const startAngle = Math.atan2(transformStart.mouse.y - selectionBounds.cy, transformStart.mouse.x - selectionBounds.cx);
            let dAngle = currentAngle - startAngle; let newRotation = transformStart.angle + dAngle;
            if (e.shiftKey) { const step = Math.PI / 12; newRotation = Math.round(newRotation / step) * step; }
            setSelectionBounds({ ...selectionBounds, rotation: newRotation });
        } else if (interactionModeRef.current === 'resizing' && activeHandle) {
            const unrotatedMouse = rotatePoint(p, transformStart.center, -transformStart.angle);
            const unrotatedStart = rotatePoint(transformStart.mouse, transformStart.center, -transformStart.angle);
            let dx = unrotatedMouse.x - unrotatedStart.x; let dy = unrotatedMouse.y - unrotatedStart.y;
            if (e.shiftKey) { const aspect = transformStart.width / transformStart.height; dy = (activeHandle === 'br' || activeHandle === 'tl') ? dx / aspect : -dx / aspect; }
            if (ui.snapToGrid && !e.shiftKey) { dx = Math.round(dx / ui.gridSize) * ui.gridSize; dy = Math.round(dy / ui.gridSize) * ui.gridSize; }
            let newW = transformStart.width; let newH = transformStart.height;
            if (activeHandle === 'br') { newW += dx * 2; newH += dy * 2; }
            if (activeHandle === 'tl') { newW -= dx * 2; newH -= dy * 2; }
            if (activeHandle === 'tr') { newW += dx * 2; newH -= dy * 2; }
            if (activeHandle === 'bl') { newW -= dx * 2; newH += dy * 2; }
            newW = Math.max(1, newW); newH = Math.max(1, newH);
            setSelectionBounds({ ...selectionBounds, width: newW, height: newH });
        }
        return;
    }

    if (interactionModeRef.current === 'drawing') {
        currentPointsRef.current.push(getSnappedPoint(p));
    }
  };

  const handlePointerUp = (e: React.PointerEvent) => {
    if (ui.mode !== 'play') {
       (e.target as Element).releasePointerCapture(e.pointerId);
    }

    // Finalize Transform (Drag/Rotate/Scale)
    if ((interactionModeRef.current === 'dragging' || interactionModeRef.current === 'rotating' || interactionModeRef.current === 'resizing') && transformStart && selectionBounds && ui.selectedStrokeId) {
        const scaleX = selectionBounds.width / transformStart.width;
        const scaleY = selectionBounds.height / transformStart.height;
        const dRot = selectionBounds.rotation - transformStart.angle;
        const dX = selectionBounds.cx - transformStart.center.x;
        const dY = selectionBounds.cy - transformStart.center.y;
        const newPoints = transformStart.points.map(pt => {
            let x = pt.x - transformStart.center.x; let y = pt.y - transformStart.center.y;
            x *= scaleX; y *= scaleY;
            const cos = Math.cos(dRot); const sin = Math.sin(dRot);
            const rx = x * cos - y * sin; const ry = x * sin + y * cos;
            return { x: rx + transformStart.center.x + dX, y: ry + transformStart.center.y + dY, pressure: pt.pressure };
        });
        updateStrokeInCurrentKeyframe(ui.selectedStrokeId, newPoints);
    }

    // DRAWING END
    if (interactionModeRef.current === 'drawing' && currentPointsRef.current.length > 1) {
        const points = [...currentPointsRef.current];
        const start = points[0];
        const end = points[points.length - 1];

        // AUTO-CLOSE LOGIC: 
        const isLoop = distance(start, end) < 20; 
        const shouldClose = isLoop && (ui.fillColor !== 'none');

        addStrokeToCurrentKeyframe(points, shouldClose);
    }
    setInteractionMode('none'); setActiveHandle(null); setTransformStart(null); setActiveVertexIndex(null); currentPointsRef.current = [];
  };

  // -- THE RENDER LOOP --
  // This loop depends mainly on canvas size to restart, but reads data from Refs to stay fresh.
  useLayoutEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    let animationFrameId: number;

    const render = (time: number) => {
      // 1. Calculate Delta Time for Physics
      if (!lastFrameTimeRef.current) lastFrameTimeRef.current = time;
      const dt = Math.min((time - lastFrameTimeRef.current) / 1000, 0.1); 
      lastFrameTimeRef.current = time;

      // 2. Read Fresh State from Refs
      const currentProject = projectRef.current;
      const currentUI = uiRef.current;
      const activeVertIdx = activeVertexIndexRef.current;

      // READ INTERACTIVE STATE FROM REFS
      const currentPolyline = polylinePointsRef.current;
      const currentSelectionBounds = selectionBoundsRef.current;
      const currentMousePos = mousePosRef.current;

      const dpr = currentUI.resolutionScale || window.devicePixelRatio || 1;
      const interpolationTargetCount = currentUI.performanceMode ? 80 : 200;

      // Ensure Canvas Size is correct 
      if (canvas.width !== CANVAS_WIDTH * dpr || canvas.height !== CANVAS_HEIGHT * dpr) {
          canvas.width = CANVAS_WIDTH * dpr;
          canvas.height = CANVAS_HEIGHT * dpr;
          ctx.scale(dpr, dpr);
      }

      // 3. PLAY MODE PHYSICS
      if (currentUI.mode === 'play') {
          const axisX = currentProject.axes.find(a => a.id === 'axis-x');
          const axisY = currentProject.axes.find(a => a.id === 'axis-y');

          if (axisX && axisY) {
              const targetX = targetAxesRef.current['axis-x'];
              const targetY = targetAxesRef.current['axis-y'];

              let nextX = axisX.currentValue;
              let nextY = axisY.currentValue;

              if (currentUI.playModePhysics) {
                  const stiffness = currentUI.springStiffness || 120;
                  const damping = currentUI.springDamping || 20;

                  const forceX = (targetX - nextX) * stiffness - velocityRef.current.x * damping;
                  const forceY = (targetY - nextY) * stiffness - velocityRef.current.y * damping;

                  velocityRef.current.x += forceX * dt;
                  velocityRef.current.y += forceY * dt;

                  nextX += velocityRef.current.x * dt;
                  nextY += velocityRef.current.y * dt;
              } else {
                  nextX = targetX;
                  nextY = targetY;
                  velocityRef.current = { x: 0, y: 0 };
              }

              if (Math.abs(nextX - axisX.currentValue) > 0.0001 || Math.abs(nextY - axisY.currentValue) > 0.0001) {
                  const clampedX = Math.max(0, Math.min(1, nextX));
                  const clampedY = Math.max(0, Math.min(1, nextY));
                  updateMultipleAxisValues({ 'axis-x': clampedX, 'axis-y': clampedY });
              }
          }
      } else {
           const curX = currentProject.axes.find(a => a.id === 'axis-x')?.currentValue || 0.5;
           const curY = currentProject.axes.find(a => a.id === 'axis-y')?.currentValue || 0.5;
           targetAxesRef.current = { 'axis-x': curX, 'axis-y': curY };
           velocityRef.current = { x: 0, y: 0 };
      }

      // 4. CLEAR & DRAW
      ctx.clearRect(0, 0, CANVAS_WIDTH, CANVAS_HEIGHT);
      ctx.fillStyle = '#FFFFFF';
      ctx.fillRect(0, 0, CANVAS_WIDTH, CANVAS_HEIGHT);

      // GRID
      if (currentUI.showGrid && currentUI.mode === 'edit') {
        ctx.fillStyle = '#D1D5DB';
        const gridSize = currentUI.gridSize;
        const centerX = CANVAS_WIDTH / 2;
        const centerY = CANVAS_HEIGHT / 2;
        const startX = (centerX % gridSize);
        const startY = (centerY % gridSize);
        for (let x = startX; x <= CANVAS_WIDTH; x += gridSize) {
           for (let y = startY; y <= CANVAS_HEIGHT; y += gridSize) {
              ctx.beginPath();
              ctx.arc(x, y, 1.5, 0, Math.PI * 2);
              ctx.fill();
           }
        }
      }

      // ONION SKIN
      if (currentUI.onionSkinEnabled && currentUI.mode === 'edit') {
         currentProject.keyframes.forEach(kf => {
           if (kf.id === currentUI.selectedKeyframeId) return; 
           ctx.globalAlpha = currentUI.onionSkinOpacity;
           kf.layerStates.forEach(ls => {
              if (ls.layerId !== currentUI.selectedLayerId) return;
              const stroke = ls.strokes[0];
              if (stroke && stroke.points.length > 1) {
                ctx.beginPath();
                ctx.moveTo(stroke.points[0].x, stroke.points[0].y);
                for (let i = 1; i < stroke.points.length; i++) ctx.lineTo(stroke.points[i].x, stroke.points[i].y);
                // NO CLOSE PATH
                ctx.strokeStyle = '#3B82F6'; 
                ctx.lineWidth = 1; 
                ctx.stroke();
              }
           });
           ctx.globalAlpha = 1.0;
         });
      }

      // INTERPOLATION RENDERING
      const currentAxesDict: Record<string, number> = {};
      currentProject.axes.forEach(a => currentAxesDict[a.id] = a.currentValue);

      currentProject.layers.forEach(layer => {
        if (!layer.visible) return;

        const layerRelevantKeyframes = currentProject.keyframes.filter(kf => {
            const ls = kf.layerStates.find(s => s.layerId === layer.id);
            return ls && ls.strokes.length > 0;
        });

        if (layerRelevantKeyframes.length === 0) return;

        const weights = calculateInterpolationWeights(currentAxesDict, layerRelevantKeyframes, currentUI.interpolationExponent, currentUI.interpolationStrategy);

        const activeKeyframes = layerRelevantKeyframes
             .map(k => ({ ...k, weight: weights[k.id] || 0 }))
             .filter(k => k.weight > 0.0001);

        const strokeId = `stroke-${layer.id}-unique`;
        const isLayerActive = layer.id === currentUI.selectedLayerId;
        const isCreatingNewState = currentUI.selectedKeyframeId === null;

        let layerGlobalAlpha = layer.opacity;
        if (!isLayerActive && currentUI.mode !== 'play') layerGlobalAlpha *= currentUI.inactiveLayerOpacity;
        if (isCreatingNewState && currentUI.mode === 'edit') layerGlobalAlpha *= currentUI.ghostStrokeOpacity;

        const strokeData = activeKeyframes.map(kf => {
            const state = kf.layerStates.find(ls => ls.layerId === layer.id);
            const s = state?.strokes[0]; 
            return { weight: kf.weight, points: s?.points, style: s, color: s?.color || 'none', fillColor: s?.fillColor, width: s?.width || 1 };
        });

        const sortedByWeight = [...strokeData].sort((a,b) => b.weight - a.weight);
        const primaryStroke = sortedByWeight.find(sd => sd.style)?.style;
        if (!primaryStroke) return;

        const { points: interpolatedPoints, color: interpolatedColor, fillColor: interpolatedFill, width: interpolatedWidth } = interpolateStrokePoints(
            strokeId, 
            primaryStroke.points, 
            strokeData, 
            layer.interpolationMode,
            interpolationTargetCount 
        );

        if (interpolatedPoints.length > 0) {
            ctx.beginPath();
            ctx.moveTo(interpolatedPoints[0].x, interpolatedPoints[0].y);
            for (let i = 1; i < interpolatedPoints.length; i++) ctx.lineTo(interpolatedPoints[i].x, interpolatedPoints[i].y);

            // REMOVED ctx.closePath() - Pure geometric closure only

            ctx.globalAlpha = layerGlobalAlpha;
            switch(layer.blendMode) {
                case 'multiply': ctx.globalCompositeOperation = 'multiply'; break;
                case 'screen': ctx.globalCompositeOperation = 'screen'; break;
                case 'overlay': ctx.globalCompositeOperation = 'overlay'; break;
                case 'difference': ctx.globalCompositeOperation = 'difference'; break;
                case 'exclusion': ctx.globalCompositeOperation = 'exclusion'; break;
                default: ctx.globalCompositeOperation = 'source-over';
            }

            if (interpolatedFill && interpolatedFill !== 'none') {
                ctx.fillStyle = interpolatedFill;
                ctx.fill();
            }
            if (interpolatedColor && interpolatedColor !== 'none') {
                ctx.lineCap = 'round';
                ctx.lineJoin = 'round';
                ctx.strokeStyle = interpolatedColor;
                ctx.lineWidth = interpolatedWidth;
                ctx.stroke();
            }

            ctx.globalAlpha = 1.0;
            ctx.globalCompositeOperation = 'source-over';
        }
      });

      // ACTIVE DRAWING (Using Refs)
      if (interactionModeRef.current === 'drawing' && currentPointsRef.current.length > 0) {
        const isGhostState = currentUI.selectedKeyframeId === null;
        ctx.globalAlpha = isGhostState ? currentUI.ghostStrokeOpacity : 1.0;

        ctx.beginPath();
        const pts = currentPointsRef.current;
        ctx.moveTo(pts[0].x, pts[0].y);
        for (let i = 1; i < pts.length; i++) ctx.lineTo(pts[i].x, pts[i].y);
        ctx.strokeStyle = currentUI.brushColor !== 'none' ? currentUI.brushColor : 'rgba(0,0,0,0.2)'; 
        ctx.lineWidth = currentUI.brushSize;
        ctx.lineCap = 'round';
        ctx.lineJoin = 'round';
        ctx.stroke();
        ctx.globalAlpha = 1.0; 
      }

      // ACTIVE POLYLINE (Using Synced Refs)
      if (currentPolyline.length > 0) {
         const isGhostState = currentUI.selectedKeyframeId === null;
         ctx.globalAlpha = isGhostState ? currentUI.ghostStrokeOpacity : 1.0;

         ctx.beginPath();
         ctx.moveTo(currentPolyline[0].x, currentPolyline[0].y);
         for (let i = 1; i < currentPolyline.length; i++) ctx.lineTo(currentPolyline[i].x, currentPolyline[i].y);

         if (currentMousePos) ctx.lineTo(currentMousePos.x, currentMousePos.y); 

         if (currentUI.fillColor !== 'none') {
             ctx.fillStyle = currentUI.fillColor;
             ctx.globalAlpha = isGhostState ? currentUI.ghostStrokeOpacity * 0.5 : 0.5;
             ctx.fill();
             ctx.globalAlpha = isGhostState ? currentUI.ghostStrokeOpacity : 1.0;
         }

         ctx.strokeStyle = currentUI.brushColor !== 'none' ? currentUI.brushColor : 'rgba(0,0,0,0.5)';
         ctx.lineWidth = currentUI.brushSize;
         ctx.stroke();

         ctx.fillStyle = currentUI.brushColor !== 'none' ? currentUI.brushColor : 'rgba(0,0,0,0.5)';
         currentPolyline.forEach((p, index) => {
            ctx.beginPath();
            const r = (index === 0) ? 5 : 3; 
            ctx.arc(p.x, p.y, r, 0, Math.PI * 2);
            ctx.fill();
         });
         ctx.globalAlpha = 1.0; 
      }

      // SELECTION GIZMO & VERTEX HANDLES
      if (currentSelectionBounds && currentUI.selectedTool === 'select' && currentUI.mode === 'edit') {
          const { cx, cy, width, height, rotation } = currentSelectionBounds;

          // 1. Draw Bounding Box & Gizmo
          ctx.save();
          ctx.translate(cx, cy);
          ctx.rotate(rotation);

          ctx.beginPath();
          ctx.strokeStyle = '#3B82F6';
          ctx.lineWidth = 1;
          ctx.rect(-width/2, -height/2, width, height);
          ctx.stroke();

          const HANDLE_SIZE = 8; 
          ctx.fillStyle = '#FFFFFF';
          ctx.strokeStyle = '#3B82F6';

          const drawHandle = (x: number, y: number) => {
              ctx.beginPath();
              ctx.rect(x - HANDLE_SIZE/2, y - HANDLE_SIZE/2, HANDLE_SIZE, HANDLE_SIZE);
              ctx.fill();
              ctx.stroke();
          };

          drawHandle(-width/2, -height/2); // TL
          drawHandle(width/2, -height/2);  // TR
          drawHandle(-width/2, height/2);  // BL
          drawHandle(width/2, height/2);   // BR

          ctx.beginPath();
          ctx.moveTo(0, -height/2);
          ctx.lineTo(0, -height/2 - 25);
          ctx.stroke();

          ctx.beginPath();
          ctx.arc(0, -height/2 - 25, 4, 0, Math.PI * 2);
          ctx.fillStyle = '#3B82F6';
          ctx.fill();

          ctx.restore();

          // 2. Draw Vertex Handles (NEW)
          // We need the ACTUAL source stroke from the active keyframe, not the interpolated one.
          const activeKf = currentProject.keyframes.find(k => k.id === currentUI.selectedKeyframeId);
          if (activeKf) {
              const activeLayerState = activeKf.layerStates.find(ls => ls.layerId === currentUI.selectedLayerId);
              const activeStroke = activeLayerState?.strokes.find(s => s.id === currentUI.selectedStrokeId);

              if (activeStroke) {
                  const VERTEX_RADIUS = 3;
                  const ACTIVE_VERTEX_RADIUS = 5;

                  ctx.strokeStyle = '#3B82F6';
                  ctx.fillStyle = '#FFFFFF';

                  activeStroke.points.forEach((p, idx) => {
                      const isActive = idx === activeVertIdx;
                      ctx.beginPath();
                      ctx.arc(p.x, p.y, isActive ? ACTIVE_VERTEX_RADIUS : VERTEX_RADIUS, 0, Math.PI * 2);
                      ctx.fillStyle = isActive ? '#3B82F6' : '#FFFFFF';
                      ctx.fill();
                      ctx.stroke();
                  });
              }
          }
      }

      animationFrameId = requestAnimationFrame(render);
    };

    animationFrameId = requestAnimationFrame(render);
    return () => cancelAnimationFrame(animationFrameId);
  }, [CANVAS_WIDTH, CANVAS_HEIGHT]); // Minimized dependencies for loop stability

  return (
    <div 
      ref={containerRef} 
      className="absolute inset-0 z-0 flex items-center justify-center bg-[#EAEAEA] touch-none"
    >
      <div 
        style={{ 
          width: CANVAS_WIDTH, 
          height: CANVAS_HEIGHT,
          transform: `scale(${scale})`,
          boxShadow: '0 20px 50px -12px rgba(0, 0, 0, 0.15)' 
        }}
        className="bg-white rounded-xl overflow-hidden relative transition-transform duration-200 ease-out origin-center ring-4 ring-white/50"
      >
          <canvas 
            ref={canvasRef} 
            className={`block w-full h-full ${ui.mode === 'play' ? 'cursor-move' : (ui.selectedTool === 'select' ? 'cursor-default' : 'cursor-crosshair')}`}
            onPointerDown={handlePointerDown}
            onPointerMove={handlePointerMove}
            onPointerUp={handlePointerUp}
            onDoubleClick={handleDoubleClick}
          />
      </div>
    </div>
  );
};

// store/useStore.ts
import { create } from 'zustand';
import { Project, UIState, ToolType, Axis, Layer, Keyframe, Point, Stroke, LayerState, BlendMode, UIMode, InterpolationMode, InterpolationStrategy } from '../types';
import { DEFAULT_PROJECT, INITIAL_UI_STATE, DEFAULT_LAYER, DEFAULT_KEYFRAME } from '../constants';
import { simplifyPoints, distance, chaikinSmooth } from '../utils/math';

interface StoreState {
  project: Project;
  ui: UIState;

  history: {
    past: Project[];
    future: Project[];
  };

  isSettingsOpen: boolean;

  // Actions
  undo: () => void;
  redo: () => void;

  // Project Actions
  resetProject: () => void;
  loadProject: (project: Project) => void;

  toggleSettings: () => void;
  toggleLayerPanel: () => void;
  closeAllPanels: () => void; // Used for clicking outside

  setMode: (mode: UIMode) => void;

  setTool: (tool: ToolType) => void;
  setBrushColor: (color: string) => void;
  setFillColor: (color: string) => void;
  setBrushSize: (size: number) => void;

  // Config Actions
  toggleGrid: () => void;
  toggleSnapToGrid: () => void;

  toggleSnapPlayMode: () => void;
  toggleSnapMatrixGrid: () => void;
  setAxisMatrixDivisions: (val: number) => void;
  setAxisMatrixPadding: (val: number) => void;
  setInterpolationExponent: (val: number) => void;
  setInterpolationStrategy: (val: InterpolationStrategy) => void;

  togglePlayModePhysics: () => void;
  setSpringStiffness: (val: number) => void;
  setSpringDamping: (val: number) => void;

  setGridSize: (size: number) => void;
  toggleSmoothing: () => void; // Renamed from toggleSimplifyStrokes

  toggleOnionSkin: () => void;
  setOnionSkinOpacity: (opacity: number) => void;
  setInactiveLayerOpacity: (opacity: number) => void;
  setGhostStrokeOpacity: (opacity: number) => void;

  // Performance Actions
  setResolutionScale: (scale: number) => void;
  togglePerformanceMode: () => void;

  // Layer Actions
  addLayer: () => void;
  deleteLayer: (layerId: string) => void;
  renameLayer: (layerId: string, name: string) => void;
  reorderLayers: (fromIndex: number, toIndex: number) => void;
  toggleLayerVisibility: (layerId: string) => void;
  toggleLayerLock: (layerId: string) => void;
  setLayerBlendMode: (layerId: string, mode: BlendMode) => void;
  setLayerInterpolationMode: (layerId: string, mode: InterpolationMode) => void;
  selectLayer: (layerId: string) => void;

  updateAxisValue: (axisId: string, value: number) => void;
  updateMultipleAxisValues: (values: Record<string, number>) => void; // Batch update

  addStrokeToCurrentKeyframe: (points: Point[], closed?: boolean, skipSimplify?: boolean) => void; 
  updateStrokeInCurrentKeyframe: (strokeId: string, newPoints: Point[]) => void;
  deleteStroke: (strokeId: string) => void; 

  createKeyframeAtCurrentAxes: () => void;
  deleteKeyframe: (keyframeId: string) => void;
  updateKeyframePosition: (keyframeId: string, x: number, y: number) => void; // NEW ACTION
  selectKeyframe: (keyframeId: string) => void;

  selectStroke: (strokeId: string | null) => void;
}

const MAX_HISTORY = 50;

export const useStore = create<StoreState>((set, get) => ({
  project: DEFAULT_PROJECT,
  ui: INITIAL_UI_STATE,
  isSettingsOpen: false,

  history: {
    past: [],
    future: []
  },

  resetProject: () => set(() => ({
      project: {
          ...DEFAULT_PROJECT,
          id: `project-${Date.now()}`,
          created: Date.now(),
          modified: Date.now(),
          // Ensure distinct instances for object references
          layers: [{...DEFAULT_LAYER, id: `layer-${Date.now()}`}],
          keyframes: [{...DEFAULT_KEYFRAME, id: `kf-${Date.now()}`, layerStates: [{ layerId: `layer-${Date.now()}`, strokes: [] }] }]
      },
      ui: {
          ...INITIAL_UI_STATE,
          selectedLayerId: `layer-${Date.now()}`,
          selectedKeyframeId: `kf-${Date.now()}`
      },
      history: { past: [], future: [] }
  })),

  loadProject: (project) => set(() => ({
      project: project,
      ui: {
          ...INITIAL_UI_STATE,
          selectedLayerId: project.layers[0]?.id || null,
          selectedKeyframeId: project.keyframes[0]?.id || null
      },
      history: { past: [], future: [] }
  })),

  toggleSettings: () => set((state) => ({ isSettingsOpen: !state.isSettingsOpen, ui: { ...state.ui, isLayerPanelOpen: false } })),
  toggleLayerPanel: () => set((state) => ({ ui: { ...state.ui, isLayerPanelOpen: !state.ui.isLayerPanelOpen }, isSettingsOpen: false })),
  closeAllPanels: () => set((state) => ({ isSettingsOpen: false, ui: { ...state.ui, isLayerPanelOpen: false } })),

  setMode: (mode) => set((state) => ({ ui: { ...state.ui, mode } })),

  undo: () => set((state) => {
    if (state.history.past.length === 0) return state;
    const previous = state.history.past[state.history.past.length - 1];
    const newPast = state.history.past.slice(0, -1);
    return {
      project: previous,
      history: {
        past: newPast,
        future: [state.project, ...state.history.future]
      }
    };
  }),

  redo: () => set((state) => {
    if (state.history.future.length === 0) return state;
    const next = state.history.future[0];
    const newFuture = state.history.future.slice(1);
    return {
      project: next,
      history: {
        past: [...state.history.past, state.project],
        future: newFuture
      }
    };
  }),

  setTool: (tool) => set((state) => ({ ui: { ...state.ui, selectedTool: tool, selectedStrokeId: null } })),

  setBrushColor: (color) => set((state) => {
    let project = state.project;
    let history = state.history;

    // Try to update existing stroke if we are on a keyframe
    if (state.ui.selectedKeyframeId && state.ui.selectedLayerId) {
        const kfId = state.ui.selectedKeyframeId;
        const layerId = state.ui.selectedLayerId;

        const kfIndex = project.keyframes.findIndex(k => k.id === kfId);
        if (kfIndex > -1) {
             const kf = project.keyframes[kfIndex];
             const lsIndex = kf.layerStates.findIndex(ls => ls.layerId === layerId);

             if (lsIndex > -1 && kf.layerStates[lsIndex].strokes.length > 0) {
                 // Push to history
                 const past = [...state.history.past, state.project].slice(-MAX_HISTORY);

                 const newKeyframes = [...project.keyframes];
                 const newKf = { ...newKeyframes[kfIndex] };
                 const newLayerStates = [...newKf.layerStates];
                 const newLs = { ...newLayerStates[lsIndex] };
                 const newStrokes = [...newLs.strokes];

                 newStrokes[0] = { ...newStrokes[0], color: color === 'none' ? 'rgba(0,0,0,0)' : color };

                 newLs.strokes = newStrokes;
                 newLayerStates[lsIndex] = newLs;
                 newKf.layerStates = newLayerStates;
                 newKeyframes[kfIndex] = newKf;

                 project = { ...project, keyframes: newKeyframes };
                 history = { past, future: [] };
             }
        }
    }

    return { 
       ui: { ...state.ui, brushColor: color },
       project,
       history
    };
  }),

  setFillColor: (color) => set((state) => {
    let project = state.project;
    let history = state.history;

    if (state.ui.selectedKeyframeId && state.ui.selectedLayerId) {
        const kfId = state.ui.selectedKeyframeId;
        const layerId = state.ui.selectedLayerId;

        const kfIndex = project.keyframes.findIndex(k => k.id === kfId);
        if (kfIndex > -1) {
             const kf = project.keyframes[kfIndex];
             const lsIndex = kf.layerStates.findIndex(ls => ls.layerId === layerId);

             if (lsIndex > -1 && kf.layerStates[lsIndex].strokes.length > 0) {
                 const past = [...state.history.past, state.project].slice(-MAX_HISTORY);

                 const newKeyframes = [...project.keyframes];
                 const newKf = { ...newKeyframes[kfIndex] };
                 const newLayerStates = [...newKf.layerStates];
                 const newLs = { ...newLayerStates[lsIndex] };
                 const newStrokes = [...newLs.strokes];

                 newStrokes[0] = { ...newStrokes[0], fillColor: color };

                 newLs.strokes = newStrokes;
                 newLayerStates[lsIndex] = newLs;
                 newKf.layerStates = newLayerStates;
                 newKeyframes[kfIndex] = newKf;

                 project = { ...project, keyframes: newKeyframes };
                 history = { past, future: [] };
             }
        }
    }

    return { 
        ui: { ...state.ui, fillColor: color },
        project,
        history
    };
  }),

  setBrushSize: (size) => set((state) => {
    let project = state.project;
    let history = state.history;

    if (state.ui.selectedKeyframeId && state.ui.selectedLayerId) {
        const kfId = state.ui.selectedKeyframeId;
        const layerId = state.ui.selectedLayerId;

        const kfIndex = project.keyframes.findIndex(k => k.id === kfId);
        if (kfIndex > -1) {
             const kf = project.keyframes[kfIndex];
             const lsIndex = kf.layerStates.findIndex(ls => ls.layerId === layerId);

             if (lsIndex > -1 && kf.layerStates[lsIndex].strokes.length > 0) {
                 const past = [...state.history.past, state.project].slice(-MAX_HISTORY);

                 const newKeyframes = [...project.keyframes];
                 const newKf = { ...newKeyframes[kfIndex] };
                 const newLayerStates = [...newKf.layerStates];
                 const newLs = { ...newLayerStates[lsIndex] };
                 const newStrokes = [...newLs.strokes];

                 newStrokes[0] = { ...newStrokes[0], width: size };

                 newLs.strokes = newStrokes;
                 newLayerStates[lsIndex] = newLs;
                 newKf.layerStates = newLayerStates;
                 newKeyframes[kfIndex] = newKf;

                 project = { ...project, keyframes: newKeyframes };
                 history = { past, future: [] };
             }
        }
    }

    return { 
        ui: { ...state.ui, brushSize: size },
        project,
        history
    };
  }),

  toggleGrid: () => set((state) => ({ ui: { ...state.ui, showGrid: !state.ui.showGrid } })),
  toggleSnapToGrid: () => set((state) => ({ ui: { ...state.ui, snapToGrid: !state.ui.snapToGrid } })),

  toggleSnapPlayMode: () => set((state) => ({ ui: { ...state.ui, snapPlayMode: !state.ui.snapPlayMode } })),
  toggleSnapMatrixGrid: () => set((state) => ({ ui: { ...state.ui, snapMatrixGrid: !state.ui.snapMatrixGrid } })),
  setAxisMatrixDivisions: (val) => set((state) => ({ ui: { ...state.ui, axisMatrixDivisions: val } })),
  setAxisMatrixPadding: (val) => set((state) => ({ ui: { ...state.ui, axisMatrixPadding: val } })),
  setInterpolationExponent: (val) => set((state) => ({ ui: { ...state.ui, interpolationExponent: val } })),
  setInterpolationStrategy: (val) => set((state) => ({ ui: { ...state.ui, interpolationStrategy: val } })),

  togglePlayModePhysics: () => set((state) => ({ ui: { ...state.ui, playModePhysics: !state.ui.playModePhysics } })),
  setSpringStiffness: (val) => set((state) => ({ ui: { ...state.ui, springStiffness: val } })),
  setSpringDamping: (val) => set((state) => ({ ui: { ...state.ui, springDamping: val } })),

  setGridSize: (size) => set((state) => ({ ui: { ...state.ui, gridSize: size } })),
  toggleSmoothing: () => set((state) => ({ ui: { ...state.ui, smoothingEnabled: !state.ui.smoothingEnabled } })),

  toggleOnionSkin: () => set((state) => ({ ui: { ...state.ui, onionSkinEnabled: !state.ui.onionSkinEnabled } })),
  setOnionSkinOpacity: (opacity) => set((state) => ({ ui: { ...state.ui, onionSkinOpacity: opacity } })),
  setInactiveLayerOpacity: (opacity) => set((state) => ({ ui: { ...state.ui, inactiveLayerOpacity: opacity } })),
  setGhostStrokeOpacity: (opacity) => set((state) => ({ ui: { ...state.ui, ghostStrokeOpacity: opacity } })),

  setResolutionScale: (scale) => set((state) => ({ ui: { ...state.ui, resolutionScale: scale } })),
  togglePerformanceMode: () => set((state) => ({ ui: { ...state.ui, performanceMode: !state.ui.performanceMode } })),

  updateAxisValue: (axisId, value) => set((state) => {
    // Smooth value
    const cleanValue = Math.max(0, Math.min(1, value));

    const newAxes = state.project.axes.map(a => 
      a.id === axisId ? { ...a, currentValue: cleanValue } : a
    );

    const currentAxisValues: Record<string, number> = {};
    newAxes.forEach(a => currentAxisValues[a.id] = a.currentValue);

    // Strict Selection Logic:
    let matchingKfId = null;

    const exactMatch = state.project.keyframes.find(kf => {
      let dist = 0;
      for (const id in currentAxisValues) {
        dist += Math.abs((kf.axisValues[id] || 0) - currentAxisValues[id]);
      }
      return dist < 0.02; // Slightly wider threshold for snapping comfort
    });

    if (exactMatch) {
      matchingKfId = exactMatch.id;
    }

    return { 
      project: { ...state.project, axes: newAxes },
      ui: { ...state.ui, selectedKeyframeId: matchingKfId }
    };
  }),

  updateMultipleAxisValues: (values) => set((state) => {
    const newAxes = state.project.axes.map(a => 
       values[a.id] !== undefined ? { ...a, currentValue: Math.max(0, Math.min(1, values[a.id])) } : a
    );

    // No strict selection logic during fast playback updates to save cycles
    return {
        project: { ...state.project, axes: newAxes }
    };
  }),

  selectLayer: (layerId) => set((state) => ({ ui: { ...state.ui, selectedLayerId: layerId } })),
  selectKeyframe: (keyframeId) => set((state) => ({ ui: { ...state.ui, selectedKeyframeId: keyframeId } })),
  selectStroke: (strokeId) => set((state) => ({ ui: { ...state.ui, selectedStrokeId: strokeId } })),

  addLayer: () => set((state) => {
    const past = [...state.history.past, state.project].slice(-MAX_HISTORY);
    const newId = `layer-${Date.now()}`;
    const newLayer: Layer = {
      id: newId,
      name: `Layer ${state.project.layers.length + 1}`,
      visible: true,
      locked: false,
      blendMode: 'normal',
      opacity: 1,
      interpolationMode: 'resample'
    };
    return {
      project: { ...state.project, layers: [...state.project.layers, newLayer] },
      ui: { ...state.ui, selectedLayerId: newId },
      history: { past, future: [] }
    };
  }),

  reorderLayers: (fromIndex, toIndex) => set((state) => {
    if (fromIndex === toIndex) return state;
    const past = [...state.history.past, state.project].slice(-MAX_HISTORY);
    const newLayers = [...state.project.layers];
    const [moved] = newLayers.splice(fromIndex, 1);
    newLayers.splice(toIndex, 0, moved);

    return {
       project: { ...state.project, layers: newLayers },
       history: { past, future: [] }
    };
  }),

  deleteLayer: (layerId) => set((state) => {
    if (state.project.layers.length <= 1) return state; 
    const past = [...state.history.past, state.project].slice(-MAX_HISTORY);
    const newLayers = state.project.layers.filter(l => l.id !== layerId);

    const newKeyframes = state.project.keyframes.map(kf => ({
       ...kf,
       layerStates: kf.layerStates.filter(ls => ls.layerId !== layerId)
    }));

    return {
      project: { ...state.project, layers: newLayers, keyframes: newKeyframes },
      ui: { ...state.ui, selectedLayerId: newLayers[newLayers.length - 1].id },
      history: { past, future: [] }
    };
  }),

  renameLayer: (layerId, name) => set((state) => ({
    project: {
      ...state.project,
      layers: state.project.layers.map(l => l.id === layerId ? { ...l, name } : l)
    }
  })),

  toggleLayerVisibility: (layerId) => set((state) => ({
    project: {
      ...state.project,
      layers: state.project.layers.map(l => 
        l.id === layerId ? { ...l, visible: !l.visible } : l
      )
    }
  })),

  toggleLayerLock: (layerId) => set((state) => ({
    project: {
      ...state.project,
      layers: state.project.layers.map(l => 
        l.id === layerId ? { ...l, locked: !l.locked } : l
      )
    }
  })),

  setLayerBlendMode: (layerId, mode) => set((state) => {
    return {
      project: {
        ...state.project,
        layers: state.project.layers.map(l => 
          l.id === layerId ? { ...l, blendMode: mode } : l
        )
      }
    };
  }),

  setLayerInterpolationMode: (layerId, mode) => set((state) => {
    return {
      project: {
        ...state.project,
        layers: state.project.layers.map(l => 
          l.id === layerId ? { ...l, interpolationMode: mode } : l
        )
      }
    };
  }),

  addStrokeToCurrentKeyframe: (rawPoints, closed = false, skipSimplify = false) => set((state) => {
    const { selectedLayerId, brushColor, fillColor, brushSize, smoothingEnabled, snapToGrid } = state.ui;
    if (!selectedLayerId) return state;

    const layer = state.project.layers.find(l => l.id === selectedLayerId);
    if (layer?.locked || !layer?.visible) return state;

    // --- SMART SMOOTHING (CHAIKIN) ---
    let points = rawPoints;
    let shouldUpdateLayerMode = false;

    if (snapToGrid) {
        points = simplifyPoints(rawPoints, 2.5);
        if (layer.interpolationMode === 'resample') {
            shouldUpdateLayerMode = true;
        }
    } else if (!skipSimplify && smoothingEnabled) { 
       const preSimplified = simplifyPoints(rawPoints, 1.5);
       points = chaikinSmooth(preSimplified, 2);
    } else if (!skipSimplify && !smoothingEnabled) {
       points = simplifyPoints(rawPoints, 1.5);
    }

    // --- GEOMETRIC CLOSURE ---
    // If 'closed' was requested (via UI or loop detection), we physically append 
    // the start point to the end to close the geometry.
    // We then set the 'closed' flag to FALSE because logically it is now an open line that loops.
    if (closed && points.length > 0) {
        points = [...points, points[0]];
    }

    const past = [...state.history.past, state.project].slice(-MAX_HISTORY);

    // --- STATE PREPARATION ---

    let updatedLayers = [...state.project.layers];
    if (shouldUpdateLayerMode) {
        updatedLayers = updatedLayers.map(l => 
            l.id === selectedLayerId ? { ...l, interpolationMode: 'points' } : l
        );
    }

    const currentAxisValues: Record<string, number> = {};
    state.project.axes.forEach(a => currentAxisValues[a.id] = a.currentValue);

    let targetKeyframeId = state.ui.selectedKeyframeId;
    let keyframes = [...state.project.keyframes];

    if (targetKeyframeId === null) {
      const newKfId = `kf-${Date.now()}`;
      const newKeyframe: Keyframe = {
        id: newKfId,
        name: `Keyframe ${keyframes.length}`,
        axisValues: currentAxisValues,
        layerStates: [] 
      };
      keyframes.push(newKeyframe);
      targetKeyframeId = newKfId;
    }

    const newStroke: Stroke = {
      id: `stroke-${selectedLayerId}-unique`,
      points,
      color: brushColor as string, 
      fillColor: fillColor,
      width: brushSize,
      style: 'solid',
      closed: false // FORCE FALSE: We rely on geometric closure (A...A)
    };

    const newKeyframes = keyframes.map(kf => {
      if (kf.id === targetKeyframeId) {
        const existingLayerStateIndex = kf.layerStates.findIndex(ls => ls.layerId === selectedLayerId);
        let newLayerStates = [...kf.layerStates];

        if (existingLayerStateIndex >= 0) {
          newLayerStates[existingLayerStateIndex] = {
            ...newLayerStates[existingLayerStateIndex],
            strokes: [newStroke]
          };
        } else {
          newLayerStates.push({
            layerId: selectedLayerId,
            strokes: [newStroke]
          });
        }
        return { ...kf, layerStates: newLayerStates };
      }
      return kf;
    });

    return { 
      project: { ...state.project, keyframes: newKeyframes, layers: updatedLayers },
      ui: { ...state.ui, selectedKeyframeId: targetKeyframeId },
      history: { past, future: [] }
    };
  }),

  updateStrokeInCurrentKeyframe: (strokeId, newPoints) => set((state) => {
    const kfId = state.ui.selectedKeyframeId;
    if (!kfId) return state;

    const keyframes = state.project.keyframes.map(kf => {
      if (kf.id === kfId) {
         const newLayerStates = kf.layerStates.map(ls => {
            if (ls.layerId === state.ui.selectedLayerId) {
               return {
                  ...ls,
                  strokes: ls.strokes.map(s => ({ ...s, points: newPoints }))
               };
            }
            return ls;
         });
         return { ...kf, layerStates: newLayerStates };
      }
      return kf;
    });

    return { project: { ...state.project, keyframes }};
  }),

  deleteStroke: (strokeId) => set((state) => {
     const kfId = state.ui.selectedKeyframeId;
     const layerId = state.ui.selectedLayerId;
     if (!kfId || !layerId) return state;

     const past = [...state.history.past, state.project].slice(-MAX_HISTORY);

     const newKeyframes = state.project.keyframes.map(kf => {
         if (kf.id === kfId) {
             const newLayerStates = kf.layerStates.map(ls => {
                 if (ls.layerId === layerId) {
                     return {
                         ...ls,
                         strokes: ls.strokes.filter(s => s.id !== strokeId)
                     };
                 }
                 return ls;
             });
             return { ...kf, layerStates: newLayerStates };
         }
         return kf;
     });

     return {
         project: { ...state.project, keyframes: newKeyframes },
         ui: { ...state.ui, selectedStrokeId: null }, // Clear selection
         history: { past, future: [] }
     };
  }),

  createKeyframeAtCurrentAxes: () => set((state) => {
     const currentAxisValues: Record<string, number> = {};
     state.project.axes.forEach(a => currentAxisValues[a.id] = a.currentValue);

     const newKeyframe: Keyframe = {
        id: `kf-${Date.now()}`,
        name: `Keyframe ${state.project.keyframes.length}`,
        axisValues: currentAxisValues,
        layerStates: []
      };

      return {
        project: { ...state.project, keyframes: [...state.project.keyframes, newKeyframe] },
        ui: { ...state.ui, selectedKeyframeId: newKeyframe.id }
      };
  }),

  deleteKeyframe: (keyframeId) => set((state) => {
    if (state.project.keyframes.length <= 1) return state; 
    const past = [...state.history.past, state.project].slice(-MAX_HISTORY);
    const newKeyframes = state.project.keyframes.filter(k => k.id !== keyframeId);

    let newSelectedId = state.ui.selectedKeyframeId;
    if (keyframeId === newSelectedId) {
      newSelectedId = newKeyframes[0].id;
    }

    return {
      project: { ...state.project, keyframes: newKeyframes },
      ui: { ...state.ui, selectedKeyframeId: newSelectedId },
      history: { past, future: [] }
    };
  }),

  updateKeyframePosition: (keyframeId, x, y) => set((state) => {
     const past = [...state.history.past, state.project].slice(-MAX_HISTORY);

     // 1. Update Keyframe Data
     const newKeyframes = state.project.keyframes.map(kf => {
         if (kf.id === keyframeId) {
             return {
                 ...kf,
                 axisValues: {
                     ...kf.axisValues,
                     'axis-x': x,
                     'axis-y': y
                 }
             };
         }
         return kf;
     });

     // 2. If moving the selected keyframe, update the View Axes too so we stay "on it"
     let newAxes = state.project.axes;
     if (state.ui.selectedKeyframeId === keyframeId) {
         newAxes = state.project.axes.map(a => {
             if (a.id === 'axis-x') return { ...a, currentValue: x };
             if (a.id === 'axis-y') return { ...a, currentValue: y };
             return a;
         });
     }

     return {
         project: { ...state.project, keyframes: newKeyframes, axes: newAxes },
         history: { past, future: [] }
     };
  })
}));

// components/AxisMap.tsx
import React, { useRef, useState, useEffect } from 'react';
import { useStore } from '../store/useStore';
import { APP_COLORS } from '../constants';
import { distance } from '../utils/math';

export const AxisMap: React.FC = () => {
  const { project, updateAxisValue, ui, selectKeyframe, deleteKeyframe, updateKeyframePosition } = useStore();
  const containerRef = useRef<HTMLDivElement>(null);
  const [draggingKfId, setDraggingKfId] = useState<string | null>(null);

  const axisX = project.axes.find(a => a.id === 'axis-x');
  const axisY = project.axes.find(a => a.id === 'axis-y');

  if (!axisX || !axisY) return null;

  // -- Helpers --

  const getAxisValuesFromEvent = (e: React.PointerEvent) => {
      if (!containerRef.current) return { x: 0, y: 0 };
      const rect = containerRef.current.getBoundingClientRect();
      const rawX = Math.max(0, Math.min(1, (e.clientX - rect.left) / rect.width));
      const rawY = Math.max(0, Math.min(1, (e.clientY - rect.top) / rect.height));

      const padding = ui.axisMatrixPadding;
      const effectiveSize = 1 - (padding * 2);
      let x = rawX;
      let y = rawY;

      if (ui.snapMatrixGrid) {
          const steps = ui.axisMatrixDivisions - 1;
          if (steps > 0) {
              const relativeX = (rawX - padding) / effectiveSize;
              const relativeY = (rawY - padding) / effectiveSize;
              const snappedRelX = Math.round(relativeX * steps) / steps;
              const snappedRelY = Math.round(relativeY * steps) / steps;

              x = padding + (snappedRelX * effectiveSize);
              y = padding + (snappedRelY * effectiveSize);

              x = Math.max(padding, Math.min(1 - padding, x));
              y = Math.max(padding, Math.min(1 - padding, y));
          }
      }
      return { x, y, rawX, rawY }; // Return raw for hit testing if needed
  };

  const findHitKeyframe = (x: number, y: number) => {
      // Find the keyframe closest to (x,y) within a tolerance
      // Coordinates are 0-1
      const HIT_TOLERANCE = 0.05; // 5% of width

      // Sort by distance to find closest top-most
      const sorted = [...project.keyframes].map(kf => {
          const kx = kf.axisValues[axisX.id] ?? 0.5;
          const ky = kf.axisValues[axisY.id] ?? 0.5;
          const dist = Math.sqrt(Math.pow(kx - x, 2) + Math.pow(ky - y, 2));
          return { id: kf.id, dist };
      }).sort((a,b) => a.dist - b.dist);

      if (sorted.length > 0 && sorted[0].dist < HIT_TOLERANCE) {
          return sorted[0].id;
      }
      return null;
  };

  // -- Event Handlers --

  const handlePointerDown = (e: React.PointerEvent) => {
    (e.target as Element).setPointerCapture(e.pointerId);

    // Calculate Click Position (Raw and Snapped)
    if (!containerRef.current) return;
    const rect = containerRef.current.getBoundingClientRect();
    const rawX = (e.clientX - rect.left) / rect.width;
    const rawY = (e.clientY - rect.top) / rect.height;

    // 1. Hit Test Keyframes first
    const hitId = findHitKeyframe(rawX, rawY);

    if (hitId) {
        setDraggingKfId(hitId);
        selectKeyframe(hitId); // Select it immediately
    } else {
        // 2. Else, move cursor
        const { x, y } = getAxisValuesFromEvent(e);
        updateAxisValue(axisX.id, x);
        updateAxisValue(axisY.id, y);
    }
  };

  const handlePointerMove = (e: React.PointerEvent) => {
    if (e.buttons === 0) return;

    const { x, y } = getAxisValuesFromEvent(e);

    if (draggingKfId) {
        // Drag Keyframe
        updateKeyframePosition(draggingKfId, x, y);
    } else {
        // Drag Cursor
        updateAxisValue(axisX.id, x);
        updateAxisValue(axisY.id, y);
    }
  };

  const handlePointerUp = (e: React.PointerEvent) => {
    (e.target as Element).releasePointerCapture(e.pointerId);
    setDraggingKfId(null);
  };

  const selectedKf = project.keyframes.find(k => k.id === ui.selectedKeyframeId);

  // Grid Lines Generation
  const gridLines = [];
  const padding = ui.axisMatrixPadding;
  const effectiveSize = 1 - (padding * 2);
  const steps = ui.axisMatrixDivisions - 1;

  if (steps > 0) {
      for (let i = 0; i <= steps; i++) {
          const pos = padding + (i / steps) * effectiveSize;
          const pct = pos * 100;

          gridLines.push(
              <div key={`v-${i}`} className="absolute top-0 bottom-0 border-l border-gray-100 pointer-events-none" style={{ left: `${pct}%`, top: `${padding*100}%`, bottom: `${padding*100}%` }} />
          );
          gridLines.push(
              <div key={`h-${i}`} className="absolute left-0 right-0 border-t border-gray-100 pointer-events-none" style={{ top: `${pct}%`, left: `${padding*100}%`, right: `${padding*100}%` }} />
          );
      }
  }

  return (
    <div className="fixed bottom-6 left-6 z-50 flex flex-col gap-2">
      <div className="bg-white/90 backdrop-blur-md rounded-2xl shadow-xl border border-gray-200 p-3 w-48">
        <div className="flex justify-between items-center mb-2">
          <span className="text-[10px] uppercase font-bold text-gray-400">Interpolation Matrix</span>

          <div className="flex items-center gap-1">
             {selectedKf && project.keyframes.length > 1 && (
                <button 
                  onClick={() => deleteKeyframe(selectedKf.id)}
                  className="text-[10px] text-red-500 hover:bg-red-50 px-2 py-0.5 rounded"
                >
                  Delete State
                </button>
             )}
          </div>
        </div>

        <div 
          ref={containerRef}
          className="relative w-full aspect-square bg-white rounded-lg border border-gray-200 cursor-crosshair overflow-hidden shadow-inner touch-none"
          onPointerDown={handlePointerDown}
          onPointerMove={handlePointerMove}
          onPointerUp={handlePointerUp}
        >
          {/* Configurable Grid */}
          {gridLines}

          {/* Keyframes Dots */}
          {project.keyframes.map(kf => {
            const kfX = kf.axisValues[axisX.id] ?? 0.5;
            const kfY = kf.axisValues[axisY.id] ?? 0.5;

            const isSelected = ui.selectedKeyframeId === kf.id;
            const isDragging = draggingKfId === kf.id;

            const hasDataForCurrentLayer = kf.layerStates.some(ls => ls.layerId === ui.selectedLayerId && ls.strokes.length > 0);

            return (
              <div
                key={kf.id}
                className={`absolute -ml-1.5 -mt-1.5 rounded-full transition-transform pointer-events-none flex items-center justify-center ${
                    isSelected ? 'z-20 scale-125' : 'z-10'
                } ${isDragging ? 'scale-150' : ''}`}
                style={{ 
                    left: `${kfX * 100}%`, 
                    top: `${kfY * 100}%`,
                    width: '12px',
                    height: '12px',
                }}
              >
                  {isSelected && (
                      <div className={`absolute inset-0 rounded-full border-2 border-blue-500 shadow-sm ${isDragging ? 'border-4' : 'animate-pulse'}`} />
                  )}

                  <div className={`rounded-full ${
                      hasDataForCurrentLayer
                        ? 'w-2 h-2 bg-gray-800' 
                        : 'w-2 h-2 border border-gray-300 bg-white' 
                  }`} />
              </div>
            );
          })}

          {/* Current Cursor */}
          <div 
            className="absolute w-4 h-4 -ml-2 -mt-2 pointer-events-none z-30 transition-opacity duration-200"
            style={{ 
                left: `${axisX.currentValue * 100}%`, 
                top: `${axisY.currentValue * 100}%`,
                opacity: draggingKfId ? 0.5 : 1 // Dim cursor when dragging a keyframe
            }}
          >
             <svg viewBox="0 0 24 24" fill="none" stroke={APP_COLORS.primary} strokeWidth="3">
               <line x1="12" y1="0" x2="12" y2="24" />
               <line x1="0" y1="12" x2="24" y2="12" />
             </svg>
          </div>
        </div>

        <div className="mt-2 flex justify-between text-[10px] text-gray-400 font-mono">
          <span>{draggingKfId ? 'DRAGGING' : `X: ${(axisX.currentValue * 100).toFixed(1)}%`}</span>
          <span>{draggingKfId ? 'STATE' : `Y: ${(axisY.currentValue * 100).toFixed(1)}%`}</span>
        </div>
      </div>
    </div>
  );
};

// store/useStore.ts
import { create } from 'zustand';
import { Project, UIState, ToolType, Axis, Layer, Keyframe, Point, Stroke, LayerState, BlendMode, UIMode, InterpolationMode, InterpolationStrategy } from '../types';
import { DEFAULT_PROJECT, INITIAL_UI_STATE, DEFAULT_LAYER, DEFAULT_KEYFRAME } from '../constants';
import { simplifyPoints, distance, chaikinSmooth } from '../utils/math';

interface StoreState {
  project: Project;
  ui: UIState;

  history: {
    past: Project[];
    future: Project[];
  };

  // Internal Clipboard for Copy/Paste State
  clipboard: LayerState[] | null; 

  isSettingsOpen: boolean;

  // Actions
  undo: () => void;
  redo: () => void;

  // Project Actions
  resetProject: () => void;
  loadProject: (project: Project) => void;

  toggleSettings: () => void;
  toggleLayerPanel: () => void;
  closeAllPanels: () => void; // Used for clicking outside

  setMode: (mode: UIMode) => void;

  setTool: (tool: ToolType) => void;
  setBrushColor: (color: string) => void;
  setFillColor: (color: string) => void;
  setBrushSize: (size: number) => void;

  // Config Actions
  toggleGrid: () => void;
  toggleSnapToGrid: () => void;

  toggleSnapPlayMode: () => void;
  toggleSnapMatrixGrid: () => void;
  setAxisMatrixDivisions: (val: number) => void;
  setAxisMatrixPadding: (val: number) => void;
  setInterpolationExponent: (val: number) => void;
  setInterpolationStrategy: (val: InterpolationStrategy) => void;

  togglePlayModePhysics: () => void;
  setSpringStiffness: (val: number) => void;
  setSpringDamping: (val: number) => void;

  setGridSize: (size: number) => void;
  toggleSmoothing: () => void; // Renamed from toggleSimplifyStrokes

  toggleOnionSkin: () => void;
  setOnionSkinOpacity: (opacity: number) => void;
  setInactiveLayerOpacity: (opacity: number) => void;
  setGhostStrokeOpacity: (opacity: number) => void;

  // Performance Actions
  setResolutionScale: (scale: number) => void;
  togglePerformanceMode: () => void;

  // Layer Actions
  addLayer: () => void;
  deleteLayer: (layerId: string) => void;
  renameLayer: (layerId: string, name: string) => void;
  reorderLayers: (fromIndex: number, toIndex: number) => void;
  toggleLayerVisibility: (layerId: string) => void;
  toggleLayerLock: (layerId: string) => void;
  setLayerBlendMode: (layerId: string, mode: BlendMode) => void;
  setLayerInterpolationMode: (layerId: string, mode: InterpolationMode) => void;
  selectLayer: (layerId: string) => void;

  updateAxisValue: (axisId: string, value: number) => void;
  updateMultipleAxisValues: (values: Record<string, number>) => void; // Batch update

  addStrokeToCurrentKeyframe: (points: Point[], closed?: boolean, skipSimplify?: boolean) => void; 
  updateStrokeInCurrentKeyframe: (strokeId: string, newPoints: Point[]) => void;
  deleteStroke: (strokeId: string) => void; 

  createKeyframeAtCurrentAxes: () => void;
  deleteKeyframe: (keyframeId: string) => void;
  updateKeyframePosition: (keyframeId: string, x: number, y: number) => void; 
  selectKeyframe: (keyframeId: string) => void;

  // Copy/Paste Actions
  copyKeyframeState: () => void;
  pasteKeyframeState: () => void;

  selectStroke: (strokeId: string | null) => void;
}

const MAX_HISTORY = 50;

export const useStore = create<StoreState>((set, get) => ({
  project: DEFAULT_PROJECT,
  ui: INITIAL_UI_STATE,
  isSettingsOpen: false,
  clipboard: null, // Initialize clipboard

  history: {
    past: [],
    future: []
  },

  resetProject: () => set(() => ({
      project: {
          ...DEFAULT_PROJECT,
          id: `project-${Date.now()}`,
          created: Date.now(),
          modified: Date.now(),
          // Ensure distinct instances for object references
          layers: [{...DEFAULT_LAYER, id: `layer-${Date.now()}`}],
          keyframes: [{...DEFAULT_KEYFRAME, id: `kf-${Date.now()}`, layerStates: [{ layerId: `layer-${Date.now()}`, strokes: [] }] }]
      },
      ui: {
          ...INITIAL_UI_STATE,
          selectedLayerId: `layer-${Date.now()}`,
          selectedKeyframeId: `kf-${Date.now()}`
      },
      clipboard: null,
      history: { past: [], future: [] }
  })),

  loadProject: (project) => set(() => ({
      project: project,
      ui: {
          ...INITIAL_UI_STATE,
          selectedLayerId: project.layers[0]?.id || null,
          selectedKeyframeId: project.keyframes[0]?.id || null
      },
      clipboard: null,
      history: { past: [], future: [] }
  })),

  toggleSettings: () => set((state) => ({ isSettingsOpen: !state.isSettingsOpen, ui: { ...state.ui, isLayerPanelOpen: false } })),
  toggleLayerPanel: () => set((state) => ({ ui: { ...state.ui, isLayerPanelOpen: !state.ui.isLayerPanelOpen }, isSettingsOpen: false })),
  closeAllPanels: () => set((state) => ({ isSettingsOpen: false, ui: { ...state.ui, isLayerPanelOpen: false } })),

  setMode: (mode) => set((state) => ({ ui: { ...state.ui, mode } })),

  undo: () => set((state) => {
    if (state.history.past.length === 0) return state;
    const previous = state.history.past[state.history.past.length - 1];
    const newPast = state.history.past.slice(0, -1);
    return {
      project: previous,
      history: {
        past: newPast,
        future: [state.project, ...state.history.future]
      }
    };
  }),

  redo: () => set((state) => {
    if (state.history.future.length === 0) return state;
    const next = state.history.future[0];
    const newFuture = state.history.future.slice(1);
    return {
      project: next,
      history: {
        past: [...state.history.past, state.project],
        future: newFuture
      }
    };
  }),

  setTool: (tool) => set((state) => ({ ui: { ...state.ui, selectedTool: tool, selectedStrokeId: null } })),

  setBrushColor: (color) => set((state) => {
    let project = state.project;
    let history = state.history;

    // Try to update existing stroke if we are on a keyframe
    if (state.ui.selectedKeyframeId && state.ui.selectedLayerId) {
        const kfId = state.ui.selectedKeyframeId;
        const layerId = state.ui.selectedLayerId;

        const kfIndex = project.keyframes.findIndex(k => k.id === kfId);
        if (kfIndex > -1) {
             const kf = project.keyframes[kfIndex];
             const lsIndex = kf.layerStates.findIndex(ls => ls.layerId === layerId);

             if (lsIndex > -1 && kf.layerStates[lsIndex].strokes.length > 0) {
                 // Push to history
                 const past = [...state.history.past, state.project].slice(-MAX_HISTORY);

                 const newKeyframes = [...project.keyframes];
                 const newKf = { ...newKeyframes[kfIndex] };
                 const newLayerStates = [...newKf.layerStates];
                 const newLs = { ...newLayerStates[lsIndex] };
                 const newStrokes = [...newLs.strokes];

                 newStrokes[0] = { ...newStrokes[0], color: color === 'none' ? 'rgba(0,0,0,0)' : color };

                 newLs.strokes = newStrokes;
                 newLayerStates[lsIndex] = newLs;
                 newKf.layerStates = newLayerStates;
                 newKeyframes[kfIndex] = newKf;

                 project = { ...project, keyframes: newKeyframes };
                 history = { past, future: [] };
             }
        }
    }

    return { 
       ui: { ...state.ui, brushColor: color },
       project,
       history
    };
  }),

  setFillColor: (color) => set((state) => {
    let project = state.project;
    let history = state.history;

    if (state.ui.selectedKeyframeId && state.ui.selectedLayerId) {
        const kfId = state.ui.selectedKeyframeId;
        const layerId = state.ui.selectedLayerId;

        const kfIndex = project.keyframes.findIndex(k => k.id === kfId);
        if (kfIndex > -1) {
             const kf = project.keyframes[kfIndex];
             const lsIndex = kf.layerStates.findIndex(ls => ls.layerId === layerId);

             if (lsIndex > -1 && kf.layerStates[lsIndex].strokes.length > 0) {
                 const past = [...state.history.past, state.project].slice(-MAX_HISTORY);

                 const newKeyframes = [...project.keyframes];
                 const newKf = { ...newKeyframes[kfIndex] };
                 const newLayerStates = [...newKf.layerStates];
                 const newLs = { ...newLayerStates[lsIndex] };
                 const newStrokes = [...newLs.strokes];

                 newStrokes[0] = { ...newStrokes[0], fillColor: color };

                 newLs.strokes = newStrokes;
                 newLayerStates[lsIndex] = newLs;
                 newKf.layerStates = newLayerStates;
                 newKeyframes[kfIndex] = newKf;

                 project = { ...project, keyframes: newKeyframes };
                 history = { past, future: [] };
             }
        }
    }

    return { 
        ui: { ...state.ui, fillColor: color },
        project,
        history
    };
  }),

  setBrushSize: (size) => set((state) => {
    let project = state.project;
    let history = state.history;

    if (state.ui.selectedKeyframeId && state.ui.selectedLayerId) {
        const kfId = state.ui.selectedKeyframeId;
        const layerId = state.ui.selectedLayerId;

        const kfIndex = project.keyframes.findIndex(k => k.id === kfId);
        if (kfIndex > -1) {
             const kf = project.keyframes[kfIndex];
             const lsIndex = kf.layerStates.findIndex(ls => ls.layerId === layerId);

             if (lsIndex > -1 && kf.layerStates[lsIndex].strokes.length > 0) {
                 const past = [...state.history.past, state.project].slice(-MAX_HISTORY);

                 const newKeyframes = [...project.keyframes];
                 const newKf = { ...newKeyframes[kfIndex] };
                 const newLayerStates = [...newKf.layerStates];
                 const newLs = { ...newLayerStates[lsIndex] };
                 const newStrokes = [...newLs.strokes];

                 newStrokes[0] = { ...newStrokes[0], width: size };

                 newLs.strokes = newStrokes;
                 newLayerStates[lsIndex] = newLs;
                 newKf.layerStates = newLayerStates;
                 newKeyframes[kfIndex] = newKf;

                 project = { ...project, keyframes: newKeyframes };
                 history = { past, future: [] };
             }
        }
    }

    return { 
        ui: { ...state.ui, brushSize: size },
        project,
        history
    };
  }),

  toggleGrid: () => set((state) => ({ ui: { ...state.ui, showGrid: !state.ui.showGrid } })),
  toggleSnapToGrid: () => set((state) => ({ ui: { ...state.ui, snapToGrid: !state.ui.snapToGrid } })),

  toggleSnapPlayMode: () => set((state) => ({ ui: { ...state.ui, snapPlayMode: !state.ui.snapPlayMode } })),
  toggleSnapMatrixGrid: () => set((state) => ({ ui: { ...state.ui, snapMatrixGrid: !state.ui.snapMatrixGrid } })),
  setAxisMatrixDivisions: (val) => set((state) => ({ ui: { ...state.ui, axisMatrixDivisions: val } })),
  setAxisMatrixPadding: (val) => set((state) => ({ ui: { ...state.ui, axisMatrixPadding: val } })),
  setInterpolationExponent: (val) => set((state) => ({ ui: { ...state.ui, interpolationExponent: val } })),
  setInterpolationStrategy: (val) => set((state) => ({ ui: { ...state.ui, interpolationStrategy: val } })),

  togglePlayModePhysics: () => set((state) => ({ ui: { ...state.ui, playModePhysics: !state.ui.playModePhysics } })),
  setSpringStiffness: (val) => set((state) => ({ ui: { ...state.ui, springStiffness: val } })),
  setSpringDamping: (val) => set((state) => ({ ui: { ...state.ui, springDamping: val } })),

  setGridSize: (size) => set((state) => ({ ui: { ...state.ui, gridSize: size } })),
  toggleSmoothing: () => set((state) => ({ ui: { ...state.ui, smoothingEnabled: !state.ui.smoothingEnabled } })),

  toggleOnionSkin: () => set((state) => ({ ui: { ...state.ui, onionSkinEnabled: !state.ui.onionSkinEnabled } })),
  setOnionSkinOpacity: (opacity) => set((state) => ({ ui: { ...state.ui, onionSkinOpacity: opacity } })),
  setInactiveLayerOpacity: (opacity) => set((state) => ({ ui: { ...state.ui, inactiveLayerOpacity: opacity } })),
  setGhostStrokeOpacity: (opacity) => set((state) => ({ ui: { ...state.ui, ghostStrokeOpacity: opacity } })),

  setResolutionScale: (scale) => set((state) => ({ ui: { ...state.ui, resolutionScale: scale } })),
  togglePerformanceMode: () => set((state) => ({ ui: { ...state.ui, performanceMode: !state.ui.performanceMode } })),

  updateAxisValue: (axisId, value) => set((state) => {
    const cleanValue = Math.max(0, Math.min(1, value));
    const newAxes = state.project.axes.map(a => 
      a.id === axisId ? { ...a, currentValue: cleanValue } : a
    );

    // Strict Selection Logic (keeps keyframe selected if we are close)
    // But doesn't FORCE snapping during drag (smooth experience)
    const currentAxisValues: Record<string, number> = {};
    newAxes.forEach(a => currentAxisValues[a.id] = a.currentValue);

    let matchingKfId = null;
    const exactMatch = state.project.keyframes.find(kf => {
      let dist = 0;
      for (const id in currentAxisValues) {
        dist += Math.abs((kf.axisValues[id] || 0) - currentAxisValues[id]);
      }
      return dist < 0.02; 
    });

    if (exactMatch) {
      matchingKfId = exactMatch.id;
    }

    return { 
      project: { ...state.project, axes: newAxes },
      ui: { ...state.ui, selectedKeyframeId: matchingKfId }
    };
  }),

  updateMultipleAxisValues: (values) => set((state) => {
    const newAxes = state.project.axes.map(a => 
       values[a.id] !== undefined ? { ...a, currentValue: Math.max(0, Math.min(1, values[a.id])) } : a
    );
    return {
        project: { ...state.project, axes: newAxes }
    };
  }),

  selectLayer: (layerId) => set((state) => ({ ui: { ...state.ui, selectedLayerId: layerId } })),
  selectKeyframe: (keyframeId) => set((state) => ({ ui: { ...state.ui, selectedKeyframeId: keyframeId } })),
  selectStroke: (strokeId) => set((state) => ({ ui: { ...state.ui, selectedStrokeId: strokeId } })),

  addLayer: () => set((state) => {
    const past = [...state.history.past, state.project].slice(-MAX_HISTORY);
    const newId = `layer-${Date.now()}`;
    const newLayer: Layer = {
      id: newId,
      name: `Layer ${state.project.layers.length + 1}`,
      visible: true,
      locked: false,
      blendMode: 'normal',
      opacity: 1,
      interpolationMode: 'resample'
    };
    return {
      project: { ...state.project, layers: [...state.project.layers, newLayer] },
      ui: { ...state.ui, selectedLayerId: newId },
      history: { past, future: [] }
    };
  }),

  reorderLayers: (fromIndex, toIndex) => set((state) => {
    if (fromIndex === toIndex) return state;
    const past = [...state.history.past, state.project].slice(-MAX_HISTORY);
    const newLayers = [...state.project.layers];
    const [moved] = newLayers.splice(fromIndex, 1);
    newLayers.splice(toIndex, 0, moved);

    return {
       project: { ...state.project, layers: newLayers },
       history: { past, future: [] }
    };
  }),

  deleteLayer: (layerId) => set((state) => {
    if (state.project.layers.length <= 1) return state; 
    const past = [...state.history.past, state.project].slice(-MAX_HISTORY);
    const newLayers = state.project.layers.filter(l => l.id !== layerId);

    const newKeyframes = state.project.keyframes.map(kf => ({
       ...kf,
       layerStates: kf.layerStates.filter(ls => ls.layerId !== layerId)
    }));

    return {
      project: { ...state.project, layers: newLayers, keyframes: newKeyframes },
      ui: { ...state.ui, selectedLayerId: newLayers[newLayers.length - 1].id },
      history: { past, future: [] }
    };
  }),

  renameLayer: (layerId, name) => set((state) => ({
    project: {
      ...state.project,
      layers: state.project.layers.map(l => l.id === layerId ? { ...l, name } : l)
    }
  })),

  toggleLayerVisibility: (layerId) => set((state) => ({
    project: {
      ...state.project,
      layers: state.project.layers.map(l => 
        l.id === layerId ? { ...l, visible: !l.visible } : l
      )
    }
  })),

  toggleLayerLock: (layerId) => set((state) => ({
    project: {
      ...state.project,
      layers: state.project.layers.map(l => 
        l.id === layerId ? { ...l, locked: !l.locked } : l
      )
    }
  })),

  setLayerBlendMode: (layerId, mode) => set((state) => {
    return {
      project: {
        ...state.project,
        layers: state.project.layers.map(l => 
          l.id === layerId ? { ...l, blendMode: mode } : l
        )
      }
    };
  }),

  setLayerInterpolationMode: (layerId, mode) => set((state) => {
    return {
      project: {
        ...state.project,
        layers: state.project.layers.map(l => 
          l.id === layerId ? { ...l, interpolationMode: mode } : l
        )
      }
    };
  }),

  addStrokeToCurrentKeyframe: (rawPoints, closed = false, skipSimplify = false) => set((state) => {
    const { selectedLayerId, brushColor, fillColor, brushSize, smoothingEnabled, snapToGrid } = state.ui;
    if (!selectedLayerId) return state;

    const layer = state.project.layers.find(l => l.id === selectedLayerId);
    if (layer?.locked || !layer?.visible) return state;

    let points = rawPoints;
    let shouldUpdateLayerMode = false;

    if (snapToGrid) {
        points = simplifyPoints(rawPoints, 2.5);
        if (layer.interpolationMode === 'resample') {
            shouldUpdateLayerMode = true;
        }
    } else if (!skipSimplify && smoothingEnabled) { 
       const preSimplified = simplifyPoints(rawPoints, 1.5);
       points = chaikinSmooth(preSimplified, 2);
    } else if (!skipSimplify && !smoothingEnabled) {
       points = simplifyPoints(rawPoints, 1.5);
    }

    if (closed && points.length > 0) {
        points = [...points, points[0]];
    }

    const past = [...state.history.past, state.project].slice(-MAX_HISTORY);

    let updatedLayers = [...state.project.layers];
    if (shouldUpdateLayerMode) {
        updatedLayers = updatedLayers.map(l => 
            l.id === selectedLayerId ? { ...l, interpolationMode: 'points' } : l
        );
    }

    const currentAxisValues: Record<string, number> = {};
    state.project.axes.forEach(a => currentAxisValues[a.id] = a.currentValue);

    let targetKeyframeId = state.ui.selectedKeyframeId;
    let keyframes = [...state.project.keyframes];

    if (targetKeyframeId === null) {
      const newKfId = `kf-${Date.now()}`;
      const newKeyframe: Keyframe = {
        id: newKfId,
        name: `Keyframe ${keyframes.length}`,
        axisValues: currentAxisValues,
        layerStates: [] 
      };
      keyframes.push(newKeyframe);
      targetKeyframeId = newKfId;
    }

    const newStroke: Stroke = {
      id: `stroke-${selectedLayerId}-unique`,
      points,
      color: brushColor as string, 
      fillColor: fillColor,
      width: brushSize,
      style: 'solid',
      closed: false
    };

    const newKeyframes = keyframes.map(kf => {
      if (kf.id === targetKeyframeId) {
        const existingLayerStateIndex = kf.layerStates.findIndex(ls => ls.layerId === selectedLayerId);
        let newLayerStates = [...kf.layerStates];

        if (existingLayerStateIndex >= 0) {
          newLayerStates[existingLayerStateIndex] = {
            ...newLayerStates[existingLayerStateIndex],
            strokes: [newStroke]
          };
        } else {
          newLayerStates.push({
            layerId: selectedLayerId,
            strokes: [newStroke]
          });
        }
        return { ...kf, layerStates: newLayerStates };
      }
      return kf;
    });

    return { 
      project: { ...state.project, keyframes: newKeyframes, layers: updatedLayers },
      ui: { ...state.ui, selectedKeyframeId: targetKeyframeId },
      history: { past, future: [] }
    };
  }),

  updateStrokeInCurrentKeyframe: (strokeId, newPoints) => set((state) => {
    const kfId = state.ui.selectedKeyframeId;
    if (!kfId) return state;

    const keyframes = state.project.keyframes.map(kf => {
      if (kf.id === kfId) {
         const newLayerStates = kf.layerStates.map(ls => {
            if (ls.layerId === state.ui.selectedLayerId) {
               return {
                  ...ls,
                  strokes: ls.strokes.map(s => ({ ...s, points: newPoints }))
               };
            }
            return ls;
         });
         return { ...kf, layerStates: newLayerStates };
      }
      return kf;
    });

    return { project: { ...state.project, keyframes }};
  }),

  deleteStroke: (strokeId) => set((state) => {
     const kfId = state.ui.selectedKeyframeId;
     const layerId = state.ui.selectedLayerId;
     if (!kfId || !layerId) return state;

     const past = [...state.history.past, state.project].slice(-MAX_HISTORY);

     const newKeyframes = state.project.keyframes.map(kf => {
         if (kf.id === kfId) {
             const newLayerStates = kf.layerStates.map(ls => {
                 if (ls.layerId === layerId) {
                     return {
                         ...ls,
                         strokes: ls.strokes.filter(s => s.id !== strokeId)
                     };
                 }
                 return ls;
             });
             return { ...kf, layerStates: newLayerStates };
         }
         return kf;
     });

     return {
         project: { ...state.project, keyframes: newKeyframes },
         ui: { ...state.ui, selectedStrokeId: null }, // Clear selection
         history: { past, future: [] }
     };
  }),

  createKeyframeAtCurrentAxes: () => set((state) => {
     const currentAxisValues: Record<string, number> = {};
     state.project.axes.forEach(a => currentAxisValues[a.id] = a.currentValue);

     const newKeyframe: Keyframe = {
        id: `kf-${Date.now()}`,
        name: `Keyframe ${state.project.keyframes.length}`,
        axisValues: currentAxisValues,
        layerStates: []
      };

      return {
        project: { ...state.project, keyframes: [...state.project.keyframes, newKeyframe] },
        ui: { ...state.ui, selectedKeyframeId: newKeyframe.id }
      };
  }),

  deleteKeyframe: (keyframeId) => set((state) => {
    if (state.project.keyframes.length <= 1) return state; 
    const past = [...state.history.past, state.project].slice(-MAX_HISTORY);
    const newKeyframes = state.project.keyframes.filter(k => k.id !== keyframeId);

    let newSelectedId = state.ui.selectedKeyframeId;
    if (keyframeId === newSelectedId) {
      newSelectedId = newKeyframes[0].id;
    }

    return {
      project: { ...state.project, keyframes: newKeyframes },
      ui: { ...state.ui, selectedKeyframeId: newSelectedId },
      history: { past, future: [] }
    };
  }),

  updateKeyframePosition: (keyframeId, x, y) => set((state) => {
     const past = [...state.history.past, state.project].slice(-MAX_HISTORY);

     const newKeyframes = state.project.keyframes.map(kf => {
         if (kf.id === keyframeId) {
             return {
                 ...kf,
                 axisValues: {
                     ...kf.axisValues,
                     'axis-x': x,
                     'axis-y': y
                 }
             };
         }
         return kf;
     });

     let newAxes = state.project.axes;
     if (state.ui.selectedKeyframeId === keyframeId) {
         newAxes = state.project.axes.map(a => {
             if (a.id === 'axis-x') return { ...a, currentValue: x };
             if (a.id === 'axis-y') return { ...a, currentValue: y };
             return a;
         });
     }

     return {
         project: { ...state.project, keyframes: newKeyframes, axes: newAxes },
         history: { past, future: [] }
     };
  }),

  // --- Copy / Paste Actions ---

  copyKeyframeState: () => set((state) => {
    const kfId = state.ui.selectedKeyframeId;
    if (!kfId) return state;

    const kf = state.project.keyframes.find(k => k.id === kfId);
    if (!kf) return state;

    // Deep copy of layerStates
    const clipboardData = JSON.parse(JSON.stringify(kf.layerStates));

    return { clipboard: clipboardData };
  }),

  pasteKeyframeState: () => set((state) => {
      const kfId = state.ui.selectedKeyframeId;
      if (!kfId || !state.clipboard) return state;

      const past = [...state.history.past, state.project].slice(-MAX_HISTORY);

      const newKeyframes = state.project.keyframes.map(kf => {
          if (kf.id === kfId) {
              // We replace the layer states with the clipboard content
              // We must ensure the strokes have NEW IDs to avoid conflicts if we paste into a new keyframe 
              // but keep the same layer structure.
              const pastedStates: LayerState[] = state.clipboard!.map(ls => ({
                  ...ls,
                  strokes: ls.strokes.map(s => ({ ...s, id: `stroke-${Date.now()}-${Math.random()}` }))
              }));

              return {
                  ...kf,
                  layerStates: pastedStates
              };
          }
          return kf;
      });

      return {
          project: { ...state.project, keyframes: newKeyframes },
          history: { past, future: [] }
      };
  })

}));

// components/AxisMap.tsx
import React, { useRef, useState, useEffect } from 'react';
import { useStore } from '../store/useStore';
import { APP_COLORS } from '../constants';
import { distance } from '../utils/math';

export const AxisMap: React.FC = () => {
  const { 
      project, updateAxisValue, ui, selectKeyframe, deleteKeyframe, 
      updateKeyframePosition, updateMultipleAxisValues,
      copyKeyframeState, pasteKeyframeState, clipboard
  } = useStore();

  const containerRef = useRef<HTMLDivElement>(null);
  const [draggingKfId, setDraggingKfId] = useState<string | null>(null);

  const axisX = project.axes.find(a => a.id === 'axis-x');
  const axisY = project.axes.find(a => a.id === 'axis-y');

  if (!axisX || !axisY) return null;

  // -- Helpers --

  const getAxisValuesFromEvent = (e: React.PointerEvent) => {
      if (!containerRef.current) return { x: 0, y: 0 };
      const rect = containerRef.current.getBoundingClientRect();
      const rawX = Math.max(0, Math.min(1, (e.clientX - rect.left) / rect.width));
      const rawY = Math.max(0, Math.min(1, (e.clientY - rect.top) / rect.height));

      const padding = ui.axisMatrixPadding;
      const effectiveSize = 1 - (padding * 2);
      let x = rawX;
      let y = rawY;

      if (ui.snapMatrixGrid) {
          const steps = ui.axisMatrixDivisions - 1;
          if (steps > 0) {
              const relativeX = (rawX - padding) / effectiveSize;
              const relativeY = (rawY - padding) / effectiveSize;
              const snappedRelX = Math.round(relativeX * steps) / steps;
              const snappedRelY = Math.round(relativeY * steps) / steps;

              x = padding + (snappedRelX * effectiveSize);
              y = padding + (snappedRelY * effectiveSize);

              x = Math.max(padding, Math.min(1 - padding, x));
              y = Math.max(padding, Math.min(1 - padding, y));
          }
      }
      return { x, y, rawX, rawY }; // Return raw for hit testing if needed
  };

  const findHitKeyframe = (x: number, y: number) => {
      // Find the keyframe closest to (x,y) within a tolerance
      // Coordinates are 0-1
      const HIT_TOLERANCE = 0.05; // 5% of width

      // Sort by distance to find closest top-most
      const sorted = [...project.keyframes].map(kf => {
          const kx = kf.axisValues[axisX.id] ?? 0.5;
          const ky = kf.axisValues[axisY.id] ?? 0.5;
          const dist = Math.sqrt(Math.pow(kx - x, 2) + Math.pow(ky - y, 2));
          return { id: kf.id, dist };
      }).sort((a,b) => a.dist - b.dist);

      if (sorted.length > 0 && sorted[0].dist < HIT_TOLERANCE) {
          return sorted[0].id;
      }
      return null;
  };

  // -- Event Handlers --

  const handlePointerDown = (e: React.PointerEvent) => {
    (e.target as Element).setPointerCapture(e.pointerId);

    // Calculate Click Position (Raw and Snapped)
    if (!containerRef.current) return;
    const rect = containerRef.current.getBoundingClientRect();
    const rawX = (e.clientX - rect.left) / rect.width;
    const rawY = (e.clientY - rect.top) / rect.height;

    // 1. Hit Test Keyframes first
    const hitId = findHitKeyframe(rawX, rawY);

    if (hitId) {
        setDraggingKfId(hitId);
        selectKeyframe(hitId); 

        // CRITICAL: Snap axes to the clicked keyframe instantly.
        // This ensures the interpolation engine renders the state at 100% opacity (weight 1.0)
        const kf = project.keyframes.find(k => k.id === hitId);
        if (kf) {
             const kx = kf.axisValues[axisX.id] ?? 0.5;
             const ky = kf.axisValues[axisY.id] ?? 0.5;
             updateMultipleAxisValues({ [axisX.id]: kx, [axisY.id]: ky });
        }

    } else {
        // 2. Else, move cursor
        const { x, y } = getAxisValuesFromEvent(e);
        updateAxisValue(axisX.id, x);
        updateAxisValue(axisY.id, y);
    }
  };

  const handlePointerMove = (e: React.PointerEvent) => {
    if (e.buttons === 0) return;

    const { x, y } = getAxisValuesFromEvent(e);

    if (draggingKfId) {
        // Drag Keyframe
        updateKeyframePosition(draggingKfId, x, y);
    } else {
        // Drag Cursor
        updateAxisValue(axisX.id, x);
        updateAxisValue(axisY.id, y);
    }
  };

  const handlePointerUp = (e: React.PointerEvent) => {
    (e.target as Element).releasePointerCapture(e.pointerId);
    setDraggingKfId(null);
  };

  const selectedKf = project.keyframes.find(k => k.id === ui.selectedKeyframeId);

  // Grid Lines Generation
  const gridLines = [];
  const padding = ui.axisMatrixPadding;
  const effectiveSize = 1 - (padding * 2);
  const steps = ui.axisMatrixDivisions - 1;

  if (steps > 0) {
      for (let i = 0; i <= steps; i++) {
          const pos = padding + (i / steps) * effectiveSize;
          const pct = pos * 100;

          gridLines.push(
              <div key={`v-${i}`} className="absolute top-0 bottom-0 border-l border-gray-100 pointer-events-none" style={{ left: `${pct}%`, top: `${padding*100}%`, bottom: `${padding*100}%` }} />
          );
          gridLines.push(
              <div key={`h-${i}`} className="absolute left-0 right-0 border-t border-gray-100 pointer-events-none" style={{ top: `${pct}%`, left: `${padding*100}%`, right: `${padding*100}%` }} />
          );
      }
  }

  return (
    <div className="fixed bottom-6 left-6 z-50 flex flex-col gap-2">
      <div className="bg-white/90 backdrop-blur-md rounded-2xl shadow-xl border border-gray-200 p-3 w-52">
        <div className="flex justify-between items-center mb-2">
          <span className="text-[10px] uppercase font-bold text-gray-400 tracking-wider">Matrix</span>

          <div className="flex items-center gap-1">
             {selectedKf && (
                 <>
                    {/* COPY */}
                    <button 
                        onClick={copyKeyframeState}
                        className="text-gray-400 hover:text-blue-500 hover:bg-blue-50 p-1 rounded transition-colors"
                        title="Copy State"
                    >
                        <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><rect x="9" y="9" width="13" height="13" rx="2" ry="2"></rect><path d="M5 15H4a2 2 0 0 1-2-2V4a2 2 0 0 1 2-2h9a2 2 0 0 1 2 2v1"></path></svg>
                    </button>

                    {/* PASTE */}
                    <button 
                        onClick={pasteKeyframeState}
                        disabled={!clipboard}
                        className={`p-1 rounded transition-colors ${!clipboard ? 'text-gray-200 cursor-not-allowed' : 'text-gray-400 hover:text-blue-500 hover:bg-blue-50'}`}
                        title="Paste State"
                    >
                        <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M16 4h2a2 2 0 0 1 2 2v14a2 2 0 0 1-2 2H6a2 2 0 0 1-2-2V6a2 2 0 0 1 2-2h2"></path><rect x="8" y="2" width="8" height="4" rx="1" ry="1"></rect></svg>
                    </button>

                    {/* SEPARATOR */}
                    <div className="w-px h-3 bg-gray-200 mx-1"></div>

                    {/* DELETE */}
                    {project.keyframes.length > 1 && (
                        <button 
                        onClick={() => deleteKeyframe(selectedKf.id)}
                        className="text-gray-400 hover:text-red-500 hover:bg-red-50 p-1 rounded transition-colors"
                        title="Delete State"
                        >
                        <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><polyline points="3 6 5 6 21 6"></polyline><path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"></path></svg>
                        </button>
                    )}
                 </>
             )}
          </div>
        </div>

        <div 
          ref={containerRef}
          className="relative w-full aspect-square bg-white rounded-lg border border-gray-200 cursor-crosshair overflow-hidden shadow-inner touch-none"
          onPointerDown={handlePointerDown}
          onPointerMove={handlePointerMove}
          onPointerUp={handlePointerUp}
        >
          {/* Configurable Grid */}
          {gridLines}

          {/* Keyframes Dots */}
          {project.keyframes.map(kf => {
            const kfX = kf.axisValues[axisX.id] ?? 0.5;
            const kfY = kf.axisValues[axisY.id] ?? 0.5;

            const isSelected = ui.selectedKeyframeId === kf.id;
            const isDragging = draggingKfId === kf.id;

            const hasDataForCurrentLayer = kf.layerStates.some(ls => ls.layerId === ui.selectedLayerId && ls.strokes.length > 0);

            return (
              <div
                key={kf.id}
                className={`absolute -ml-1.5 -mt-1.5 rounded-full transition-transform pointer-events-none flex items-center justify-center ${
                    isSelected ? 'z-20 scale-125' : 'z-10'
                } ${isDragging ? 'scale-150' : ''}`}
                style={{ 
                    left: `${kfX * 100}%`, 
                    top: `${kfY * 100}%`,
                    width: '12px',
                    height: '12px',
                }}
              >
                  {isSelected && (
                      <div className={`absolute inset-0 rounded-full border-2 border-blue-500 shadow-sm ${isDragging ? 'border-4' : 'animate-pulse'}`} />
                  )}

                  <div className={`rounded-full ${
                      hasDataForCurrentLayer
                        ? 'w-2 h-2 bg-gray-800' 
                        : 'w-2 h-2 border border-gray-300 bg-white' 
                  }`} />
              </div>
            );
          })}

          {/* Current Cursor */}
          <div 
            className="absolute w-4 h-4 -ml-2 -mt-2 pointer-events-none z-30 transition-opacity duration-200"
            style={{ 
                left: `${axisX.currentValue * 100}%`, 
                top: `${axisY.currentValue * 100}%`,
                opacity: draggingKfId ? 0.5 : 1 // Dim cursor when dragging a keyframe
            }}
          >
             <svg viewBox="0 0 24 24" fill="none" stroke={APP_COLORS.primary} strokeWidth="3">
               <line x1="12" y1="0" x2="12" y2="24" />
               <line x1="0" y1="12" x2="24" y2="12" />
             </svg>
          </div>
        </div>

        <div className="mt-2 flex justify-between text-[10px] text-gray-400 font-mono">
          <span>{draggingKfId ? 'DRAGGING' : `X: ${(axisX.currentValue * 100).toFixed(1)}%`}</span>
          <span>{draggingKfId ? 'STATE' : `Y: ${(axisY.currentValue * 100).toFixed(1)}%`}</span>
        </div>
      </div>
    </div>
  );
};

// store/useStore.ts
import { create } from 'zustand';
import { Project, UIState, ToolType, Axis, Layer, Keyframe, Point, Stroke, LayerState, BlendMode, UIMode, InterpolationMode, InterpolationStrategy } from '../types';
import { DEFAULT_PROJECT, INITIAL_UI_STATE, DEFAULT_LAYER, DEFAULT_KEYFRAME } from '../constants';
import { simplifyPoints, distance, chaikinSmooth } from '../utils/math';

interface StoreState {
  project: Project;
  ui: UIState;

  history: {
    past: Project[];
    future: Project[];
  };

  // Internal Clipboard for Copy/Paste State
  clipboard: LayerState[] | null; 

  isSettingsOpen: boolean;

  // Actions
  undo: () => void;
  redo: () => void;

  // Project Actions
  resetProject: () => void;
  loadProject: (project: Project) => void;

  toggleSettings: () => void;
  toggleLayerPanel: () => void;
  closeAllPanels: () => void; // Used for clicking outside

  setMode: (mode: UIMode) => void;

  setTool: (tool: ToolType) => void;
  setBrushColor: (color: string) => void;
  setFillColor: (color: string) => void;
  setBrushSize: (size: number) => void;

  // Config Actions
  toggleGrid: () => void;
  toggleSnapToGrid: () => void;

  toggleSnapPlayMode: () => void;
  toggleSnapMatrixGrid: () => void;
  setAxisMatrixDivisions: (val: number) => void;
  setAxisMatrixPadding: (val: number) => void;
  setInterpolationExponent: (val: number) => void;
  setInterpolationStrategy: (val: InterpolationStrategy) => void;

  togglePlayModePhysics: () => void;
  setSpringStiffness: (val: number) => void;
  setSpringDamping: (val: number) => void;

  setGridSize: (size: number) => void;
  toggleSmoothing: () => void; // Renamed from toggleSimplifyStrokes

  toggleOnionSkin: () => void;
  setOnionSkinOpacity: (opacity: number) => void;
  setInactiveLayerOpacity: (opacity: number) => void;
  setGhostStrokeOpacity: (opacity: number) => void;

  // Performance Actions
  setResolutionScale: (scale: number) => void;
  togglePerformanceMode: () => void;

  // Layer Actions
  addLayer: () => void;
  deleteLayer: (layerId: string) => void;
  renameLayer: (layerId: string, name: string) => void;
  reorderLayers: (fromIndex: number, toIndex: number) => void;
  toggleLayerVisibility: (layerId: string) => void;
  toggleLayerLock: (layerId: string) => void;
  setLayerBlendMode: (layerId: string, mode: BlendMode) => void;
  setLayerInterpolationMode: (layerId: string, mode: InterpolationMode) => void;
  selectLayer: (layerId: string) => void;

  updateAxisValue: (axisId: string, value: number) => void;
  updateMultipleAxisValues: (values: Record<string, number>) => void; // Batch update

  addStrokeToCurrentKeyframe: (points: Point[], closed?: boolean, skipSimplify?: boolean) => void; 
  updateStrokeInCurrentKeyframe: (strokeId: string, newPoints: Point[]) => void;
  deleteStroke: (strokeId: string) => void; 

  createKeyframeAtCurrentAxes: () => void;
  deleteKeyframe: (keyframeId: string) => void;
  updateKeyframePosition: (keyframeId: string, x: number, y: number) => void; 
  selectKeyframe: (keyframeId: string) => void;

  // Copy/Paste Actions
  copyKeyframeState: () => void;
  pasteKeyframeState: () => void;

  selectStroke: (strokeId: string | null) => void;
}

const MAX_HISTORY = 50;

export const useStore = create<StoreState>((set, get) => ({
  project: DEFAULT_PROJECT,
  ui: INITIAL_UI_STATE,
  isSettingsOpen: false,
  clipboard: null, // Initialize clipboard

  history: {
    past: [],
    future: []
  },

  resetProject: () => set(() => ({
      project: {
          ...DEFAULT_PROJECT,
          id: `project-${Date.now()}`,
          created: Date.now(),
          modified: Date.now(),
          // Ensure distinct instances for object references
          layers: [{...DEFAULT_LAYER, id: `layer-${Date.now()}`}],
          keyframes: [{...DEFAULT_KEYFRAME, id: `kf-${Date.now()}`, layerStates: [{ layerId: `layer-${Date.now()}`, strokes: [] }] }]
      },
      ui: {
          ...INITIAL_UI_STATE,
          selectedLayerId: `layer-${Date.now()}`,
          selectedKeyframeId: `kf-${Date.now()}`
      },
      clipboard: null,
      history: { past: [], future: [] }
  })),

  loadProject: (project) => set(() => ({
      project: project,
      ui: {
          ...INITIAL_UI_STATE,
          selectedLayerId: project.layers[0]?.id || null,
          selectedKeyframeId: project.keyframes[0]?.id || null
      },
      clipboard: null,
      history: { past: [], future: [] }
  })),

  toggleSettings: () => set((state) => ({ isSettingsOpen: !state.isSettingsOpen, ui: { ...state.ui, isLayerPanelOpen: false } })),
  toggleLayerPanel: () => set((state) => ({ ui: { ...state.ui, isLayerPanelOpen: !state.ui.isLayerPanelOpen }, isSettingsOpen: false })),
  closeAllPanels: () => set((state) => ({ isSettingsOpen: false, ui: { ...state.ui, isLayerPanelOpen: false } })),

  setMode: (mode) => set((state) => ({ ui: { ...state.ui, mode } })),

  undo: () => set((state) => {
    if (state.history.past.length === 0) return state;
    const previous = state.history.past[state.history.past.length - 1];
    const newPast = state.history.past.slice(0, -1);
    return {
      project: previous,
      history: {
        past: newPast,
        future: [state.project, ...state.history.future]
      }
    };
  }),

  redo: () => set((state) => {
    if (state.history.future.length === 0) return state;
    const next = state.history.future[0];
    const newFuture = state.history.future.slice(1);
    return {
      project: next,
      history: {
        past: [...state.history.past, state.project],
        future: newFuture
      }
    };
  }),

  setTool: (tool) => set((state) => ({ ui: { ...state.ui, selectedTool: tool, selectedStrokeId: null } })),

  setBrushColor: (color) => set((state) => {
    let project = state.project;
    let history = state.history;

    // Try to update existing stroke if we are on a keyframe
    if (state.ui.selectedKeyframeId && state.ui.selectedLayerId) {
        const kfId = state.ui.selectedKeyframeId;
        const layerId = state.ui.selectedLayerId;

        const kfIndex = project.keyframes.findIndex(k => k.id === kfId);
        if (kfIndex > -1) {
             const kf = project.keyframes[kfIndex];
             const lsIndex = kf.layerStates.findIndex(ls => ls.layerId === layerId);

             if (lsIndex > -1 && kf.layerStates[lsIndex].strokes.length > 0) {
                 // Push to history
                 const past = [...state.history.past, state.project].slice(-MAX_HISTORY);

                 const newKeyframes = [...project.keyframes];
                 const newKf = { ...newKeyframes[kfIndex] };
                 const newLayerStates = [...newKf.layerStates];
                 const newLs = { ...newLayerStates[lsIndex] };
                 const newStrokes = [...newLs.strokes];

                 newStrokes[0] = { ...newStrokes[0], color: color === 'none' ? 'rgba(0,0,0,0)' : color };

                 newLs.strokes = newStrokes;
                 newLayerStates[lsIndex] = newLs;
                 newKf.layerStates = newLayerStates;
                 newKeyframes[kfIndex] = newKf;

                 project = { ...project, keyframes: newKeyframes };
                 history = { past, future: [] };
             }
        }
    }

    return { 
       ui: { ...state.ui, brushColor: color },
       project,
       history
    };
  }),

  setFillColor: (color) => set((state) => {
    let project = state.project;
    let history = state.history;

    if (state.ui.selectedKeyframeId && state.ui.selectedLayerId) {
        const kfId = state.ui.selectedKeyframeId;
        const layerId = state.ui.selectedLayerId;

        const kfIndex = project.keyframes.findIndex(k => k.id === kfId);
        if (kfIndex > -1) {
             const kf = project.keyframes[kfIndex];
             const lsIndex = kf.layerStates.findIndex(ls => ls.layerId === layerId);

             if (lsIndex > -1 && kf.layerStates[lsIndex].strokes.length > 0) {
                 const past = [...state.history.past, state.project].slice(-MAX_HISTORY);

                 const newKeyframes = [...project.keyframes];
                 const newKf = { ...newKeyframes[kfIndex] };
                 const newLayerStates = [...newKf.layerStates];
                 const newLs = { ...newLayerStates[lsIndex] };
                 const newStrokes = [...newLs.strokes];

                 newStrokes[0] = { ...newStrokes[0], fillColor: color };

                 newLs.strokes = newStrokes;
                 newLayerStates[lsIndex] = newLs;
                 newKf.layerStates = newLayerStates;
                 newKeyframes[kfIndex] = newKf;

                 project = { ...project, keyframes: newKeyframes };
                 history = { past, future: [] };
             }
        }
    }

    return { 
        ui: { ...state.ui, fillColor: color },
        project,
        history
    };
  }),

  setBrushSize: (size) => set((state) => {
    let project = state.project;
    let history = state.history;

    if (state.ui.selectedKeyframeId && state.ui.selectedLayerId) {
        const kfId = state.ui.selectedKeyframeId;
        const layerId = state.ui.selectedLayerId;

        const kfIndex = project.keyframes.findIndex(k => k.id === kfId);
        if (kfIndex > -1) {
             const kf = project.keyframes[kfIndex];
             const lsIndex = kf.layerStates.findIndex(ls => ls.layerId === layerId);

             if (lsIndex > -1 && kf.layerStates[lsIndex].strokes.length > 0) {
                 const past = [...state.history.past, state.project].slice(-MAX_HISTORY);

                 const newKeyframes = [...project.keyframes];
                 const newKf = { ...newKeyframes[kfIndex] };
                 const newLayerStates = [...newKf.layerStates];
                 const newLs = { ...newLayerStates[lsIndex] };
                 const newStrokes = [...newLs.strokes];

                 newStrokes[0] = { ...newStrokes[0], width: size };

                 newLs.strokes = newStrokes;
                 newLayerStates[lsIndex] = newLs;
                 newKf.layerStates = newLayerStates;
                 newKeyframes[kfIndex] = newKf;

                 project = { ...project, keyframes: newKeyframes };
                 history = { past, future: [] };
             }
        }
    }

    return { 
        ui: { ...state.ui, brushSize: size },
        project,
        history
    };
  }),

  toggleGrid: () => set((state) => ({ ui: { ...state.ui, showGrid: !state.ui.showGrid } })),
  toggleSnapToGrid: () => set((state) => ({ ui: { ...state.ui, snapToGrid: !state.ui.snapToGrid } })),

  toggleSnapPlayMode: () => set((state) => ({ ui: { ...state.ui, snapPlayMode: !state.ui.snapPlayMode } })),
  toggleSnapMatrixGrid: () => set((state) => ({ ui: { ...state.ui, snapMatrixGrid: !state.ui.snapMatrixGrid } })),
  setAxisMatrixDivisions: (val) => set((state) => ({ ui: { ...state.ui, axisMatrixDivisions: val } })),
  setAxisMatrixPadding: (val) => set((state) => ({ ui: { ...state.ui, axisMatrixPadding: val } })),
  setInterpolationExponent: (val) => set((state) => ({ ui: { ...state.ui, interpolationExponent: val } })),
  setInterpolationStrategy: (val) => set((state) => ({ ui: { ...state.ui, interpolationStrategy: val } })),

  togglePlayModePhysics: () => set((state) => ({ ui: { ...state.ui, playModePhysics: !state.ui.playModePhysics } })),
  setSpringStiffness: (val) => set((state) => ({ ui: { ...state.ui, springStiffness: val } })),
  setSpringDamping: (val) => set((state) => ({ ui: { ...state.ui, springDamping: val } })),

  setGridSize: (size) => set((state) => ({ ui: { ...state.ui, gridSize: size } })),
  toggleSmoothing: () => set((state) => ({ ui: { ...state.ui, smoothingEnabled: !state.ui.smoothingEnabled } })),

  toggleOnionSkin: () => set((state) => ({ ui: { ...state.ui, onionSkinEnabled: !state.ui.onionSkinEnabled } })),
  setOnionSkinOpacity: (opacity) => set((state) => ({ ui: { ...state.ui, onionSkinOpacity: opacity } })),
  setInactiveLayerOpacity: (opacity) => set((state) => ({ ui: { ...state.ui, inactiveLayerOpacity: opacity } })),
  setGhostStrokeOpacity: (opacity) => set((state) => ({ ui: { ...state.ui, ghostStrokeOpacity: opacity } })),

  setResolutionScale: (scale) => set((state) => ({ ui: { ...state.ui, resolutionScale: scale } })),
  togglePerformanceMode: () => set((state) => ({ ui: { ...state.ui, performanceMode: !state.ui.performanceMode } })),

  updateAxisValue: (axisId, value) => set((state) => {
    const cleanValue = Math.max(0, Math.min(1, value));
    const newAxes = state.project.axes.map(a => 
      a.id === axisId ? { ...a, currentValue: cleanValue } : a
    );

    // Strict Selection Logic (keeps keyframe selected if we are close)
    // But doesn't FORCE snapping during drag (smooth experience)
    const currentAxisValues: Record<string, number> = {};
    newAxes.forEach(a => currentAxisValues[a.id] = a.currentValue);

    let matchingKfId = null;
    const exactMatch = state.project.keyframes.find(kf => {
      let dist = 0;
      for (const id in currentAxisValues) {
        dist += Math.abs((kf.axisValues[id] || 0) - currentAxisValues[id]);
      }
      return dist < 0.02; 
    });

    if (exactMatch) {
      matchingKfId = exactMatch.id;
    }

    return { 
      project: { ...state.project, axes: newAxes },
      ui: { ...state.ui, selectedKeyframeId: matchingKfId }
    };
  }),

  updateMultipleAxisValues: (values) => set((state) => {
    const newAxes = state.project.axes.map(a => 
       values[a.id] !== undefined ? { ...a, currentValue: Math.max(0, Math.min(1, values[a.id])) } : a
    );
    return {
        project: { ...state.project, axes: newAxes }
    };
  }),

  selectLayer: (layerId) => set((state) => ({ ui: { ...state.ui, selectedLayerId: layerId } })),
  selectKeyframe: (keyframeId) => set((state) => ({ ui: { ...state.ui, selectedKeyframeId: keyframeId } })),
  selectStroke: (strokeId) => set((state) => ({ ui: { ...state.ui, selectedStrokeId: strokeId } })),

  addLayer: () => set((state) => {
    const past = [...state.history.past, state.project].slice(-MAX_HISTORY);
    const newId = `layer-${Date.now()}`;
    const newLayer: Layer = {
      id: newId,
      name: `Layer ${state.project.layers.length + 1}`,
      visible: true,
      locked: false,
      blendMode: 'normal',
      opacity: 1,
      interpolationMode: 'resample'
    };
    return {
      project: { ...state.project, layers: [...state.project.layers, newLayer] },
      ui: { ...state.ui, selectedLayerId: newId },
      history: { past, future: [] }
    };
  }),

  reorderLayers: (fromIndex, toIndex) => set((state) => {
    if (fromIndex === toIndex) return state;
    const past = [...state.history.past, state.project].slice(-MAX_HISTORY);
    const newLayers = [...state.project.layers];
    const [moved] = newLayers.splice(fromIndex, 1);
    newLayers.splice(toIndex, 0, moved);

    return {
       project: { ...state.project, layers: newLayers },
       history: { past, future: [] }
    };
  }),

  deleteLayer: (layerId) => set((state) => {
    if (state.project.layers.length <= 1) return state; 
    const past = [...state.history.past, state.project].slice(-MAX_HISTORY);
    const newLayers = state.project.layers.filter(l => l.id !== layerId);

    const newKeyframes = state.project.keyframes.map(kf => ({
       ...kf,
       layerStates: kf.layerStates.filter(ls => ls.layerId !== layerId)
    }));

    return {
      project: { ...state.project, layers: newLayers, keyframes: newKeyframes },
      ui: { ...state.ui, selectedLayerId: newLayers[newLayers.length - 1].id },
      history: { past, future: [] }
    };
  }),

  renameLayer: (layerId, name) => set((state) => ({
    project: {
      ...state.project,
      layers: state.project.layers.map(l => l.id === layerId ? { ...l, name } : l)
    }
  })),

  toggleLayerVisibility: (layerId) => set((state) => ({
    project: {
      ...state.project,
      layers: state.project.layers.map(l => 
        l.id === layerId ? { ...l, visible: !l.visible } : l
      )
    }
  })),

  toggleLayerLock: (layerId) => set((state) => ({
    project: {
      ...state.project,
      layers: state.project.layers.map(l => 
        l.id === layerId ? { ...l, locked: !l.locked } : l
      )
    }
  })),

  setLayerBlendMode: (layerId, mode) => set((state) => {
    return {
      project: {
        ...state.project,
        layers: state.project.layers.map(l => 
          l.id === layerId ? { ...l, blendMode: mode } : l
        )
      }
    };
  }),

  setLayerInterpolationMode: (layerId, mode) => set((state) => {
    return {
      project: {
        ...state.project,
        layers: state.project.layers.map(l => 
          l.id === layerId ? { ...l, interpolationMode: mode } : l
        )
      }
    };
  }),

  addStrokeToCurrentKeyframe: (rawPoints, closed = false, skipSimplify = false) => set((state) => {
    const { selectedLayerId, brushColor, fillColor, brushSize, smoothingEnabled, snapToGrid } = state.ui;
    if (!selectedLayerId) return state;

    const layer = state.project.layers.find(l => l.id === selectedLayerId);
    if (layer?.locked || !layer?.visible) return state;

    let points = rawPoints;
    let shouldUpdateLayerMode = false;

    if (snapToGrid) {
        points = simplifyPoints(rawPoints, 2.5);
        if (layer.interpolationMode === 'resample') {
            shouldUpdateLayerMode = true;
        }
    } else if (!skipSimplify && smoothingEnabled) { 
       const preSimplified = simplifyPoints(rawPoints, 1.5);
       points = chaikinSmooth(preSimplified, 2);
    } else if (!skipSimplify && !smoothingEnabled) {
       points = simplifyPoints(rawPoints, 1.5);
    }

    if (closed && points.length > 0) {
        points = [...points, points[0]];
    }

    const past = [...state.history.past, state.project].slice(-MAX_HISTORY);

    let updatedLayers = [...state.project.layers];
    if (shouldUpdateLayerMode) {
        updatedLayers = updatedLayers.map(l => 
            l.id === selectedLayerId ? { ...l, interpolationMode: 'points' } : l
        );
    }

    const currentAxisValues: Record<string, number> = {};
    state.project.axes.forEach(a => currentAxisValues[a.id] = a.currentValue);

    let targetKeyframeId = state.ui.selectedKeyframeId;
    let keyframes = [...state.project.keyframes];

    if (targetKeyframeId === null) {
      const newKfId = `kf-${Date.now()}`;
      const newKeyframe: Keyframe = {
        id: newKfId,
        name: `Keyframe ${keyframes.length}`,
        axisValues: currentAxisValues,
        layerStates: [] 
      };
      keyframes.push(newKeyframe);
      targetKeyframeId = newKfId;
    }

    const newStroke: Stroke = {
      id: `stroke-${selectedLayerId}-unique`,
      points,
      color: brushColor as string, 
      fillColor: fillColor,
      width: brushSize,
      style: 'solid',
      closed: false
    };

    const newKeyframes = keyframes.map(kf => {
      if (kf.id === targetKeyframeId) {
        const existingLayerStateIndex = kf.layerStates.findIndex(ls => ls.layerId === selectedLayerId);
        let newLayerStates = [...kf.layerStates];

        if (existingLayerStateIndex >= 0) {
          newLayerStates[existingLayerStateIndex] = {
            ...newLayerStates[existingLayerStateIndex],
            strokes: [newStroke]
          };
        } else {
          newLayerStates.push({
            layerId: selectedLayerId,
            strokes: [newStroke]
          });
        }
        return { ...kf, layerStates: newLayerStates };
      }
      return kf;
    });

    return { 
      project: { ...state.project, keyframes: newKeyframes, layers: updatedLayers },
      ui: { ...state.ui, selectedKeyframeId: targetKeyframeId },
      history: { past, future: [] }
    };
  }),

  updateStrokeInCurrentKeyframe: (strokeId, newPoints) => set((state) => {
    const kfId = state.ui.selectedKeyframeId;
    if (!kfId) return state;

    const keyframes = state.project.keyframes.map(kf => {
      if (kf.id === kfId) {
         const newLayerStates = kf.layerStates.map(ls => {
            if (ls.layerId === state.ui.selectedLayerId) {
               return {
                  ...ls,
                  strokes: ls.strokes.map(s => ({ ...s, points: newPoints }))
               };
            }
            return ls;
         });
         return { ...kf, layerStates: newLayerStates };
      }
      return kf;
    });

    return { project: { ...state.project, keyframes }};
  }),

  deleteStroke: (strokeId) => set((state) => {
     const kfId = state.ui.selectedKeyframeId;
     const layerId = state.ui.selectedLayerId;
     if (!kfId || !layerId) return state;

     const past = [...state.history.past, state.project].slice(-MAX_HISTORY);

     const newKeyframes = state.project.keyframes.map(kf => {
         if (kf.id === kfId) {
             const newLayerStates = kf.layerStates.map(ls => {
                 if (ls.layerId === layerId) {
                     return {
                         ...ls,
                         strokes: ls.strokes.filter(s => s.id !== strokeId)
                     };
                 }
                 return ls;
             });
             return { ...kf, layerStates: newLayerStates };
         }
         return kf;
     });

     return {
         project: { ...state.project, keyframes: newKeyframes },
         ui: { ...state.ui, selectedStrokeId: null }, // Clear selection
         history: { past, future: [] }
     };
  }),

  createKeyframeAtCurrentAxes: () => set((state) => {
     const currentAxisValues: Record<string, number> = {};
     state.project.axes.forEach(a => currentAxisValues[a.id] = a.currentValue);

     const newKeyframe: Keyframe = {
        id: `kf-${Date.now()}`,
        name: `Keyframe ${state.project.keyframes.length}`,
        axisValues: currentAxisValues,
        layerStates: []
      };

      return {
        project: { ...state.project, keyframes: [...state.project.keyframes, newKeyframe] },
        ui: { ...state.ui, selectedKeyframeId: newKeyframe.id }
      };
  }),

  deleteKeyframe: (keyframeId) => set((state) => {
    if (state.project.keyframes.length <= 1) return state; 
    const past = [...state.history.past, state.project].slice(-MAX_HISTORY);
    const newKeyframes = state.project.keyframes.filter(k => k.id !== keyframeId);

    let newSelectedId = state.ui.selectedKeyframeId;
    if (keyframeId === newSelectedId) {
      newSelectedId = newKeyframes[0].id;
    }

    return {
      project: { ...state.project, keyframes: newKeyframes },
      ui: { ...state.ui, selectedKeyframeId: newSelectedId },
      history: { past, future: [] }
    };
  }),

  updateKeyframePosition: (keyframeId, x, y) => set((state) => {
     const past = [...state.history.past, state.project].slice(-MAX_HISTORY);

     const newKeyframes = state.project.keyframes.map(kf => {
         if (kf.id === keyframeId) {
             return {
                 ...kf,
                 axisValues: {
                     ...kf.axisValues,
                     'axis-x': x,
                     'axis-y': y
                 }
             };
         }
         return kf;
     });

     let newAxes = state.project.axes;
     if (state.ui.selectedKeyframeId === keyframeId) {
         newAxes = state.project.axes.map(a => {
             if (a.id === 'axis-x') return { ...a, currentValue: x };
             if (a.id === 'axis-y') return { ...a, currentValue: y };
             return a;
         });
     }

     return {
         project: { ...state.project, keyframes: newKeyframes, axes: newAxes },
         history: { past, future: [] }
     };
  }),

  // --- Copy / Paste Actions ---

  copyKeyframeState: () => set((state) => {
    const kfId = state.ui.selectedKeyframeId;
    if (!kfId) return state;

    const kf = state.project.keyframes.find(k => k.id === kfId);
    if (!kf) return state;

    // Deep copy of layerStates
    const clipboardData = JSON.parse(JSON.stringify(kf.layerStates));

    return { clipboard: clipboardData };
  }),

  pasteKeyframeState: () => set((state) => {
      const past = [...state.history.past, state.project].slice(-MAX_HISTORY);

      // If no clipboard data, do nothing
      if (!state.clipboard) return state;

      const kfId = state.ui.selectedKeyframeId;

      // CASE 1: Paste into an existing selected Keyframe
      if (kfId) {
          const newKeyframes = state.project.keyframes.map(kf => {
              if (kf.id === kfId) {
                  const pastedStates: LayerState[] = state.clipboard!.map(ls => ({
                      ...ls,
                      strokes: ls.strokes.map(s => ({ ...s, id: `stroke-${Date.now()}-${Math.random()}` }))
                  }));
                  return { ...kf, layerStates: pastedStates };
              }
              return kf;
          });

          return {
              project: { ...state.project, keyframes: newKeyframes },
              history: { past, future: [] }
          };
      } 
      // CASE 2: Paste into Undefined State (Create New Keyframe)
      else {
          const currentAxisValues: Record<string, number> = {};
          state.project.axes.forEach(a => currentAxisValues[a.id] = a.currentValue);

          const newKfId = `kf-${Date.now()}`;
          const pastedStates: LayerState[] = state.clipboard!.map(ls => ({
              ...ls,
              strokes: ls.strokes.map(s => ({ ...s, id: `stroke-${Date.now()}-${Math.random()}` }))
          }));

          const newKeyframe: Keyframe = {
              id: newKfId,
              name: `Keyframe ${state.project.keyframes.length}`,
              axisValues: currentAxisValues,
              layerStates: pastedStates
          };

          return {
              project: { ...state.project, keyframes: [...state.project.keyframes, newKeyframe] },
              ui: { ...state.ui, selectedKeyframeId: newKfId },
              history: { past, future: [] }
          };
      }
  })

}));

// components/Canvas.tsx
import React, { useRef, useLayoutEffect, useEffect, useState } from 'react';
import { useStore } from '../store/useStore';
import { interpolateStrokePoints, snapPointToGrid, isPointInStroke, calculateInterpolationWeights, distance, getBoundingBox, rotatePoint, lerp } from '../utils/math';
import { Point } from '../types';
import { APP_COLORS } from '../constants';

type InteractionMode = 'none' | 'drawing' | 'polyline' | 'dragging' | 'resizing' | 'rotating' | 'draggingVertex';
type ResizeHandle = 'tl' | 'tr' | 'bl' | 'br';

export const Canvas: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  const { 
      ui, project, updateAxisValue, updateMultipleAxisValues, 
      addStrokeToCurrentKeyframe, updateStrokeInCurrentKeyframe, selectStroke,
      undo, redo, deleteStroke 
  } = useStore();

  // -- Stable Refs for Animation Loop --
  const projectRef = useRef(project);
  const uiRef = useRef(ui);

  useEffect(() => { projectRef.current = project; }, [project]);
  useEffect(() => { uiRef.current = ui; }, [ui]);

  // -- Physics State (Refs to avoid re-renders) --
  const targetAxesRef = useRef<Record<string, number>>({ 'axis-x': 0.5, 'axis-y': 0.5 });
  const velocityRef = useRef<{ x: number, y: number }>({ x: 0, y: 0 });
  const lastFrameTimeRef = useRef<number>(0);

  // -- Interaction State (Refs needed for Loop access without stale closure) --
  const currentPointsRef = useRef<Point[]>([]); 
  const interactionModeRef = useRef<InteractionMode>('none');

  // -- SYNCED REFS FOR RENDERING --
  // We use State for React updates (UI), but Refs for the Canvas Loop to avoid stale closures.
  const [polylinePoints, setPolylinePoints] = useState<Point[]>([]);
  const polylinePointsRef = useRef<Point[]>([]);
  useEffect(() => { polylinePointsRef.current = polylinePoints; }, [polylinePoints]);

  const [mousePos, setMousePos] = useState<Point | null>(null);
  const mousePosRef = useRef<Point | null>(null);
  useEffect(() => { mousePosRef.current = mousePos; }, [mousePos]);

  const [selectionBounds, setSelectionBounds] = useState<{cx: number; cy: number; width: number; height: number; rotation: number;} | null>(null);
  const selectionBoundsRef = useRef(selectionBounds);
  useEffect(() => { selectionBoundsRef.current = selectionBounds; }, [selectionBounds]);

  const [transformStart, setTransformStart] = useState<{
      mouse: Point;
      center: Point;
      angle: number;
      width: number;
      height: number;
      points: Point[]; 
  } | null>(null);
  const transformStartRef = useRef(transformStart);
  useEffect(() => { transformStartRef.current = transformStart; }, [transformStart]);

  const [activeHandle, setActiveHandle] = useState<ResizeHandle | null>(null);
  const [activeVertexIndex, setActiveVertexIndex] = useState<number | null>(null);
  const activeVertexIndexRef = useRef<number | null>(null);
  useEffect(() => { activeVertexIndexRef.current = activeVertexIndex; }, [activeVertexIndex]);

  // Helpers to sync Ref and State
  const setInteractionMode = (mode: InteractionMode) => {
      interactionModeRef.current = mode;
      setInteractionModeState(mode);
  };
  const [interactionModeState, setInteractionModeState] = useState<InteractionMode>('none');

  // Layout
  const [scale, setScale] = useState(1);
  const CANVAS_WIDTH = project.canvasSize.width;
  const CANVAS_HEIGHT = project.canvasSize.height;

  // -- Helpers --

  // Auto-Scale Canvas
  useEffect(() => {
    const handleResize = () => {
      if (!containerRef.current) return;
      const { width: contW, height: contH } = containerRef.current.getBoundingClientRect();
      const margin = 80;
      const newScale = Math.min((contW - margin) / CANVAS_WIDTH, (contH - margin) / CANVAS_HEIGHT, 1);
      setScale(Math.max(0.1, newScale));
    };
    window.addEventListener('resize', handleResize);
    handleResize();
    return () => window.removeEventListener('resize', handleResize);
  }, [CANVAS_WIDTH, CANVAS_HEIGHT]);

  const getCanvasPoint = (e: React.PointerEvent): Point => {
    if (!canvasRef.current) return { x: 0, y: 0 };
    const rect = canvasRef.current.getBoundingClientRect();
    const x = (e.clientX - rect.left) * (CANVAS_WIDTH / rect.width);
    const y = (e.clientY - rect.top) * (CANVAS_HEIGHT / rect.height);
    return { x, y, pressure: e.pressure || 0.5 };
  };

  const getSnappedPoint = (p: Point): Point => {
      if (ui.snapToGrid) return snapPointToGrid(p, ui.gridSize);
      return p;
  };

  // -- GLOBAL PLAY MODE TRACKING --
  useEffect(() => {
    if (ui.mode !== 'play') return;

    const handleWindowPointerMove = (e: PointerEvent) => {
        if (!canvasRef.current) return;
        const rect = canvasRef.current.getBoundingClientRect();

        let normX = (e.clientX - rect.left) / rect.width;
        let normY = (e.clientY - rect.top) / rect.height;

        // Clamp strictly to 0-1 for axis value logic
        normX = Math.max(0, Math.min(1, normX));
        normY = Math.max(0, Math.min(1, normY));

        if (ui.snapPlayMode) {
            normX = Math.round(normX * 10) / 10;
            normY = Math.round(normY * 10) / 10;
        }

        targetAxesRef.current = { 'axis-x': normX, 'axis-y': normY };
    };

    window.addEventListener('pointermove', handleWindowPointerMove);
    return () => {
        window.removeEventListener('pointermove', handleWindowPointerMove);
    };
  }, [ui.mode, ui.snapPlayMode]);

  const handleDoubleClick = () => {
      if (ui.selectedTool === 'polyline') {
          if (polylinePoints.length > 1) addStrokeToCurrentKeyframe(polylinePoints, false, true);
          setPolylinePoints([]);
      }
  };

  // -- KEYBOARD SHORTCUTS MANAGER --
  useEffect(() => {
      const handleKeyDown = (e: KeyboardEvent) => {
          // Ignore if user is typing in an input
          if ((e.target as HTMLElement).tagName === 'INPUT') return;

          // 1. Tool Shortcuts
          if (e.key === 'Enter') { 
              if (ui.selectedTool === 'polyline') handleDoubleClick(); 
          }
          if (e.key === 'Escape') { 
              setPolylinePoints([]); 
              setInteractionMode('none'); 
              selectStroke(null);
          }

          // 2. Undo / Redo
          if ((e.metaKey || e.ctrlKey) && e.key === 'z') {
              e.preventDefault();
              if (e.shiftKey) redo();
              else undo();
          }
          if ((e.metaKey || e.ctrlKey) && e.key === 'y') {
              e.preventDefault();
              redo();
          }

          // 3. Deletion
          if (e.key === 'Backspace' || e.key === 'Delete') {
              if (ui.selectedStrokeId) {
                  deleteStroke(ui.selectedStrokeId);
              }
          }

          // 4. Nudge (Arrow Keys)
          if (ui.selectedStrokeId && ui.selectedKeyframeId && ui.selectedLayerId && (e.key.startsWith('Arrow'))) {
              e.preventDefault();
              const kf = project.keyframes.find(k => k.id === ui.selectedKeyframeId);
              const ls = kf?.layerStates.find(s => s.layerId === ui.selectedLayerId);
              const stroke = ls?.strokes.find(s => s.id === ui.selectedStrokeId);

              if (stroke) {
                  const step = e.shiftKey ? ui.gridSize : 1;
                  let dx = 0;
                  let dy = 0;
                  if (e.key === 'ArrowUp') dy = -step;
                  if (e.key === 'ArrowDown') dy = step;
                  if (e.key === 'ArrowLeft') dx = -step;
                  if (e.key === 'ArrowRight') dx = step;

                  const newPoints = stroke.points.map(p => ({ ...p, x: p.x + dx, y: p.y + dy }));
                  updateStrokeInCurrentKeyframe(stroke.id, newPoints);
              }
          }
      };

      window.addEventListener('keydown', handleKeyDown);
      return () => window.removeEventListener('keydown', handleKeyDown);
  }, [ui.selectedTool, ui.selectedStrokeId, ui.selectedKeyframeId, ui.selectedLayerId, polylinePoints, project.keyframes]);

  // -- Selection Logic --
  useEffect(() => {
    if (ui.selectedTool !== 'select' || !ui.selectedStrokeId || !ui.selectedKeyframeId) {
        setSelectionBounds(null);
        return;
    }
    const kf = project.keyframes.find(k => k.id === ui.selectedKeyframeId);
    if (!kf) return;
    const layerState = kf.layerStates.find(ls => ls.layerId === ui.selectedLayerId);
    if (!layerState) return;
    const stroke = layerState.strokes.find(s => s.id === ui.selectedStrokeId);
    if (!stroke) return;
    const bbox = getBoundingBox(stroke.points);
    setSelectionBounds({
        cx: bbox.centerX, cy: bbox.centerY, width: bbox.width, height: bbox.height, rotation: 0
    });
  }, [ui.selectedStrokeId, ui.selectedKeyframeId, ui.selectedLayerId, ui.selectedTool, project.keyframes]);

  // -- Gizmo Hit Testing --
  const getGizmoHit = (p: Point, bounds: { cx: number, cy: number, width: number, height: number, rotation: number } | null) => {
      if (!bounds) return null;
      const { cx, cy, width, height, rotation } = bounds;
      const hw = width / 2; const hh = height / 2;
      const localP = rotatePoint(p, {x: cx, y: cy}, -rotation);
      const HANDLE_SIZE = 10 / scale;
      if (distance(localP, {x: cx, y: cy - hh - 25}) < HANDLE_SIZE) return 'rotator';
      if (distance(localP, {x: cx - hw, y: cy - hh}) < HANDLE_SIZE) return 'tl';
      if (distance(localP, {x: cx + hw, y: cy - hh}) < HANDLE_SIZE) return 'tr';
      if (distance(localP, {x: cx - hw, y: cy + hh}) < HANDLE_SIZE) return 'bl';
      if (distance(localP, {x: cx + hw, y: cy + hh}) < HANDLE_SIZE) return 'br';
      if (localP.x >= cx - hw && localP.x <= cx + hw && localP.y >= cy - hh && localP.y <= cy + hh) return 'body';
      return null;
  };

  const getVertexHit = (p: Point, strokePoints: Point[]): number => {
      const HIT_THRESHOLD = 8 / scale;
      // Check in reverse to grab top-most if overlapping
      for (let i = strokePoints.length - 1; i >= 0; i--) {
          if (distance(p, strokePoints[i]) < HIT_THRESHOLD) return i;
      }
      return -1;
  };

  const findHitStroke = (p: Point): string | null => {
     const kf = project.keyframes.find(k => k.id === ui.selectedKeyframeId);
     if (!kf) return null;
     const layerState = kf.layerStates.find(ls => ls.layerId === ui.selectedLayerId);
     if (!layerState) return null;
     for (let i = layerState.strokes.length - 1; i >= 0; i--) {
        const s = layerState.strokes[i];
        if (isPointInStroke(p, s.points)) return s.id;
     }
     return null;
  };

  // -- Event Handlers --

  const handlePointerDown = (e: React.PointerEvent) => {
    const p = getCanvasPoint(e);

    if (ui.mode === 'play') {
       return;
    }

    if (ui.selectedTool === 'select') {

        // 1. VERTEX EDITING CHECK (If a stroke is already selected)
        if (ui.selectedStrokeId && selectionBounds) {
             const kf = project.keyframes.find(k => k.id === ui.selectedKeyframeId);
             const ls = kf?.layerStates.find(s => s.layerId === ui.selectedLayerId);
             const stroke = ls?.strokes.find(s => s.id === ui.selectedStrokeId);

             if (stroke) {
                 const vertexIndex = getVertexHit(p, stroke.points);
                 if (vertexIndex !== -1) {
                     setInteractionMode('draggingVertex');
                     setActiveVertexIndex(vertexIndex);
                     setTransformStart({
                        mouse: p, center: {x:0,y:0}, angle: 0, width: 0, height: 0, 
                        points: stroke.points // Store initial state
                     });
                     (e.target as Element).setPointerCapture(e.pointerId);
                     return;
                 }
             }
        }

        // 2. GIZMO CHECK
        const hitGizmo = getGizmoHit(p, selectionBounds);
        if (hitGizmo && selectionBounds && ui.selectedStrokeId) {
            const kf = project.keyframes.find(k => k.id === ui.selectedKeyframeId);
            const ls = kf?.layerStates.find(s => s.layerId === ui.selectedLayerId);
            const stroke = ls?.strokes.find(s => s.id === ui.selectedStrokeId);
            if (stroke) {
                setTransformStart({
                    mouse: p, center: { x: selectionBounds.cx, y: selectionBounds.cy },
                    angle: selectionBounds.rotation, width: selectionBounds.width, height: selectionBounds.height, points: stroke.points
                });
                if (hitGizmo === 'body') setInteractionMode('dragging');
                else if (hitGizmo === 'rotator') setInteractionMode('rotating');
