          // If Open: Skip alignment. Rely on stable 0-100% resampling. 
          //          This fixes the "Floating Ends" and "Inversion" bugs.
          // If Closed: Use alignment to handle start-point shifting in loops.
          const alignedPoints = alignPoints(referenceResampled, processedPoints, isClosed);

