// store/useStore.ts
import { create } from 'zustand';
import { Project, UIState, ToolType, Axis, Layer, Keyframe, Point, Stroke, LayerState, BlendMode, UIMode, InterpolationMode, InterpolationStrategy } from '../types';
import { DEFAULT_PROJECT, INITIAL_UI_STATE, DEFAULT_LAYER, DEFAULT_KEYFRAME } from '../constants';
import { simplifyPoints, distance, chaikinSmooth, simplifyCollinearPoints } from '../utils/math';

interface StoreState {
  project: Project;
  ui: UIState;

  history: {
    past: Project[];
    future: Project[];
  };

  // Internal Clipboard for Copy/Paste State
  clipboard: LayerState[] | null; 

  isSettingsOpen: boolean;

  // Actions
  undo: () => void;
  redo: () => void;

  // Project Actions
  resetProject: () => void;
  loadProject: (project: Project) => void;

  toggleSettings: () => void;
  toggleLayerPanel: () => void;
  closeAllPanels: () => void; // Used for clicking outside

  setMode: (mode: UIMode) => void;

  setTool: (tool: ToolType) => void;
  setBrushColor: (color: string) => void;
  setFillColor: (color: string) => void;
  setBrushSize: (size: number) => void;

  // Config Actions
  toggleGrid: () => void;
  toggleSnapToGrid: () => void;
  setCornerRoundness: (val: number) => void;

  toggleSnapPlayMode: () => void;
  toggleSnapMatrixGrid: () => void;
  setAxisMatrixDivisions: (val: number) => void;
  setAxisMatrixPadding: (val: number) => void;
  setInterpolationExponent: (val: number) => void;
  setInterpolationStrategy: (val: InterpolationStrategy) => void;

  togglePlayModePhysics: () => void;
  setSpringStiffness: (val: number) => void;
  setSpringDamping: (val: number) => void;

  setGridSize: (size: number) => void;
  toggleSmoothing: () => void; // Renamed from toggleSimplifyStrokes

  toggleOnionSkin: () => void;
  setOnionSkinOpacity: (opacity: number) => void;
  setInactiveLayerOpacity: (opacity: number) => void;
  setGhostStrokeOpacity: (opacity: number) => void;

  // Performance Actions
  setResolutionScale: (scale: number) => void;
  togglePerformanceMode: () => void;

  // Layer Actions
  addLayer: () => void;
  deleteLayer: (layerId: string) => void;
  renameLayer: (layerId: string, name: string) => void;
  reorderLayers: (fromIndex: number, toIndex: number) => void;
  toggleLayerVisibility: (layerId: string) => void;
  toggleLayerLock: (layerId: string) => void;
  setLayerBlendMode: (layerId: string, mode: BlendMode) => void;
  setLayerInterpolationMode: (layerId: string, mode: InterpolationMode) => void;
  selectLayer: (layerId: string) => void;

  updateAxisValue: (axisId: string, value: number) => void;
  updateMultipleAxisValues: (values: Record<string, number>) => void; // Batch update

  addStrokeToCurrentKeyframe: (points: Point[], closed?: boolean, skipSimplify?: boolean) => void; 
  updateStrokeInCurrentKeyframe: (strokeId: string, newPoints: Point[]) => void;
  deleteStroke: (strokeId: string) => void; 

  createKeyframeAtCurrentAxes: () => void;
  deleteKeyframe: (keyframeId: string) => void;
  updateKeyframePosition: (keyframeId: string, x: number, y: number) => void; 
  selectKeyframe: (keyframeId: string) => void;

  // Copy/Paste Actions
  copyKeyframeState: () => void;
  pasteKeyframeState: () => void;

  selectStroke: (strokeId: string | null) => void;
}

const MAX_HISTORY = 50;

export const useStore = create<StoreState>((set, get) => ({
  project: DEFAULT_PROJECT,
  ui: INITIAL_UI_STATE,
  isSettingsOpen: false,
  clipboard: null, // Initialize clipboard

  history: {
    past: [],
    future: []
  },

  resetProject: () => set(() => ({
      project: {
          ...DEFAULT_PROJECT,
          id: `project-${Date.now()}`,
          created: Date.now(),
          modified: Date.now(),
          // Ensure distinct instances for object references
          layers: [{...DEFAULT_LAYER, id: `layer-${Date.now()}`}],
          keyframes: [{...DEFAULT_KEYFRAME, id: `kf-${Date.now()}`, layerStates: [{ layerId: `layer-${Date.now()}`, strokes: [] }] }]
      },
      ui: {
          ...INITIAL_UI_STATE,
          selectedLayerId: `layer-${Date.now()}`,
          selectedKeyframeId: `kf-${Date.now()}`
      },
      clipboard: null,
      history: { past: [], future: [] }
  })),

  loadProject: (project) => set(() => ({
      project: project,
      ui: {
          ...INITIAL_UI_STATE,
          selectedLayerId: project.layers[0]?.id || null,
          selectedKeyframeId: project.keyframes[0]?.id || null
      },
      clipboard: null,
      history: { past: [], future: [] }
  })),

  toggleSettings: () => set((state) => ({ isSettingsOpen: !state.isSettingsOpen, ui: { ...state.ui, isLayerPanelOpen: false } })),
  toggleLayerPanel: () => set((state) => ({ ui: { ...state.ui, isLayerPanelOpen: !state.ui.isLayerPanelOpen }, isSettingsOpen: false })),
  closeAllPanels: () => set((state) => ({ isSettingsOpen: false, ui: { ...state.ui, isLayerPanelOpen: false } })),

  setMode: (mode) => set((state) => ({ ui: { ...state.ui, mode } })),

  undo: () => set((state) => {
    if (state.history.past.length === 0) return state;
    const previous = state.history.past[state.history.past.length - 1];
    const newPast = state.history.past.slice(0, -1);
    return {
      project: previous,
      history: {
        past: newPast,
        future: [state.project, ...state.history.future]
      }
    };
  }),

  redo: () => set((state) => {
    if (state.history.future.length === 0) return state;
    const next = state.history.future[0];
    const newFuture = state.history.future.slice(1);
    return {
      project: next,
      history: {
        past: [...state.history.past, state.project],
        future: newFuture
      }
    };
  }),

  setTool: (tool) => set((state) => ({ ui: { ...state.ui, selectedTool: tool, selectedStrokeId: null } })),

  setBrushColor: (color) => set((state) => {
    let project = state.project;
    let history = state.history;

    // Try to update existing stroke if we are on a keyframe
    if (state.ui.selectedKeyframeId && state.ui.selectedLayerId) {
        const kfId = state.ui.selectedKeyframeId;
        const layerId = state.ui.selectedLayerId;

        const kfIndex = project.keyframes.findIndex(k => k.id === kfId);
        if (kfIndex > -1) {
             const kf = project.keyframes[kfIndex];
             const lsIndex = kf.layerStates.findIndex(ls => ls.layerId === layerId);

             if (lsIndex > -1 && kf.layerStates[lsIndex].strokes.length > 0) {
                 // Push to history
                 const past = [...state.history.past, state.project].slice(-MAX_HISTORY);

                 const newKeyframes = [...project.keyframes];
                 const newKf = { ...newKeyframes[kfIndex] };
                 const newLayerStates = [...newKf.layerStates];
                 const newLs = { ...newLayerStates[lsIndex] };
                 const newStrokes = [...newLs.strokes];

                 newStrokes[0] = { ...newStrokes[0], color: color === 'none' ? 'rgba(0,0,0,0)' : color };

                 newLs.strokes = newStrokes;
                 newLayerStates[lsIndex] = newLs;
                 newKf.layerStates = newLayerStates;
                 newKeyframes[kfIndex] = newKf;

                 project = { ...project, keyframes: newKeyframes };
                 history = { past, future: [] };
             }
        }
    }

    return { 
       ui: { ...state.ui, brushColor: color },
       project,
       history
    };
  }),

  setFillColor: (color) => set((state) => {
    let project = state.project;
    let history = state.history;

    if (state.ui.selectedKeyframeId && state.ui.selectedLayerId) {
        const kfId = state.ui.selectedKeyframeId;
        const layerId = state.ui.selectedLayerId;

        const kfIndex = project.keyframes.findIndex(k => k.id === kfId);
        if (kfIndex > -1) {
             const kf = project.keyframes[kfIndex];
             const lsIndex = kf.layerStates.findIndex(ls => ls.layerId === layerId);

             if (lsIndex > -1 && kf.layerStates[lsIndex].strokes.length > 0) {
                 const past = [...state.history.past, state.project].slice(-MAX_HISTORY);

                 const newKeyframes = [...project.keyframes];
                 const newKf = { ...newKeyframes[kfIndex] };
                 const newLayerStates = [...newKf.layerStates];
                 const newLs = { ...newLayerStates[lsIndex] };
                 const newStrokes = [...newLs.strokes];

                 newStrokes[0] = { ...newStrokes[0], fillColor: color };

                 newLs.strokes = newStrokes;
                 newLayerStates[lsIndex] = newLs;
                 newKf.layerStates = newLayerStates;
                 newKeyframes[kfIndex] = newKf;

                 project = { ...project, keyframes: newKeyframes };
                 history = { past, future: [] };
             }
        }
    }

    return { 
        ui: { ...state.ui, fillColor: color },
        project,
        history
    };
  }),

  setBrushSize: (size) => set((state) => {
    let project = state.project;
    let history = state.history;

    if (state.ui.selectedKeyframeId && state.ui.selectedLayerId) {
        const kfId = state.ui.selectedKeyframeId;
        const layerId = state.ui.selectedLayerId;

        const kfIndex = project.keyframes.findIndex(k => k.id === kfId);
        if (kfIndex > -1) {
             const kf = project.keyframes[kfIndex];
             const lsIndex = kf.layerStates.findIndex(ls => ls.layerId === layerId);

             if (lsIndex > -1 && kf.layerStates[lsIndex].strokes.length > 0) {
                 const past = [...state.history.past, state.project].slice(-MAX_HISTORY);

                 const newKeyframes = [...project.keyframes];
                 const newKf = { ...newKeyframes[kfIndex] };
                 const newLayerStates = [...newKf.layerStates];
                 const newLs = { ...newLayerStates[lsIndex] };
                 const newStrokes = [...newLs.strokes];

                 newStrokes[0] = { ...newStrokes[0], width: size };

                 newLs.strokes = newStrokes;
                 newLayerStates[lsIndex] = newLs;
                 newKf.layerStates = newLayerStates;
                 newKeyframes[kfIndex] = newKf;

                 project = { ...project, keyframes: newKeyframes };
                 history = { past, future: [] };
             }
        }
    }

    return { 
        ui: { ...state.ui, brushSize: size },
        project,
        history
    };
  }),

  toggleGrid: () => set((state) => ({ ui: { ...state.ui, showGrid: !state.ui.showGrid } })),
  toggleSnapToGrid: () => set((state) => ({ ui: { ...state.ui, snapToGrid: !state.ui.snapToGrid } })),
  setCornerRoundness: (val) => set((state) => ({ ui: { ...state.ui, cornerRoundness: val } })),

  toggleSnapPlayMode: () => set((state) => ({ ui: { ...state.ui, snapPlayMode: !state.ui.snapPlayMode } })),
  toggleSnapMatrixGrid: () => set((state) => ({ ui: { ...state.ui, snapMatrixGrid: !state.ui.snapMatrixGrid } })),
  setAxisMatrixDivisions: (val) => set((state) => ({ ui: { ...state.ui, axisMatrixDivisions: val } })),
  setAxisMatrixPadding: (val) => set((state) => ({ ui: { ...state.ui, axisMatrixPadding: val } })),
  setInterpolationExponent: (val) => set((state) => ({ ui: { ...state.ui, interpolationExponent: val } })),
  setInterpolationStrategy: (val) => set((state) => ({ ui: { ...state.ui, interpolationStrategy: val } })),

  togglePlayModePhysics: () => set((state) => ({ ui: { ...state.ui, playModePhysics: !state.ui.playModePhysics } })),
  setSpringStiffness: (val) => set((state) => ({ ui: { ...state.ui, springStiffness: val } })),
  setSpringDamping: (val) => set((state) => ({ ui: { ...state.ui, springDamping: val } })),

  setGridSize: (size) => set((state) => ({ ui: { ...state.ui, gridSize: size } })),
  toggleSmoothing: () => set((state) => ({ ui: { ...state.ui, smoothingEnabled: !state.ui.smoothingEnabled } })),

  toggleOnionSkin: () => set((state) => ({ ui: { ...state.ui, onionSkinEnabled: !state.ui.onionSkinEnabled } })),
  setOnionSkinOpacity: (opacity) => set((state) => ({ ui: { ...state.ui, onionSkinOpacity: opacity } })),
  setInactiveLayerOpacity: (opacity) => set((state) => ({ ui: { ...state.ui, inactiveLayerOpacity: opacity } })),
  setGhostStrokeOpacity: (opacity) => set((state) => ({ ui: { ...state.ui, ghostStrokeOpacity: opacity } })),

  setResolutionScale: (scale) => set((state) => ({ ui: { ...state.ui, resolutionScale: scale } })),
  togglePerformanceMode: () => set((state) => ({ ui: { ...state.ui, performanceMode: !state.ui.performanceMode } })),

  updateAxisValue: (axisId, value) => set((state) => {
    const cleanValue = Math.max(0, Math.min(1, value));
    const newAxes = state.project.axes.map(a => 
      a.id === axisId ? { ...a, currentValue: cleanValue } : a
    );

    // Strict Selection Logic (keeps keyframe selected if we are close)
    // But doesn't FORCE snapping during drag (smooth experience)
    const currentAxisValues: Record<string, number> = {};
    newAxes.forEach(a => currentAxisValues[a.id] = a.currentValue);

    let matchingKfId = null;
    const exactMatch = state.project.keyframes.find(kf => {
      let dist = 0;
      for (const id in currentAxisValues) {
        dist += Math.abs((kf.axisValues[id] || 0) - currentAxisValues[id]);
      }
      return dist < 0.02; 
    });

    if (exactMatch) {
      matchingKfId = exactMatch.id;
    }

    return { 
      project: { ...state.project, axes: newAxes },
      ui: { ...state.ui, selectedKeyframeId: matchingKfId }
    };
  }),

  updateMultipleAxisValues: (values) => set((state) => {
    const newAxes = state.project.axes.map(a => 
       values[a.id] !== undefined ? { ...a, currentValue: Math.max(0, Math.min(1, values[a.id])) } : a
    );
    return {
        project: { ...state.project, axes: newAxes }
    };
  }),

  selectLayer: (layerId) => set((state) => ({ ui: { ...state.ui, selectedLayerId: layerId } })),
  selectKeyframe: (keyframeId) => set((state) => ({ ui: { ...state.ui, selectedKeyframeId: keyframeId } })),
  selectStroke: (strokeId) => set((state) => ({ ui: { ...state.ui, selectedStrokeId: strokeId } })),

  addLayer: () => set((state) => {
    const past = [...state.history.past, state.project].slice(-MAX_HISTORY);
    const newId = `layer-${Date.now()}`;
    const newLayer: Layer = {
      id: newId,
      name: `Layer ${state.project.layers.length + 1}`,
      visible: true,
      locked: false,
      blendMode: 'normal',
      opacity: 1,
      interpolationMode: 'resample'
    };
    return {
      project: { ...state.project, layers: [...state.project.layers, newLayer] },
      ui: { ...state.ui, selectedLayerId: newId },
      history: { past, future: [] }
    };
  }),

  reorderLayers: (fromIndex, toIndex) => set((state) => {
    if (fromIndex === toIndex) return state;
    const past = [...state.history.past, state.project].slice(-MAX_HISTORY);
    const newLayers = [...state.project.layers];
    const [moved] = newLayers.splice(fromIndex, 1);
    newLayers.splice(toIndex, 0, moved);

    return {
       project: { ...state.project, layers: newLayers },
       history: { past, future: [] }
    };
  }),

  deleteLayer: (layerId) => set((state) => {
    if (state.project.layers.length <= 1) return state; 
    const past = [...state.history.past, state.project].slice(-MAX_HISTORY);
    const newLayers = state.project.layers.filter(l => l.id !== layerId);

    const newKeyframes = state.project.keyframes.map(kf => ({
       ...kf,
       layerStates: kf.layerStates.filter(ls => ls.layerId !== layerId)
    }));

    return {
      project: { ...state.project, layers: newLayers, keyframes: newKeyframes },
      ui: { ...state.ui, selectedLayerId: newLayers[newLayers.length - 1].id },
      history: { past, future: [] }
    };
  }),

  renameLayer: (layerId, name) => set((state) => ({
    project: {
      ...state.project,
      layers: state.project.layers.map(l => l.id === layerId ? { ...l, name } : l)
    }
  })),

  toggleLayerVisibility: (layerId) => set((state) => ({
    project: {
      ...state.project,
      layers: state.project.layers.map(l => 
        l.id === layerId ? { ...l, visible: !l.visible } : l
      )
    }
  })),

  toggleLayerLock: (layerId) => set((state) => ({
    project: {
      ...state.project,
      layers: state.project.layers.map(l => 
        l.id === layerId ? { ...l, locked: !l.locked } : l
      )
    }
  })),

  setLayerBlendMode: (layerId, mode) => set((state) => {
    return {
      project: {
        ...state.project,
        layers: state.project.layers.map(l => 
          l.id === layerId ? { ...l, blendMode: mode } : l
        )
      }
    };
  }),

  setLayerInterpolationMode: (layerId, mode) => set((state) => {
    return {
      project: {
        ...state.project,
        layers: state.project.layers.map(l => 
          l.id === layerId ? { ...l, interpolationMode: mode } : l
        )
      }
    };
  }),

  addStrokeToCurrentKeyframe: (rawPoints, closed = false, skipSimplify = false) => set((state) => {
    const { selectedLayerId, brushColor, fillColor, brushSize, smoothingEnabled, snapToGrid, cornerRoundness } = state.ui;
    if (!selectedLayerId) return state;

    const layer = state.project.layers.find(l => l.id === selectedLayerId);
    if (layer?.locked || !layer?.visible) return state;

    let points = rawPoints;
    let shouldUpdateLayerMode = false;

    // --- GRID OPTIMIZATION ---
    if (snapToGrid) {
        points = simplifyCollinearPoints(rawPoints, 0.1);
        if (layer.interpolationMode === 'resample') {
            shouldUpdateLayerMode = true;
        }
    } 
    // --- SPLINE OPTIMIZATION ---
    // If we are in Spline mode, we want Anchors, not 1000 mouse points.
    else if (layer.interpolationMode === 'spline' && !skipSimplify) {
        // Aggressive simplification to create structural anchors
        points = simplifyPoints(rawPoints, 2.5);
    }
    // --- STANDARD OPTIMIZATION ---
    else if (!skipSimplify && smoothingEnabled) { 
       const preSimplified = simplifyPoints(rawPoints, 1.5);
       points = chaikinSmooth(preSimplified, 2);
    } else if (!skipSimplify && !smoothingEnabled) {
       points = simplifyPoints(rawPoints, 1.5);
    }

    // STRICT GEOMETRIC CLOSURE
    if (closed && points.length > 2) {
        const first = points[0];
        const last = points[points.length - 1];
        if (distance(first, last) < 2.0) {
             points[points.length - 1] = { ...first };
        } else {
             points.push({ ...first });
        }
    }

    const past = [...state.history.past, state.project].slice(-MAX_HISTORY);

    let updatedLayers = [...state.project.layers];
    if (shouldUpdateLayerMode) {
        updatedLayers = updatedLayers.map(l => 
            l.id === selectedLayerId ? { ...l, interpolationMode: 'points' } : l
        );
    }

    const currentAxisValues: Record<string, number> = {};
    state.project.axes.forEach(a => currentAxisValues[a.id] = a.currentValue);

    let targetKeyframeId = state.ui.selectedKeyframeId;
    let keyframes = [...state.project.keyframes];

    if (targetKeyframeId === null) {
      const newKfId = `kf-${Date.now()}`;
      const newKeyframe: Keyframe = {
        id: newKfId,
        name: `Keyframe ${keyframes.length}`,
        axisValues: currentAxisValues,
        layerStates: [] 
      };
      keyframes.push(newKeyframe);
      targetKeyframeId = newKfId;
    }

    const newStroke: Stroke = {
      id: `stroke-${selectedLayerId}-unique`,
      points,
      color: brushColor as string, 
      fillColor: fillColor,
      width: brushSize,
      style: 'solid',
      closed: false 
    };

    const newKeyframes = keyframes.map(kf => {
      if (kf.id === targetKeyframeId) {
        const existingLayerStateIndex = kf.layerStates.findIndex(ls => ls.layerId === selectedLayerId);
        let newLayerStates = [...kf.layerStates];

        if (existingLayerStateIndex >= 0) {
          newLayerStates[existingLayerStateIndex] = {
            ...newLayerStates[existingLayerStateIndex],
            strokes: [newStroke]
          };
        } else {
          newLayerStates.push({
            layerId: selectedLayerId,
            strokes: [newStroke]
          });
        }
        return { ...kf, layerStates: newLayerStates };
      }
      return kf;
    });

    return { 
      project: { ...state.project, keyframes: newKeyframes, layers: updatedLayers },
      ui: { ...state.ui, selectedKeyframeId: targetKeyframeId },
      history: { past, future: [] }
    };
  }),

  updateStrokeInCurrentKeyframe: (strokeId, newPoints) => set((state) => {
    const kfId = state.ui.selectedKeyframeId;
    if (!kfId) return state;

    const keyframes = state.project.keyframes.map(kf => {
      if (kf.id === kfId) {
         const newLayerStates = kf.layerStates.map(ls => {
            if (ls.layerId === state.ui.selectedLayerId) {
               return {
                  ...ls,
                  strokes: ls.strokes.map(s => ({ ...s, points: newPoints }))
               };
            }
            return ls;
         });
         return { ...kf, layerStates: newLayerStates };
      }
      return kf;
    });

    return { project: { ...state.project, keyframes }};
  }),

  deleteStroke: (strokeId) => set((state) => {
     const kfId = state.ui.selectedKeyframeId;
     const layerId = state.ui.selectedLayerId;
     if (!kfId || !layerId) return state;

     const past = [...state.history.past, state.project].slice(-MAX_HISTORY);

     const newKeyframes = state.project.keyframes.map(kf => {
         if (kf.id === kfId) {
             const newLayerStates = kf.layerStates.map(ls => {
                 if (ls.layerId === layerId) {
                     return {
                         ...ls,
                         strokes: ls.strokes.filter(s => s.id !== strokeId)
                     };
                 }
                 return ls;
             });
             return { ...kf, layerStates: newLayerStates };
         }
         return kf;
     });

     return {
         project: { ...state.project, keyframes: newKeyframes },
         ui: { ...state.ui, selectedStrokeId: null }, // Clear selection
         history: { past, future: [] }
     };
  }),

  createKeyframeAtCurrentAxes: () => set((state) => {
     const currentAxisValues: Record<string, number> = {};
     state.project.axes.forEach(a => currentAxisValues[a.id] = a.currentValue);

     const newKeyframe: Keyframe = {
        id: `kf-${Date.now()}`,
        name: `Keyframe ${state.project.keyframes.length}`,
        axisValues: currentAxisValues,
        layerStates: []
      };

      return {
        project: { ...state.project, keyframes: [...state.project.keyframes, newKeyframe] },
        ui: { ...state.ui, selectedKeyframeId: newKeyframe.id }
      };
  }),

  deleteKeyframe: (keyframeId) => set((state) => {
    if (state.project.keyframes.length <= 1) return state; 
    const past = [...state.history.past, state.project].slice(-MAX_HISTORY);
    const newKeyframes = state.project.keyframes.filter(k => k.id !== keyframeId);

    let newSelectedId = state.ui.selectedKeyframeId;
    if (keyframeId === newSelectedId) {
      newSelectedId = newKeyframes[0].id;
    }

    return {
      project: { ...state.project, keyframes: newKeyframes },
      ui: { ...state.ui, selectedKeyframeId: newSelectedId },
      history: { past, future: [] }
    };
  }),

  updateKeyframePosition: (keyframeId, x, y) => set((state) => {
     const past = [...state.history.past, state.project].slice(-MAX_HISTORY);

     const newKeyframes = state.project.keyframes.map(kf => {
         if (kf.id === keyframeId) {
             return {
                 ...kf,
                 axisValues: {
                     ...kf.axisValues,
                     'axis-x': x,
                     'axis-y': y
                 }
             };
         }
         return kf;
     });

     let newAxes = state.project.axes;
     if (state.ui.selectedKeyframeId === keyframeId) {
         newAxes = state.project.axes.map(a => {
             if (a.id === 'axis-x') return { ...a, currentValue: x };
             if (a.id === 'axis-y') return { ...a, currentValue: y };
             return a;
         });
     }

     return {
         project: { ...state.project, keyframes: newKeyframes, axes: newAxes },
         history: { past, future: [] }
     };
  }),

  // --- Copy / Paste Actions ---

  copyKeyframeState: () => set((state) => {
    const kfId = state.ui.selectedKeyframeId;
    if (!kfId) return state;

    const kf = state.project.keyframes.find(k => k.id === kfId);
    if (!kf) return state;

    // Deep copy of layerStates
    const clipboardData = JSON.parse(JSON.stringify(kf.layerStates));

    return { clipboard: clipboardData };
  }),

  pasteKeyframeState: () => set((state) => {
      const past = [...state.history.past, state.project].slice(-MAX_HISTORY);

      // If no clipboard data, do nothing
      if (!state.clipboard) return state;

      const kfId = state.ui.selectedKeyframeId;

      // CASE 1: Paste into an existing selected Keyframe
      if (kfId) {
          const newKeyframes = state.project.keyframes.map(kf => {
              if (kf.id === kfId) {
                  const pastedStates: LayerState[] = state.clipboard!.map(ls => ({
                      ...ls,
                      strokes: ls.strokes.map(s => ({ ...s, id: `stroke-${Date.now()}-${Math.random()}` }))
                  }));
                  return { ...kf, layerStates: pastedStates };
              }
              return kf;
          });

          return {
              project: { ...state.project, keyframes: newKeyframes },
              history: { past, future: [] }
          };
      } 
      // CASE 2: Paste into Undefined State (Create New Keyframe)
      else {
          const currentAxisValues: Record<string, number> = {};
          state.project.axes.forEach(a => currentAxisValues[a.id] = a.currentValue);

          const newKfId = `kf-${Date.now()}`;
          const pastedStates: LayerState[] = state.clipboard!.map(ls => ({
              ...ls,
              strokes: ls.strokes.map(s => ({ ...s, id: `stroke-${Date.now()}-${Math.random()}` }))
          }));

          const newKeyframe: Keyframe = {
              id: newKfId,
              name: `Keyframe ${state.project.keyframes.length}`,
              axisValues: currentAxisValues,
              layerStates: pastedStates
          };

          return {
              project: { ...state.project, keyframes: [...state.project.keyframes, newKeyframe] },
              ui: { ...state.ui, selectedKeyframeId: newKfId },
              history: { past, future: [] }
          };
      }
  })

}));

// utils/math.ts
import { Point, Stroke, InterpolationStrategy } from '../types';

export const distance = (p1: Point, p2: Point): number => {
  return Math.sqrt(Math.pow(p2.x - p1.x, 2) + Math.pow(p2.y - p1.y, 2));
};

export const lerp = (start: number, end: number, t: number): number => {
  return start * (1 - t) + end * t;
};

// --- Transformation Helpers ---

export const rotatePoint = (p: Point, center: Point, angleRad: number): Point => {
  const cos = Math.cos(angleRad);
  const sin = Math.sin(angleRad);
  const dx = p.x - center.x;
  const dy = p.y - center.y;
  return {
    x: center.x + (dx * cos - dy * sin),
    y: center.y + (dx * sin + dy * cos),
    pressure: p.pressure
  };
};

export const getBoundingBox = (points: Point[]): { minX: number, maxX: number, minY: number, maxY: number, width: number, height: number, centerX: number, centerY: number } => {
  if (points.length === 0) return { minX:0, maxX:0, minY:0, maxY:0, width:0, height:0, centerX:0, centerY:0 };

  let minX = Infinity, maxX = -Infinity, minY = Infinity, maxY = -Infinity;
  for (const p of points) {
    if (p.x < minX) minX = p.x;
    if (p.x > maxX) maxX = p.x;
    if (p.y < minY) minY = p.y;
    if (p.y > maxY) maxY = p.y;
  }

  return {
    minX, maxX, minY, maxY,
    width: maxX - minX,
    height: maxY - minY,
    centerX: minX + (maxX - minX) / 2,
    centerY: minY + (maxY - minY) / 2
  };
};

// --- Color Interpolation (RGBA) ---

const colorCache: Record<string, { r: number, g: number, b: number, a: number }> = {};

const parseColor = (color: string): { r: number, g: number, b: number, a: number } => {
  if (!color || color === 'none') return { r: 0, g: 0, b: 0, a: 1 }; 
  if (colorCache[color]) return colorCache[color];

  let result = { r: 0, g: 0, b: 0, a: 1 };

  if (color.startsWith('#')) {
    let hex = color.slice(1);
    if (hex.length === 3) hex = hex.split('').map(c => c + c).join('');
    const bigint = parseInt(hex, 16);
    result = {
      r: (bigint >> 16) & 255,
      g: (bigint >> 8) & 255,
      b: bigint & 255,
      a: 1
    };
  }
  else if (color.startsWith('rgb')) {
    const match = color.match(/(\d+(\.\d+)?)/g);
    if (match) {
        result = {
            r: parseFloat(match[0]),
            g: parseFloat(match[1]),
            b: parseFloat(match[2]),
            a: match[3] ? parseFloat(match[3]) : 1
        };
    }
  }

  colorCache[color] = result;
  return result;
};

export const mixColors = (colors: { color: string | 'none', weight: number }[]): string => {
  let rSum = 0, gSum = 0, bSum = 0, aSum = 0;
  let hasColor = false;

  for (const c of colors) {
    const rgba = parseColor(c.color);
    const alpha = c.color === 'none' ? 0 : rgba.a;

    if (alpha > 0) {
        hasColor = true;
        rSum += rgba.r * c.weight * alpha;
        gSum += rgba.g * c.weight * alpha;
        bSum += rgba.b * c.weight * alpha;
    }
    aSum += alpha * c.weight;
  }

  if (!hasColor || aSum <= 0.001) return 'none';

  let totalAlphaWeight = 0; 
  colors.forEach(c => {
     const rgba = parseColor(c.color);
     const alpha = c.color === 'none' ? 0 : rgba.a;
     totalAlphaWeight += c.weight * alpha;
  });

  if (totalAlphaWeight <= 0.0001) return 'rgba(0,0,0,0)';

  const finalR = rSum / totalAlphaWeight;
  const finalG = gSum / totalAlphaWeight;
  const finalB = bSum / totalAlphaWeight;

  return `rgba(${Math.round(finalR)}, ${Math.round(finalG)}, ${Math.round(finalB)}, ${aSum.toFixed(3)})`;
};

// --- Geometry Helpers ---

const getPathLength = (points: Point[]): number => {
  let len = 0;
  for (let i = 1; i < points.length; i++) {
    len += distance(points[i - 1], points[i]);
  }
  return len;
};

// Curve Resampling (Arc-Length)
export const resamplePoints = (points: Point[], targetCount: number): Point[] => {
  if (points.length < 2 || targetCount < 2) return points;

  const totalLength = getPathLength(points);
  if (totalLength === 0) return Array(targetCount).fill(points[0]);

  const step = totalLength / (targetCount - 1);
  const newPoints: Point[] = [points[0]];

  let currentDist = 0;
  let nextPointIndex = 1;

  for (let i = 1; i < targetCount; i++) {
    const targetDist = i * step;
    let distSoFar = currentDist;
    let p1 = points[nextPointIndex - 1];
    let p2 = points[nextPointIndex];
    let segmentDist = distance(p1, p2);

    while (distSoFar + segmentDist < targetDist && nextPointIndex < points.length - 1) {
      distSoFar += segmentDist;
      currentDist = distSoFar;
      nextPointIndex++;
      p1 = points[nextPointIndex - 1];
      p2 = points[nextPointIndex];
      segmentDist = distance(p1, p2);
    }

    const segmentLocalDist = targetDist - distSoFar;
    const t = segmentDist === 0 ? 0 : segmentLocalDist / segmentDist;

    newPoints.push({
      x: lerp(p1.x, p2.x, t),
      y: lerp(p1.y, p2.y, t),
      pressure: lerp(p1.pressure || 0.5, p2.pressure || 0.5, t)
    });
  }

  // Ensure strict end-point matching
  if (newPoints.length < targetCount) {
      while (newPoints.length < targetCount) newPoints.push(points[points.length - 1]);
  } else if (newPoints.length === targetCount) {
      // Force last point to be exactly the source last point to avoid floating error
      newPoints[targetCount - 1] = points[points.length - 1];
  } else {
      newPoints.length = targetCount;
      newPoints[targetCount - 1] = points[points.length - 1];
  }

  return newPoints;
};

// --- CORNER-PRESERVING UPSAMPLING ---
export const upsamplePreservingCorners = (points: Point[], targetCount: number): Point[] => {
    if (points.length === 0) return [];
    if (points.length >= targetCount) return points; 

    const pointsToAdd = targetCount - points.length;
    const segments = points.length - 1;
    if (segments < 1) return Array(targetCount).fill(points[0]);

    const baseAdd = Math.floor(pointsToAdd / segments);
    const remainder = pointsToAdd % segments;

    const newPoints: Point[] = [];

    for (let i = 0; i < segments; i++) {
        newPoints.push(points[i]);

        const count = baseAdd + (i < remainder ? 1 : 0);

        if (count > 0) {
            const pStart = points[i];
            const pEnd = points[i+1];
            for (let k = 1; k <= count; k++) {
                const t = k / (count + 1);
                newPoints.push({
                    x: lerp(pStart.x, pEnd.x, t),
                    y: lerp(pStart.y, pEnd.y, t),
                    pressure: lerp(pStart.pressure||0.5, pEnd.pressure||0.5, t)
                });
            }
        }
    }
    // Always add the very last point
    newPoints.push(points[points.length - 1]);

    return newPoints;
};

export const snapPointToGrid = (p: Point, gridSize: number, offset: {x: number, y: number} = {x:0, y:0}): Point => {
  return {
    x: Math.round((p.x - offset.x) / gridSize) * gridSize + offset.x,
    y: Math.round((p.y - offset.y) / gridSize) * gridSize + offset.y,
    pressure: p.pressure
  };
};

// --- Hit Testing ---

const distToSegment = (p: Point, v: Point, w: Point) => {
  const l2 = Math.pow(distance(v, w), 2);
  if (l2 === 0) return distance(p, v);
  let t = ((p.x - v.x) * (w.x - v.x) + (p.y - v.y) * (w.y - v.y)) / l2;
  t = Math.max(0, Math.min(1, t));
  const projection = { x: v.x + t * (w.x - v.x), y: v.y + t * (w.y - v.y) };
  return distance(p, projection);
};

export const isPointInStroke = (p: Point, points: Point[], threshold: number = 10): boolean => {
  for (let i = 0; i < points.length - 1; i++) {
    if (distToSegment(p, points[i], points[i+1]) < threshold) return true;
  }
  return false;
};

// --- ALIGNMENT (ABSOLUTE LINEAR) ---

// NO-CLOSE POLICY: We intentionally disabled all cyclic logic.
// Points are matched strictly by index/percentage from Start to End.
// This prevents "jumping" when interpolating between open and closed shapes.
const alignPoints = (reference: Point[], target: Point[], isClosed: boolean): Point[] => {
    // We simply return the target. 
    // The previous cyclic shifting logic was causing the artifacts.
    // By forcing strict linear mapping, P[0] is always P[0].
    return target; 
};

// --- INTERPOLATION STRATEGIES ---

const calculateBilinearGridWeights = (
  currentAxes: Record<string, number>,
  keyframes: { id: string; axisValues: Record<string, number> }[]
) => {
  const weights: Record<string, number> = {};

  const curX = currentAxes['axis-x'] || 0;
  const curY = currentAxes['axis-y'] || 0;
  const EPSILON = 0.005;

  const distinctCoords = (arr: number[]) => {
      const sorted = [...arr].sort((a,b) => a - b);
      const result = [];
      if (sorted.length > 0) result.push(sorted[0]);
      for (let i = 1; i < sorted.length; i++) {
          if (sorted[i] > sorted[i-1] + EPSILON) result.push(sorted[i]);
      }
      return result;
  };
  const xCoords = distinctCoords(keyframes.map(k => k.axisValues['axis-x'] || 0));
  const yCoords = distinctCoords(keyframes.map(k => k.axisValues['axis-y'] || 0));

  if (xCoords.length === 0 || yCoords.length === 0) {
      if (keyframes.length > 0) weights[keyframes[0].id] = 1;
      return weights;
  }

  const findInterval = (val: number, grid: number[]) => {
      if (val <= grid[0]) return { lower: grid[0], upper: grid[0], t: 0 };
      if (val >= grid[grid.length - 1]) return { lower: grid[grid.length - 1], upper: grid[grid.length - 1], t: 0 };
      for (let i = 0; i < grid.length - 1; i++) {
          if (val >= grid[i] && val <= grid[i+1]) {
              const span = grid[i+1] - grid[i];
              return { lower: grid[i], upper: grid[i+1], t: span === 0 ? 0 : (val - grid[i]) / span };
          }
      }
      return { lower: grid[0], upper: grid[0], t: 0 };
  };

  const xInfo = findInterval(curX, xCoords);
  const yInfo = findInterval(curY, yCoords);

  const resolveCornerWeights = (targetX: number, targetY: number) => {
      const exact = keyframes.find(k => Math.abs((k.axisValues['axis-x']||0) - targetX) < EPSILON && Math.abs((k.axisValues['axis-y']||0) - targetY) < EPSILON);
      if (exact) return { [exact.id]: 1.0 };

      let totalW = 0;
      const cornerWeights: Record<string, number> = {};

      keyframes.forEach(k => {
          const dx = (k.axisValues['axis-x']||0) - targetX;
          const dy = (k.axisValues['axis-y']||0) - targetY;
          const dist = Math.sqrt(dx*dx + dy*dy);
          if (dist < 0.001) { cornerWeights[k.id] = 1000; totalW += 1000; }
          else {
              const w = 1 / Math.pow(dist, 2);
              cornerWeights[k.id] = w;
              totalW += w;
          }
      });

      for(const id in cornerWeights) cornerWeights[id] /= totalW;
      return cornerWeights;
  };

  const corners = [
      { x: xInfo.lower, y: yInfo.lower, wBase: (1 - xInfo.t) * (1 - yInfo.t) },
      { x: xInfo.upper, y: yInfo.lower, wBase: xInfo.t * (1 - yInfo.t) },
      { x: xInfo.lower, y: yInfo.upper, wBase: (1 - xInfo.t) * yInfo.t },
      { x: xInfo.upper, y: yInfo.upper, wBase: xInfo.t * yInfo.t }
  ];

  corners.forEach(c => {
      if (c.wBase <= 0.0001) return;
      const cornerComposition = resolveCornerWeights(c.x, c.y);
      for (const kfId in cornerComposition) {
          weights[kfId] = (weights[kfId] || 0) + (cornerComposition[kfId] * c.wBase);
      }
  });

  return weights;
};

const calculateIDWWeights = (currentAxes: Record<string, number>, keyframes: { id: string; axisValues: Record<string, number> }[], exponent: number) => {
    const weights: Record<string, number> = {};
    let totalWeight = 0;
    for (const kf of keyframes) {
        let dist = 0;
        for (const axisId in currentAxes) dist += Math.pow((currentAxes[axisId] || 0) - (kf.axisValues[axisId] || 0), 2);
        dist = Math.sqrt(dist);
        if (dist < 0.001) {
             keyframes.forEach(k => weights[k.id] = 0);
             weights[kf.id] = 1; 
             return weights; 
        }
        const w = 1 / Math.pow(dist, exponent);
        weights[kf.id] = w;
        totalWeight += w;
    }
    for (const id in weights) weights[id] /= totalWeight;
    return weights;
};

export const calculateInterpolationWeights = (
  currentAxes: Record<string, number>,
  keyframes: { id: string; axisValues: Record<string, number> }[],
  exponent: number = 2,
  strategy: InterpolationStrategy = 'bilinear-grid'
): Record<string, number> => {
   if (keyframes.length === 0) return {};
   if (keyframes.length === 1) return { [keyframes[0].id]: 1.0 };
   if (strategy === 'bilinear-grid') return calculateBilinearGridWeights(currentAxes, keyframes);
   return calculateIDWWeights(currentAxes, keyframes, exponent);
};

// --- CORE INTERPOLATION ENGINE ---

export const interpolateStrokePoints = (
  strokeId: string,
  basePoints: Point[], 
  keyframesData: { weight: number; points: Point[] | undefined, style: Stroke | undefined }[],
  mode: 'resample' | 'points' | 'spline' = 'resample',
  targetCount: number = 200 
): { points: Point[], color: string, fillColor: string, width: number } => {

  // 1. Filter active keyframes
  const activeKeyframes = keyframesData.filter(k => k.weight > 0.0001 && k.points && k.points.length > 0);
  if (activeKeyframes.length === 0) return { points: [], color: 'rgba(0,0,0,0)', fillColor: 'none', width: 1 };

  // 2. Mix Properties
  const color = mixColors(activeKeyframes.map(k => ({ color: k.style?.color || 'none', weight: k.weight })));
  const fillColor = mixColors(activeKeyframes.map(k => ({ color: k.style?.fillColor || 'none', weight: k.weight })));

  let totalWidth = 0;
  let widthWeightDivisor = 0;
  activeKeyframes.forEach(k => {
      totalWidth += (k.style?.width || 1) * k.weight;
      widthWeightDivisor += k.weight;
  });
  const width = widthWeightDivisor > 0 ? totalWidth / widthWeightDivisor : 1;

  // 3. Point Count Calculation
  let ACTUAL_TARGET_COUNT = targetCount; 
  const maxPts = Math.max(...activeKeyframes.map(k => k.points!.length));

  if (mode === 'points' || mode === 'spline') {
      ACTUAL_TARGET_COUNT = maxPts;
  }

  // 4. Reference Selection & Geometry Analysis
  const referenceKeyframe = activeKeyframes.reduce((prev, current) => {
      return (prev.weight >= current.weight) ? prev : current;
  });

  const referenceStroke = referenceKeyframe.points!;

  // Note: isClosed is purely geometric now (for resampling), NOT for alignment logic.
  const isClosed = distance(referenceStroke[0], referenceStroke[referenceStroke.length - 1]) < 5.0;

  // Resample Reference
  let referenceResampled: Point[];
  if (mode === 'points' || mode === 'spline') {
      referenceResampled = upsamplePreservingCorners(referenceStroke, ACTUAL_TARGET_COUNT);
  } else {
      referenceResampled = resamplePoints(referenceStroke, ACTUAL_TARGET_COUNT);
  }

  const resultPoints: Point[] = [];

  for (let i = 0; i < ACTUAL_TARGET_COUNT; i++) {
      let x = 0;
      let y = 0;
      let pressure = 0;
      let totalWeight = 0;

      for (const kf of activeKeyframes) {
          const rawPoints = kf.points!;
          let processedPoints: Point[] = [];

          if (mode === 'points' || mode === 'spline') {
             if (rawPoints.length === ACTUAL_TARGET_COUNT) {
                 processedPoints = rawPoints;
             } else {
                 processedPoints = upsamplePreservingCorners(rawPoints, ACTUAL_TARGET_COUNT);
             }
          } else {
             processedPoints = resamplePoints(rawPoints, ACTUAL_TARGET_COUNT);
          }

          // STRICT LINEAR ALIGNMENT
          // We pass isClosed, but inside alignPoints we ignore it to force linear matching
          const alignedPoints = alignPoints(referenceResampled, processedPoints, isClosed);

          const pt = alignedPoints[i];

          x += pt.x * kf.weight;
          y += pt.y * kf.weight;
          pressure += (pt.pressure || 0.5) * kf.weight;
          totalWeight += kf.weight;
      }

      if (totalWeight > 0) {
          resultPoints.push({
              x: x / totalWeight,
              y: y / totalWeight,
              pressure: pressure / totalWeight
          });
      }
  }

  return { points: resultPoints, color, fillColor, width };
};

// --- OPTIMIZATION & SMOOTHING ---

const perpendicularDistance = (point: Point, lineStart: Point, lineEnd: Point): number => {
  let dx = lineEnd.x - lineStart.x;
  let dy = lineEnd.y - lineStart.y;
  const mag = Math.sqrt(dx * dx + dy * dy);
  if (mag > 0.0) { dx /= mag; dy /= mag; }
  const pvx = point.x - lineStart.x;
  const pvy = point.y - lineStart.y;
  const pvdot = pvx * dx + pvy * dy;
  const dsx = pvdot * dx;
  const dsy = pvdot * dy;
  const ax = pvx - dsx;
  const ay = pvy - dsy;
  return Math.sqrt(ax * ax + ay * ay);
};

export const simplifyPoints = (points: Point[], epsilon: number = 2): Point[] => {
  if (points.length < 3) return points;
  let dmax = 0;
  let index = 0;
  const end = points.length - 1;
  for (let i = 1; i < end; i++) {
    const d = perpendicularDistance(points[i], points[0], points[end]);
    if (d > dmax) { index = i; dmax = d; }
  }
  if (dmax > epsilon) {
    const recResults1 = simplifyPoints(points.slice(0, index + 1), epsilon);
    const recResults2 = simplifyPoints(points.slice(index, end + 1), epsilon);
    return [...recResults1.slice(0, -1), ...recResults2];
  } else {
    return [points[0], points[end]];
  }
};

export const simplifyCollinearPoints = (points: Point[], epsilon: number = 0.1): Point[] => {
  if (points.length < 3) return points;
  const result = [points[0]];
  for (let i = 1; i < points.length - 1; i++) {
    const prev = result[result.length - 1];
    const curr = points[i];
    const next = points[i + 1];
    const val = (curr.y - prev.y) * (next.x - curr.x) - (curr.x - prev.x) * (next.y - curr.y);
    if (Math.abs(val) > epsilon) {
       result.push(curr);
    }
  }
  result.push(points[points.length - 1]);
  return result;
};

export const chaikinSmooth = (points: Point[], iterations: number = 2): Point[] => {
    if (points.length < 3) return points;
    let output = [...points];
    for (let i = 0; i < iterations; i++) {
        const next: Point[] = [];
        next.push(output[0]);
        for (let j = 0; j < output.length - 1; j++) {
            const p0 = output[j];
            const p1 = output[j + 1];
            next.push({
                x: 0.75 * p0.x + 0.25 * p1.x,
                y: 0.75 * p0.y + 0.25 * p1.y,
                pressure: lerp(p0.pressure || 0.5, p1.pressure || 0.5, 0.25)
            });
            next.push({
                x: 0.25 * p0.x + 0.75 * p1.x,
                y: 0.25 * p0.y + 0.75 * p1.y,
                pressure: lerp(p0.pressure || 0.5, p1.pressure || 0.5, 0.75)
            });
        }
        next.push(output[output.length - 1]);
        output = next;
    }
    return output;
};

// --- RENDERERS (NO-CLOSE POLICY) ---

// Replaced ctx.closePath() with explicit lineTo for absolute open-path rendering.
export const drawCornerRoundedPath = (ctx: CanvasRenderingContext2D, rawPoints: Point[], roundness: number) => {
    if (rawPoints.length < 2) return;

    // 1. FILTERING: Robustness against collinear/dense points
    const points: Point[] = [];
    points.push(rawPoints[0]);

    for (let i = 1; i < rawPoints.length; i++) {
        const curr = rawPoints[i];
        const prev = points[points.length - 1];
        if (distance(prev, curr) < 0.1) continue;

        if (points.length > 1) {
            const prevPrev = points[points.length - 2];
            const v1x = prev.x - prevPrev.x;
            const v1y = prev.y - prevPrev.y;
            const v2x = curr.x - prev.x;
            const v2y = curr.y - prev.y;
            const l1 = Math.sqrt(v1x*v1x + v1y*v1y);
            const l2 = Math.sqrt(v2x*v2x + v2y*v2y);
            if (l1 > 0 && l2 > 0) {
                const dot = (v1x*v2x + v1y*v2y) / (l1 * l2);
                if (dot > 0.999) { points[points.length - 1] = curr; continue; }
            }
        }
        points.push(curr);
    }

    // Ensure geometric loop consistency without logical closure
    const rawClosed = distance(rawPoints[0], rawPoints[rawPoints.length-1]) < 0.1;
    if (rawClosed && distance(points[0], points[points.length-1]) > 0.1) {
         points.push(points[0]);
    }

    if (points.length < 2) return;

    const isClosed = distance(points[0], points[points.length - 1]) < 0.1;
    let uniquePoints = isClosed ? points.slice(0, -1) : points;

    if (uniquePoints.length < 2) return;

    ctx.beginPath();

    if (!isClosed) {
        ctx.moveTo(points[0].x, points[0].y);
    } 

    const len = uniquePoints.length;
    const startIdx = isClosed ? 0 : 1;
    const endIdx = isClosed ? len : len - 1;

    if (isClosed) {
        const pLast = uniquePoints[len-1];
        const pFirst = uniquePoints[0];
        ctx.moveTo((pLast.x + pFirst.x)/2, (pLast.y + pFirst.y)/2);
    }

    for (let i = startIdx; i < endIdx; i++) {
        const curr = uniquePoints[i];

        const prevIdx = (i - 1 + len) % len;
        const nextIdx = (i + 1) % len;

        const prev = isClosed ? uniquePoints[prevIdx] : points[i-1];
        const next = isClosed ? uniquePoints[nextIdx] : points[i+1];

        const len1 = distance(prev, curr);
        const len2 = distance(curr, next);

        if (len1 < 0.01 || len2 < 0.01) {
            ctx.lineTo(curr.x, curr.y);
            continue;
        }

        const v1x = curr.x - prev.x; const v1y = curr.y - prev.y;
        const v2x = next.x - curr.x; const v2y = next.y - curr.y;
        const n1x = v1x/len1; const n1y = v1y/len1;
        const n2x = v2x/len2; const n2y = v2y/len2;
        const dot = n1x * n2x + n1y * n2y;

        if (dot > 0.99) {
             ctx.lineTo(curr.x, curr.y);
             continue;
        }

        const maxTangent = Math.min(len1, len2) * 0.5;
        const currentTangent = maxTangent * (roundness / 100);
        const angle = Math.acos(Math.max(-1, Math.min(1, dot)));
        const innerAngle = Math.PI - angle;
        const radius = currentTangent * Math.tan(innerAngle / 2);

        ctx.arcTo(curr.x, curr.y, next.x, next.y, radius);
    }

    // MANDATORY: Never closePath. Always lineTo last point.
    if (isClosed) {
        // If it was closed, we started at the midpoint of last segment.
        // We must draw line to there to finish.
        const pLast = uniquePoints[len-1];
        const pFirst = uniquePoints[0];
        ctx.lineTo((pLast.x + pFirst.x)/2, (pLast.y + pFirst.y)/2);
    } else {
        ctx.lineTo(points[points.length-1].x, points[points.length-1].y);
    }
};

export const drawCatmullRomSpline = (ctx: CanvasRenderingContext2D, points: Point[], tension: number = 0.5) => {
    if (points.length < 2) return;

    ctx.beginPath();
    ctx.moveTo(points[0].x, points[0].y);

    const len = points.length;
    const isClosed = distance(points[0], points[len - 1]) < 0.1;

    for (let i = 0; i < len - 1; i++) {
        const p0 = i > 0 ? points[i - 1] : points[0];
        const p1 = points[i];
        const p2 = points[i + 1];
        const p3 = i < len - 2 ? points[i + 2] : points[len - 1];

        // Even in "Open" logic, if geometry loops, we smooth the tangent using the loop points
        const p0_loop = isClosed && i === 0 ? points[len - 2] : p0;
        const p3_loop = isClosed && i === len - 2 ? points[1] : p3;

        const cp1x = p1.x + (p2.x - (isClosed ? p0_loop.x : p0.x)) / 6 * tension;
        const cp1y = p1.y + (p2.y - (isClosed ? p0_loop.y : p0.y)) / 6 * tension;
        const cp2x = p2.x - ((isClosed ? p3_loop.x : p3.x) - p1.x) / 6 * tension;
        const cp2y = p2.y - ((isClosed ? p3_loop.y : p3.y) - p1.y) / 6 * tension;

        ctx.bezierCurveTo(cp1x, cp1y, cp2x, cp2y, p2.x, p2.y);
    }

    // NEVER ctx.closePath(). The path is visually closed by the last segment connecting to P_n (which is == P_0).
};

// utils/math.ts
import { Point, Stroke, InterpolationStrategy } from '../types';

export const distance = (p1: Point, p2: Point): number => {
  return Math.sqrt(Math.pow(p2.x - p1.x, 2) + Math.pow(p2.y - p1.y, 2));
};

export const lerp = (start: number, end: number, t: number): number => {
  return start * (1 - t) + end * t;
};

// --- Transformation Helpers ---

export const rotatePoint = (p: Point, center: Point, angleRad: number): Point => {
  const cos = Math.cos(angleRad);
  const sin = Math.sin(angleRad);
  const dx = p.x - center.x;
  const dy = p.y - center.y;
  return {
    x: center.x + (dx * cos - dy * sin),
    y: center.y + (dx * sin + dy * cos),
    pressure: p.pressure
  };
};

export const getBoundingBox = (points: Point[]): { minX: number, maxX: number, minY: number, maxY: number, width: number, height: number, centerX: number, centerY: number } => {
  if (points.length === 0) return { minX:0, maxX:0, minY:0, maxY:0, width:0, height:0, centerX:0, centerY:0 };

  let minX = Infinity, maxX = -Infinity, minY = Infinity, maxY = -Infinity;
  for (const p of points) {
    if (p.x < minX) minX = p.x;
    if (p.x > maxX) maxX = p.x;
    if (p.y < minY) minY = p.y;
    if (p.y > maxY) maxY = p.y;
  }

  return {
    minX, maxX, minY, maxY,
    width: maxX - minX,
    height: maxY - minY,
    centerX: minX + (maxX - minX) / 2,
    centerY: minY + (maxY - minY) / 2
  };
};

// --- Color Interpolation (RGBA) ---

const colorCache: Record<string, { r: number, g: number, b: number, a: number }> = {};

const parseColor = (color: string): { r: number, g: number, b: number, a: number } => {
  if (!color || color === 'none') return { r: 0, g: 0, b: 0, a: 1 }; 
  if (colorCache[color]) return colorCache[color];

  let result = { r: 0, g: 0, b: 0, a: 1 };

  if (color.startsWith('#')) {
    let hex = color.slice(1);
    if (hex.length === 3) hex = hex.split('').map(c => c + c).join('');
    const bigint = parseInt(hex, 16);
    result = {
      r: (bigint >> 16) & 255,
      g: (bigint >> 8) & 255,
      b: bigint & 255,
      a: 1
    };
  }
  else if (color.startsWith('rgb')) {
    const match = color.match(/(\d+(\.\d+)?)/g);
    if (match) {
        result = {
            r: parseFloat(match[0]),
            g: parseFloat(match[1]),
            b: parseFloat(match[2]),
            a: match[3] ? parseFloat(match[3]) : 1
        };
    }
  }

  colorCache[color] = result;
  return result;
};

export const mixColors = (colors: { color: string | 'none', weight: number }[]): string => {
  let rSum = 0, gSum = 0, bSum = 0, aSum = 0;
  let hasColor = false;

  for (const c of colors) {
    const rgba = parseColor(c.color);
    const alpha = c.color === 'none' ? 0 : rgba.a;

    if (alpha > 0) {
        hasColor = true;
        rSum += rgba.r * c.weight * alpha;
        gSum += rgba.g * c.weight * alpha;
        bSum += rgba.b * c.weight * alpha;
    }
    aSum += alpha * c.weight;
  }

  if (!hasColor || aSum <= 0.001) return 'none';

  let totalAlphaWeight = 0; 
  colors.forEach(c => {
     const rgba = parseColor(c.color);
     const alpha = c.color === 'none' ? 0 : rgba.a;
     totalAlphaWeight += c.weight * alpha;
  });

  if (totalAlphaWeight <= 0.0001) return 'rgba(0,0,0,0)';

  const finalR = rSum / totalAlphaWeight;
  const finalG = gSum / totalAlphaWeight;
  const finalB = bSum / totalAlphaWeight;

  return `rgba(${Math.round(finalR)}, ${Math.round(finalG)}, ${Math.round(finalB)}, ${aSum.toFixed(3)})`;
};

// --- Geometry Helpers ---

const getPathLength = (points: Point[]): number => {
  let len = 0;
  for (let i = 1; i < points.length; i++) {
    len += distance(points[i - 1], points[i]);
  }
  return len;
};

// Curve Resampling (Arc-Length)
export const resamplePoints = (points: Point[], targetCount: number): Point[] => {
  if (points.length < 2 || targetCount < 2) return points;

  const totalLength = getPathLength(points);
  if (totalLength === 0) return Array(targetCount).fill(points[0]);

  const step = totalLength / (targetCount - 1);
  const newPoints: Point[] = [points[0]];

  let currentDist = 0;
  let nextPointIndex = 1;

  for (let i = 1; i < targetCount; i++) {
    const targetDist = i * step;
    let distSoFar = currentDist;
    let p1 = points[nextPointIndex - 1];
    let p2 = points[nextPointIndex];
    let segmentDist = distance(p1, p2);

    while (distSoFar + segmentDist < targetDist && nextPointIndex < points.length - 1) {
      distSoFar += segmentDist;
      currentDist = distSoFar;
      nextPointIndex++;
      p1 = points[nextPointIndex - 1];
      p2 = points[nextPointIndex];
      segmentDist = distance(p1, p2);
    }

    const segmentLocalDist = targetDist - distSoFar;
    const t = segmentDist === 0 ? 0 : segmentLocalDist / segmentDist;

    newPoints.push({
      x: lerp(p1.x, p2.x, t),
      y: lerp(p1.y, p2.y, t),
      pressure: lerp(p1.pressure || 0.5, p2.pressure || 0.5, t)
    });
  }

  // Ensure strict end-point matching
  if (newPoints.length < targetCount) {
      while (newPoints.length < targetCount) newPoints.push(points[points.length - 1]);
  } else if (newPoints.length === targetCount) {
      // Force last point to be exactly the source last point to avoid floating error
      newPoints[targetCount - 1] = points[points.length - 1];
  } else {
      newPoints.length = targetCount;
      newPoints[targetCount - 1] = points[points.length - 1];
  }

  return newPoints;
};

// --- CORNER-PRESERVING UPSAMPLING ---
export const upsamplePreservingCorners = (points: Point[], targetCount: number): Point[] => {
    if (points.length === 0) return [];
    if (points.length >= targetCount) return points; 

    const pointsToAdd = targetCount - points.length;
    const segments = points.length - 1;
    if (segments < 1) return Array(targetCount).fill(points[0]);

    const baseAdd = Math.floor(pointsToAdd / segments);
    const remainder = pointsToAdd % segments;

    const newPoints: Point[] = [];

    for (let i = 0; i < segments; i++) {
        newPoints.push(points[i]);

        const count = baseAdd + (i < remainder ? 1 : 0);

        if (count > 0) {
            const pStart = points[i];
            const pEnd = points[i+1];
            for (let k = 1; k <= count; k++) {
                const t = k / (count + 1);
                newPoints.push({
                    x: lerp(pStart.x, pEnd.x, t),
                    y: lerp(pStart.y, pEnd.y, t),
                    pressure: lerp(pStart.pressure||0.5, pEnd.pressure||0.5, t)
                });
            }
        }
    }
    // Always add the very last point
    newPoints.push(points[points.length - 1]);

    return newPoints;
};

export const snapPointToGrid = (p: Point, gridSize: number, offset: {x: number, y: number} = {x:0, y:0}): Point => {
  return {
    x: Math.round((p.x - offset.x) / gridSize) * gridSize + offset.x,
    y: Math.round((p.y - offset.y) / gridSize) * gridSize + offset.y,
    pressure: p.pressure
  };
};

// --- Hit Testing ---

const distToSegment = (p: Point, v: Point, w: Point) => {
  const l2 = Math.pow(distance(v, w), 2);
  if (l2 === 0) return distance(p, v);
  let t = ((p.x - v.x) * (w.x - v.x) + (p.y - v.y) * (w.y - v.y)) / l2;
  t = Math.max(0, Math.min(1, t));
  const projection = { x: v.x + t * (w.x - v.x), y: v.y + t * (w.y - v.y) };
  return distance(p, projection);
};

export const isPointInStroke = (p: Point, points: Point[], threshold: number = 10): boolean => {
  for (let i = 0; i < points.length - 1; i++) {
    if (distToSegment(p, points[i], points[i+1]) < threshold) return true;
  }
  return false;
};

// --- HYBRID ALIGNMENT STRATEGY (The Fix) ---

// If isClosed is FALSE (Line), we perform strict linear alignment (No jumps).
// If isClosed is TRUE (Loop), we perform cyclic alignment (Prevents vrille/twisting).
const alignPoints = (reference: Point[], target: Point[], isClosed: boolean): Point[] => {

    // 1. OPEN PATHS: Strict Linear Mapping
    // This fixes the "Jumps" when drawing lines.
    if (!isClosed) return target;

    // 2. CLOSED PATHS: Cyclic Optimization
    // This fixes the "Twisting" when morphing loops.
    if (reference.length !== target.length || reference.length === 0) return target;

    const len = reference.length;

    const getError = (ptsA: Point[], ptsB: Point[]) => {
        let err = 0;
        for(let i=0; i<len; i++) {
            const dx = ptsA[i].x - ptsB[i].x;
            const dy = ptsA[i].y - ptsB[i].y;
            err += dx*dx + dy*dy;
        }
        return err;
    };

    let bestPoints = [...target];
    let minError = getError(reference, target);

    // Check Reverse (for when user draws loop in opposite direction)
    const reversed = [...target].reverse();
    const reverseError = getError(reference, reversed);

    if (reverseError < minError * 0.8) { 
        minError = reverseError;
        bestPoints = reversed;
    }

    // Check Cyclic Shift (start point matching)
    let workingSet = [...bestPoints];
    // Optimization: Check fewer points for performance
    const step = len > 200 ? 5 : 1; 

    for (let offset = 1; offset < len; offset += step) {
            const shifted = new Array(len);
            for(let k=0; k<len; k++) {
                shifted[k] = workingSet[(k + offset) % len];
            }

            const err = getError(reference, shifted);
            if (err < minError) {
                minError = err;
                bestPoints = shifted;
            }
    }

    return bestPoints;
};

// --- INTERPOLATION STRATEGIES ---

const calculateBilinearGridWeights = (
  currentAxes: Record<string, number>,
  keyframes: { id: string; axisValues: Record<string, number> }[]
) => {
  const weights: Record<string, number> = {};

  const curX = currentAxes['axis-x'] || 0;
  const curY = currentAxes['axis-y'] || 0;
  const EPSILON = 0.005;

  const distinctCoords = (arr: number[]) => {
      const sorted = [...arr].sort((a,b) => a - b);
      const result = [];
      if (sorted.length > 0) result.push(sorted[0]);
      for (let i = 1; i < sorted.length; i++) {
          if (sorted[i] > sorted[i-1] + EPSILON) result.push(sorted[i]);
      }
      return result;
  };
  const xCoords = distinctCoords(keyframes.map(k => k.axisValues['axis-x'] || 0));
  const yCoords = distinctCoords(keyframes.map(k => k.axisValues['axis-y'] || 0));

  if (xCoords.length === 0 || yCoords.length === 0) {
      if (keyframes.length > 0) weights[keyframes[0].id] = 1;
      return weights;
  }

  const findInterval = (val: number, grid: number[]) => {
      if (val <= grid[0]) return { lower: grid[0], upper: grid[0], t: 0 };
      if (val >= grid[grid.length - 1]) return { lower: grid[grid.length - 1], upper: grid[grid.length - 1], t: 0 };
      for (let i = 0; i < grid.length - 1; i++) {
          if (val >= grid[i] && val <= grid[i+1]) {
              const span = grid[i+1] - grid[i];
              return { lower: grid[i], upper: grid[i+1], t: span === 0 ? 0 : (val - grid[i]) / span };
          }
      }
      return { lower: grid[0], upper: grid[0], t: 0 };
  };

  const xInfo = findInterval(curX, xCoords);
  const yInfo = findInterval(curY, yCoords);

  const resolveCornerWeights = (targetX: number, targetY: number) => {
      const exact = keyframes.find(k => Math.abs((k.axisValues['axis-x']||0) - targetX) < EPSILON && Math.abs((k.axisValues['axis-y']||0) - targetY) < EPSILON);
      if (exact) return { [exact.id]: 1.0 };

      let totalW = 0;
      const cornerWeights: Record<string, number> = {};

      keyframes.forEach(k => {
          const dx = (k.axisValues['axis-x']||0) - targetX;
          const dy = (k.axisValues['axis-y']||0) - targetY;
          const dist = Math.sqrt(dx*dx + dy*dy);
          if (dist < 0.001) { cornerWeights[k.id] = 1000; totalW += 1000; }
          else {
              const w = 1 / Math.pow(dist, 2);
              cornerWeights[k.id] = w;
              totalW += w;
          }
      });

      for(const id in cornerWeights) cornerWeights[id] /= totalW;
      return cornerWeights;
  };

  const corners = [
      { x: xInfo.lower, y: yInfo.lower, wBase: (1 - xInfo.t) * (1 - yInfo.t) },
      { x: xInfo.upper, y: yInfo.lower, wBase: xInfo.t * (1 - yInfo.t) },
      { x: xInfo.lower, y: yInfo.upper, wBase: (1 - xInfo.t) * yInfo.t },
      { x: xInfo.upper, y: yInfo.upper, wBase: xInfo.t * yInfo.t }
  ];

  corners.forEach(c => {
      if (c.wBase <= 0.0001) return;
      const cornerComposition = resolveCornerWeights(c.x, c.y);
      for (const kfId in cornerComposition) {
          weights[kfId] = (weights[kfId] || 0) + (cornerComposition[kfId] * c.wBase);
      }
  });

  return weights;
};

const calculateIDWWeights = (currentAxes: Record<string, number>, keyframes: { id: string; axisValues: Record<string, number> }[], exponent: number) => {
    const weights: Record<string, number> = {};
    let totalWeight = 0;
    for (const kf of keyframes) {
        let dist = 0;
        for (const axisId in currentAxes) dist += Math.pow((currentAxes[axisId] || 0) - (kf.axisValues[axisId] || 0), 2);
        dist = Math.sqrt(dist);
        if (dist < 0.001) {
             keyframes.forEach(k => weights[k.id] = 0);
             weights[kf.id] = 1; 
             return weights; 
        }
        const w = 1 / Math.pow(dist, exponent);
        weights[kf.id] = w;
        totalWeight += w;
    }
    for (const id in weights) weights[id] /= totalWeight;
    return weights;
};

export const calculateInterpolationWeights = (
  currentAxes: Record<string, number>,
  keyframes: { id: string; axisValues: Record<string, number> }[],
  exponent: number = 2,
  strategy: InterpolationStrategy = 'bilinear-grid'
): Record<string, number> => {
   if (keyframes.length === 0) return {};
   if (keyframes.length === 1) return { [keyframes[0].id]: 1.0 };
   if (strategy === 'bilinear-grid') return calculateBilinearGridWeights(currentAxes, keyframes);
   return calculateIDWWeights(currentAxes, keyframes, exponent);
};

// --- CORE INTERPOLATION ENGINE ---

export const interpolateStrokePoints = (
  strokeId: string,
  basePoints: Point[], 
  keyframesData: { weight: number; points: Point[] | undefined, style: Stroke | undefined }[],
  mode: 'resample' | 'points' | 'spline' = 'resample',
  targetCount: number = 200 
): { points: Point[], color: string, fillColor: string, width: number } => {

  // 1. Filter active keyframes
  const activeKeyframes = keyframesData.filter(k => k.weight > 0.0001 && k.points && k.points.length > 0);
  if (activeKeyframes.length === 0) return { points: [], color: 'rgba(0,0,0,0)', fillColor: 'none', width: 1 };

  // 2. Mix Properties
  const color = mixColors(activeKeyframes.map(k => ({ color: k.style?.color || 'none', weight: k.weight })));
  const fillColor = mixColors(activeKeyframes.map(k => ({ color: k.style?.fillColor || 'none', weight: k.weight })));

  let totalWidth = 0;
  let widthWeightDivisor = 0;
  activeKeyframes.forEach(k => {
      totalWidth += (k.style?.width || 1) * k.weight;
      widthWeightDivisor += k.weight;
  });
  const width = widthWeightDivisor > 0 ? totalWidth / widthWeightDivisor : 1;

  // 3. Point Count Calculation
  let ACTUAL_TARGET_COUNT = targetCount; 
  const maxPts = Math.max(...activeKeyframes.map(k => k.points!.length));

  if (mode === 'points' || mode === 'spline') {
      ACTUAL_TARGET_COUNT = maxPts;
  }

  // 4. Reference Selection & Geometry Analysis
  const referenceKeyframe = activeKeyframes.reduce((prev, current) => {
      return (prev.weight >= current.weight) ? prev : current;
  });

  const referenceStroke = referenceKeyframe.points!;

  // Geometric Closure Detection
  const isClosed = distance(referenceStroke[0], referenceStroke[referenceStroke.length - 1]) < 5.0;

  // Resample Reference
  let referenceResampled: Point[];
  if (mode === 'points' || mode === 'spline') {
      referenceResampled = upsamplePreservingCorners(referenceStroke, ACTUAL_TARGET_COUNT);
  } else {
      referenceResampled = resamplePoints(referenceStroke, ACTUAL_TARGET_COUNT);
  }

  const resultPoints: Point[] = [];

  for (let i = 0; i < ACTUAL_TARGET_COUNT; i++) {
      let x = 0;
      let y = 0;
      let pressure = 0;
      let totalWeight = 0;

      for (const kf of activeKeyframes) {
          const rawPoints = kf.points!;
          let processedPoints: Point[] = [];

          if (mode === 'points' || mode === 'spline') {
             if (rawPoints.length === ACTUAL_TARGET_COUNT) {
                 processedPoints = rawPoints;
             } else {
                 processedPoints = upsamplePreservingCorners(rawPoints, ACTUAL_TARGET_COUNT);
             }
          } else {
             processedPoints = resamplePoints(rawPoints, ACTUAL_TARGET_COUNT);
          }

          // SMART ALIGNMENT
          // Only perform cyclic alignment if the shape is geometrically closed.
          // Otherwise, linear.
          const alignedPoints = alignPoints(referenceResampled, processedPoints, isClosed);

          const pt = alignedPoints[i];

          x += pt.x * kf.weight;
          y += pt.y * kf.weight;
          pressure += (pt.pressure || 0.5) * kf.weight;
          totalWeight += kf.weight;
      }

      if (totalWeight > 0) {
          resultPoints.push({
              x: x / totalWeight,
              y: y / totalWeight,
              pressure: pressure / totalWeight
          });
      }
  }

  return { points: resultPoints, color, fillColor, width };
};

// --- OPTIMIZATION & SMOOTHING ---

const perpendicularDistance = (point: Point, lineStart: Point, lineEnd: Point): number => {
  let dx = lineEnd.x - lineStart.x;
  let dy = lineEnd.y - lineStart.y;
  const mag = Math.sqrt(dx * dx + dy * dy);
  if (mag > 0.0) { dx /= mag; dy /= mag; }
  const pvx = point.x - lineStart.x;
  const pvy = point.y - lineStart.y;
  const pvdot = pvx * dx + pvy * dy;
  const dsx = pvdot * dx;
  const dsy = pvdot * dy;
  const ax = pvx - dsx;
  const ay = pvy - dsy;
  return Math.sqrt(ax * ax + ay * ay);
};

export const simplifyPoints = (points: Point[], epsilon: number = 2): Point[] => {
  if (points.length < 3) return points;
  let dmax = 0;
  let index = 0;
  const end = points.length - 1;
  for (let i = 1; i < end; i++) {
    const d = perpendicularDistance(points[i], points[0], points[end]);
    if (d > dmax) { index = i; dmax = d; }
  }
  if (dmax > epsilon) {
    const recResults1 = simplifyPoints(points.slice(0, index + 1), epsilon);
    const recResults2 = simplifyPoints(points.slice(index, end + 1), epsilon);
    return [...recResults1.slice(0, -1), ...recResults2];
  } else {
    return [points[0], points[end]];
  }
};

export const simplifyCollinearPoints = (points: Point[], epsilon: number = 0.1): Point[] => {
  if (points.length < 3) return points;
  const result = [points[0]];
  for (let i = 1; i < points.length - 1; i++) {
    const prev = result[result.length - 1];
    const curr = points[i];
    const next = points[i + 1];
    const val = (curr.y - prev.y) * (next.x - curr.x) - (curr.x - prev.x) * (next.y - curr.y);
    if (Math.abs(val) > epsilon) {
       result.push(curr);
    }
  }
  result.push(points[points.length - 1]);
  return result;
};

export const chaikinSmooth = (points: Point[], iterations: number = 2): Point[] => {
    if (points.length < 3) return points;
    let output = [...points];
    for (let i = 0; i < iterations; i++) {
        const next: Point[] = [];
        next.push(output[0]);
        for (let j = 0; j < output.length - 1; j++) {
            const p0 = output[j];
            const p1 = output[j + 1];
            next.push({
                x: 0.75 * p0.x + 0.25 * p1.x,
                y: 0.75 * p0.y + 0.25 * p1.y,
                pressure: lerp(p0.pressure || 0.5, p1.pressure || 0.5, 0.25)
            });
            next.push({
                x: 0.25 * p0.x + 0.75 * p1.x,
                y: 0.25 * p0.y + 0.75 * p1.y,
                pressure: lerp(p0.pressure || 0.5, p1.pressure || 0.5, 0.75)
            });
        }
        next.push(output[output.length - 1]);
        output = next;
    }
    return output;
};

// --- RENDERERS ---

export const drawCornerRoundedPath = (ctx: CanvasRenderingContext2D, rawPoints: Point[], roundness: number) => {
    if (rawPoints.length < 2) return;

    // 1. FILTERING
    const points: Point[] = [];
    points.push(rawPoints[0]);

    for (let i = 1; i < rawPoints.length; i++) {
        const curr = rawPoints[i];
        const prev = points[points.length - 1];
        if (distance(prev, curr) < 0.1) continue;

        if (points.length > 1) {
            const prevPrev = points[points.length - 2];
            const v1x = prev.x - prevPrev.x;
            const v1y = prev.y - prevPrev.y;
            const v2x = curr.x - prev.x;
            const v2y = curr.y - prev.y;
            const l1 = Math.sqrt(v1x*v1x + v1y*v1y);
            const l2 = Math.sqrt(v2x*v2x + v2y*v2y);
            if (l1 > 0 && l2 > 0) {
                const dot = (v1x*v2x + v1y*v2y) / (l1 * l2);
                if (dot > 0.999) { points[points.length - 1] = curr; continue; }
            }
        }
        points.push(curr);
    }

    // Ensure geometric loop consistency without logical closure
    const rawClosed = distance(rawPoints[0], rawPoints[rawPoints.length-1]) < 0.1;
    if (rawClosed && distance(points[0], points[points.length-1]) > 0.1) {
         points.push(points[0]);
    }

    if (points.length < 2) return;

    const isClosed = distance(points[0], points[points.length - 1]) < 0.1;
    let uniquePoints = isClosed ? points.slice(0, -1) : points;

    if (uniquePoints.length < 2) return;

    ctx.beginPath();

    if (!isClosed) {
        ctx.moveTo(points[0].x, points[0].y);
    } 

    const len = uniquePoints.length;
    const startIdx = isClosed ? 0 : 1;
    const endIdx = isClosed ? len : len - 1;

    if (isClosed) {
        // Start at midpoint of last segment
        const pLast = uniquePoints[len-1];
        const pFirst = uniquePoints[0];
        ctx.moveTo((pLast.x + pFirst.x)/2, (pLast.y + pFirst.y)/2);
    }

    for (let i = startIdx; i < endIdx; i++) {
        const curr = uniquePoints[i];

        const prevIdx = (i - 1 + len) % len;
        const nextIdx = (i + 1) % len;

        const prev = isClosed ? uniquePoints[prevIdx] : points[i-1];
        const next = isClosed ? uniquePoints[nextIdx] : points[i+1];

        const len1 = distance(prev, curr);
        const len2 = distance(curr, next);

        if (len1 < 0.01 || len2 < 0.01) {
            ctx.lineTo(curr.x, curr.y);
            continue;
        }

        const v1x = curr.x - prev.x; const v1y = curr.y - prev.y;
        const v2x = next.x - curr.x; const v2y = next.y - curr.y;
        const n1x = v1x/len1; const n1y = v1y/len1;
        const n2x = v2x/len2; const n2y = v2y/len2;
        const dot = n1x * n2x + n1y * n2y;

        if (dot > 0.99) {
             ctx.lineTo(curr.x, curr.y);
             continue;
        }

        const maxTangent = Math.min(len1, len2) * 0.5;
        const currentTangent = maxTangent * (roundness / 100);
        const angle = Math.acos(Math.max(-1, Math.min(1, dot)));
        const innerAngle = Math.PI - angle;
        const radius = currentTangent * Math.tan(innerAngle / 2);

        ctx.arcTo(curr.x, curr.y, next.x, next.y, radius);
    }

    if (isClosed) {
        // Close loop manually to midpoint
        const pLast = uniquePoints[len-1];
        const pFirst = uniquePoints[0];
        ctx.lineTo((pLast.x + pFirst.x)/2, (pLast.y + pFirst.y)/2);
    } else {
        ctx.lineTo(points[points.length-1].x, points[points.length-1].y);
    }
};

export const drawCatmullRomSpline = (ctx: CanvasRenderingContext2D, points: Point[], tension: number = 0.5) => {
    if (points.length < 2) return;

    ctx.beginPath();
    ctx.moveTo(points[0].x, points[0].y);

    const len = points.length;
    const isClosed = distance(points[0], points[len - 1]) < 0.1;

    for (let i = 0; i < len - 1; i++) {
        const p0 = i > 0 ? points[i - 1] : points[0];
        const p1 = points[i];
        const p2 = points[i + 1];
        const p3 = i < len - 2 ? points[i + 2] : points[len - 1];

        const p0_loop = isClosed && i === 0 ? points[len - 2] : p0;
        const p3_loop = isClosed && i === len - 2 ? points[1] : p3;

        const cp1x = p1.x + (p2.x - (isClosed ? p0_loop.x : p0.x)) / 6 * tension;
        const cp1y = p1.y + (p2.y - (isClosed ? p0_loop.y : p0.y)) / 6 * tension;
        const cp2x = p2.x - ((isClosed ? p3_loop.x : p3.x) - p1.x) / 6 * tension;
        const cp2y = p2.y - ((isClosed ? p3_loop.y : p3.y) - p1.y) / 6 * tension;

        ctx.bezierCurveTo(cp1x, cp1y, cp2x, cp2y, p2.x, p2.y);
    }
};

