// utils/math.ts
import { Point, Stroke, InterpolationStrategy } from '../types';

export const distance = (p1: Point, p2: Point): number => {
  return Math.sqrt(Math.pow(p2.x - p1.x, 2) + Math.pow(p2.y - p1.y, 2));
};

export const lerp = (start: number, end: number, t: number): number => {
  return start * (1 - t) + end * t;
};

// --- Transformation Helpers ---

export const rotatePoint = (p: Point, center: Point, angleRad: number): Point => {
  const cos = Math.cos(angleRad);
  const sin = Math.sin(angleRad);
  const dx = p.x - center.x;
  const dy = p.y - center.y;
  return {
    x: center.x + (dx * cos - dy * sin),
    y: center.y + (dx * sin + dy * cos),
    pressure: p.pressure
  };
};

export const getBoundingBox = (points: Point[]): { minX: number, maxX: number, minY: number, maxY: number, width: number, height: number, centerX: number, centerY: number } => {
  if (points.length === 0) return { minX:0, maxX:0, minY:0, maxY:0, width:0, height:0, centerX:0, centerY:0 };

  let minX = Infinity, maxX = -Infinity, minY = Infinity, maxY = -Infinity;
  for (const p of points) {
    if (p.x < minX) minX = p.x;
    if (p.x > maxX) maxX = p.x;
    if (p.y < minY) minY = p.y;
    if (p.y > maxY) maxY = p.y;
  }

  return {
    minX, maxX, minY, maxY,
    width: maxX - minX,
    height: maxY - minY,
    centerX: minX + (maxX - minX) / 2,
    centerY: minY + (maxY - minY) / 2
  };
};

// --- Color Interpolation (RGBA) ---

const colorCache: Record<string, { r: number, g: number, b: number, a: number }> = {};

const parseColor = (color: string): { r: number, g: number, b: number, a: number } => {
  if (!color || color === 'none') return { r: 0, g: 0, b: 0, a: 1 }; 
  if (colorCache[color]) return colorCache[color];

  let result = { r: 0, g: 0, b: 0, a: 1 };

  if (color.startsWith('#')) {
    let hex = color.slice(1);
    if (hex.length === 3) hex = hex.split('').map(c => c + c).join('');
    const bigint = parseInt(hex, 16);
    result = {
      r: (bigint >> 16) & 255,
      g: (bigint >> 8) & 255,
      b: bigint & 255,
      a: 1
    };
  }
  else if (color.startsWith('rgb')) {
    const match = color.match(/(\d+(\.\d+)?)/g);
    if (match) {
        result = {
            r: parseFloat(match[0]),
            g: parseFloat(match[1]),
            b: parseFloat(match[2]),
            a: match[3] ? parseFloat(match[3]) : 1
        };
    }
  }

  colorCache[color] = result;
  return result;
};

export const mixColors = (colors: { color: string | 'none', weight: number }[]): string => {
  let rSum = 0, gSum = 0, bSum = 0, aSum = 0;
  let hasColor = false;

  for (const c of colors) {
    const rgba = parseColor(c.color);
    const alpha = c.color === 'none' ? 0 : rgba.a;

    if (alpha > 0) {
        hasColor = true;
        rSum += rgba.r * c.weight * alpha;
        gSum += rgba.g * c.weight * alpha;
        bSum += rgba.b * c.weight * alpha;
    }
    aSum += alpha * c.weight;
  }

  if (!hasColor || aSum <= 0.001) return 'none';

  let totalAlphaWeight = 0; 
  colors.forEach(c => {
     const rgba = parseColor(c.color);
     const alpha = c.color === 'none' ? 0 : rgba.a;
     totalAlphaWeight += c.weight * alpha;
  });

  if (totalAlphaWeight <= 0.0001) return 'rgba(0,0,0,0)';

  const finalR = rSum / totalAlphaWeight;
  const finalG = gSum / totalAlphaWeight;
  const finalB = bSum / totalAlphaWeight;

  return `rgba(${Math.round(finalR)}, ${Math.round(finalG)}, ${Math.round(finalB)}, ${aSum.toFixed(3)})`;
};

// --- Geometry Helpers ---

const getPathLength = (points: Point[]): number => {
  let len = 0;
  for (let i = 1; i < points.length; i++) {
    len += distance(points[i - 1], points[i]);
  }
  return len;
};

// Curve Resampling (Arc-Length)
export const resamplePoints = (points: Point[], targetCount: number): Point[] => {
  if (points.length < 2 || targetCount < 2) return points;

  const totalLength = getPathLength(points);
  if (totalLength === 0) return Array(targetCount).fill(points[0]);

  const step = totalLength / (targetCount - 1);
  const newPoints: Point[] = [points[0]];

  let currentDist = 0;
  let nextPointIndex = 1;

  for (let i = 1; i < targetCount; i++) {
    const targetDist = i * step;
    let distSoFar = currentDist;
    let p1 = points[nextPointIndex - 1];
    let p2 = points[nextPointIndex];
    let segmentDist = distance(p1, p2);

    while (distSoFar + segmentDist < targetDist && nextPointIndex < points.length - 1) {
      distSoFar += segmentDist;
      currentDist = distSoFar;
      nextPointIndex++;
      p1 = points[nextPointIndex - 1];
      p2 = points[nextPointIndex];
      segmentDist = distance(p1, p2);
    }

    const segmentLocalDist = targetDist - distSoFar;
    const t = segmentDist === 0 ? 0 : segmentLocalDist / segmentDist;

    newPoints.push({
      x: lerp(p1.x, p2.x, t),
      y: lerp(p1.y, p2.y, t),
      pressure: lerp(p1.pressure || 0.5, p2.pressure || 0.5, t)
    });
  }

  // Ensure strict end-point matching
  if (newPoints.length < targetCount) {
      while (newPoints.length < targetCount) newPoints.push(points[points.length - 1]);
  } else if (newPoints.length === targetCount) {
      // Force last point to be exactly the source last point to avoid floating error
      newPoints[targetCount - 1] = points[points.length - 1];
  } else {
      newPoints.length = targetCount;
      newPoints[targetCount - 1] = points[points.length - 1];
  }

  return newPoints;
};

// --- CORNER-PRESERVING UPSAMPLING ---
export const upsamplePreservingCorners = (points: Point[], targetCount: number): Point[] => {
    if (points.length === 0) return [];
    if (points.length >= targetCount) return points; 

    const pointsToAdd = targetCount - points.length;
    const segments = points.length - 1;
    if (segments < 1) return Array(targetCount).fill(points[0]);

    const baseAdd = Math.floor(pointsToAdd / segments);
    const remainder = pointsToAdd % segments;

    const newPoints: Point[] = [];

    for (let i = 0; i < segments; i++) {
        newPoints.push(points[i]);

        const count = baseAdd + (i < remainder ? 1 : 0);

        if (count > 0) {
            const pStart = points[i];
            const pEnd = points[i+1];
            for (let k = 1; k <= count; k++) {
                const t = k / (count + 1);
                newPoints.push({
                    x: lerp(pStart.x, pEnd.x, t),
                    y: lerp(pStart.y, pEnd.y, t),
                    pressure: lerp(pStart.pressure||0.5, pEnd.pressure||0.5, t)
                });
            }
        }
    }
    // Always add the very last point
    newPoints.push(points[points.length - 1]);

    return newPoints;
};

export const snapPointToGrid = (p: Point, gridSize: number, offset: {x: number, y: number} = {x:0, y:0}): Point => {
  return {
    x: Math.round((p.x - offset.x) / gridSize) * gridSize + offset.x,
    y: Math.round((p.y - offset.y) / gridSize) * gridSize + offset.y,
    pressure: p.pressure
  };
};

// --- Hit Testing ---

const distToSegment = (p: Point, v: Point, w: Point) => {
  const l2 = Math.pow(distance(v, w), 2);
  if (l2 === 0) return distance(p, v);
  let t = ((p.x - v.x) * (w.x - v.x) + (p.y - v.y) * (w.y - v.y)) / l2;
  t = Math.max(0, Math.min(1, t));
  const projection = { x: v.x + t * (w.x - v.x), y: v.y + t * (w.y - v.y) };
  return distance(p, projection);
};

export const isPointInStroke = (p: Point, points: Point[], threshold: number = 10): boolean => {
  for (let i = 0; i < points.length - 1; i++) {
    if (distToSegment(p, points[i], points[i+1]) < threshold) return true;
  }
  return false;
};

// --- ABSOLUTE LINEAR ALIGNMENT (The Fix for "Jumps") ---

const alignPoints = (reference: Point[], target: Point[], isClosed: boolean): Point[] => {
    // CRITICAL: We return target AS IS.
    // The previous logic that tried to rotate/shift points when `isClosed` was true
    // caused the "Jumps" because the interpolation engine flipped between 
    // Linear (when open) and Cyclic (when closed) strategies in real-time.
    // By enforcing linearity, P[0] is always P[0]. Stability is restored.
    return target;
};

// --- INTERPOLATION STRATEGIES ---

const calculateBilinearGridWeights = (
  currentAxes: Record<string, number>,
  keyframes: { id: string; axisValues: Record<string, number> }[]
) => {
  const weights: Record<string, number> = {};

  const curX = currentAxes['axis-x'] || 0;
  const curY = currentAxes['axis-y'] || 0;
  const EPSILON = 0.005;

  const distinctCoords = (arr: number[]) => {
      const sorted = [...arr].sort((a,b) => a - b);
      const result = [];
      if (sorted.length > 0) result.push(sorted[0]);
      for (let i = 1; i < sorted.length; i++) {
          if (sorted[i] > sorted[i-1] + EPSILON) result.push(sorted[i]);
      }
      return result;
  };
  const xCoords = distinctCoords(keyframes.map(k => k.axisValues['axis-x'] || 0));
  const yCoords = distinctCoords(keyframes.map(k => k.axisValues['axis-y'] || 0));

  if (xCoords.length === 0 || yCoords.length === 0) {
      if (keyframes.length > 0) weights[keyframes[0].id] = 1;
      return weights;
  }

  const findInterval = (val: number, grid: number[]) => {
      if (val <= grid[0]) return { lower: grid[0], upper: grid[0], t: 0 };
      if (val >= grid[grid.length - 1]) return { lower: grid[grid.length - 1], upper: grid[grid.length - 1], t: 0 };
      for (let i = 0; i < grid.length - 1; i++) {
          if (val >= grid[i] && val <= grid[i+1]) {
              const span = grid[i+1] - grid[i];
              return { lower: grid[i], upper: grid[i+1], t: span === 0 ? 0 : (val - grid[i]) / span };
          }
      }
      return { lower: grid[0], upper: grid[0], t: 0 };
  };

  const xInfo = findInterval(curX, xCoords);
  const yInfo = findInterval(curY, yCoords);

  const resolveCornerWeights = (targetX: number, targetY: number) => {
      const exact = keyframes.find(k => Math.abs((k.axisValues['axis-x']||0) - targetX) < EPSILON && Math.abs((k.axisValues['axis-y']||0) - targetY) < EPSILON);
      if (exact) return { [exact.id]: 1.0 };

      let totalW = 0;
      const cornerWeights: Record<string, number> = {};

      keyframes.forEach(k => {
          const dx = (k.axisValues['axis-x']||0) - targetX;
          const dy = (k.axisValues['axis-y']||0) - targetY;
          const dist = Math.sqrt(dx*dx + dy*dy);
          if (dist < 0.001) { cornerWeights[k.id] = 1000; totalW += 1000; }
          else {
              const w = 1 / Math.pow(dist, 2);
              cornerWeights[k.id] = w;
              totalW += w;
          }
      });

      for(const id in cornerWeights) cornerWeights[id] /= totalW;
      return cornerWeights;
  };

  const corners = [
      { x: xInfo.lower, y: yInfo.lower, wBase: (1 - xInfo.t) * (1 - yInfo.t) },
      { x: xInfo.upper, y: yInfo.lower, wBase: xInfo.t * (1 - yInfo.t) },
      { x: xInfo.lower, y: yInfo.upper, wBase: (1 - xInfo.t) * yInfo.t },
      { x: xInfo.upper, y: yInfo.upper, wBase: xInfo.t * yInfo.t }
  ];

  corners.forEach(c => {
      if (c.wBase <= 0.0001) return;
      const cornerComposition = resolveCornerWeights(c.x, c.y);
      for (const kfId in cornerComposition) {
          weights[kfId] = (weights[kfId] || 0) + (cornerComposition[kfId] * c.wBase);
      }
  });

  return weights;
};

const calculateIDWWeights = (currentAxes: Record<string, number>, keyframes: { id: string; axisValues: Record<string, number> }[], exponent: number) => {
    const weights: Record<string, number> = {};
    let totalWeight = 0;
    for (const kf of keyframes) {
        let dist = 0;
        for (const axisId in currentAxes) dist += Math.pow((currentAxes[axisId] || 0) - (kf.axisValues[axisId] || 0), 2);
        dist = Math.sqrt(dist);
        if (dist < 0.001) {
             keyframes.forEach(k => weights[k.id] = 0);
             weights[kf.id] = 1; 
             return weights; 
        }
        const w = 1 / Math.pow(dist, exponent);
        weights[kf.id] = w;
        totalWeight += w;
    }
    for (const id in weights) weights[id] /= totalWeight;
    return weights;
};

export const calculateInterpolationWeights = (
  currentAxes: Record<string, number>,
  keyframes: { id: string; axisValues: Record<string, number> }[],
  exponent: number = 2,
  strategy: InterpolationStrategy = 'bilinear-grid'
): Record<string, number> => {
   if (keyframes.length === 0) return {};
   if (keyframes.length === 1) return { [keyframes[0].id]: 1.0 };
   if (strategy === 'bilinear-grid') return calculateBilinearGridWeights(currentAxes, keyframes);
   return calculateIDWWeights(currentAxes, keyframes, exponent);
};

// --- CORE INTERPOLATION ENGINE ---

export const interpolateStrokePoints = (
  strokeId: string,
  basePoints: Point[], 
  keyframesData: { weight: number; points: Point[] | undefined, style: Stroke | undefined }[],
  mode: 'resample' | 'points' | 'spline' = 'resample',
  targetCount: number = 200 
): { points: Point[], color: string, fillColor: string, width: number } => {

  // 1. Filter active keyframes
  const activeKeyframes = keyframesData.filter(k => k.weight > 0.0001 && k.points && k.points.length > 0);
  if (activeKeyframes.length === 0) return { points: [], color: 'rgba(0,0,0,0)', fillColor: 'none', width: 1 };

  // 2. Mix Properties
  const color = mixColors(activeKeyframes.map(k => ({ color: k.style?.color || 'none', weight: k.weight })));
  const fillColor = mixColors(activeKeyframes.map(k => ({ color: k.style?.fillColor || 'none', weight: k.weight })));

  let totalWidth = 0;
  let widthWeightDivisor = 0;
  activeKeyframes.forEach(k => {
      totalWidth += (k.style?.width || 1) * k.weight;
      widthWeightDivisor += k.weight;
  });
  const width = widthWeightDivisor > 0 ? totalWidth / widthWeightDivisor : 1;

  // 3. Point Count Calculation
  let ACTUAL_TARGET_COUNT = targetCount; 
  const maxPts = Math.max(...activeKeyframes.map(k => k.points!.length));

  if (mode === 'points' || mode === 'spline') {
      ACTUAL_TARGET_COUNT = maxPts;
  }

  // 4. Reference Selection
  const referenceKeyframe = activeKeyframes.reduce((prev, current) => {
      return (prev.weight >= current.weight) ? prev : current;
  });

  const referenceStroke = referenceKeyframe.points!;

  // We NO LONGER check for closure to switch algorithms.
  // The algorithm is now ALWAYS Linear.
  const isClosed = false; 

  // Resample Reference
  let referenceResampled: Point[];
  if (mode === 'points' || mode === 'spline') {
      referenceResampled = upsamplePreservingCorners(referenceStroke, ACTUAL_TARGET_COUNT);
  } else {
      referenceResampled = resamplePoints(referenceStroke, ACTUAL_TARGET_COUNT);
  }

  const resultPoints: Point[] = [];

  for (let i = 0; i < ACTUAL_TARGET_COUNT; i++) {
      let x = 0;
      let y = 0;
      let pressure = 0;
      let totalWeight = 0;

      for (const kf of activeKeyframes) {
          const rawPoints = kf.points!;
          let processedPoints: Point[] = [];

          if (mode === 'points' || mode === 'spline') {
             if (rawPoints.length === ACTUAL_TARGET_COUNT) {
                 processedPoints = rawPoints;
             } else {
                 processedPoints = upsamplePreservingCorners(rawPoints, ACTUAL_TARGET_COUNT);
             }
          } else {
             processedPoints = resamplePoints(rawPoints, ACTUAL_TARGET_COUNT);
          }

          // STRICT LINEAR ALIGNMENT (isClosed is always false)
          const alignedPoints = alignPoints(referenceResampled, processedPoints, isClosed);

          const pt = alignedPoints[i];

          x += pt.x * kf.weight;
          y += pt.y * kf.weight;
          pressure += (pt.pressure || 0.5) * kf.weight;
          totalWeight += kf.weight;
      }

      if (totalWeight > 0) {
          resultPoints.push({
              x: x / totalWeight,
              y: y / totalWeight,
              pressure: pressure / totalWeight
          });
      }
  }

  return { points: resultPoints, color, fillColor, width };
};

// --- OPTIMIZATION & SMOOTHING ---

const perpendicularDistance = (point: Point, lineStart: Point, lineEnd: Point): number => {
  let dx = lineEnd.x - lineStart.x;
  let dy = lineEnd.y - lineStart.y;
  const mag = Math.sqrt(dx * dx + dy * dy);
  if (mag > 0.0) { dx /= mag; dy /= mag; }
  const pvx = point.x - lineStart.x;
  const pvy = point.y - lineStart.y;
  const pvdot = pvx * dx + pvy * dy;
  const dsx = pvdot * dx;
  const dsy = pvdot * dy;
  const ax = pvx - dsx;
  const ay = pvy - dsy;
  return Math.sqrt(ax * ax + ay * ay);
};

export const simplifyPoints = (points: Point[], epsilon: number = 2): Point[] => {
  if (points.length < 3) return points;
  let dmax = 0;
  let index = 0;
  const end = points.length - 1;
  for (let i = 1; i < end; i++) {
    const d = perpendicularDistance(points[i], points[0], points[end]);
    if (d > dmax) { index = i; dmax = d; }
  }
  if (dmax > epsilon) {
    const recResults1 = simplifyPoints(points.slice(0, index + 1), epsilon);
    const recResults2 = simplifyPoints(points.slice(index, end + 1), epsilon);
    return [...recResults1.slice(0, -1), ...recResults2];
  } else {
    return [points[0], points[end]];
  }
};

export const simplifyCollinearPoints = (points: Point[], epsilon: number = 0.5): Point[] => {
  if (points.length < 3) return points;
  const result = [points[0]];
  for (let i = 1; i < points.length - 1; i++) {
    const prev = result[result.length - 1];
    const curr = points[i];
    const next = points[i + 1];

    // Check Collinearity using Cross Product
    // The "epsilon" here acts as an area check.
    const val = (curr.y - prev.y) * (next.x - curr.x) - (curr.x - prev.x) * (next.y - curr.y);

    // Check if point is very close to previous (Micro-segment removal)
    const dist = distance(curr, prev);

    // Keep point ONLY if it is significant
    if (Math.abs(val) > epsilon && dist > 1.0) {
       result.push(curr);
    }
  }
  result.push(points[points.length - 1]);
  return result;
};

export const chaikinSmooth = (points: Point[], iterations: number = 2): Point[] => {
    if (points.length < 3) return points;
    let output = [...points];
    for (let i = 0; i < iterations; i++) {
        const next: Point[] = [];
        next.push(output[0]);
        for (let j = 0; j < output.length - 1; j++) {
            const p0 = output[j];
            const p1 = output[j + 1];
            next.push({
                x: 0.75 * p0.x + 0.25 * p1.x,
                y: 0.75 * p0.y + 0.25 * p1.y,
                pressure: lerp(p0.pressure || 0.5, p1.pressure || 0.5, 0.25)
            });
            next.push({
                x: 0.25 * p0.x + 0.75 * p1.x,
                y: 0.25 * p0.y + 0.75 * p1.y,
                pressure: lerp(p0.pressure || 0.5, p1.pressure || 0.5, 0.75)
            });
        }
        next.push(output[output.length - 1]);
        output = next;
    }
    return output;
};

// --- RENDERERS ---

export const drawCornerRoundedPath = (ctx: CanvasRenderingContext2D, rawPoints: Point[], roundness: number) => {
    if (rawPoints.length < 2) return;

    // 1. ROBUST FILTERING:
    // Remove micro-segments (< 1px) that confuse the normal calculations
    const points: Point[] = [];
    points.push(rawPoints[0]);

    for (let i = 1; i < rawPoints.length; i++) {
        const curr = rawPoints[i];
        const prev = points[points.length - 1];
        if (distance(prev, curr) < 1.0) continue; // Minimum segment length 1px
        points.push(curr);
    }

    // Ensure geometric loop consistency without logical closure
    const rawClosed = distance(rawPoints[0], rawPoints[rawPoints.length-1]) < 0.1;
    if (rawClosed && distance(points[0], points[points.length-1]) > 1.0) {
         points.push(points[0]);
    }

    if (points.length < 2) return;

    const isClosed = distance(points[0], points[points.length - 1]) < 0.1;
    let uniquePoints = isClosed ? points.slice(0, -1) : points;

    if (uniquePoints.length < 2) return;

    ctx.beginPath();

    if (!isClosed) {
        ctx.moveTo(points[0].x, points[0].y);
    } 

    const len = uniquePoints.length;
    const startIdx = isClosed ? 0 : 1;
    const endIdx = isClosed ? len : len - 1;

    if (isClosed) {
        const pLast = uniquePoints[len-1];
        const pFirst = uniquePoints[0];
        ctx.moveTo((pLast.x + pFirst.x)/2, (pLast.y + pFirst.y)/2);
    }

    for (let i = startIdx; i < endIdx; i++) {
        const curr = uniquePoints[i];

        const prevIdx = (i - 1 + len) % len;
        const nextIdx = (i + 1) % len;

        const prev = isClosed ? uniquePoints[prevIdx] : points[i-1];
        const next = isClosed ? uniquePoints[nextIdx] : points[i+1];

        const len1 = distance(prev, curr);
        const len2 = distance(curr, next);

        // Skip rounding if segments are too short, even after filtering
        if (len1 < 1.0 || len2 < 1.0) {
            ctx.lineTo(curr.x, curr.y);
            continue;
        }

        const v1x = curr.x - prev.x; const v1y = curr.y - prev.y;
        const v2x = next.x - curr.x; const v2y = next.y - curr.y;
        const n1x = v1x/len1; const n1y = v1y/len1;
        const n2x = v2x/len2; const n2y = v2y/len2;
        const dot = n1x * n2x + n1y * n2y;

        // ANGLE THRESHOLD
        // If the angle is very flat (collinear), skip rounding to avoid jitter.
        // 0.999 is approx 2.5 degrees. Any bend less than that is treated as straight.
        if (dot > 0.999) {
             ctx.lineTo(curr.x, curr.y);
             continue;
        }

        const maxTangent = Math.min(len1, len2) * 0.5;
        const currentTangent = maxTangent * (roundness / 100);
        const angle = Math.acos(Math.max(-1, Math.min(1, dot)));
        const innerAngle = Math.PI - angle;
        const radius = currentTangent * Math.tan(innerAngle / 2);

        ctx.arcTo(curr.x, curr.y, next.x, next.y, radius);
    }

    if (isClosed) {
        const pLast = uniquePoints[len-1];
        const pFirst = uniquePoints[0];
        ctx.lineTo((pLast.x + pFirst.x)/2, (pLast.y + pFirst.y)/2);
    } else {
        ctx.lineTo(points[points.length-1].x, points[points.length-1].y);
    }
};

export const drawCatmullRomSpline = (ctx: CanvasRenderingContext2D, points: Point[], tension: number = 0.5) => {
    if (points.length < 2) return;

    ctx.beginPath();
    ctx.moveTo(points[0].x, points[0].y);

    const len = points.length;
    const isClosed = distance(points[0], points[len - 1]) < 0.1;

    for (let i = 0; i < len - 1; i++) {
        const p0 = i > 0 ? points[i - 1] : points[0];
        const p1 = points[i];
        const p2 = points[i + 1];
        const p3 = i < len - 2 ? points[i + 2] : points[len - 1];

        const p0_loop = isClosed && i === 0 ? points[len - 2] : p0;
        const p3_loop = isClosed && i === len - 2 ? points[1] : p3;

        const cp1x = p1.x + (p2.x - (isClosed ? p0_loop.x : p0.x)) / 6 * tension;
        const cp1y = p1.y + (p2.y - (isClosed ? p0_loop.y : p0.y)) / 6 * tension;
        const cp2x = p2.x - ((isClosed ? p3_loop.x : p3.x) - p1.x) / 6 * tension;
        const cp2y = p2.y - ((isClosed ? p3_loop.y : p3.y) - p1.y) / 6 * tension;

        ctx.bezierCurveTo(cp1x, cp1y, cp2x, cp2y, p2.x, p2.y);
    }
};

// components/Canvas.tsx
import React, { useRef, useLayoutEffect, useEffect, useState } from 'react';
import { useStore } from '../store/useStore';
import { interpolateStrokePoints, snapPointToGrid, isPointInStroke, calculateInterpolationWeights, distance, getBoundingBox, rotatePoint, lerp, drawCornerRoundedPath, drawCatmullRomSpline, simplifyCollinearPoints } from '../utils/math';
import { Point } from '../types';
import { APP_COLORS } from '../constants';

type InteractionMode = 'none' | 'drawing' | 'polyline' | 'dragging' | 'resizing' | 'rotating' | 'draggingVertex';
type ResizeHandle = 'tl' | 'tr' | 'bl' | 'br';

export const Canvas: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  const { 
      ui, project, updateAxisValue, updateMultipleAxisValues, 
      addStrokeToCurrentKeyframe, updateStrokeInCurrentKeyframe, selectStroke,
      undo, redo, deleteStroke 
  } = useStore();

  // -- Stable Refs for Animation Loop --
  const projectRef = useRef(project);
  const uiRef = useRef(ui);

  useEffect(() => { projectRef.current = project; }, [project]);
  useEffect(() => { uiRef.current = ui; }, [ui]);

  // -- Physics State (Refs to avoid re-renders) --
  const targetAxesRef = useRef<Record<string, number>>({ 'axis-x': 0.5, 'axis-y': 0.5 });
  const velocityRef = useRef<{ x: number, y: number }>({ x: 0, y: 0 });
  const lastFrameTimeRef = useRef<number>(0);

  // -- Interaction State (Refs needed for Loop access without stale closure) --
  const currentPointsRef = useRef<Point[]>([]); 
  const interactionModeRef = useRef<InteractionMode>('none');

  // -- SYNCED REFS FOR RENDERING --
  const [polylinePoints, setPolylinePoints] = useState<Point[]>([]);
  const polylinePointsRef = useRef<Point[]>([]);
  useEffect(() => { polylinePointsRef.current = polylinePoints; }, [polylinePoints]);

  const [mousePos, setMousePos] = useState<Point | null>(null);
  const mousePosRef = useRef<Point | null>(null);
  useEffect(() => { mousePosRef.current = mousePos; }, [mousePos]);

  const [selectionBounds, setSelectionBounds] = useState<{cx: number; cy: number; width: number; height: number; rotation: number;} | null>(null);
  const selectionBoundsRef = useRef(selectionBounds);
  useEffect(() => { selectionBoundsRef.current = selectionBounds; }, [selectionBounds]);

  const [transformStart, setTransformStart] = useState<{
      mouse: Point;
      center: Point;
      angle: number;
      width: number;
      height: number;
      points: Point[]; 
  } | null>(null);
  const transformStartRef = useRef(transformStart);
  useEffect(() => { transformStartRef.current = transformStart; }, [transformStart]);

  const [activeHandle, setActiveHandle] = useState<ResizeHandle | null>(null);
  const [activeVertexIndex, setActiveVertexIndex] = useState<number | null>(null);
  const activeVertexIndexRef = useRef<number | null>(null);
  useEffect(() => { activeVertexIndexRef.current = activeVertexIndex; }, [activeVertexIndex]);

  const [isVertexMode, setIsVertexMode] = useState(false);
  const isVertexModeRef = useRef(false);
  useEffect(() => { isVertexModeRef.current = isVertexMode; }, [isVertexMode]);

  useEffect(() => {
      if (!ui.selectedStrokeId) {
          setIsVertexMode(false);
      }
  }, [ui.selectedStrokeId]);

  const setInteractionMode = (mode: InteractionMode) => {
      interactionModeRef.current = mode;
      setInteractionModeState(mode);
  };
  const [interactionModeState, setInteractionModeState] = useState<InteractionMode>('none');

  const [scale, setScale] = useState(1);
  const CANVAS_WIDTH = project.canvasSize.width;
  const CANVAS_HEIGHT = project.canvasSize.height;

  // -- Helpers --

  useEffect(() => {
    const handleResize = () => {
      if (!containerRef.current) return;
      const { width: contW, height: contH } = containerRef.current.getBoundingClientRect();
      const margin = 80;
      const newScale = Math.min((contW - margin) / CANVAS_WIDTH, (contH - margin) / CANVAS_HEIGHT, 1);
      setScale(Math.max(0.1, newScale));
    };
    window.addEventListener('resize', handleResize);
    handleResize();
    return () => window.removeEventListener('resize', handleResize);
  }, [CANVAS_WIDTH, CANVAS_HEIGHT]);

  const getCanvasPoint = (e: React.PointerEvent): Point => {
    if (!canvasRef.current) return { x: 0, y: 0 };
    const rect = canvasRef.current.getBoundingClientRect();
    const x = (e.clientX - rect.left) * (CANVAS_WIDTH / rect.width);
    const y = (e.clientY - rect.top) * (CANVAS_HEIGHT / rect.height);
    return { x, y, pressure: e.pressure || 0.5 };
  };

  const getSnappedPoint = (p: Point): Point => {
      if (ui.snapToGrid) {
          const centerX = CANVAS_WIDTH / 2;
          const centerY = CANVAS_HEIGHT / 2;
          const offset = {
              x: (centerX % ui.gridSize),
              y: (centerY % ui.gridSize)
          };
          return snapPointToGrid(p, ui.gridSize, offset);
      }
      return p;
  };

  useEffect(() => {
    if (ui.mode !== 'play') return;

    const handleWindowPointerMove = (e: PointerEvent) => {
        if (!canvasRef.current) return;
        const rect = canvasRef.current.getBoundingClientRect();

        let normX = (e.clientX - rect.left) / rect.width;
        let normY = (e.clientY - rect.top) / rect.height;

        normX = Math.max(0, Math.min(1, normX));
        normY = Math.max(0, Math.min(1, normY));

        if (ui.snapPlayMode) {
            normX = Math.round(normX * 10) / 10;
            normY = Math.round(normY * 10) / 10;
        }

        targetAxesRef.current = { 'axis-x': normX, 'axis-y': normY };
    };

    window.addEventListener('pointermove', handleWindowPointerMove);
    return () => {
        window.removeEventListener('pointermove', handleWindowPointerMove);
    };
  }, [ui.mode, ui.snapPlayMode]);

  const handleDoubleClick = (e: React.MouseEvent) => {
      if (ui.selectedTool === 'polyline') {
          if (polylinePoints.length > 1) addStrokeToCurrentKeyframe(polylinePoints, false, true);
          setPolylinePoints([]);
          return;
      }

      if (ui.selectedTool === 'select' && ui.selectedStrokeId) {
           setIsVertexMode(true); 
      }
  };

  useEffect(() => {
      const handleKeyDown = (e: KeyboardEvent) => {
          if ((e.target as HTMLElement).tagName === 'INPUT') return;

          if (e.key === 'Enter') { 
              if (ui.selectedTool === 'polyline') handleDoubleClick({} as React.MouseEvent);
          }
          if (e.key === 'Escape') { 
              if (isVertexMode) {
                  setIsVertexMode(false); 
              } else {
                  setPolylinePoints([]); 
                  setInteractionMode('none'); 
                  selectStroke(null);
              }
          }

          if ((e.metaKey || e.ctrlKey) && e.key === 'z') {
              e.preventDefault();
              if (e.shiftKey) redo();
              else undo();
          }
          if ((e.metaKey || e.ctrlKey) && e.key === 'y') {
              e.preventDefault();
              redo();
          }

          if (e.key === 'Backspace' || e.key === 'Delete') {
              if (ui.selectedStrokeId) {
                  deleteStroke(ui.selectedStrokeId);
              }
          }

          if (ui.selectedStrokeId && ui.selectedKeyframeId && ui.selectedLayerId && (e.key.startsWith('Arrow'))) {
              e.preventDefault();
              const kf = project.keyframes.find(k => k.id === ui.selectedKeyframeId);
              const ls = kf?.layerStates.find(s => s.layerId === ui.selectedLayerId);
              const stroke = ls?.strokes.find(s => s.id === ui.selectedStrokeId);

              if (stroke) {
                  const step = e.shiftKey ? ui.gridSize : 1;
                  let dx = 0;
                  let dy = 0;
                  if (e.key === 'ArrowUp') dy = -step;
                  if (e.key === 'ArrowDown') dy = step;
                  if (e.key === 'ArrowLeft') dx = -step;
                  if (e.key === 'ArrowRight') dx = step;

                  const newPoints = stroke.points.map(p => ({ ...p, x: p.x + dx, y: p.y + dy }));
                  updateStrokeInCurrentKeyframe(stroke.id, newPoints);
              }
          }
      };

      window.addEventListener('keydown', handleKeyDown);
      return () => window.removeEventListener('keydown', handleKeyDown);
  }, [ui.selectedTool, ui.selectedStrokeId, ui.selectedKeyframeId, ui.selectedLayerId, polylinePoints, project.keyframes, isVertexMode]);

  useEffect(() => {
    if (ui.selectedTool !== 'select' || !ui.selectedStrokeId || !ui.selectedKeyframeId) {
        setSelectionBounds(null);
        return;
    }
    const kf = project.keyframes.find(k => k.id === ui.selectedKeyframeId);
    if (!kf) return;
    const layerState = kf.layerStates.find(ls => ls.layerId === ui.selectedLayerId);
    if (!layerState) return;
    const stroke = layerState.strokes.find(s => s.id === ui.selectedStrokeId);
    if (!stroke) return;
    const bbox = getBoundingBox(stroke.points);
    setSelectionBounds({
        cx: bbox.centerX, cy: bbox.centerY, width: bbox.width, height: bbox.height, rotation: 0
    });
  }, [ui.selectedStrokeId, ui.selectedKeyframeId, ui.selectedLayerId, ui.selectedTool, project.keyframes]);

  const getGizmoHit = (p: Point, bounds: { cx: number, cy: number, width: number, height: number, rotation: number } | null) => {
      if (!bounds) return null;
      const { cx, cy, width, height, rotation } = bounds;
      const hw = width / 2; const hh = height / 2;
      const localP = rotatePoint(p, {x: cx, y: cy}, -rotation);
      const HANDLE_SIZE = 10 / scale;
      if (distance(localP, {x: cx, y: cy - hh - 25}) < HANDLE_SIZE) return 'rotator';
      if (distance(localP, {x: cx - hw, y: cy - hh}) < HANDLE_SIZE) return 'tl';
      if (distance(localP, {x: cx + hw, y: cy - hh}) < HANDLE_SIZE) return 'tr';
      if (distance(localP, {x: cx - hw, y: cy + hh}) < HANDLE_SIZE) return 'bl';
      if (distance(localP, {x: cx + hw, y: cy + hh}) < HANDLE_SIZE) return 'br';
      if (localP.x >= cx - hw && localP.x <= cx + hw && localP.y >= cy - hh && localP.y <= cy + hh) return 'body';
      return null;
  };

  const getVertexHit = (p: Point, strokePoints: Point[]): number => {
      const HIT_THRESHOLD = 8 / scale;
      for (let i = strokePoints.length - 1; i >= 0; i--) {
          if (distance(p, strokePoints[i]) < HIT_THRESHOLD) return i;
      }
      return -1;
  };

  const findHitStroke = (p: Point): string | null => {
     const kf = project.keyframes.find(k => k.id === ui.selectedKeyframeId);
     if (!kf) return null;
     const layerState = kf.layerStates.find(ls => ls.layerId === ui.selectedLayerId);
     if (!layerState) return null;
     for (let i = layerState.strokes.length - 1; i >= 0; i--) {
        const s = layerState.strokes[i];
        if (isPointInStroke(p, s.points)) return s.id;
     }
     return null;
  };

  const handlePointerDown = (e: React.PointerEvent) => {
    const p = getCanvasPoint(e);

    if (ui.mode === 'play') {
       return;
    }

    if (ui.selectedTool === 'select') {

        if (isVertexMode && ui.selectedStrokeId) {
             const kf = project.keyframes.find(k => k.id === ui.selectedKeyframeId);
             const ls = kf?.layerStates.find(s => s.layerId === ui.selectedLayerId);
             const stroke = ls?.strokes.find(s => s.id === ui.selectedStrokeId);

             if (stroke) {
                 const vertexIndex = getVertexHit(p, stroke.points);
                 if (vertexIndex !== -1) {
                     setInteractionMode('draggingVertex');
                     setActiveVertexIndex(vertexIndex);
                     setTransformStart({
                        mouse: p, center: {x:0,y:0}, angle: 0, width: 0, height: 0, 
                        points: stroke.points 
                     });
                     (e.target as Element).setPointerCapture(e.pointerId);
                     return;
                 }
             }
        }

        if (!isVertexMode && ui.selectedStrokeId && selectionBounds) {
            const hitGizmo = getGizmoHit(p, selectionBounds);
            if (hitGizmo) {
                const kf = project.keyframes.find(k => k.id === ui.selectedKeyframeId);
                const ls = kf?.layerStates.find(s => s.layerId === ui.selectedLayerId);
                const stroke = ls?.strokes.find(s => s.id === ui.selectedStrokeId);
                if (stroke) {
                    setTransformStart({
                        mouse: p, center: { x: selectionBounds.cx, y: selectionBounds.cy },
                        angle: selectionBounds.rotation, width: selectionBounds.width, height: selectionBounds.height, points: stroke.points
                    });
                    if (hitGizmo === 'body') setInteractionMode('dragging');
                    else if (hitGizmo === 'rotator') setInteractionMode('rotating');
                    else { setInteractionMode('resizing'); setActiveHandle(hitGizmo as ResizeHandle); }
                    (e.target as Element).setPointerCapture(e.pointerId);
                }
                return;
            }
        }

        const hitId = findHitStroke(p);
        if (hitId) {
             selectStroke(hitId); 
             setIsVertexMode(false); 
        } else {
             selectStroke(null);
             setIsVertexMode(false); 
        }
        return;
    }

    if (ui.selectedTool === 'polyline') {
       const snappedP = getSnappedPoint(p);
       // REMOVED AUTO-CLOSE SNAP LOGIC HERE
       // We strictly just add points. Double-click terminates.
       setPolylinePoints(prev => [...prev, snappedP]);
       return;
    }

    if (ui.selectedTool === 'pen') {
      setInteractionMode('drawing'); 
      currentPointsRef.current = [getSnappedPoint(p)];
      (e.target as Element).setPointerCapture(e.pointerId);
    } 
  };

  const handlePointerMove = (e: React.PointerEvent) => {
    const p = getCanvasPoint(e);
    setMousePos(getSnappedPoint(p));

    if (ui.mode === 'play') return;

    if (interactionModeRef.current === 'draggingVertex' && transformStart && activeVertexIndex !== null) {
        let draggedPos = p;
        if (ui.snapToGrid) draggedPos = getSnappedPoint(p);

        const newPoints = [...transformStart.points];

        const len = newPoints.length;
        const isClosedGeometry = distance(newPoints[0], newPoints[len-1]) < 0.1;

        newPoints[activeVertexIndex] = { ...newPoints[activeVertexIndex], x: draggedPos.x, y: draggedPos.y };

        if (isClosedGeometry) {
            if (activeVertexIndex === 0) newPoints[len-1] = { ...newPoints[len-1], x: draggedPos.x, y: draggedPos.y };
            else if (activeVertexIndex === len-1) newPoints[0] = { ...newPoints[0], x: draggedPos.x, y: draggedPos.y };
        }

        if (ui.selectedStrokeId) {
            updateStrokeInCurrentKeyframe(ui.selectedStrokeId, newPoints);
             setTransformStart({
                 ...transformStart,
                 points: newPoints
             });
        }
        return;
    }

    if (interactionModeRef.current !== 'none' && transformStart && selectionBounds) {
        if (interactionModeRef.current === 'dragging') {
            let dx = p.x - transformStart.mouse.x; 
            let dy = p.y - transformStart.mouse.y;

            if (ui.snapToGrid) {
                dx = Math.round(dx / ui.gridSize) * ui.gridSize;
                dy = Math.round(dy / ui.gridSize) * ui.gridSize;
            }

            setSelectionBounds({ ...selectionBounds, cx: transformStart.center.x + dx, cy: transformStart.center.y + dy });

        } else if (interactionModeRef.current === 'rotating') {
            const currentAngle = Math.atan2(p.y - selectionBounds.cy, p.x - selectionBounds.cx);
            const startAngle = Math.atan2(transformStart.mouse.y - selectionBounds.cy, transformStart.mouse.x - selectionBounds.cx);
            let dAngle = currentAngle - startAngle; let newRotation = transformStart.angle + dAngle;
            if (e.shiftKey) { const step = Math.PI / 12; newRotation = Math.round(newRotation / step) * step; }
            setSelectionBounds({ ...selectionBounds, rotation: newRotation });
        } else if (interactionModeRef.current === 'resizing' && activeHandle) {
            const unrotatedMouse = rotatePoint(p, transformStart.center, -transformStart.angle);
            const unrotatedStart = rotatePoint(transformStart.mouse, transformStart.center, -transformStart.angle);
            let dx = unrotatedMouse.x - unrotatedStart.x; let dy = unrotatedMouse.y - unrotatedStart.y;
            if (e.shiftKey) { const aspect = transformStart.width / transformStart.height; dy = (activeHandle === 'br' || activeHandle === 'tl') ? dx / aspect : -dx / aspect; }
            if (ui.snapToGrid && !e.shiftKey) { dx = Math.round(dx / ui.gridSize) * ui.gridSize; dy = Math.round(dy / ui.gridSize) * ui.gridSize; }
            let newW = transformStart.width; let newH = transformStart.height;
            if (activeHandle === 'br') { newW += dx * 2; newH += dy * 2; }
            if (activeHandle === 'tl') { newW -= dx * 2; newH -= dy * 2; }
            if (activeHandle === 'tr') { newW += dx * 2; newH -= dy * 2; }
            if (activeHandle === 'bl') { newW -= dx * 2; newH += dy * 2; }
            newW = Math.max(1, newW); newH = Math.max(1, newH);
            setSelectionBounds({ ...selectionBounds, width: newW, height: newH });
        }
        return;
    }

    if (interactionModeRef.current === 'drawing') {
        currentPointsRef.current.push(getSnappedPoint(p));
    }
  };

  const handlePointerUp = (e: React.PointerEvent) => {
    if (ui.mode !== 'play') {
       (e.target as Element).releasePointerCapture(e.pointerId);
    }

    if ((interactionModeRef.current === 'dragging' || interactionModeRef.current === 'rotating' || interactionModeRef.current === 'resizing') && transformStart && selectionBounds && ui.selectedStrokeId) {
        const scaleX = selectionBounds.width / transformStart.width;
        const scaleY = selectionBounds.height / transformStart.height;
        const dRot = selectionBounds.rotation - transformStart.angle;
        const dX = selectionBounds.cx - transformStart.center.x;
        const dY = selectionBounds.cy - transformStart.center.y;
        const newPoints = transformStart.points.map(pt => {
            let x = pt.x - transformStart.center.x; let y = pt.y - transformStart.center.y;
            x *= scaleX; y *= scaleY;
            const cos = Math.cos(dRot); const sin = Math.sin(dRot);
            const rx = x * cos - y * sin; const ry = x * sin + y * cos;
            return { x: rx + transformStart.center.x + dX, y: ry + transformStart.center.y + dY, pressure: pt.pressure };
        });
        updateStrokeInCurrentKeyframe(ui.selectedStrokeId, newPoints);
    }

    if (interactionModeRef.current === 'drawing' && currentPointsRef.current.length > 1) {
        const points = [...currentPointsRef.current];
        addStrokeToCurrentKeyframe(points, false);
    }
    setInteractionMode('none'); setActiveHandle(null); setTransformStart(null); setActiveVertexIndex(null); currentPointsRef.current = [];
  };

  useLayoutEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    let animationFrameId: number;

    const render = (time: number) => {
      if (!lastFrameTimeRef.current) lastFrameTimeRef.current = time;
      const dt = Math.min((time - lastFrameTimeRef.current) / 1000, 0.1); 
      lastFrameTimeRef.current = time;

      const currentProject = projectRef.current;
      const currentUI = uiRef.current;
      const activeVertIdx = activeVertexIndexRef.current;
      const isVertexModeActive = isVertexModeRef.current; 

      const currentPolyline = polylinePointsRef.current;
      const currentSelectionBounds = selectionBoundsRef.current;
      const currentMousePos = mousePosRef.current;

      const dpr = currentUI.resolutionScale || window.devicePixelRatio || 1;
      const interpolationTargetCount = currentUI.performanceMode ? 80 : 200;

      if (canvas.width !== CANVAS_WIDTH * dpr || canvas.height !== CANVAS_HEIGHT * dpr) {
          canvas.width = CANVAS_WIDTH * dpr;
          canvas.height = CANVAS_HEIGHT * dpr;
          ctx.scale(dpr, dpr);
      }

      if (currentUI.mode === 'play') {
          const axisX = currentProject.axes.find(a => a.id === 'axis-x');
          const axisY = currentProject.axes.find(a => a.id === 'axis-y');

          if (axisX && axisY) {
              const targetX = targetAxesRef.current['axis-x'];
              const targetY = targetAxesRef.current['axis-y'];

              let nextX = axisX.currentValue;
              let nextY = axisY.currentValue;

              if (currentUI.playModePhysics) {
                  const stiffness = currentUI.springStiffness || 120;
                  const damping = currentUI.springDamping || 20;

                  const forceX = (targetX - nextX) * stiffness - velocityRef.current.x * damping;
                  const forceY = (targetY - nextY) * stiffness - velocityRef.current.y * damping;

                  velocityRef.current.x += forceX * dt;
                  velocityRef.current.y += forceY * dt;

                  nextX += velocityRef.current.x * dt;
                  nextY += velocityRef.current.y * dt;
              } else {
                  nextX = targetX;
                  nextY = targetY;
                  velocityRef.current = { x: 0, y: 0 };
              }

              if (Math.abs(nextX - axisX.currentValue) > 0.0001 || Math.abs(nextY - axisY.currentValue) > 0.0001) {
                  const clampedX = Math.max(0, Math.min(1, nextX));
                  const clampedY = Math.max(0, Math.min(1, nextY));
                  updateMultipleAxisValues({ 'axis-x': clampedX, 'axis-y': clampedY });
              }
          }
      } else {
           const curX = currentProject.axes.find(a => a.id === 'axis-x')?.currentValue || 0.5;
           const curY = currentProject.axes.find(a => a.id === 'axis-y')?.currentValue || 0.5;
           targetAxesRef.current = { 'axis-x': curX, 'axis-y': curY };
           velocityRef.current = { x: 0, y: 0 };
      }

      ctx.clearRect(0, 0, CANVAS_WIDTH, CANVAS_HEIGHT);
      ctx.fillStyle = '#FFFFFF';
      ctx.fillRect(0, 0, CANVAS_WIDTH, CANVAS_HEIGHT);

      if (currentUI.showGrid && currentUI.mode === 'edit') {
        ctx.fillStyle = '#D1D5DB';
        const gridSize = currentUI.gridSize;
        const centerX = CANVAS_WIDTH / 2;
        const centerY = CANVAS_HEIGHT / 2;
        const startX = (centerX % gridSize);
        const startY = (centerY % gridSize);
        for (let x = startX; x <= CANVAS_WIDTH; x += gridSize) {
           for (let y = startY; y <= CANVAS_HEIGHT; y += gridSize) {
              ctx.beginPath();
              ctx.arc(x, y, 1.5, 0, Math.PI * 2);
              ctx.fill();
           }
        }
      }

      if (currentUI.onionSkinEnabled && currentUI.mode === 'edit') {
         currentProject.keyframes.forEach(kf => {
           if (kf.id === currentUI.selectedKeyframeId) return; 
           ctx.globalAlpha = currentUI.onionSkinOpacity;
           kf.layerStates.forEach(ls => {
              if (ls.layerId !== currentUI.selectedLayerId) return;
              const stroke = ls.strokes[0];
              if (stroke && stroke.points.length > 1) {
                const targetLayer = currentProject.layers.find(l => l.id === ls.layerId);
                const isSpline = targetLayer?.interpolationMode === 'spline';

                if (isSpline) {
                     drawCatmullRomSpline(ctx, stroke.points, 0.5);
                     ctx.stroke();
                } else {
                    ctx.beginPath();
                    if (currentUI.cornerRoundness > 0) {
                       drawCornerRoundedPath(ctx, stroke.points, currentUI.cornerRoundness);
                    } else {
                       ctx.moveTo(stroke.points[0].x, stroke.points[0].y);
                       for (let i = 1; i < stroke.points.length; i++) ctx.lineTo(stroke.points[i].x, stroke.points[i].y);
                    }
                    ctx.strokeStyle = '#3B82F6'; 
                    ctx.lineWidth = 1; 
                    ctx.stroke();
                }
              }
           });
           ctx.globalAlpha = 1.0;
         });
      }

      const currentAxesDict: Record<string, number> = {};
      currentProject.axes.forEach(a => currentAxesDict[a.id] = a.currentValue);

      currentProject.layers.forEach(layer => {
        if (!layer.visible) return;

        const layerRelevantKeyframes = currentProject.keyframes.filter(kf => {
            const ls = kf.layerStates.find(s => s.layerId === layer.id);
            return ls && ls.strokes.length > 0;
        });

        if (layerRelevantKeyframes.length === 0) return;

        const weights = calculateInterpolationWeights(currentAxesDict, layerRelevantKeyframes, currentUI.interpolationExponent, currentUI.interpolationStrategy);

        const activeKeyframes = layerRelevantKeyframes
             .map(k => ({ ...k, weight: weights[k.id] || 0 }))
             .filter(k => k.weight > 0.0001);

        const strokeId = `stroke-${layer.id}-unique`;
        const isLayerActive = layer.id === currentUI.selectedLayerId;
        const isCreatingNewState = currentUI.selectedKeyframeId === null;

        let layerGlobalAlpha = layer.opacity;
        if (!isLayerActive && currentUI.mode !== 'play') layerGlobalAlpha *= currentUI.inactiveLayerOpacity;
        if (isCreatingNewState && currentUI.mode === 'edit') layerGlobalAlpha *= currentUI.ghostStrokeOpacity;

        const strokeData = activeKeyframes.map(kf => {
            const state = kf.layerStates.find(ls => ls.layerId === layer.id);
            const s = state?.strokes[0]; 
            return { weight: kf.weight, points: s?.points, style: s, color: s?.color || 'none', fillColor: s?.fillColor, width: s?.width || 1 };
        });

        const sortedByWeight = [...strokeData].sort((a,b) => b.weight - a.weight);
        const primaryStroke = sortedByWeight.find(sd => sd.style)?.style;
        if (!primaryStroke) return;

        const { points: interpolatedPoints, color: interpolatedColor, fillColor: interpolatedFill, width: interpolatedWidth } = interpolateStrokePoints(
            strokeId, 
            primaryStroke.points, 
            strokeData, 
            layer.interpolationMode,
            interpolationTargetCount 
        );

        if (interpolatedPoints.length > 0) {

            if (layer.interpolationMode === 'spline') {
                drawCatmullRomSpline(ctx, interpolatedPoints, 0.5); 
            } else {
                ctx.beginPath();
                if (currentUI.cornerRoundness > 0) {
                    // CLEANUP: We must clean collinear points created by interpolation before applying rounded corners.
                    // This prevents the "jumping" when an interpolated vertex passes through a straight line angle.
                    const cleanPoints = simplifyCollinearPoints(interpolatedPoints, 0.5);
                    drawCornerRoundedPath(ctx, cleanPoints, currentUI.cornerRoundness);
                } else {
                    ctx.moveTo(interpolatedPoints[0].x, interpolatedPoints[0].y);
                    for (let i = 1; i < interpolatedPoints.length; i++) ctx.lineTo(interpolatedPoints[i].x, interpolatedPoints[i].y);
                }
            }

            ctx.globalAlpha = layerGlobalAlpha;
            switch(layer.blendMode) {
                case 'multiply': ctx.globalCompositeOperation = 'multiply'; break;
                case 'screen': ctx.globalCompositeOperation = 'screen'; break;
                case 'overlay': ctx.globalCompositeOperation = 'overlay'; break;
                case 'difference': ctx.globalCompositeOperation = 'difference'; break;
                case 'exclusion': ctx.globalCompositeOperation = 'exclusion'; break;
                default: ctx.globalCompositeOperation = 'source-over';
            }

            if (interpolatedFill && interpolatedFill !== 'none') {
                ctx.fillStyle = interpolatedFill;
                ctx.fill();
            }
            if (interpolatedColor && interpolatedColor !== 'none') {
                ctx.lineCap = 'round';
                ctx.lineJoin = 'round';
                ctx.strokeStyle = interpolatedColor;
                ctx.lineWidth = interpolatedWidth;
                ctx.stroke();
            }

            ctx.globalAlpha = 1.0;
            ctx.globalCompositeOperation = 'source-over';
        }
      });

      if (interactionModeRef.current === 'drawing' && currentPointsRef.current.length > 0) {
        ctx.globalAlpha = 1.0; 

        ctx.beginPath();
        const pts = currentPointsRef.current;

        if (currentUI.cornerRoundness > 0) {
             drawCornerRoundedPath(ctx, pts, currentUI.cornerRoundness);
        } else {
             ctx.moveTo(pts[0].x, pts[0].y);
             for (let i = 1; i < pts.length; i++) ctx.lineTo(pts[i].x, pts[i].y);
        }

        ctx.strokeStyle = currentUI.brushColor !== 'none' ? currentUI.brushColor : 'rgba(0,0,0,0.5)';
        ctx.lineWidth = currentUI.brushSize;
        ctx.lineCap = 'round';
        ctx.lineJoin = 'round';
        ctx.stroke();
        ctx.globalAlpha = 1.0; 
      }

      if (currentPolyline.length > 0) {
         const isGhostState = currentUI.selectedKeyframeId === null;

         const polyPreview = currentMousePos ? [...currentPolyline, currentMousePos] : currentPolyline;

         const currentLayer = currentProject.layers.find(l => l.id === currentUI.selectedLayerId);
         const isSpline = currentLayer?.interpolationMode === 'spline';

         if (isSpline) {
             drawCatmullRomSpline(ctx, polyPreview, 0.5);
         } else {
             ctx.beginPath();
             if (currentUI.cornerRoundness > 0) {
                 drawCornerRoundedPath(ctx, polyPreview, currentUI.cornerRoundness);
             } else {
                 ctx.moveTo(polyPreview[0].x, polyPreview[0].y);
                 for (let i = 1; i < polyPreview.length; i++) ctx.lineTo(polyPreview[i].x, polyPreview[i].y);
             }
         }

         if (currentUI.fillColor !== 'none') {
             ctx.fillStyle = currentUI.fillColor;
             ctx.globalAlpha = isGhostState ? currentUI.ghostStrokeOpacity * 0.8 : 0.5;
             ctx.fill();
         }

         ctx.globalAlpha = 1.0;
         ctx.strokeStyle = currentUI.brushColor !== 'none' ? currentUI.brushColor : 'rgba(0,0,0,0.5)';
         ctx.lineWidth = currentUI.brushSize;
         ctx.stroke();

         ctx.fillStyle = currentUI.brushColor !== 'none' ? currentUI.brushColor : 'rgba(0,0,0,0.5)';
         currentPolyline.forEach((p, index) => {
            ctx.beginPath();
            const r = (index === 0) ? 5 : 3; 
            ctx.arc(p.x, p.y, r, 0, Math.PI * 2);
            ctx.fill();
         });
         ctx.globalAlpha = 1.0; 
      }

      if (currentSelectionBounds && currentUI.selectedTool === 'select' && currentUI.mode === 'edit') {
          const { cx, cy, width, height, rotation } = currentSelectionBounds;

          if (!isVertexModeActive) {
            ctx.save();
            ctx.translate(cx, cy);
            ctx.rotate(rotation);

            ctx.beginPath();
            ctx.strokeStyle = '#3B82F6';
            ctx.lineWidth = 1;
            ctx.rect(-width/2, -height/2, width, height);
            ctx.stroke();

            const HANDLE_SIZE = 8; 
            ctx.fillStyle = '#FFFFFF';
            ctx.strokeStyle = '#3B82F6';

            const drawHandle = (x: number, y: number) => {
                ctx.beginPath();
                ctx.rect(x - HANDLE_SIZE/2, y - HANDLE_SIZE/2, HANDLE_SIZE, HANDLE_SIZE);
                ctx.fill();
                ctx.stroke();
            };

            drawHandle(-width/2, -height/2);
            drawHandle(width/2, -height/2);
            drawHandle(-width/2, height/2);
            drawHandle(width/2, height/2);

            ctx.beginPath();
            ctx.moveTo(0, -height/2);
            ctx.lineTo(0, -height/2 - 25);
            ctx.stroke();

            ctx.beginPath();
            ctx.arc(0, -height/2 - 25, 4, 0, Math.PI * 2);
            ctx.fillStyle = '#3B82F6';
            ctx.fill();

            ctx.restore();
          }

          if (isVertexModeActive) {
            const activeKf = currentProject.keyframes.find(k => k.id === currentUI.selectedKeyframeId);
            if (activeKf) {
                const activeLayerState = activeKf.layerStates.find(ls => ls.layerId === currentUI.selectedLayerId);
                const activeStroke = activeLayerState?.strokes.find(s => s.id === currentUI.selectedStrokeId);

                if (activeStroke) {
                    const VERTEX_RADIUS = 3;
                    const ACTIVE_VERTEX_RADIUS = 5;

                    ctx.strokeStyle = '#3B82F6';
                    ctx.fillStyle = '#FFFFFF';

                    activeStroke.points.forEach((p, idx) => {
                        const isActive = idx === activeVertIdx;
                        ctx.beginPath();
                        ctx.arc(p.x, p.y, isActive ? ACTIVE_VERTEX_RADIUS : VERTEX_RADIUS, 0, Math.PI * 2);
                        ctx.fillStyle = isActive ? '#3B82F6' : '#FFFFFF';
                        ctx.fill();
                        ctx.stroke();
                    });
                }
            }
          }
      }

      animationFrameId = requestAnimationFrame(render);
    };

    animationFrameId = requestAnimationFrame(render);
    return () => cancelAnimationFrame(animationFrameId);
  }, [CANVAS_WIDTH, CANVAS_HEIGHT]); 

  return (
    <div 
      ref={containerRef} 
      className="absolute inset-0 z-0 flex items-center justify-center bg-[#EAEAEA] touch-none"
    >
      <div 
        style={{ 
          width: CANVAS_WIDTH, 
          height: CANVAS_HEIGHT,
          transform: `scale(${scale})`,
          boxShadow: '0 20px 50px -12px rgba(0, 0, 0, 0.15)' 
        }}
        className="bg-white rounded-xl overflow-hidden relative transition-transform duration-200 ease-out origin-center ring-4 ring-white/50"
      >
          <canvas 
            ref={canvasRef} 
            className={`block w-full h-full ${ui.mode === 'play' ? 'cursor-move' : (ui.selectedTool === 'select' ? 'cursor-default' : 'cursor-crosshair')}`}
            onPointerDown={handlePointerDown}
            onPointerMove={handlePointerMove}
            onPointerUp={handlePointerUp}
            onDoubleClick={handleDoubleClick}
          />
      </div>
    </div>
  );
};

